/**
 * Класс для построения меню в Google Apps Script
 */
class MenuBuilder {
  /**
   * @param {GoogleAppsScript.Base.Ui} ui - UI объект Google Apps Script
   * @param {string} title - Заголовок меню
   */
  constructor(ui, title) {
    this.ui = ui;
    this.title = title;
  }

  /**
   * Создает меню из предопределенной структуры CONFIG
   * @param {string} menuType - Тип меню ('karandaev' или 'artur')
   * @param {Object} options - Дополнительные опции
   * @returns {GoogleAppsScript.Base.Menu} Объект меню
   */
  createMenuFromConfig(menuType, options = {}) {
    try {
      const menuConfig = MENU_STRUCTURE[menuType];
      if (!menuConfig) {
        throw new Error(`Тип меню '${menuType}' не найден в MENU_STRUCTURE`);
      }

      this.title = menuConfig.title;
      let menu = this.ui.createMenu(this.title);
      this.buildMenuItems(menu, menuConfig.items);

      // Добавляем дополнительные элементы если нужно
      if (options?.moysklad) {
        menu = this.addCustomSubMenu(menu, MENU_STRUCTURE["moysklad"]);
      }

      return menu;
    } catch (error) {
      throw new Error(`Не удалось создать меню из CONFIG: ${error.message}`);
    }
  }

  /**
   * Добавляет меню МойСклад
   * @param {GoogleAppsScript.Base.Menu} menu - Существующее меню
   * @returns {GoogleAppsScript.Base.Menu} Обновленное меню
   */
  addCustomSubMenu(menu, menuConfig) {
    menu.addSeparator();
    const submenu = this.ui.createMenu(menuConfig.titleAdd);
    this.buildMenuItems(submenu, menuConfig.items);
    menu.addSubMenu(submenu);
    return menu;
  }

  /**
   * Создает меню из объектной структуры
   * @param {Object} menuStructure - Структура меню
   * @returns {GoogleAppsScript.Base.Menu} Объект меню
   */
  createMenu(menuStructure) {
    try {
      const menu = this.ui.createMenu(this.title);
      this.buildMenuItems(menu, menuStructure);
      return menu;
    } catch (error) {
      throw new Error(`Не удалось создать меню: ${error.message}`);
    }
  }

  /**
   * Рекурсивно строит пункты меню
   * @param {GoogleAppsScript.Base.Menu} menu - Объект меню
   * @param {Object} items - Пункты меню
   */
  buildMenuItems(menu, items) {
    if (!items || typeof items !== "object") {
      console.warn("Передана некорректная структура меню");
      return;
    }

    Object.entries(items).forEach(([key, value]) => {
      try {
        // Обработка разделителя
        if (key === "separator" || value.separator) {
          menu.addSeparator();
          return;
        }

        // Проверка обязательных полей
        if (!value.label) {
          console.warn(`Пропущен label для пункта меню: ${key}`);
          return;
        }

        // Создание подменю
        if (value.submenu) {
          const submenu = this.ui.createMenu(value.label);
          this.buildMenuItems(submenu, value.submenu);
          menu.addSubMenu(submenu);
          return;
        }

        // Создание пункта меню
        if (value.func) {
          menu.addItem(value.label, value.func);
          return;
        }

        console.warn(`Некорректная структура пункта меню: ${key}`);
      } catch (error) {
        console.warn(`Ошибка добавления пункта меню ${key}:`, error.message);
      }
    });
  }

  /**
   * Добавляет дополнительные пункты меню
   * @param {GoogleAppsScript.Base.Menu} menu - Существующее меню
   * @param {Object} items - Дополнительные пункты
   * @returns {GoogleAppsScript.Base.Menu} Обновленное меню
   */
  addItems(menu, items) {
    try {
      this.buildMenuItems(menu, items);
      return menu;
    } catch (error) {
      console.error("Ошибка добавления пунктов меню:", error.stack);
      return menu;
    }
  }

  /**
   * Генерирует строковое представление готового меню для печати
   * @param {string} menuType - Тип меню ('karandaev', 'artur', 'full', etc.)
   * @param {Object} options - Дополнительные опции
   * @returns {string} Строковое представление кода для создания меню
   */
  generateMenuCode(options) {
    const { menuType = "full", moysklad = false } = options;

    try {
      const menuConfig = MENU_STRUCTURE[menuType];
      if (!menuConfig) {
        throw new Error(`Тип меню '${menuType}' не найден в MENU_STRUCTURE`);
      }

      let code = `var ui = SpreadsheetApp.getUi();\n`;
      code += `var menu = ui\n`;
      code += `  .createMenu("${menuConfig.title}")\n`;

      // Генерируем код для пунктов меню
      const menuItemsCode = this.generateMenuItemsCode(menuConfig.items, 2);
      code += menuItemsCode;

      // Добавляем МойСклад если нужно
      if (moysklad) {
        const moyskladConfig = MENU_STRUCTURE["moysklad"];
        if (moyskladConfig) {
          code += `  .addSeparator()\n`;
          code += `  .addSubMenu(\n`;
          code += `    ui\n`;
          code += `      .createMenu("${moyskladConfig.titleAdd}")\n`;
          const moyskladItemsCode = this.generateMenuItemsCode(
            moyskladConfig.items,
            6,
          );
          code += moyskladItemsCode;
          code += `  )\n`;
        }
      }

      return code + `.addToUi();`;
    } catch (error) {
      throw new Error(`Не удалось сгенерировать код меню: ${error.message}`);
    }
  }

  /**
   * Рекурсивно генерирует код для пунктов меню
   * @param {Object} items - Пункты меню
   * @param {number} indentLevel - Уровень отступа
   * @returns {string} Строковое представление кода пунктов меню
   */
  generateMenuItemsCode(items, indentLevel = 0) {
    if (!items || typeof items !== "object") {
      return "";
    }

    const indent = "  ".repeat(indentLevel);
    let code = "";

    Object.entries(items).forEach(([key, value]) => {
      try {
        // Обработка разделителя
        if (key === "separator" || value.separator) {
          code += `${indent}.addSeparator()\n`;
          return;
        }

        // Проверка обязательных полей
        if (!value.label) {
          console.warn(`Пропущен label для пункта меню: ${key}`);
          return;
        }

        // Создание подменю
        if (value.submenu) {
          code += `${indent}.addSubMenu(\n`;
          code += `${indent}  ui\n`;
          code += `${indent}    .createMenu("${value.label}")\n`;
          const submenuCode = this.generateMenuItemsCode(
            value.submenu,
            indentLevel + 4,
          );
          code += submenuCode;
          code += `${indent})\n`;
          return;
        }

        // Создание пункта меню
        if (value.func) {
          code += `${indent}.addItem("${value.label}", "${value.func}")\n`;
          return;
        }

        console.warn(`Некорректная структура пункта меню: ${key}`);
      } catch (error) {
        console.error(
          `Ошибка генерации кода для пункта меню ${key}:`,
          error.message,
        );
      }
    });

    return code;
  }

  /**
   * Статический метод для создания меню из CONFIG (совместимость)
   * @param {string} menuType - Тип меню
   * @param {Object} options - Опции для создания меню
   * @returns {GoogleAppsScript.Base.Menu} Объект меню
   */
  static createMenuFromConfig(menuType, options = {}) {
    const ui = SpreadsheetApp.getUi();
    const builder = new MenuBuilder(ui);
    return builder.createMenuFromConfig(menuType, options);
  }

  /**
   * Статический метод для создания меню Karandaev
   * @param {Object} options - Опции для создания меню
   * @returns {GoogleAppsScript.Base.Menu} Объект меню
   */
  static createKarandaevMenu(options = {}) {
    const ui = SpreadsheetApp.getUi();
    const builder = new MenuBuilder(ui);
    return builder.createMenuFromConfig("karandaev", options);
  }

  /**
   * Статический метод для создания меню FeedbacksGpt
   * @param {Object} options - Опции для создания меню
   * @returns {GoogleAppsScript.Base.Menu} Объект меню
   */
  static createFeedbacksGptMenu(options = {}) {
    const ui = SpreadsheetApp.getUi();
    const builder = new MenuBuilder(ui);
    return builder.createMenuFromConfig("feedbacksGpt", options);
  }

  /**
   * Статический метод для создания меню Full
   * @param {Object} options - Опции для создания меню
   * @returns {GoogleAppsScript.Base.Menu} Объект меню
   */
  static createFullMenu(options = {}) {
    const ui = SpreadsheetApp.getUi();
    const builder = new MenuBuilder(ui);
    return builder.createMenuFromConfig("full", options);
  }

  /**
   * Статический метод для создания меню Statistics
   * @param {Object} options - Опции для создания меню
   * @returns {GoogleAppsScript.Base.Menu} Объект меню
   */
  static createStatisticsMenu(options = {}) {
    const ui = SpreadsheetApp.getUi();
    const builder = new MenuBuilder(ui);
    return builder.createMenuFromConfig("statistics", options);
  }

  /**
   * Статический метод для создания меню Stocks
   * @param {Object} options - Опции для создания меню
   * @returns {GoogleAppsScript.Base.Menu} Объект меню
   */
  static createStocksMenu(options = {}) {
    const ui = SpreadsheetApp.getUi();
    const builder = new MenuBuilder(ui);
    return builder.createMenuFromConfig("stocks", options);
  }

  /**
   * Статический метод для создания меню Prices
   * @param {Object} options - Опции для создания меню
   * @returns {GoogleAppsScript.Base.Menu} Объект меню
   */
  static createPricesMenu(options = {}) {
    const ui = SpreadsheetApp.getUi();
    const builder = new MenuBuilder(ui);
    return builder.createMenuFromConfig("prices", options);
  }

  /**
   * Статический метод для создания меню StocksPrices
   * @param {Object} options - Опции для создания меню
   * @returns {GoogleAppsScript.Base.Menu} Объект меню
   */
  static createStocksPricesMenu(options = {}) {
    const ui = SpreadsheetApp.getUi();
    const builder = new MenuBuilder(ui);
    return builder.createMenuFromConfig("stocks_prices", options);
  }

  /**
   * Статический метод для генерации кода меню
   * @param {Object} options - Опции для создания меню
   * @returns {string} Строковое представление кода для создания меню
   */
  static menuCode(options = {}) {
    const builder = new MenuBuilder(null, "MenuBuilder");
    return builder.generateMenuCode(options);
  }
}

