function setApiKeys(service) {
  const config = CONFIG.settings;
  const { sheetSettings } = config;
  const { range, keysTypes } = config.apiKeys;
  const keysArray = setSheet(sheetSettings)
    .getRange(range)
    .getValues()
    .filter((e) => e[1]);
  const types = keysTypes;
  const keys = keysArray.reduce((acc, e) => {
    return { ...acc, [types[e[0]]]: String(e[1]) };
  }, {});

  const storage =
    context?.storage || (service && new StorageService({ service })) || null;

  storage.setProperties({ keys: JSON.stringify(keys) }, false);

  SpreadsheetApp.getUi().alert(
    `✅ SUCCESS`,
    `Установлены ключи API:\n${Object.keys(Object.fromEntries(keysArray)).join(
      "\n"
    )}`,
    SpreadsheetApp.getUi().ButtonSet.OK
  );
}

