function setApiKey_(service, keyName, keyType) {
  // Установить ключ
  const ui = SpreadsheetApp.getUi();
  const response = ui.prompt(
    `Введите ключ API (${keyType})`,
    keyType === "Токен (сайт)"
      ? "Получить из авторизованного кабинетак клиента (F12)"
      : "Генерируется на портале Продавца в разделе:\nНастройки > Доступ к новому API",
    ui.ButtonSet.OK
  );

  if (response.getSelectedButton() != ui.Button.OK) {
    ss.toast("Отмена", "⚠️ ATTENTION", 10);
    return;
  }

  if (!response.getResponseText()) {
    ss.toast("Нет данных", "⚠️ ATTENTION", 10);
    return;
  }

  const storage =
    context?.storage ||
    (service && setStorage({ service, serviceType: context?.serviceType })) ||
    null;

  // service.deleteProperty(keyName);
  // service.setProperty(keyName, response.getResponseText().trim());

  storage.refresh({ [keyName]: response.getResponseText().trim() });

  ss.toast(`Ключ (${keyType}) установлен`, "✅ SUCCESS", 10);
}

function setFolder(service) {
  // Установить папку
  var ui = SpreadsheetApp.getUi();
  const response = ui.prompt(
    "Вставьте ссылку на папку или ее ID",
    "Папка, куда будут сохраняться этикетки.\nID в строке браузера: https://drive.google.com/drive/folders/*******это id*******",
    ui.ButtonSet.OK
  );

  if (response.getSelectedButton() != ui.Button.OK) {
    ss.toast("Отмена", "⚠️ ATTENTION", 10);
    return;
  }

  if (!response.getResponseText()) {
    ss.toast("Нет данных", "⚠️ ATTENTION", 10);
    return;
  }

  const folderId = response
    .getResponseText()
    .trim()
    .match(/[-\w]{25,}/);

  if (!folderId) {
    ss.toast("Не верная ссылка!!!", "⚠️ ATTENTION", 10);
    return;
  }

  const storage =
    context?.storage ||
    (service && setStorage({ service, serviceType: context?.serviceType })) ||
    null;

  storage.refresh({ folderId: folderId[0] });

  ss.toast("Папка добавлена", "✅ SUCCESS", 10);
}

