}

/**
 * Класс для работы с сервисными свойствами
 * @class
 */
class StorageService {
  /**
   * @typedef {Object} ServiceConfig
   * @property {PropertiesService} service - Сервисный объект
   * @property {string} [serviceName ='Info'] - Название сервиса
   * @property {string} [serviceType ='getScriptProperties'] - Тип сервиса
   */

  /**
   * @param {ServiceConfig} config - Конфигурация сервиса
   * @throws {Error} Если сервис не определен
   */
  constructor({
    service,
    serviceName = "Info",
    serviceType = "getScriptProperties",
  } = {}) {
    if (!service) {
      throw new Error("Service is required");
    }

    // Проверим, что serviceType является действительным методом
    if (typeof service[serviceType] !== "function") {
      throw new Error(`Invalid serviceType: ${serviceType}`);
    }

    /** @private */
    this._service = service[serviceType](); // Получаем экземпляр сервиса

    // Дополнительные проверки
    if (!this._service) {
      throw new Error("Failed to get the service instance");
    }

    /** @private */
    this._property = serviceName;

    // Проверяем работоспособность сервиса при инициализации
    this._validateService();
  }

  /**
   * Проверяет работоспособность сервиса
   * @private
   * @throws {Error} Если методы сервиса недоступны
   */
  _validateService() {
    if (
      typeof this._service.getProperty !== "function" ||
      typeof this._service.setProperty !== "function"
    ) {
      throw new Error("Invalid service: required methods are missing");
    }
  }

  /**
   * Получает текущие свойства
   * @private
   * @returns {Object}
   */
  _getCurrentProperties() {
    try {
      const prop = this._service.getProperty(this._property);
      return prop ? JSON.parse(prop) : {};
    } catch (error) {
      console.error("Error getting properties:", error);
      return {};
    }
  }

  /**
   * Сохраняет свойства
   * @private
   * @param {Object} properties - Свойства для сохранения
   * @throws {Error} При ошибке сохранения
   */
  _saveProperties(properties) {
    try {
      this._service.setProperty(this._property, JSON.stringify(properties));
    } catch (error) {
      throw new Error(`Failed to save properties: ${error.message}`);
    }
  }

  /**
   * Обновляет свойства
   * @param {Object} newValue - Новые значения для обновления
   * @returns {Object} Обновленные свойства
   * @throws {Error} При ошибке обновления
   */
  refresh(newValue) {
    if (!newValue || typeof newValue !== "object") {
      throw new Error("New value must be an object");
    }

    try {
      const currentValue = this._getCurrentProperties();
      const updatedValue = {
        ...currentValue,
        ...newValue,
        lastUpdated: new Date().toISOString(),
      };

      this._saveProperties(updatedValue);
      return updatedValue;
    } catch (error) {
      throw new Error(`Refresh failed: ${error.message}`);
    }
  }

  /**
   * Получает все свойства
   * @returns {Object} Текущие свойства
   */
  get() {
    return this._getCurrentProperties();
  }

  /**
   * Получает конкретное свойство по ключу
   * @param {string} key - Ключ свойства
   * @returns {*} Значение свойства
   */
  getProperty(key) {
    const properties = this._getCurrentProperties();
    return properties[key];
  }

  /**
   * Устанавливает конкретное свойство
   * @param {string} key - Ключ свойства
   * @param {*} value - Значение свойства
   */
  setProperty(key, value) {
    const properties = this._getCurrentProperties();
    properties[key] = value;
    this._saveProperties(properties);
  }

  setProperties(properties) {
    this._service.setProperties(properties);
  }

  /**
   * Удаляет свойство
   * @param {string} key - Ключ свойства для удаления
   * @returns {boolean} Успешность удаления
   */
  deleteProperty(key) {
    const properties = this._getCurrentProperties();
    if (key in properties) {
      delete properties[key];
      this._saveProperties(properties);
      return true;
    }
    return false;
  }

  /**
   * Очищает все свойства
   */
  clear() {
    this._saveProperties({});
  }

  /**
   * Получает все ключи свойств
   * @returns {string[]} Массив ключей
   */
  keys() {
    return Object.keys(this._getCurrentProperties());
  }

  /**
   * Проверяет существование свойства
   * @param {string} key - Ключ для проверки
   * @returns {boolean} Существует ли свойство
   */
  has(key) {
    return key in this._getCurrentProperties();
  }
}

