// ####################################################################################################################################

class Moysklad {
  /**
   * @param {*} service
   * @param {string | { path?: string, endpoint?: string, query?: Object }} urlOrSpec — готовый URL или { path|endpoint, query } для buildUrl
   * @param {*} [fetchOptions] — опции UrlFetchApp (пока не мержатся с дефолтами)
   */
  constructor(service, urlOrSpec, fetchOptions) {
    this.region = fetchOptions?.region || "ru";
    let url = "";
    if (typeof urlOrSpec === "string") {
      url = urlOrSpec;
    } else if (urlOrSpec != null && typeof urlOrSpec === "object") {
      const path = urlOrSpec.path || urlOrSpec.endpoint;
      if (!path) {
        throw new Error("Moysklad: укажите path или endpoint");
      }
      url = Moysklad.buildUrl(path, urlOrSpec.query || {});
    } else {
      url = urlOrSpec;
    }

    this.url = url;
    this.urlEncoded = encodeURI(this.url);
    this._storage = new StorageService({
      service: context?.service || service,
      serviceType: context?.serviceType,
      serviceName: "Moysklad",
    });

    this.positionRows = [];
    this.options =
      {
        muteHttpExceptions: true,
        headers: {
          Authorization: `Bearer ${this.token}`,
          "Accept-Encoding": "gzip",
          // "Content-Type": "application/json",
          // "Lognex-Pretty-Print-JSON": "true",
          "X-Lognex-Accept-Region": this.region,
        },
      } || fetchOptions;

    if (context?.debug) {
      console.log({ url: this.url });
    }
  }

  /**
   * Get the token value from the service property "MoyskladToken".
   *
   * @return {string} The token value
   */
  get token() {
    const token = this._storage.getProperty("token");
    if (!token) {
      throw new Error("Добавьте Токен МойСклад, через настройки меню.");
    }
    return token;
  }

  static get API_BASE() {
    return "https://api.moysklad.ru/api/remap/1.2";
  }

  /**
   * Часть filter без encodeURIComponent по значению (см. buildUrl + requestOffset + encodeURI).
   * @param {string} field
   * @param {string} [op]
   * @param {string|number|boolean} value
   */
  static filterClause(field, op, value) {
    if (value === undefined || value === null || value === "") return "";
    return String(field) + (op || "=") + String(value);
  }

  static filterJoin(parts) {
    return (parts || []).filter(Boolean).join(";");
  }

  /**
   * @param {Object<string, *>} spec
   */
  static filterFromSpec(spec) {
    const parts = [];
    for (const field in spec) {
      if (!Object.prototype.hasOwnProperty.call(spec, field)) continue;
      const raw = spec[field];
      if (raw === undefined || raw === null) continue;
      if (Object.prototype.toString.call(raw) === "[object Array]") {
        if (raw.length === 0) continue;
        for (let j = 0; j < raw.length; j++) {
          const item = raw[j];
          if (item === undefined || item === null) continue;
          if (typeof item === "object" && item !== null && "value" in item) {
            parts.push(
              Moysklad.filterClause(field, item.op || "=", item.value),
            );
          } else {
            parts.push(Moysklad.filterClause(field, "=", item));
          }
        }
      } else if (typeof raw === "object" && raw !== null && "value" in raw) {
        parts.push(Moysklad.filterClause(field, raw.op || "=", raw.value));
      } else {
        parts.push(Moysklad.filterClause(field, "=", raw));
      }
    }
    return Moysklad.filterJoin(parts);
  }

  /**
   * Параметр order: поля через ; , у каждого опционально ,asc|,desc (по умолчанию asc — в строку без суффикса).
   * @param {Array<string|{field: string, dir?: string}>} clauses
   */
  static buildOrderString(clauses) {
    if (!clauses || !clauses.length) return "";
    return clauses
      .map((c) => {
        if (typeof c === "string" || typeof c === "number") return String(c);
        if (!c || typeof c !== "object") return "";
        const field = c.field;
        const dir = String(c.dir || c.direction || "asc").toLowerCase();
        if (!field) return "";
        if (dir === "asc") return field;
        return field + "," + dir;
      })
      .filter(Boolean)
      .join(";");
  }

  /**
   * Query для Remap 1.2. Значение filter — сырое (не encodeURIComponent), иначе encodeURI в requestOffset даёт 412.
   * Параметр order — так же сырая строка (как в доке; потом один encodeURI на URL).
   * Остальные параметры кодируются как обычно.
   * @param {string} path например '/report/stock/all'
   * @param {Object} [query]
   */
  static buildUrl(path, query) {
    const p = path.indexOf("/") === 0 ? path : "/" + path;
    const base = Moysklad.API_BASE + p;
    const q = query || {};
    let filterStr = "";
    if (q.filter != null && q.filter !== "") {
      filterStr =
        typeof q.filter === "string"
          ? q.filter
          : Moysklad.filterFromSpec(q.filter);
    }
    let orderStr = "";
    if (q.order != null && q.order !== "") {
      orderStr = Array.isArray(q.order)
        ? Moysklad.buildOrderString(q.order)
        : String(q.order);
    }
    const parts = [];
    const keys = Object.keys(q);
    for (let i = 0; i < keys.length; i++) {
      const k = keys[i];
      if (k === "filter" || k === "order") continue;
      const v = q[k];
      if (v === undefined || v === null) continue;
      if (Object.prototype.toString.call(v) === "[object Array]") {
        for (let j = 0; j < v.length; j++) {
          if (v[j] !== undefined && v[j] !== null) {
            parts.push(
              encodeURIComponent(k) + "=" + encodeURIComponent(String(v[j])),
            );
          }
        }
      } else {
        parts.push(encodeURIComponent(k) + "=" + encodeURIComponent(String(v)));
      }
    }
    if (filterStr) {
      parts.push("filter=" + filterStr);
    }
    if (orderStr) {
      parts.push("order=" + orderStr);
    }
    return parts.length ? base + "?" + parts.join("&") : base;
  }

  /**
   * Executes a request to the API and retrieves data.
   *
   * @return {Array} An array containing the rows of data retrieved from the API.
   */
  requestOffset() {
    let length = 0;
    let urlToFetch = this.url;

    do {
      try {
        const urlEncoded = encodeURI(urlToFetch);
        const response = UrlFetchApp.fetch(urlEncoded, this.options);

        const code = response.getResponseCode();

        if (code !== 200) {
          const json = JSON.parse(response.getContentText());
          console.log(json);

          const message =
            json?.errors.map(
              (e, index) =>
                `${index + 1}: ${e?.error}\nCode: ${e?.code}\nInfo: ${e?.moreInfo}\n`,
            ) || json;

          SpreadsheetApp.getUi().alert(
            `⚠️ ATTENTION`,
            `Response сode: ${code}\nMessage:\n${message.toString()}`,
            SpreadsheetApp.getUi().ButtonSet.OK,
          );

          break;
        }

        const parsed = JSON.parse(response.getContentText());

        length = parsed?.rows.length;
        urlToFetch = encodeURI(decodeURIComponent(parsed.meta.nextHref));
        this.positionRows.push(...parsed.rows);
      } catch (error) {
        console.warn(`[Moysklad] Error: ${urlToFetch}\n`, error.stack);
        Utilities.sleep(2000);
        this.requestOffset();
      }
    } while (length === 1000);

    return this.positionRows;
  }
}

/**
 * Retrieves the Moysklad token from the specified service.
 *
 * @param {PropertiesService} service - the service object to retrieve the token from
 * @return {string} the Moysklad token
 */
function moyskladGetToken(service) {
  const storage = new StorageService({
    service: context?.service || service,
    serviceType: context?.serviceType,
    serviceName: "Moysklad",
  });

  return storage.getProperty("token");
}

/**
 * Параметр filter: строка/enum по умолчанию или объект { op, value } из options.
 */
function msFilterParam(raw, defaultScalar) {
  if (raw === undefined || raw === null || raw === "") {
    return defaultScalar;
  }
  if (typeof raw === "object" && raw !== null && "value" in raw) {
    return raw;
  }
  return raw;
}

/** Скаляр после msFilterParam — для сравнений в скрипте (if, фильтрация строк). */
function msFilterParamValue(raw, defaultScalar) {
  const v = msFilterParam(raw, defaultScalar);
  if (typeof v === "object" && v !== null && "value" in v) {
    return v.value;
  }
  return v;
}

/**
 * Параметр order: массив для buildOrderString / строка / null отключает; при undefined — defaultClauses.
 */
function msOrderParam(raw, defaultClauses) {
  if (raw === undefined) {
    return defaultClauses;
  }
  return raw;
}

/**
 * Function to fetch data from Moysklad API and populate the Google Sheets with the retrieved information.
 *
 * @param {Object} service - The Google Sheets service object.
 * @return {void} This function does not return any value.
 */
function moyskladAssortment(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  // https://dev.moysklad.ru/doc/api/remap/1.2/dictionaries/#suschnosti-assortiment

  const start = CONFIG.func.start();
  const script = moyskladAssortment.name;

  const {
    service,
    groupBy,
    stockMode,
    quantityMode,
    stockStore = [],
    formulas = [],
    emptyCols,
  } = options;

  const positionRows = new Moysklad(service, {
    path: "/entity/assortment",
    query: {
      groupBy: groupBy || MsGroupBy.consignment,
      filter: {
        stockMode: msFilterParam(stockMode, MsStockMode.all),
        quantityMode: msFilterParam(quantityMode, MsQuantityMode.all),
        stockStore: stockStore,
      },
    },
  }).requestOffset();
  debugLog("Ответ:", positionRows);

  if (!positionRows.length) {
    return CONFIG.func.endScript({
      script,
      start,
      message: "Нет данных",
      messageType: 2,
    });
  }

  const updatedAt = Utilities.formatDate(
    new Date(),
    "Europe/Moscow",
    "dd.MM.yyyy HH:mm",
  );

  const result = [];
  positionRows.forEach((row) => {
    const updateAtRow = Utilities.formatDate(
      new Date(row.updated),
      "Europe/Moscow",
      "dd.MM.yyyy HH:mm",
    );

    const info = [
      row.code,
      row.article,
      row.name,
      row.weight,
      row.volume,
      row.images?.meta?.href,
      row?.quantity,
      row.reserve,
      row.inTransit,
      row?.stock,
      row?.buyPrice?.value > 0 ? row.buyPrice.value / 100 : 0,
    ];

    if (row?.barcodes)
      row.barcodes.forEach((barcode) => {
        result.push([updatedAt, updateAtRow, barcode?.ean13, ...info]);
      });
    else {
      result.push([updatedAt, updateAtRow, null, ...info]);
    }
  });

  debugLog("Обработанный:", result);

  const header = [
    "Обновлено",
    "Обновления Бонусной операции",
    "EAN-13",
    "Код",
    "Артикул",
    "Наименование",
    "Вес",
    "Объем",
    "Фото",
    "Доступно",
    "Резерв",
    "Ожидание",
    "Остаток",
    "Закупочная цена",
  ];

  const sheet = setSheetNew("МойСклад (ассортимент)", "BLACK", ss);
  setSheetHead(sheet, true);

  let headers = header;

  if (sheet.getLastRow() === 0) {
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    sheet.appendRow(headers);
  }

  sheet.getRange(2, 1, result.length, result[0].length).setValues(result);

  CONFIG.func.endScript({
    script,
    start,
    sheet,
    emptyCols,
  });
}

/**
 * Retrieves stock information from the Moysklad API and processes it into a spreadsheet.
 *
 * @param {Object} service - the service object for making API requests
 * @param {Object} options - the options object containing stockMode, quantityMode, and emptyCols
 * @return {void}
 */
function moyskladStocks(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  // https://dev.moysklad.ru/doc/api/remap/1.2/reports/#otchety-otchet-ostatki

  const start = CONFIG.func.start();
  const script = moyskladStocks.name;

  const {
    service,
    groupBy,
    stockMode,
    quantityMode,
    stores = [],
    order,
    formulas = [],
    emptyCols,
  } = options;

  const positionRows = new Moysklad(service, {
    path: "/report/stock/all",
    query: {
      groupBy: groupBy || MsGroupBy.consignment,
      filter: {
        stockMode: msFilterParam(stockMode, MsStockMode.all),
        quantityMode: msFilterParam(quantityMode, MsQuantityMode.all),
        store: stores,
      },
      order: msOrderParam(order, [
        { field: MsStockOrder.name, dir: MsStockOrderDir.asc },
      ]),
    },
  }).requestOffset();
  debugLog("Ответ:", positionRows);

  if (!positionRows.length) {
    return CONFIG.func.endScript({
      script,
      start,
      message: "Нет данных",
      messageType: 2,
    });
  }

  const folders = new Set();
  positionRows.forEach((row) => {
    const folder = row.folder;
    if (folder) {
      folders.add(folder.name);
    } else {
      folders.add("Без группы");
      row.folder = { name: "Без группы" };
    }
  });

  const updatedAt = Utilities.formatDate(
    new Date(),
    "Europe/Moscow",
    "dd.MM.yyyy HH:mm",
  );

  const result = [];
  folders.forEach((folder) => {
    result.push([
      folder,
      null,
      null,
      null,
      null,
      null,
      null,
      null,
      null,
      null,
      null,
      null,
      null,
      null,
      null,
    ]);

    const filtered = positionRows
      .filter((r) => r.folder.name === folder)
      .sort((obj1, obj2) => obj1.code - obj2.code);

    filtered.forEach((row) => {
      const stock = row.stock;
      const costPrice = row.price / 100;
      const salePrice = row.salePrice / 100;
      const newRow = [
        updatedAt,
        row.code,
        row.article,
        row.name,
        row.uom.name,
        row.quantity,
        row.reserve,
        row.inTransit,
        stock,
        costPrice,
        costPrice * stock,
        salePrice,
        salePrice * stock,
        row.stockDays,
        folder,
      ];
      result.push(newRow);
    });
  });

  debugLog("Обработанный:", result);

  const header = [
    "Обновлено",
    "Код",
    "Артикул",
    "Наименование",
    "Ед. изм.",
    "Доступно",
    "Резерв",
    "Ожидание",
    "Остаток",
    "Себестоимость",
    "Сумма себестоимости",
    "Цена продажи",
    "Сумма продажи",
    "Дней на складе",
    "Группа",
  ];

  const sheet = setSheetNew("МойСклад (остатки)", "BLACK", ss);

  setSheetHead(sheet, true);

  let headers = header;

  if (sheet.getLastRow() === 0) {
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    sheet.appendRow(headers);
  }

  sheet.getRange(2, 1, result.length, result[0].length).setValues(result);

  CONFIG.func.endScript({
    script,
    start,
    sheet,
    emptyCols,
  });
}

/**
 * Retrieves stock data by stores from Moysklad API and generates a report.
 *
 * @param {Object} service - The service object for making API requests
 * @param {Object} options - The options object containing groupBy and emptyCols properties
 * @return {undefined} This function does not return a value
 */
function moyskladStocksByStores(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  // https://dev.moysklad.ru/doc/api/remap/1.2/reports/#otchety-otchet-ostatki-ostatki-po-skladam

  const start = CONFIG.func.start();
  const script = moyskladStocksByStores.name;

  const {
    service,
    groupBy,
    stockMode,
    stores = [],
    order,
    formulas = [],
    emptyCols,
  } = options;

  const products = products_(service); // assortment_(service, options);
  const uom = uom_(service);

  debugLog("Ответ products:", products);
  debugLog("Ответ uom:", uom);

  const positionRows = new Moysklad(service, {
    path: "/report/stock/bystore",
    query: {
      groupBy: groupBy || MsGroupBy.consignment,
      filter: {
        stockMode: msFilterParam(stockMode, MsStockMode.all),
        store: stores,
      },
      order: msOrderParam(order, [
        { field: MsStockOrder.name, dir: MsStockOrderDir.asc },
      ]),
    },
  }).requestOffset();
  debugLog("Ответ:", positionRows);

  if (!positionRows.length) {
    return CONFIG.func.endScript({
      script,
      start,
      message: "Нет данных",
      messageType: 2,
    });
  }

  const updatedAt = Utilities.formatDate(
    new Date(),
    "Europe/Moscow",
    "dd.MM.yyyy HH:mm",
  );

  let result = [];
  positionRows.forEach((row) => {
    const url = row?.meta?.href;
    // if (context?.debug) console.log(url);
    const id = url?.replace("?expand=supplier", "")?.split("/").pop();

    // if (context?.debug) console.log(id);
    const product = products[id];
    // if (context?.debug) console.log(product);

    const type = row.meta.type;

    row.stockByStore.forEach(
      ({ name: stock_name, stock, reserve, inTransit }) => {
        const available = stock - reserve;
        result.push([
          updatedAt,
          stock_name,
          product?.pathName,
          product?.attributes?.["Предмет"] ||
            product?.attributes?.["Категория"] ||
            null,
          product?.barcodes?.ean13,
          product?.code,
          product?.article,
          product?.name,
          uom[product?.uom_href],
          product?.archived,
          product?.buyPrice,
          available,
          stock,
          reserve,
          inTransit,
          type,
        ]);
      },
    );
  });

  if (msFilterParamValue(stockMode, MsStockMode.all) === MsStockMode.nonEmpty) {
    result = result.filter(
      (row) => row[11] > 0 || row[12] > 0 || row[13] > 0 || row[14] > 0,
    );
  }

  debugLog("Обработанный:", result);

  const header = [
    "Обновлено",
    "Склад",
    "Группа",
    "Предмет / Категория",
    "EAN-13",
    "Код",
    "Артикул",
    "Наименование",
    "Ед. изм.",
    "Архивный",
    "Закупочная цена",
    "Доступно",
    "Остаток",
    "Резерв",
    "Ожидание",
    "Тип",
  ];

  const sheet = setSheetNew("МойСклад (остатки по складам)", "BLACK", ss);

  setSheetHead(sheet, true);

  let headers = header;

  if (sheet.getLastRow() === 0) {
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    sheet.appendRow(headers);
  }

  sheet.getRange(2, 1, result.length, result[0].length).setValues(result);

  CONFIG.func.endScript({
    script,
    start,
    sheet,
    emptyCols,
  });
}

