  let headers = header;

  if (sheet.getLastRow() === 0) {
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    sheet.appendRow(headers);
  }

  sheet.getRange(2, 1, result.length, result[0].length).setValues(result);

  CONFIG.func.endScript({
    script,
    start,
    sheet,
    emptyCols,
  });
}

