// Получить Склады
function stores_(service) {
  // https://dev.moysklad.ru/doc/api/remap/1.2/dictionaries/#suschnosti-assortiment

  const positionRows = new Moysklad(service, {
    path: "/entity/store",
  }).requestOffset();
  debugSaveFileToDrive("moysklad_stores", positionRows);
  if (context?.debug) console.log(JSON.stringify(positionRows, null, 2));
  return positionRows.reduce((acc, { name, id }) => {
    acc[id] = name;
    return acc;
  }, {});
}

function stocksLiteCurrent_(service) {
  // https://dev.moysklad.ru/doc/api/remap/1.2/#/reports/report-stock#3-kratkij-otchet-ob-ostatkah

  return new Moysklad(service, {
    path: "/report/stock/all/current",
  }).requestOffset();
}

// Получить Товары
function assortment_(service) {
  // https://dev.moysklad.ru/doc/api/remap/1.2/dictionaries/#suschnosti-assortiment

  const positionRows = new Moysklad(service, {
    path: "/entity/assortment",
  }).requestOffset();
  return positionRows.reduce((acc, { name, code, article, id, uom }) => {
    // _ = `https://api.moysklad.ru/api/remap/1.2/entity/variant/${id}?expand=supplier`;
    const e = uom?.meta ? uom.meta.href : null;
    acc[id] = { name, article, code, e };
    return acc;
  }, {});
}

// Получить Единицы измерения
function uom_(service) {
  // https://dev.moysklad.ru/doc/api/remap/1.2/dictionaries/#suschnosti-edinica-izmereniq-edinicy-izmereniq

  const positionRows = new Moysklad(service, {
    path: "/entity/uom",
  }).requestOffset();
  return positionRows.reduce((acc, { meta, name }) => {
    acc[meta.href] = name;
    return acc;
  }, {});
}

// Товары
function products_(service) {
  // https://dev.moysklad.ru/doc/api/remap/1.2/dictionaries/#suschnosti-towar-towary

  const positionRows = new Moysklad(service, {
    path: "/entity/product",
  }).requestOffset();

  return positionRows.reduce(
    (
      acc,
      {
        id,
        code,
        name,
        buyPrice,
        barcodes,
        article,
        weight,
        volume,
        pathName,
        vat,
        archived,
        uom,
        attributes,
      },
    ) => {
      acc[id] = {
        uom_href: uom?.meta?.href,
        code,
        name,
        buyPrice: buyPrice?.value ? buyPrice?.value / 100 : 0,
        barcodes: barcodes?.reduce((acc, barcode) => {
          return { ...acc, ...barcode };
        }, {}),
        article,
        weight,
        volume,
        pathName,
        vat,
        archived,
        attributes: attributes?.reduce((acc, attribute) => {
          acc[attribute.name] = attribute.value.name;
          return acc;
        }, {}),
      };
      return acc;
    },
    {},
  );
}

