const MsGroupBy = Object.freeze({
  product: "product", // выдает только товары
  variant: "variant", // выдает товары и модификации
  consignment: "consignment", // выдает товары, модификации, партии
});

const MsStockMode = Object.freeze({
  all: "all", // Любое значение остатка
  positiveOnly: "positiveOnly", // Положительный остаток
  negativeOnly: "negativeOnly", // Отрицательный остаток
  empty: "empty", // Нулевой остаток
  nonEmpty: "nonEmpty", // Ненулевой остаток
  underMinimum: "underMinimum", // Остаток ниже неснижаемого остатка
});

const MsQuantityMode = Object.freeze({
  all: "all", // Любое значение остатка
  positiveOnly: "positiveOnly", // Положительный остаток
  negativeOnly: "negativeOnly", // Отрицательный остаток
  empty: "empty", // Нулевой остаток
  nonEmpty: "nonEmpty", // Ненулевой остаток
  underMinimum: "underMinimum", // Остаток ниже неснижаемого остатка
});

const MsStockType = Object.freeze({
  stock: "stock", // Физический остаток на складах, без учёта резерва и ожидания
  freeStock: "freeStock", // Остаток на складах за вычетом резерва
  quantity: "quantity", // Доступно. Учитывает резерв и ожидания
  reserve: "reserve", // Резерв
  inTransit: "inTransit", // Ожидание
});

const MsStockOrder = Object.freeze({
  avgStockDays: "avgStockDays", //	по количеству дней на складе
  code: "code", //		по коду
  inTransit: "inTransit", //	по значению ожидания
  minimumBalance: "minimumBalance", //	по неснижаемому остатку
  name: "name", //	по наименованию
  pathName: "pathName", // по группе товаров
  price: "price", //	по себестоимости
  productCode: "productCode", //	по артикулу
  quantity: "quantity", //	по значению доступно
  reserve: "reserve", //	по значению резерва
  salePrice: "salePrice", //	по цене продажи
  stock: "stock", //	по значению остатка
  sumTotal: "sumTotal", //	по сумме себестоимости
});

const MsStockOrderDir = Object.freeze({
  asc: "asc", //	по возрастанию
  desc: "desc", //	по убыванию
});

/** Операторы параметра filter в JSON API Remap 1.2 */
const MsFilterOp = Object.freeze({
  eq: "=",
  ne: "!=",
  gt: ">",
  gte: ">=",
  lt: "<",
  lte: "<=",
  like: "~",
  notLike: "!~",
  /** полное совпадение с начала значения */
  startsWith: "~=",
  /** полное совпадение с конца значения */
  endsWith: "=~",
});

