 * @author Mikhail Nosaev <m.nosaev@gmail.com>
 * @see {@link https://t.me/nosaev_m Telegram } разработка Google таблиц и GAS скриптов
 * @license MIT
 */
class WildberriesApi {
  constructor({ apiKey, requestLog, check, service, storage }) {
    if (apiKey) {
      this.apiKey = apiKey;
    } else {
      if (!storage || !service) {
        throw new Error("Storage or service are required");
      }

      this.storage =
        storage ||
        (service &&
          setStorage({ service, serviceType: context?.serviceType })) ||
        null;

      this.apiKey = this.storage.getProperty("MultipleAccess");
      this.token = this.storage.getProperty("SiteToken");
    }

    this.options = {
      apiKey: this.apiKey,
      token: this.token,
      requestLog,
      check,
    };
    if (requestLog) console.log({ options: this.options });

    // Классы
    this.content = new Content(this.options);
    this.marketplace = new Marketplace(this.options);
    this.statistics = new Statistics(this.options);
    this.analytics = new Analytics(this.options);
    this.advertising = new Advert(this.options);
    this.feedbacksQuestions = new FeedbacksQuestions(this.options);
    this.pricesDiscounts = new PricesDiscounts(this.options);
    this.tariffs = new Tariffs(this.options);
    this.supplies = new Supplies(this.options);
    this.returns = new Returns(this.options);
    this.calendarPromo = new CalendarPromo(this.options);
    this.documents = new Documents(this.options);
    this.communications = new Communications(this.options);
    this.finance = new Finance(this.options);
    this.buyerChat = new BuyerChat(this.options);
  }
}

/**
 * Вызывает методы: Wildberries API
 * @param {object} options
 * @param {string} options.apiKey любой не тестовый ключ API { apiKey: "xxxxxxx" }
 * @param {boolean} [options.requestLog] True печать URL и OPTIONS запроса при выполнении, по умочанию false
 * @param {boolean} [options.check] True проверка ключа API, по умочанию false
 * @returns {WildberriesApi|Error} конструктор класса или ошибка, если пропущен ключ API
 */
function wildberriesApi({
  apiKey,
  requestLog,
  storage,
  service,
  check = false,
}) {
  return new WildberriesApi({ apiKey, requestLog, storage, service, check });
}

