    this.baseUrl = "";
    this.__query = "";

    this.cookies = "";
    this.userAgent =
      "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/89.0.142.86 Safari/537.36";

    this.rateLimiter = new RateLimiter(this.requestLog);
    this.remaining = null;
    this.limit = null;
    this.retry = null;
    this.reset = null;
    this.headers = {};

    this.HTTP_RESPONSE_STATUS_CODE = null;
    this.HTTP = HTTPResponseStatusCodes;
    this.HTTP_STATUS = this.HTTP.STATUS;

    this.EXIT_STATES = [
      this.HTTP_STATUS.BAD_REQUEST_400,
      this.HTTP_STATUS.UNAUTHORIZED_401,
      this.HTTP_STATUS.FORBIDDEN_403,
      this.HTTP_STATUS.NOT_FOUND_404,
      this.HTTP_STATUS.METHOD_NOT_ALLOWED_405,
    ];

    this.RETRY_STATES = [
      this.HTTP_STATUS.INTERNAL_SERVER_ERROR_500,
      this.HTTP_STATUS.BAD_GATEWAY_502,
      this.HTTP_STATUS.SERVICE_UNAVAILABLE_503,
    ];

    this.SKIP_STATES = [
      this.HTTP_STATUS.TOO_MANY_REQUESTS_429,
      this.HTTP_STATUS.UNPROCESSABLE_ENTITY_422,
    ];

    this.SUCCESS_STATES = [
      this.HTTP_STATUS.OK_200,
      this.HTTP_STATUS.NO_CONTENT_204,
      this.HTTP_STATUS.ALREADY_REPORTED_208,
    ];

    this.RETRY_DELAY_SECONDS = 5;
    this.MAX_BACKOFF_SECONDS = 60; // Максимальная задержка в секундах
  }

  /**
   * Get the value of the apiKey property.
   *
   * @return {string} The value of the apiKey property.
   */
  get apiKey() {
    return this.__apiKey;
  }

  /**
   * Sets the API key for the object.
   *
   * @param {string} apiKey - The API key to set.
   */
  set apiKey(apiKey) {
    this.__apiKey = apiKey;
  }

  /**
   * Logs the given information using the helper's log function.
   *
   * @param {any} info - The information to be logged.
   * @return {any} The result of the helper's log function.
   */
  log(info) {
    return console.log(info);
  }

  /**
   * Retrieves the methods of a given class.
   *
   * @param {type} method - the class to retrieve the methods from
   * @return {type} the methods of the given class
   */
  getMethods(method) {
    return this.getMethodsOfClass_(method);
  }

  /**
   * Retrieves the methods of a given class.
   *
   * @param {object} classObj - The class to retrieve the methods from.
   * @return {array} An array of method names.
   */
  getMethodsOfClass_(classObj) {
    // список методов класса
    return Object.getOwnPropertyNames(classObj.prototype).filter(
      (property) => typeof classObj.prototype[property] === "function"
    );
  }

  /**
   * Generates a version 4 UUID.
   *
   * @return {string} The generated UUID.
   */
  generateUUID() {
    let dt = new Date().getTime();
    const uuid = "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(
      /[xy]/g,
      function (c) {
        const r = (dt + Math.random() * 16) % 16 | 0;
        dt = Math.floor(dt / 16);
        return (c == "x" ? r : (r & 0x3) | 0x8).toString(16);
      }
    );
    return uuid;
  }

  /**
   * Builds a query string from params object
   * @param {object} params - Object with query string parameters
   * @param {string} fullUrl - Full URL without query string
   * @returns {string} URL with query string
   */
  queryString(params, fullUrl) {
    if (!params) return fullUrl;

    if (params.join) {
      return `${fullUrl}?${params.join}`;
    }

    const paramStr = Object.entries(params)
      .filter(
        ([_, value]) => value !== null && value !== undefined && value !== ""
      )
      .map(([key, value]) => `${key}=${value}`)
      .join("&");

    return paramStr ? `${fullUrl}?${paramStr}` : fullUrl;
  }

  /**
   * Recursively removes properties with null, undefined, or empty array values from an object.
   *
   * @param {object} obj - The object from which empty properties are to be removed.
   * @return {object} The modified object with empty properties removed.
   */
  removeEmpty(obj) {
    Object.keys(obj).forEach((key) => {
      if (
        obj[key] === null ||
        obj[key] === undefined ||
        (Array.isArray(obj[key]) && obj[key].length === 0)
      ) {
        delete obj[key];
      } else if (typeof obj[key] === "object") {
        this.removeEmpty(obj[key]);
      }
    });
    return obj;
  }

  /**
   * Recursively removes properties with null, undefined, empty array, or empty object values from an object.
   *
   * @param {object} obj - The object from which empty properties are to be removed.
   * @return {object} The modified object with empty properties removed.
   */
  removeEmptyAll(obj) {
    Object.keys(obj).forEach((key) => {
      if (
        obj[key] === null ||
        obj[key] === undefined ||
        (Array.isArray(obj[key]) && obj[key].length === 0) ||
        (typeof obj[key] === "object" && Object.keys(obj[key]).length === 0)
      ) {
        delete obj[key];
      } else if (typeof obj[key] === "object") {
        this.removeEmptyAll(obj[key]);
        if (Object.keys(obj[key]).length === 0) {
          delete obj[key];
        }
      }
    });
    return obj;
  }

  /**
   * Gets the number value of a header from the headers object.
   *
   * @param {string} name - The name of the header to get.
   * @param {object} headers - The headers object to get the header from.
   * @return {number} The number value of the header.
   */
  getHeaderNumber(name, headers = this.headers) {
    const value = headers[name];
    return value ? Number(value) || 0 : null;
  }

  /**
   * Processes the response from the server and updates the corresponding properties of the class.
   *
   * @param {object} response - The response object from the server.
   * @return {void} This function does not return anything.
   */
  processResponse(response) {
    const statusCode = response.getResponseCode();

    this.HTTP_RESPONSE_STATUS_CODE = statusCode;
    const code = this.HTTP.message(this.HTTP_RESPONSE_STATUS_CODE);
    this.headers = response.getAllHeaders();

    // // Безопасное получение числовых значений
    // const getHeaderNumber = (name) => {
    //   const value = this.headers[name];
    //   return value ? Number(value) || 0 : 0;
    // };

    this.remaining = this.getHeaderNumber("x-ratelimit-remaining");
    this.limit = this.getHeaderNumber("x-ratelimit-limit");
    this.retry = this.getHeaderNumber("x-ratelimit-retry");
    this.reset = this.getHeaderNumber("x-ratelimit-reset");

    var cookies = this.headers["Set-Cookie"];

    // Проверяем и обрабатываем куки
    if (cookies) {
      if (Array.isArray(cookies)) {
        // Если куки - это массив, объединяем их
        this.cookies = cookies.join("; ");
      } else if (typeof cookies === "string") {
        // Если куки - это строка, используем как есть
        this.cookies = cookies;
      }
    }

    if (this.HTTP.SUCCESS[this.HTTP_RESPONSE_STATUS_CODE]) {
      if (this.requestLog) {
        console.log(
          "RESPONSE >>> %s, remaining: %s, limit: %s, retry: %s, reset: %s\nHeaders:\n%s",
          code,
          this.remaining,
          this.limit,
          this.retry,
          this.reset,
          JSON.stringify(this.headers, null, 2)
        );
      } else {
        console.log("RESPONSE >>> %s", code);
      }
      return { ok: true };
    }

    console.log(`RESPONSE >>> ${code}\n${response.getContentText()}`);

    if (this.EXIT_STATES.includes(this.HTTP_RESPONSE_STATUS_CODE)) {
      return { ok: true };
    }

    if (this.RETRY_STATES.includes(this.HTTP_RESPONSE_STATUS_CODE)) {
      const { delaInXSeconds } = calculateDelay({
        requestInSeconds: this.RETRY_DELAY_SECONDS,
      });
      Utilities.sleep(delaInXSeconds);
      return { ok: false, retry: true };
    }

    if (this.SKIP_STATES.includes(this.HTTP_RESPONSE_STATUS_CODE)) {
      if (this.requestLog)
        console.log(
          "RESPONSE >>> %s, remaining: %s, limit: %s, retry: %s, reset: %s\nHeaders:\n%s",
          code,
          this.remaining,
          this.limit,
          this.retry,
          this.reset,
          JSON.stringify(this.headers, null, 2)
        );
      return { ok: true };
    }

    console.log(
      `RESPONSE (else) >>> ${code}\n${JSON.stringify(
        this.headers,
        null,
        2
      )}\n${response.getContentText()}`
    );
    return new Error(typeError(response, this.constructor.name));
  }

  /**
   * Sleeps for the specified delay in milliseconds and logs the
   * duration if logging is enabled.
   *
   * @param {number} delay - The number of milliseconds to sleep.
   */
  sleepWithLogging(delay, message) {
    if (this.requestLog) {
      console.log(
        `${message}, sleeping %s mseconds...` || "Sleeping %s mseconds...",
        delay
      );
    }
    Utilities.sleep(delay);
  }

  /**
   * A function to handle JSON chunking based on the provided JSON string and chunk size.
   *
   * @param {string} jsonString - The JSON string to be chunked.
   * @param {number} chunkSize - The size of the chunk to be used.
   * @return {string} The chunked JSON string.
   */
  jsonChunk(jsonString, chunkSize) {
    if (jsonString.length < chunkSize) {
      console.warn("Длина строки меньше размера чанка. Невозможно продолжить.");
      return jsonString;
    }

    let closingIndex = -1;
    for (let i = chunkSize; i < jsonString.length; i++) {
      if (jsonString[i] === "}") {
        closingIndex = i;
        break;
      }
    }

    if (closingIndex !== -1) {
      const resultString = jsonString.slice(0, closingIndex + 1) + "]";
      return resultString;
    } else {
      console.error(
        "Закрывающая фигурная скобка не найдена после заданного размера чанка."
      );
      return jsonString;
    }
  }

  /**
   * Send requests to the Wildberries API with the specified authorization key
   * @param {object} options
   * @param {string} [options.method]
   * @param {string} options.endpoint
   * @param {string} [options.contentType]
   * @param {boolean} [options.muteHttpExceptions]
   * @param {object} [options.params]
   * @param {object} [options.body]
   */
  request(options) {
    const {
      method = "GET",
      endpoint = "",
      contentType = "application/json",
      accept,
      muteHttpExceptions = true,
      followRedirects = true,
      validateHttpsCertificates = false,
      params,
      body,
      _headers = {},
      url,
      hesersDelete,
      maxRetries = 2,
    } = options;

    let fullUrl = url || `${this.baseUrl}${endpoint?.name || endpoint}`;
    if (params) fullUrl = this.queryString(params, fullUrl);

    const requestOptions = this.buildRequestOptions({
      method: endpoint?.method || method,
      _headers,
      contentType: endpoint?.contentType || contentType,
      accept,
      muteHttpExceptions,
      validateHttpsCertificates,
      followRedirects,
      body,
      hesersDelete,
    });

    if (this.requestLog)
      console.log(
        `TRYING 1 URL >>> ${fullUrl}\nOPTIONS >>>\n ${JSON.stringify(
          requestOptions,
          null,
          2
        )}`
      );
    else {
      console.log(`TRYING 1 URL >>> ${fullUrl}`);
    }

    let retryCount = 0;
    while (retryCount < maxRetries) {
      try {
        const response = UrlFetchApp.fetch(fullUrl, requestOptions);
        const processResult = this.processResponse(response);

        // Проверяем терминальные ошибки в первую очередь
        if (this.EXIT_STATES.includes(this.HTTP_RESPONSE_STATUS_CODE)) {
          // Для терминальных ошибок сразу выбрасываем исключение без повторных попыток
          const error = typeError(response, this.constructor.name);
          if (this.requestLog) console.log(`TERMINAL ERROR >>> ${error}`);
          throw new Error(error);
        }

        if (processResult?.ok) return response;
        if (processResult?.retry && retryCount < maxRetries - 1) {
          retryCount++;
          console.log(`TRYING ${retryCount + 1} >>> ${fullUrl}`);
          continue;
        }

        return response;
      } catch (err) {
        // Проверяем, является ли ошибка терминальной
        if (
          /Unauthorized|Forbidden|Not Found|Bad Request|Method Not Allowed/.test(
            err.message
          )
        ) {
          throw err; // Пробрасываем терминальную ошибку дальше без повторных попыток
        }

        console.log(`ERROR ${retryCount + 1} >>>\n${err.stack}`);
        if (retryCount >= maxRetries - 1) {
          throw new Error(typeError(err, this.constructor.name));
        }
        retryCount++;
      }
    }
  }

  buildRequestOptions({
    method,
    _headers,
    contentType,
    accept,
    muteHttpExceptions,
    validateHttpsCertificates,
    followRedirects,
    body,
    hesersDelete,
  }) {
    const headers = {
      ..._headers,
      "Content-Type": contentType,
      Cookie: this.cookies ?? "",
      "User-Agent": this.userAgent,
    };

    if (accept) headers.accept = accept;

    const requestOptions = {
      method,
      headers,
      muteHttpExceptions,
      validateHttpsCertificates,
      followRedirects,
    };

    if (this.__apiKey) requestOptions.headers.Authorization = this.__apiKey;
    if (this.__query) fullUrl += this.__query;

    if (hesersDelete) {
      delete requestOptions.headers;
    }

    if (body) requestOptions.payload = JSON.stringify(this.removeEmpty(body));
    return requestOptions;
  }

  getBatch(batch) {
    const requests = batch.map((options) => {
      const { url, endpoint, params, apiKey, token, headersOptions } = options;

      let fullUrl = url ? url : `${this.baseUrl}${endpoint}`;

      if (params) {
        fullUrl = this.queryString(params, fullUrl);
      }

      const headers = { ...headersOptions };
      headers.Authorization = `Bearer ${apiKey || token || this.__apiKey}`;

      return {
        url: fullUrl,
        method: "GET",
        headers,
        muteHttpExceptions: true,
      };
    });

    if (this.requestLog)
      console.log(`TRYING 1 URL >>> ${JSON.stringify(requests, null, 2)}`);

    return UrlFetchApp.fetchAll(requests);
  }

  sendBatch(batch, options) {
    const { url, endpoint, apiKey } = options;
    return UrlFetchApp.fetchAll(
      batch.map((requestBody) => ({
        url: url ? url : `${this.baseUrl}${endpoint}`,
        method: "POST",
        headers: {
          Authorization: apiKey || this.__apiKey,
          "Content-Type": "application/json",
        },
        payload: JSON.stringify(requestBody),
        muteHttpExceptions: true,
      }))
    );
  }

  /**
   * Находит соответствующий endpoint в MethodLimits по URL
   * @param {string} url - URL запроса
   * @returns {string|null} - найденный endpoint или null
   */
  findEndpointByUrl(url) {
    // Извлекаем путь из URL (убираем домен и ведущий слеш)
    const urlPath = url.replace(/^https?:\/\/[^\/]+/, "").replace(/^\//, "");

    // Сначала ищем точное совпадение на верхнем уровне
    if (Methods[urlPath]) {
      return urlPath;
    }

    // Рекурсивная функция для поиска во вложенных структурах
    const findInNested = (obj, path = "") => {
      for (const [key, value] of Object.entries(obj)) {
        // Если это строка и содержит %, проверяем как шаблон
        if (typeof key === "string" && key.includes("%")) {
          const regexPattern = key.replace(/%[^%]+%/g, "[^/]+");
          const regex = new RegExp(`^${regexPattern}$`);
          if (regex.test(urlPath)) {
            console.log(`Matched URL pattern: ${urlPath} -> ${key}`);
            return key;
          }
        }

        // Если это объект, рекурсивно ищем в нем
        if (typeof value === "object" && value !== null) {
          const result = findInNested(value, path + key + ".");
          if (result) return result;
        }
      }
      return null;
    };

    // Ищем шаблоны с параметрами на верхнем уровне
    for (const [pattern, config] of Object.entries(Methods)) {
      if (pattern.includes("%")) {
        // Заменяем %PARAM% на regex pattern
        const regexPattern = pattern.replace(/%[^%]+%/g, "[^/]+");
        const regex = new RegExp(`^${regexPattern}$`);
        if (regex.test(urlPath)) {
          console.log(`Matched URL pattern: ${urlPath} -> ${pattern}`);
          return pattern;
        }
      }
    }

    // Ищем во вложенных структурах
    const nestedResult = findInNested(Methods);
    if (nestedResult) {
      return nestedResult;
    }

    console.log(`No endpoint found for URL: ${urlPath}`);
    return null;
  }

  /**
   * Получает вложенное значение из объекта по пути
   * @param {object} obj - Объект
   * @param {string[]} path - Путь к значению
   * @returns {any} - Значение
   */
  getNested(obj, path) {
    if (!obj || !Array.isArray(path) || !path.length) return obj;
    let current = obj;
    for (let key of path) {
      if (
        current == null || // null или undefined
        (typeof current === "object" && !(key in current)) // ключа нет в объекте/массиве
      ) {
        return undefined;
      }
      current = current[key];
    }
    return current;
  }

  /**
   * Проверка подключения
   * @returns {json|Error}
   */
  ping() {
    const response = this.makeRequest({
      // url: this.baseUrl + "ping",
      endpointObject: Methods.COMMON.PING,
    });

    const endpoint = response?.endpoint;
    const status = response?.json?.Status;

    if (status === "OK") {
      return true;
    }

    console.warn(
      `API недоступен: ${endpoint}, ответ: ${status}, ${JSON.stringify(
        response,
        null,
        2
      )}`
    );

    response.message = `API недоступен: ${endpoint}, ответ: ${status}`;
    const error = typeError(response, this.constructor.name);
    // throw new Error(`API недоступен, ответ: ${status}`);
    throw new Error(error);
  }

  /**
   * Новый метод makeRequest с логикой повторных запросов
   * @param {Object} options - параметры запроса
   * @param {string} url - URL для запроса
   * @param {string} method - HTTP метод
   * @param {object} options - дополнительные опции
   * @param {string} endpoint - тип эндпоинта для лимитов
   * @param {object} params - параметры запроса
   * @param {object} body - тело запроса
   * @param {number} maxRetries - максимальное количество повторных попыток (по умолчанию 3)
   */
  makeRequest({
    method = "GET",
    url,
    endpointObject = "",
    endpoint = "",
    options = {},
    params,
    body,
    contentType = "application/json",
    accept,
    muteHttpExceptions = true,
    followRedirects = true,
    validateHttpsCertificates = false,
    maxRetries = 5,
    fixJson = false,
  }) {
    let fullUrl = url || this.baseUrl;

    if (endpointObject?.findEndpoint) {
      endpoint = endpoint;
    } else if (endpointObject?.name && !endpointObject?.findEndpoint) {
      endpoint = endpointObject?.name;
    }

    const config = endpointObject[endpointObject?.name || endpoint] || {};
    const { period, limit, interval, splash } = config.limits || {};
    const { block } = config.response || {};

    const defaultOptions = {
      method: endpointObject?.method || method,
      headers: {
        "Content-Type": endpointObject?.contentType || contentType,
      },
      muteHttpExceptions: muteHttpExceptions,
      followRedirects: followRedirects,
      validateHttpsCertificates: validateHttpsCertificates,
    };

    if (accept) defaultOptions.headers.Accept = accept;

    // Формируем полный URL
    if (endpoint) {
      fullUrl = `${fullUrl}${endpoint}`;
    }
    if (params) fullUrl = this.queryString(params, fullUrl);

    const requestOptions = Object.assign(defaultOptions, options);
    if (this.__apiKey) requestOptions.headers.Authorization = this.__apiKey;
    if (body) requestOptions.payload = JSON.stringify(this.removeEmpty(body));

    let retryCount = 0;
    while (retryCount < maxRetries) {
      // Проверяем лимиты перед каждым запросом
      if (endpoint)
        this.rateLimiter.waitForTokenAndPeriod({
          endpoint,
          period,
          limit,
          interval,
          splash,
        });

      try {
        if (this.requestLog)
          console.log(
            `TRYING ${
              retryCount + 1
            } URL >>> ${fullUrl}\nOPTIONS >>>\n ${JSON.stringify(
              requestOptions,
              null,
              2
            )}`
          );
        else console.log(`TRYING ${retryCount + 1} URL >>> ${fullUrl}`);

        const response = UrlFetchApp.fetch(fullUrl, requestOptions);
        const responseCode = response.getResponseCode();
        const rawData = response.getContentText("UTF-8");
        const responseHeaders = response.getAllHeaders();
        this.headers = responseHeaders;

        // Получаем blob для более точного определения типа файла
        const responseBlob = response.getBlob();
        const blobType = responseBlob ? responseBlob.getContentType() : "";

        // Безопасное парсинг JSON с улучшенной проверкой типа контента
        let responseJson = null;
        let isErrorJson = false;
        if (rawData) {
          const contentType = responseHeaders["Content-Type"] || blobType || "";
          const isJson =
            contentType.includes("application/json") ||
            contentType.includes("json") ||
            contentType.includes("text/json");

          if (isJson && fixJson) {
            const jsonString = rawData;

            const jsoBlobLength = responseBlob.getBytes().length;
            const jsonStringLength = jsonString.length;
            const chunkSize = 40 * 1024 * 1024;
            const isNotToLong = jsonStringLength < chunkSize;
            // const chunkSize = 50 * 1024 * 1024;
            // const n = 100000; // 100 КБ в байтах // 20000; // 20 КБ в байтах // 1048576 // 1 МБ в байтах
            // const isNotToLong = jsoBlobLength < chunkSize - n;

            if (this.requestLog) {
              console.info(
                "JSON STRING >>>",
                "jsonStringLength:",
                jsonStringLength,
                "jsoBlobLength:",
                jsoBlobLength,
                "chunkSize:",
                chunkSize,
                "is walid json:",
                isNotToLong
              );
            }

            if (isNotToLong) {
              try {
                responseJson = JSON.parse(jsonString);
              } catch (error) {
                console.warn(
                  "[MAKE_REQUEST] Ошибка парсинга JSON:",
                  error.message
                );
                console.warn("[MAKE_REQUEST] Проблемный JSON:", jsonString);
                responseJson = {};
              }
            } else {
              if (this.requestLog) console.warn("FIX JSON STRING...");
              const validJson = this.jsonChunk(
                jsonString,
                jsonStringLength - 3000
              );

              try {
                responseJson = JSON.parse(validJson);
                isErrorJson = true;
                console.warn(
                  "FIX JSON STRING SUCCESS, length:",
                  validJson.length,
                  responseJson.length
                );
              } catch (error) {
                console.warn(
                  "[MAKE_REQUEST] Ошибка парсинга JSON:",
                  error.message
                );
                console.warn(
                  "[MAKE_REQUEST] Проблемный JSON чанка:",
                  validJson
                );
                responseJson = {};
              }
            }
          } else if (isJson && !fixJson) {
            try {
              responseJson = JSON.parse(rawData);
            } catch (error) {
              if (this.requestLog)
                console.warn(
                  `[MAKE_REQUEST] Ошибка парсинга JSON: ${error.message}`
                );
              responseJson = {};
            }
          } else {
            if (this.requestLog) {
              console.warn(
                `[MAKE_REQUEST] Ответ не является JSON. Content-Type: ${contentType}, Blob Type: ${blobType}`
              );
            }
          }
        }

        // Безопасное получение числовых значений
        const getHeaderNumber = (name) => {
          const value = this.headers[name];
          if (value === undefined || value === null) return null;
          // Если заголовок - массив, берем первый элемент
          const strValue = Array.isArray(value) ? value[0] : value;
          const numValue = Number(strValue);
          return isNaN(numValue) ? null : numValue;
        };

        this.remaining = getHeaderNumber("x-ratelimit-remaining");
        this.limit = getHeaderNumber("x-ratelimit-limit");
        this.retry = getHeaderNumber("x-ratelimit-retry");
        this.reset = getHeaderNumber("x-ratelimit-reset");

        // Синхронизируем статистику и заголовки ПОСЛЕ обработки заголовков
        if (endpoint)
          this.rateLimiter.syncAfterRequest({
            endpoint,
            period,
            limit,
            interval,
            splash,
            headers: this.headers,
          });

        if (this.requestLog) {
          console.log(
            "RESPONSE >>> url: %s\ncode: %s, remaining: %s, limit: %s, retry: %s, reset: %s\nHeaders:\n%s",
            fullUrl,
            responseCode,
            this.remaining,
            this.limit,
            this.retry,
            this.reset,
            JSON.stringify(responseHeaders, null, 2)
          );

          if (endpoint)
            console.log(
              JSON.stringify(
                this.rateLimiter.endpointStats?.[endpoint] || [],
                null,
                2
              )
            );

          debugLog("API:", responseJson);

          // console.log(
          //   JSON.stringify(
          //     responseJson && responseJson?.length > 0
          //       ? responseJson[0]
          //       : responseJson,
          //     null,
          //     2
          //   )
          // );
        }

        // Обрабатываем различные статус коды
        switch (responseCode) {
          case 200:
          case 204:
            if (endpoint) {
              // Увеличиваем счетчик успешных запросов
              this.rateLimiter.endpointStats[endpoint].ok++;
              // Добавляем состояние успешного запроса
              this.rateLimiter.addState(
                endpoint,
                responseCode,
                "Успешный запрос"
              );
            }

            return {
              success: true,
              isErrorJson,
              code: responseCode,
              headers: responseHeaders,
              json: block
                ? Array.isArray(block)
                  ? this.getNested(responseJson, block)
                  : responseJson && responseJson[block] !== null
                  ? responseJson[block]
                  : null
                : responseJson,
              text: rawData,
              response: response,
              endpoint,
            };

          case 400:
          case 401:
          case 403:
          case 404:
          case 405:
            const error = typeError(response, this.constructor.name);
            // Добавляем состояние терминальной ошибки
            if (endpoint)
              this.rateLimiter.addState(endpoint, responseCode, error);

            if (
              (responseCode === 400 && endpoint.includes("adv/v3/fullstats")) ||
              endpoint.includes("adv/v1/budget")
            ) {
              return {
                success: false,
                code: responseCode,
                text: rawData,
                endpoint,
                response: response, // Сохраняем response для возможного сохранения бинарных данных
              };
            }

            // Создаем объект ошибки с сохранением response для возможного сохранения бинарных данных
            const errorObj = new Error(error);
            errorObj.response = response; // Сохраняем response в объекте ошибки
            throw errorObj;

          case 409:
            // Ошибка 409 учитывается как 5 запросов - добавляем дополнительные записи в историю
            const error409 =
              responseJson?.detail ||
              "Ошибка сохранения - проверьте данные запроса";
            console.warn(`409 Conflict: ${error409}`);

            if (endpoint) {
              // Добавляем состояние ошибки 409
              this.rateLimiter.addState(endpoint, responseCode, error409);
              // Обновляем статистику для новой логики
              const stats = this.rateLimiter.endpointStats[endpoint];
              // Добавляем 4 дополнительных burstCount
              for (let i = 0; i < 4; i++) {
                stats.burstCount++;
              }
            }

            return {
              success: false,
              code: responseCode,
              endpoint,
            };

          case 413:
            const error413 =
              responseJson?.detail ||
              "Превышен лимит объёма данных - уменьшите количество объектов в запросе";

            if (endpoint) {
              // Добавляем состояние ошибки 413
              this.rateLimiter.addState(endpoint, responseCode, error413);
            }
            throw new Error(`413 Payload Too Large: ${error413}`);

          case 422:
            const error422 =
              responseJson?.detail ||
              "Ошибка валидации - проверьте данные запроса";

            if (endpoint) {
              // Добавляем состояние ошибки 422
              this.rateLimiter.addState(endpoint, responseCode, error422);
            }
            // throw new Error(`422 Unprocessable Entity: ${error422}`);
            console.warn(`422 Unprocessable Entity: ${error422}`);
            return {
              success: false,
              code: responseCode,
              endpoint,
            };

          case 429:
            if (endpoint) {
              const error429 =
                responseJson?.detail || "Превышен лимит запросов";
              this.rateLimiter.addState(endpoint, responseCode, error429);
              const stats = this.rateLimiter.endpointStats[endpoint];
              stats.burstCount++;
            }

            // Добавляем повторную попытку для 429 с ожиданием
            if (retryCount < maxRetries - 1) {
              retryCount++;

              // Определяем время ожидания из заголовков или используем дефолтное
              let waitTime = 60000; // 60 секунд по умолчанию
              if (this.retry !== null && this.retry > 0) {
                waitTime = this.retry * 1000;
              } else if (this.reset !== null && this.reset > 0) {
                const resetTime = this.reset * 1000;
                const now = Date.now();
                waitTime = Math.max(0, resetTime - now);
              }

              // Минимальная задержка 1 секунда, максимальная 5 минут
              waitTime = Math.max(1000, Math.min(waitTime, 300000));

              if (this.requestLog) {
                console.log(
                  `429 Too Many Requests. Waiting ${Math.ceil(
                    waitTime / 1000
                  )}s before retry ${retryCount}/${maxRetries}...`
                );
              } else {
                console.log(
                  `⏳ 429 - Ожидание ${Math.ceil(
                    waitTime / 1000
                  )}с перед повтором...`
                );
              }

              this.sleepWithLogging(waitTime, `Retrying after 429 error...`);
              continue; // Повторяем запрос
            }

            return {
              success: false,
              code: responseCode,
              endpoint,
            };

          case 500:
          case 502:
          case 503:
          case 504:
            const serverError_ =
              responseJson?.detail || "Внутренняя ошибка сервиса";

            if (endpoint) {
              // Добавляем состояние серверной ошибки
              this.rateLimiter.addState(endpoint, responseCode, serverError_);
            }

            // Для серверных ошибок - повторяем запрос
            if (retryCount < maxRetries - 1) {
              const { delaInXSeconds } = calculateDelay({
                requestInSeconds: this.RETRY_DELAY_SECONDS,
              });
              this.sleepWithLogging(
                delaInXSeconds,
                `${responseCode}: ${serverError_}`
              );
              retryCount++;
              continue; // Повторяем запрос
            }

            if (responseCode === 500 && endpoint.includes("adv/v3/fullstats")) {
              return {
                success: false,
                code: responseCode,
                text: rawData,
                endpoint,
              };
            }

            const serverError = typeError(response, this.constructor.name);
            // Если превысили лимит попыток - возвращаем ошибку
            throw new Error(serverError);

          default:
            const defaultError =
              responseJson?.detail || `Неожиданный код ответа: ${responseCode}`;

            if (endpoint) {
              // Добавляем состояние неожиданной ошибки
              this.rateLimiter.addState(endpoint, responseCode, defaultError);
            }
            throw new Error(`Unexpected ${responseCode}: ${defaultError}`);
        }
      } catch (error) {
        if (this.requestLog) console.error("[MAKE_REQUEST]", error.stack);

        // Добавляем состояние исключения
        // if (endpoint)
        //   this.rateLimiter.addState(endpoint, "EXCEPTION", error.message);

        // Проверяем терминальные ошибки
        if (
          /Unauthorized|Forbidden|Not Found|Bad Request|Method Not Allowed|Internal Server Error|Bad Gateway|Service Unavailable/.test(
            error.message
          )
        ) {
          throw error; // Пробрасываем терминальную ошибку дальше без повторных попыток
        }

        // Если это последняя попытка - выбрасываем ошибку
        if (retryCount >= maxRetries - 1) {
          // Добавляем дополнительную информацию об ошибке
          let errorInfo = {
            success: false,
            error: error.message,
            code: null,
            url: fullUrl,
            method: method,
            endpoint: endpoint,
            timestamp: new Date().toISOString(),
          };

          // Если это ошибка сети или соединения
          if (error.message.includes("UrlFetchApp")) {
            errorInfo.error = "Ошибка сети - проверьте подключение к интернету";
            errorInfo.code = "NETWORK_ERROR";
            // this.rateLimiter.addState(
            //   endpoint,
            //   "NETWORK_ERROR",
            //   errorInfo.error
            // );
          }

          // Если это ошибка парсинга JSON
          if (error.message.includes("JSON")) {
            errorInfo.error = "Ошибка парсинга ответа сервера";
            errorInfo.code = "JSON_PARSE_ERROR";
            // this.rateLimiter.addState(
            //   endpoint,
            //   "JSON_PARSE_ERROR",
            //   errorInfo.error
            // );
          }

          if (this.requestLog) console.warn(JSON.stringify(errorInfo, null, 2));

          return errorInfo;
        }

        // Логируем ошибку и повторяем
        console.warn(`ERROR ${retryCount + 1} >>>\n${error.stack}`);
        retryCount++;

        // Ждем перед следующей попыткой
        const delay = 2000 * Math.pow(2, retryCount - 1); // Экспоненциальная задержка
        this.sleepWithLogging(delay, `Retrying in ${delay}ms...`);
      }
    }
  }
}

class WildberriesRequestError extends Error {
  constructor(response, statusCode, class_) {
    super(response);
    this.name = `Wildberries${class_}RequestError` || "WildberriesRequestError";
    this.statusCode = HTTPResponseStatusCodes.message(statusCode);

    this.code = response?.errors
      ? response?.errors.code
      : response?.error_code
      ? response.error_code
      : response?.code
      ? response.code
      : null;

    this.description = response?.message
      ? response.message
      : response?.errors &&
        Array.isArray(response.errors) &&
        typeof response.errors[0] === "object"
      ? response.errors
          .map((error) => `${error.detail} ${error.field}`)
          .join("\n")
      : response?.errors &&
        Array.isArray(response.errors) &&
        typeof response.errors[0] === "string"
      ? response.errors.join("\n")
      : response?.errors?.message
      ? response.errors.message
      : response?.errorText
      ? response.errorText
      : response?.error
      ? response?.error
      : null;

    this.data = response?.errors?.data ? response.errors.data : null;
    this.detail = response?.detail || null;
    this.additionalErrors = response?.additionalErrors
      ? response.additionalErrors
      : null;

    this.origin = response?.origin || null;
    this.requestId = response?.requestId || response?.request_id || null;
  }

  info() {
    const nonNullValues = Object.keys(this)
      .filter((key) => this[key] !== null)
      .reduce((acc, key) => {
        acc[key] = this[key];
        return acc;
      }, {});
    return nonNullValues; // JSON.stringify(nonNullValues, null, 2);
  }
}

class WildberriesRequestErrorString {
  constructor(response, statusCode, class_) {
    this.name =
      `Wildberries${class_}RequestErrorString` ||
      "WildberriesRequestErrorString";
    this.statusCode = HTTPResponseStatusCodes.message(statusCode);
    this.details = response;
  }
}

class RequestErrorStringNotObject {
  constructor(response, statusCode, class_) {
    this.name =
      `${class_}RequestErrorStringNotObject` || "RequestErrorStringNotObject";
    this.statusCode = HTTPResponseStatusCodes.message(statusCode);

    // Безопасное парсинг JSON
    let parsedResponse = null;
    try {
      parsedResponse = JSON.parse(response);
    } catch (error) {
      console.warn(
        `Ошибка парсинга JSON в RequestErrorStringNotObject: ${error.message}`
      );
    }

    this.message = parsedResponse?.errorText || response;
  }
}

class RequestErrorString {
  constructor(response) {
    this.name = "RequestError";
    this.message = response?.message || response;
  }
}

class ValidationError extends Error {
  constructor(message, class_) {
    super(message);
    this.name = this.name = `${class_}ValidationError` || "ValidationError";
  }
}

function typeError(e, class_) {
  try {
    if (e instanceof Error || e?.name === "Exception") {
      return JSON.stringify(new RequestErrorString(e), null, 2);
    } else {
      // Проверяем, является ли e объектом HttpResponse (имеет методы getContentText и getResponseCode)
      const hasGetContentText = typeof e?.getContentText === "function";
      const hasGetResponseCode = typeof e?.getResponseCode === "function";

      let contentText;
      let responseCode;

      if (hasGetContentText && hasGetResponseCode) {
        // Это объект HttpResponse
        contentText = e.getContentText();
        responseCode = e.getResponseCode();
      } else if (e?.text !== undefined || e?.response !== undefined) {
        // Это результат makeRequest (объект с полями text, response, code)
        contentText =
          e.text ||
          (e.response && typeof e.response.getContentText === "function"
            ? e.response.getContentText()
            : null);
        responseCode =
          e.code ||
          (e.response && typeof e.response.getResponseCode === "function"
            ? e.response.getResponseCode()
            : null);
      } else {
        // Это обычный объект или что-то другое
        contentText =
          e?.message ||
          e?.errorText ||
          e?.error ||
          (typeof e === "string" ? e : null);
        responseCode = e?.code || e?.statusCode || null;
      }

      // Безопасное парсинг JSON
      let parsedContent = null;
      let isJson = false;

      if (typeof contentText === "string" && contentText.trim()) {
        try {
          parsedContent = JSON.parse(contentText);
          isJson = true;
        } catch (parseError) {
          console.log(
            `Ошибка парсинга JSON в typeError: ${parseError.message}`
          );
          isJson = false;
        }
      }

      if (!isJson && typeof contentText === "string") {
        return JSON.stringify(
          new RequestErrorStringNotObject(contentText, responseCode, class_),
          null,
          2
        );
      } else {
        return JSON.stringify(
          new WildberriesRequestError(
            parsedContent,
            responseCode,
            class_
          ).info(),
          null,
          2
        );
      }
    }
  } catch (error) {
    console.error(
      `ERROR MESSAGE:\nstring:\n${
        e?.toString ? e.toString() : String(e)
      }\nstack:\n${error.stack}`
    );

    // Безопасное получение errorText
    let errorText;
    if (typeof e?.getContentText === "function") {
      errorText = e.getContentText();
    } else if (e?.text) {
      errorText = e.text;
    } else if (e?.message) {
      errorText = e.message;
    } else if (e?.toString) {
      errorText = e.toString();
    } else {
      errorText = String(e) || error.stack;
    }

    // Безопасное получение responseCode
    let responseCode = 0;
    if (typeof e?.getResponseCode === "function") {
      responseCode = e.getResponseCode();
    } else if (e?.code) {
      responseCode = e.code;
    } else if (e?.statusCode) {
      responseCode = e.statusCode;
    }

    return JSON.stringify(
      new WildberriesRequestErrorString(errorText, responseCode, class_),
      null,
      2
    );
  }
}

/**
 * Checks if a token is valid for accessing the HTTP Wildberries API.
 *
 * @param {string} token - The token to be checked.
 * @throws {ValidationError} If the token is missing, not a string, or contains spaces.
 * @returns {boolean} Returns true if the token is valid.
 */
function checkToken(essence) {
  // Check if token is missing
  if (!essence) {
    throw new ValidationError(
      `Пропущен ключ для доступа к Wildberry API { apiKey: "xxxxxxx" }\n
Получить ключ можно на портале Продавца в разделе: Настройки > Доступ к API.\n
Используйте комбинированный ключ с множественный доступом или отдельно разные типы ключей.\n`
    );
  }

  const token =
    typeof essence !== "undefined" &&
    essence instanceof _Client &&
    typeof essence.apiKey === "string"
      ? essence.apiKey
      : essence;

  // Check if token is not a string
  if (typeof token !== "string") {
    throw new ValidationError(
      `Токен недействителен! Должен быть тип «str», а не тип ${typeof token}.\n`
    );
  }
  // Check if token contains spaces
  if (token.includes(" ")) {
    throw new ValidationError(
      "Токен недействителен! Он не может содержать пробелов.\n"
    );
  }

  // Return true if token is valid
  return true;
}

/**
 * Generates API classes based on provided service and configuration options.
 *
 * @param {Object} options - The options object for configuring the API classes.
 * @param {Function} options.service - The PropertiesService.getScriptProperties used for API calls.
 * @param {boolean} options.requestLog - Flag to enable request logging.
 * @param {boolean} [options.check=false] - Flag to enable token checking.
 * @return {Object} The API classes generated based on the provided service and options.
 */
function apiClasses({
  service,
  requestLog,
  check = false,
  specificClass = null,
}) {
  try {
    const storage =
      context?.storage ||
      (service && setStorage({ service, serviceType: context?.serviceType })) ||
      null;

    if (!storage) {
      throw new ValidationError(
        `Передайте service: PropertiesService, тип «obj», а не тип ${typeof storage}.\n`
      );
    }

    const keys = [
      "MarketplaceKey",
      "ContentKey",
      "AnalyticsKey",
      "StatisticsKey",
      "AdverteKey",
      "FeedbacksQuestionsKey",
      "PricesDiscountsKey",
      "BuyerChatKey",
      "SuppliesKey",
      "DocumentsKey",
      "FinanceKey",
      "ReturnsKey",
      "MultipleAccess",
    ];

    const apiKeys = keys.map((key) => storage.getProperty(key));

    const hasToken = (apiKey) => {
      if (apiKey && check) {
        checkToken(apiKey);
      }
    };

    apiKeys.forEach(hasToken);

    const commonParams = {
      requestLog,
      check,
    };

    const getApiKey = (key) =>
      storage.getProperty(key) || storage.getProperty("MultipleAccess");

    const firstNonUndefined = apiKeys.find((key) => key);

    // Если запрошен конкретный класс, возвращаем только его
    if (specificClass) {
      const classMap = {
        WBC: new Content({ apiKey: getApiKey("ContentKey"), ...commonParams }),
        WBM: new Marketplace({
          apiKey: getApiKey("MarketplaceKey"),
          ...commonParams,
        }),
        WBA: new Analytics({
          apiKey: getApiKey("AnalyticsKey"),
          ...commonParams,
        }),
        WBS: new Statistics({
          apiKey: getApiKey("StatisticsKey"),
          ...commonParams,
        }),
        WBADV: new Advert({ apiKey: getApiKey("AdvertKey"), ...commonParams }),
        WBFQ: new FeedbacksQuestions({
          apiKey: getApiKey("FeedbacksQuestionsKey"),
          ...commonParams,
        }),
        WBPD: new PricesDiscounts({
          apiKey: getApiKey("PricesDiscountsKey"),
          ...commonParams,
        }),
        WBCP: new CalendarPromo({
          apiKey: getApiKey("PricesDiscountsKey"),
          ...commonParams,
        }),
        WBSP: new Supplies({
          apiKey: getApiKey("SuppliesKey"),
          ...commonParams,
        }),
        WBD: new Documents({
          apiKey: getApiKey("DocumentsKey"),
          ...commonParams,
        }),
        WBR: new Returns({ apiKey: getApiKey("ReturnsKey"), ...commonParams }),
        WBF: new Finance({ apiKey: getApiKey("FinanceKey"), ...commonParams }),
        WBBC: new BuyerChat({
          apiKey: getApiKey("BuyerChatKey"),
          ...commonParams,
        }),
        WBT: new Tariffs({ apiKey: firstNonUndefined, ...commonParams }),
        WCM: new Communications({ apiKey: firstNonUndefined, ...commonParams }),
      };

      if (classMap[specificClass]) {
        return { [specificClass]: classMap[specificClass] };
      } else {
        throw new Error(`Неизвестный API класс: ${specificClass}`);
      }
    }

    // Возвращаем все классы как раньше
    return {
      WBC: new Content({ apiKey: getApiKey("ContentKey"), ...commonParams }),
      WBM: new Marketplace({
        apiKey: getApiKey("MarketplaceKey"),
        ...commonParams,
      }),
      WBA: new Analytics({
        apiKey: getApiKey("AnalyticsKey"),
        ...commonParams,
      }),
      WBS: new Statistics({
        apiKey: getApiKey("StatisticsKey"),
        ...commonParams,
      }),
      WBADV: new Advert({
        apiKey: getApiKey("AdvertKey"),
        ...commonParams,
      }),
      WBFQ: new FeedbacksQuestions({
        apiKey: getApiKey("FeedbacksQuestionsKey"),
        ...commonParams,
      }),
      WBPD: new PricesDiscounts({
        apiKey: getApiKey("PricesDiscountsKey"),
        ...commonParams,
      }),
      WBCP: new CalendarPromo({
        apiKey: getApiKey("PricesDiscountsKey"),
        ...commonParams,
      }),
      WBSP: new Supplies({
        apiKey: getApiKey("SuppliesKey"),
        ...commonParams,
      }),
      WBD: new Documents({
        apiKey: getApiKey("DocumentsKey"),
        ...commonParams,
      }),
      WBR: new Returns({
        apiKey: getApiKey("ReturnsKey"),
        ...commonParams,
      }),
      WBF: new Finance({ apiKey: getApiKey("FinanceKey"), ...commonParams }),
      WBBC: new BuyerChat({
        apiKey: getApiKey("BuyerChatKey"),
        ...commonParams,
      }),
      WBT: new Tariffs({ apiKey: firstNonUndefined, ...commonParams }),
      WCM: new Communications({
        apiKey: firstNonUndefined,
        ...commonParams,
      }),
    };
  } catch (error) {
    console.error("[API CLASSES]", error.stack);
    return SpreadsheetApp.getUi().alert(
      `⚠️ ATTENTION`,
      `[WARNING] Произошла ошибка:\n${error.stack}`,
      SpreadsheetApp.getUi().ButtonSet.OK
    );
  }
}

