class Content extends _Client {
  constructor({ apiKey, requestLog }) {
    super({ apiKey, requestLog });
    this.baseUrl = Urls.CONTENT;
  }

  info() {
    const info = {
      description: "Контент",
      link: "https://dev.wildberries.ru/",
      baseUrl: this.baseUrl,
      methods: this.getMethods(Content),
    };
    return this.log(info);
  }

  /**
   * Использование тестового сервиса контента
   * Во всех методах нет параметра locale, все данные возвращаются на русском языке.
   * Карточка товара создаётся сразу.
   * В запросе метода Список номенклатур не используются параметры allowedCategoriesOnly, tagIDs и withPhoto.
   * Нет лимита на количество карточек.
   * Нет методов для работы с медиафайлами (фото и видео) и тегами.
   * Максимум 1 запрос в секунду суммарно для всех методов.
   */
  useTestCircuitUrl() {
    this.baseUrl = Urls.CONTENT_TEST_CIRCUIT;
  }

  // CARDS Создание карточек товаров

  /**
   * Лимиты по КТ
   * @description Метод позволяет получить отдельно бесплатные и платные лимиты продавца на создание карточек товаров.
   * Формула для получения количества карточек, которые можно создать: (freeLimits + paidLimits) - Количество созданных карточек.
   * Созданными считаются все карточки, которые можно получить методами "Список НМ" и "Список НМ, находящихся в корзине".
   * @returns {json|Error}
   */
  limits() {
    const response = this.makeRequest({
      endpointObject: Methods.CONTENT.LIMITS,
    });

    if (response?.code === this.HTTP_STATUS.OK_200) return response?.json || {};
    else throw new Error(typeError(response, this.constructor.name));
  }

  /**
   * Генерация баркодов
   * @description Метод позволяет сгенерировать массив уникальных баркодов для создания размера НМ в КТ.
   * @param {number} count кол-во баркодов которые надо сгенерировать, максимальное доступное количество баркодов для генерации - 5000
   * @returns {json|Error}
   */
  barcodes(count) {
    if (count > 5000)
      throw new Error(
        `Значение count не может быть больше 5000, передано ${count}`
      );
    const response = this.makeRequest({
      endpointObject: Methods.CONTENT.BARCODES,
      body: Number(count),
    });

    if (response?.code === this.HTTP_STATUS.OK_200) return response?.json || [];
    else throw new Error(typeError(response, this.constructor.name));
  }

  /**
   * Создание КТ
   * @description Создание карточки товара происходит асинхронно, при отправке запроса на создание КТ ваш запрос становится в очередь на создание КТ.
   *
   * ПРИМЕЧАНИЕ: Карточка товара считается созданной, если успешно создалась хотя бы одна НМ.
   * ВАЖНО: Если во время обработки запроса в очереди выявляются ошибки, то НМ считается ошибочной.
   * За раз можно создать 100 КТ по 30 вариантов товара (НМ) в каждой.
   *
   * Порядок создания КТ:
   * 1. Получить список всех родительских категорий методом "Родительские категории товаров"
   * 2. По имени или ID родительской категории получите список всех доступных предметов методом "Список предметов"
   * 3. По ID предмета получите характеристики доступные для Вашего предмета, методом "Характеристики предмета"
   * Для характеристик Цвет, Страна производства, Сезон, Ставка НДС, ТНВЭД значения необходимо брать из справочников в разделе Конфигуратор.
   * 4. Создайте запрос и отправьте его на сервер. Если запрос на создание прошел успешно, а карточка не создалась, то необходимо в первую очередь проверить наличие карточки в
   * методе Список несозданных НМ с ошибками. Если карточка попала в ответ к этому методу, то необходимо исправить описанные ошибки в
   * запросе на создание карточки и отправить его повторно.
   * @param {Array.<[object]>} json массив карточек
   * @returns {json|Error}
   */
  upload(json) {
    const response = this.makeRequest({
      endpointObject: Methods.CONTENT.UPLOAD,
      body: json,
    });

    if (response?.code === this.HTTP_STATUS.OK_200) return response?.json || {};
    else throw new Error(typeError(response, this.constructor.name));
  }

  /**
   * Добавление НМ к КТ
   * @description Метод позволяет добавить к карточке товара новую номенклатуру. new
   * Добавление НМ к КТ происходит асинхронно, после отправки запрос становится в очередь на обработку.
   * Важно! Если после успешной отправки запроса номенклатура не создалась, то необходимо проверить раздел "Список несозданных НМ с ошибками".
   * Для того чтобы убрать НМ из ошибочных, необходимо повторно сделать запрос с исправленными ошибками.
   * @param {number} imtID imtID КТ, к которой добавляется НМ
   * @param {Array.<object>} cardsToAdd массив НМ которые хотим добавить к КТ (Структура добавляемой НМ)
   * @returns {json|Error}
   */
  uploadAdd(imtID, cardsToAdd) {
    const response = this.makeRequest({
      endpointObject: Methods.CONTENT.UPLOAD_ADD,
      body: {
        imtID,
        cardsToAdd,
      },
    });

    if (response?.code === this.HTTP_STATUS.OK_200) return response?.json || {};
    else throw new Error(typeError(response, this.constructor.name));
  }

  // CARDS Карточки товаров

  /**
   * Список НМ
   * @description Метод позволяет получить список созданых НМ по фильтру (артикул продавца, артикул WB (nmId), тег) с пагинацией и сортировкой.
   *
   * Важно! Карточки, находящиеся в корзине, в ответе метода не выдаются.
   * Получить такие карточки можно только методом "Список НМ, находящихся в корзине".
   * Порядок работы с get/cards/list:
   * Чтобы получить полный список номенклатур, если их > 1000, необходимо воспользоваться пагинацией.
   * 1. Cделать первый запрос, по желанию можно добавить поиск по "textSearch" в filter, и сортировку.
   * 2. Пройти в конец полученного списка номенклатур, скопировать из cursor две строки:
   * - "updatedAt": "***",
   * - "nmID": ***,
   * 3. Вставить скопированные строки в cursor запроса, повторить вызов метода.
   * 4. Повторять пункты 2 и 3, пока total в ответе не станет меньше чем limit в запросе. Это будет означать, что Вы получили все карточки.
   * @returns {json|Error}
   */
  list({
    textSearch,
    withPhoto = -1,
    tagIDs,
    allowedCategoriesOnly = false,
    objectIDs,
    brands,
    imtID,
    limit = 100,
    ascending = false,
    // sortColumn,
    updatedAt,
    nmID,
    locale = Locale.RU,
  } = {}) {
    const result = [];

    // this.ping();

    while (true) {
      var response = this.makeRequest({
        endpointObject: Methods.CONTENT.LIST,
        params: { locale },
        body: {
          settings: {
            cursor: { limit, updatedAt, nmID },
            filter: {
              textSearch: textSearch ? String(textSearch) : null, // string по артикулу продавца, артикулу WB, баркоду
              withPhoto: Number(withPhoto), // -1 - Показать все КТ; 0 - Показать КТ без фото; 1 - Показать КТ с фото
              tagIDs, // Array of integers
              allowedCategoriesOnly,
              objectIDs, // Array of integers
              brands, // Array of strings
              imtID, // integer
            },
            sort: { ascending },
          },
        },
      });

      if (response?.code === this.HTTP_STATUS.OK_200) {
        const main = response?.json;
        if (!main) break;

        const cursor = main?.cursor;
        const total = cursor?.total || 0;
        // const currentBatch = main?.cards?.length || 0;

        result.push(...(main?.cards || []));

        console.log(`Получено: ${total} всего: ${result.length}`);

        if (total < limit) {
          break;
        }

        updatedAt = cursor?.updatedAt;
        nmID = cursor?.nmID;
      }
    }

    return result;
  }

  /**
   * Список несозданных НМ с ошибками
   * @description Метод позволяет получить список НМ и список ошибок которые произошли во время создания КТ.
   *
   * ВАЖНО: Для того чтобы убрать НМ из ошибочных, надо повторно сделать запрос с исправленными ошибками на создание КТ.
   * @param {string} locale параметр выбора языка значений полей ответа (для котороых предусмотрена мультиязычность)
   * @returns {json|Error}
   */
  errorCardsList({
    limit = 100,
    ascending = false,
    updatedAt,
    batchUUID,
    locale = Locale.RU,
  } = {}) {
    const result = [];

    while (true) {
      var response = this.makeRequest({
        endpointObject: Methods.CONTENT.ERROR_LIST_V2,
        params: { locale },
        body: {
          settings: {
            cursor: { limit, updatedAt, batchUUID },
            order: { ascending },
          },
        },
      });

      if (response?.code === this.HTTP_STATUS.OK_200) {
        const main = response?.json;
        if (!main) break;

        const cursor = main?.cursor;
        const next = cursor?.next || 0;
        const currentBatch = main?.items || [];

        result.push(...currentBatch);

        console.log(`Получено: ${currentBatch.length} всего: ${result.length}`);

        if (!next) {
          break;
        }

        updatedAt = cursor?.updatedAt;
        batchUUID = cursor?.batchUUID;
      }
    }

    return result;
  }

  /**
   * Редактирование КТ
   * @description Метод позволяет редактировать КТ
   * За раз можно отредактировать 1 КТ.
   * Баркоды редактированию/удалению не подлежат. Добавить баркод к уже существующему можно.
   * photos, video и tags в запросе передавать не обязательно, редактирование и удаление этих структур данным методом не предусмотрено.'
   * Если запрос прошел успешно, а информация в карточке не обновилась, значит были допущены ошибки и карточка попала в
   * Список несозданных НМ с ошибками (метод cards/error/list) с описанием ошибок. Необходимо исправить ошибки в запросе и отправить его повторно.
   * Для успешного обновления карточки рекомендуем Вам придерживаться следующего порядка действий:
   * 1. Сначала существующую карточку необходимо запросить методом get/card/full
   * 2. Забираем из ответа данные карточки, до поля createdAt.
   * 3. Данные помещаем в массив.
   * 4. В этом массиве вносим необходимые изменения и отправляем его в cards/update.
   * @param {Array.<object>} json массив карточек
   * @returns {json|Error}
   */
  update(json) {
    const response = this.makeRequest({
      endpointObject: Methods.CONTENT.UPDATE,
      body: json,
    });

    if (response?.code === this.HTTP_STATUS.OK_200) return response?.json || [];
    else throw new Error(typeError(response, this.constructor.name));
  }

  /**
   * Объединение / Разъединение НМ
   * @description Метод позволяет объединять номенклатуры (nmID) под одним imtID и разъединять их.
   * Для объединения НМ необходимо отправить запрос со списком НМ с заполненным параметром targetIMT в теле запроса. При этом все НМ объединятся под imtID указанном в targetIMT.
   *
   * Чтобы отсоединить НМ от карточки, необходимо передать эту НМ без параметра targetIMT в теле запроса.
   * При этом для передаваемой НМ создается новый imtID.
   * Если в запросе на разъединение передается несколько НМ, то все они автоматически объединятся под одним новым imtID.
   * Чтобы присвоить каждой НМ уникальный imtID необходимо передавать по одной НМ за запрос. Для НМ, не участвующих в запросе, никаких изменений не происходит.
   *
   * ВАЖНО: Объединить можно только номенклатуры с одинаковыми предметами.
   * ВАЖНО: В одной КТ (под одним imtID) не может быть больше 30 номенклатур (nmID).
   * @param {number} targetIMT существующий у продавца imtID, под которым необходимо объединить НМ
   * @param {Array.<object>} nmIDs nmID, которые необходимо объединить / разъединить (max 30)
   * @returns {json|Error}
   */
  moveMn({ targetIMT, nmIDs, conn = true }) {
    const body = {
      targetIMT,
      nmIDs,
    };

    if (!conn) delete body.targetIMT;

    const response = this.makeRequest({
      endpointObject: Methods.CONTENT.MOVE_MN,
      body: body,
    });

    if (response?.code === this.HTTP_STATUS.OK_200) return response?.json || {};
    else throw new Error(typeError(response, this.constructor.name));
  }

  // CARDS Корзина

  /**
   * Список карточек товаров в корзине
   * @description Метод позволяет получить список созданых НМ по фильтру (артикул продавца, артикул WB (nmId), тег) с пагинацией и сортировкой.
   *@returns {json|Error}
   */
  trashList({
    textSearch,
    ascending = false,
    limit = 100,
    trashedAt,
    nmID,
    locale = Locale.RU,
  } = {}) {
    const result = [];

    while (true) {
      var response = this.makeRequest({
        endpointObject: Methods.CONTENT.TRASH.LIST,
        params: { locale },
        body: {
          settings: {
            cursor: { limit, trashedAt, nmID },
            filter: {
              textSearch: textSearch ? String(textSearch) : null, // string по артикулу продавца, артикулу WB, баркоду
            },
            sort: { ascending },
          },
        },
      });

      if (response?.code === this.HTTP_STATUS.OK_200) {
        const main = response?.json;
        if (!main) break;

        const cursor = main?.cursor;
        const total = cursor?.total || 0;
        // const currentBatch = main?.cards?.length || 0;

        result.push(...(main?.cards || []));

        console.log(`Получено: ${total} всего: ${result.length}`);

        if (total < limit) {
          break;
        }

        trashedAt = cursor?.trashedAt;
        nmID = cursor?.nmID;
      }
    }

    return result;
  }

  /**
   * Перенос карточек товаров в корзину
   * @returns {json|Error}
   */
  trashDelete({ nmIDs }) {
    if (Array.isArray(nmIDs) && nmIDs.length > 1000)
      throw new Error(
        `Значение nmIDs не может быть больше 1000, передано ${nmIDs.length}`
      );

    const response = this.makeRequest({
      endpointObject: Methods.CONTENT.TRASH.DELETE,
      body: { nmIDs: Array.isArray(nmIDs) ? nmIDs : [nmIDs] },
    });

    if (response?.code === this.HTTP_STATUS.OK_200) return response?.json || {};
    else throw new Error(typeError(response, this.constructor.name));
  }

  /**
   * Восстановление карточек товаров из корзины
   * @returns {json|Error}
   */
  trashRecover({ nmIDs }) {
    if (Array.isArray(nmIDs) && nmIDs.length > 1000)
      throw new Error(
        `Значение nmIDs не может быть больше 1000, передано ${nmIDs.length}`
      );

    const response = this.makeRequest({
      endpointObject: Methods.CONTENT.TRASH.RECOVER,
      body: { nmIDs: Array.isArray(nmIDs) ? nmIDs : [nmIDs] },
    });

    if (response?.code === this.HTTP_STATUS.OK_200) return response?.json || {};
    else throw new Error(typeError(response, this.constructor.name));
  }

  // CARDS Медиафайлы

  /**
   * Изменение медиа контента КТ
   * @description Метод позволяет изменить порядок изображений или удалить медиафайлы с НМ в КТ, а также загрузить изображения в НМ со сторонних ресурсов по URL.
   *
   * Текущие изображения заменяются на переданные в массиве data.
   *
   * Требования к медиафайлам:
   * Фото: минимальное разрешение – 700x900.
   * Максимально допустимое количество фото в КТ 30.
   * Допустимые форматы изображений - jpg и png.
   * Минимальный уровень качества изображения - 65%.
   *
   * Если хотя бы одно изображение в запросе не соответствует требованиям к медиафайлам, то даже при коде ответа 200 ни одно изображение не загрузится в КТ.
   *
   * ВАЖНО! Всё, что передаётся в массиве data полностью заменяет собой содержимое массива mediaFiles в КТ.
   * Если Вы добавляете фото к уже имеющимся в КТ, то вместе с новыми передайте в запросе все ссылки на фото и видео, которые уже содержатся в КТ.
   * В противном случае в карточке окажутся только передаваемые фото.
   * @param {string} vendorCode артикул продавца
   * @param {Array.<string>} data ссылки на изображения в том порядке, в котором мы хотим их увидеть в карточке товара
   * @returns {json|Error}
   */
  mediaSave({ vendorCode, data }) {
    const response = this.makeRequest({
      endpointObject: Methods.CONTENT.MEDIA.SAVE,
      body: { vendorCode, data },
    });

    if (response?.code === this.HTTP_STATUS.OK_200) return response?.json || {};
    else throw new Error(typeError(response, this.constructor.name));
  }

  /**
   * Добавление медиа контента в КТ
   * @description Метод позволяет загрузить и добавить один медиафайл за запрос, к НМ в КТ.
   *
   * Требования к медиафайлам:
   * Фото: минимальное разрешение – 700x900.
   * Максимально допустимое количество фото в КТ 30.
   * Допустимые форматы изображений - jpg и png.
   * Минимальный уровень качества изображения - 65%.
   * Видео: максимальный размер 50 мб. Форматы MOV, MP4.
   * Максимально допустимое количество видео в КТ 1.
   *
   * @param {string} vendorCode артикул продавца
   * @param {number} photoNumber номер медиафайла на загрузку. Начинать с 1.
   * Чтобы добавить фото к уже загруженным в НМ, номер медиафайла должен быть больше кол-ва загруженных в НМ медиафайлов.
   * @param {string} uploadfile медиафайл multipart/form-data
   * @returns {json|Error}
   */
  mediaFile({ vendorCode, photoNumber, uploadfile }) {
    const response = this.makeRequest({
      endpointObject: Methods.CONTENT.MEDIA.FILE,
      contentType: "multipart/form-data",
      params: {
        "X-Vendor-Code": vendorCode,
        "X-Photo-Number": photoNumber,
      },
      body: { uploadfile },
    });

    if (response?.code === this.HTTP_STATUS.OK_200) return response?.json || {};
    else throw new Error(typeError(response, this.constructor.name));
  }

  // CARDS Контент / Конфигуратор

  /**
   * Родительские категории товаров
   * @description С помощью данного метода можно получить список всех родительских категорий товаров.
   * @param {string} locale параметр выбора языка (ru, en, zh) значений поля name
   * @returns {json|Error}
   */
  categoryParent(locale = Locale.RU) {
    const response = this.makeRequest({
      endpointObject: Methods.CONTENT.OBJECT.PARENT_ALL,
      params: { locale },
    });

    if (response?.code === this.HTTP_STATUS.OK_200) {
      return response?.json || [];
    } else throw new Error(typeError(response, this.constructor.name));
  }

  /**
   * Список предметов
   * @description С помощью данного метода можно получить список всех доступных предметов,
   * родительских категорий преметов, и их идентификаторов.
   * @param {string} name поиск по наименованию предмета (Носки), поиск работает по подстроке, искать можно на любом из поддерживаемых языков
   * @param {string} locale параметр выбора языка (ru, en, zh) значений поля name
   * @param {number} parentID идентификатор родительской категории предмета
   * @param {number} limit идентификатор родительской категории предмета
   * @param {number} offset идентификатор родительской категории предмета
   * @returns {json|Error}
   */
  objectList(name, locale = Locale.RU, limit, offset, parentID) {
    const response = this.makeRequest({
      endpointObject: Methods.CONTENT.OBJECT.ALL,
      params: { name, locale, parentID, limit, offset },
    });

    if (response?.code === this.HTTP_STATUS.OK_200) {
      return response?.json || [];
    } else throw new Error(typeError(response, this.constructor.name));
  }

  /**
   * Характеристики предмета
   * @description Получение списка характеристик предмета по его ID
   * @param {number} subjectId идентификатор предмета
   * @param {string} locale параметр выбора языка (ru, en, zh) значений поля name
   * @returns {json|Error}
   */
  charcsObject(subjectId, locale = Locale.RU) {
    const response = this.makeRequest({
      endpointObject: Methods.CONTENT.OBJECT.CHARCS_OBJECT,
      endpoint: Methods.CONTENT.OBJECT.CHARCS_OBJECT.name.replace(
        "%SUBJECT_ID%",
        String(subjectId)
      ),
      params: { locale },
    });

    if (response?.code === this.HTTP_STATUS.OK_200) {
      return response?.json || [];
    } else throw new Error(typeError(response, this.constructor.name));
  }

  /**
   * Цвет
   * @description Получение значения характеристики цвет.
   * @param {string} locale параметр выбора языка (ru, en, zh) значений полей subjectName, name
   * @returns {json|Error}
   */
