  /**
   * Список документов
   * @returns {json|Error}
   */
  news({ from, fromID }) {

    const result = [];

    do {
      const response = this.makeRequest({
        endpointObject: Methods.COMMON.NEWS,
        params: {
          from,
          fromID,
        },
      });

      if (response.code === this.HTTP_STATUS.OK_200) {
        const main = response.json;
        if (!main) break;

        const lenght = main?.length;

        result.push(...main);
        console.log(`Получено: ${lenght} всего: ${result.length}`);

        if (lenght < 100) break;
        const dateStr = main[lenght - 1]?.date.split("T")[0];
        // разбиваем на числа
        const [year, month, day] = dateStr.split("-").map(Number);
        // создаём объект Date (месяцы в JS — 0-indexed)
        const dateObj = new Date(year, month - 1, day);
        // прибавляем один день
        dateObj.setDate(dateObj.getDate() + 1);
        // приводим обратно к строке "YYYY-MM-DD"
        from = dateObj.toISOString().slice(0, 10);
      }
    } while (true);
    return result;
  }
}

