  /**
   * Получить информацию по сборочным заданиям
   * @param {number} [limit] параметр пагинации, устанавливает предельное количество возвращаемых данных max 1000
   * @param {number} [next] параметр пагинации, устанавливает значение, с которого надо получить следующий пакет данных
   * @param {number|string} [dateFrom] дата начала периода в формате Unix timestamp или "2023-01-01"
   * @param {number|string} [dateTo] дата конца периода в формате Unix timestamp или "2023-01-01"
   * @returns {json|number|Error} Returns the retrieved data, or -1 if there is an error
   */
  ordersFbs({ limit = 1000, next = 0, dateFrom, dateTo }) {
    const result = [];
    const MAX_LIMIT = 1000;
    const pageLimit = Math.min(limit, MAX_LIMIT);

    // this.ping();

    while (true) {
      var response = this.makeRequest({
        endpointObject: Methods.MARKETPLACE.ORDERS_FBS.LIST,
        params: {
          limit: pageLimit,
          next,
          dateFrom:
            typeof dateFrom === "string"
              ? unixTimestamp(dateFrom)
              : typeof dateFrom === "number"
                ? dateFrom
                : null,
          dateTo:
            typeof dateTo === "string"
              ? unixTimestamp(dateTo)
              : typeof dateTo === "number"
                ? dateTo
                : null,
        },
      });

      if (response.code === this.HTTP_STATUS.OK_200) {
        const main = response.json;
        if (!main) break;

        const len = main.orders.length;

        result.push(...main.orders);
        console.log(`Получено: ${len}, всего: ${result.length}`);

        next = main?.next;
        if (len < pageLimit || !next) {
          break;
        }
      }
    }

    return result;
  }

