    if (response.code === this.HTTP_STATUS.CREATED_201) return response.json;
    else throw new Error(typeError(response, this.constructor.name));
  }

  /**
   * Обновить склад
   * @param {number} passId ID пропуска
   * @param {ItemPass} pass данные пропуска
   * @returns {string|Error} OK в сдучае успеха
   */
  warehousesPassesUpdate({ passId, pass }) {
    const response = this.makeRequest({
      endpointObject: Methods.MARKETPLACE.PASSES.UPDATE,
      endpoint: Methods.MARKETPLACE.PASSES.UPDATE.name.replace(
        "%PASS_ID%",
        passId,
      ),
      body: pass,
    });

    if (response.code === this.HTTP_STATUS.NO_CONTENT_204) return "OK";
    else throw new Error(typeError(response, this.constructor.name));
  }

  /**
   * Удалить склад продавца
   * @param {number} passId ID пропуска
   * @returns {string|Error} OK в сдучае успеха
   */
  warehousesPassesDelete({ passId }) {
    const response = this.makeRequest({
      endpointObject: Methods.MARKETPLACE.PASSES.DELETE,
      endpoint: Methods.MARKETPLACE.PASSES.DELETE.name.replace(
        "%PASS_ID%",
        passId,
      ),
    });

    if (response.code === this.HTTP_STATUS.NO_CONTENT_204) return "OK";
    else throw new Error(typeError(response, this.constructor.name));
  }
}

