// Оптимизированный индекс для быстрого поиска по подстроке
// Ключи отсортированы по длине (от длинных к коротким) для приоритета специфичных совпадений
const warehousesDistrictIndex = (() => {
  const entries = Object.entries(warehousesDistrictMapping);
  // Сортируем по длине ключа (от длинных к коротким), затем по алфавиту
  entries.sort((a, b) => {
    const lenDiff = b[0].length - a[0].length;
    return lenDiff !== 0 ? lenDiff : a[0].localeCompare(b[0], "ru");
  });
  return entries;
})();

/**
 * Быстрый поиск района склада по названию (поиск по подстроке)
 * @param {string} warehouseName - название склада для поиска
 * @returns {string|null} название района или null если не найдено
 */
function findWarehouseDistrict(warehouseName) {
  if (!warehouseName) return null;
  const normalizedName = warehouseName.toLowerCase().trim();
  // Проверяем точное совпадение сначала (O(1))
  if (warehousesDistrictMapping[normalizedName]) {
    return warehousesDistrictMapping[normalizedName];
  }
  // Поиск по подстроке - проверяем от длинных ключей к коротким
  for (const [key, district] of warehousesDistrictIndex) {
    if (normalizedName.includes(key)) {
      return district;
    }
  }
  return null;
}

