   */
  filterObjectArrayAboveZero(objArray, filterKeysAboveZero) {
    return objArray.filter((obj) =>
      filterKeysAboveZero.some((key) => obj[key] > 0),
    );
  }

  /**
   * Formats a given date value based on the specified format.
   *
   * @param {string} key - The key used to determine the format.
   * @param {string} value - The date value to be formatted.
   * @param {number} format - The format code indicating the desired format.
   * @return {string|Date} The formatted date value or an empty string if the value is "0001-01-01T00:00:00".
   */
  dateFormat(key, value, format) {
    if (!value || value === "0001-01-01T00:00:00") return null;
    if (format === 0) return new Date(value);

    if (format === 1) {
      ["lastChangeDate", "date"].includes(key)
        ? (value = dateStrToFormatDate(value, "yyyy-MM-dd HH:mm:ss"))
        : (value = dateStrToFormatDate(value, "yyyy-MM-dd"));
      return value;
    }

    if (format === 2) {
      ["lastChangeDate", "order_dt", "sale_dt"].includes(key) &&
      !value.includes("T00:00:00Z")
        ? (value = dateStrToFormatDate(value, "yyyy-MM-dd HH:mm:ss"))
        : ["rr_dt"].includes(key) && value.includes("T")
          ? (value = dateStrToFormatDate(value, "yyyy-MM-dd HH:mm:ss"))
          : (value = dateStrToFormatDate(value, "yyyy-MM-dd"));
      return value;
    }

    if (format === 3) return value?.replace(/[TZ]/gi, " ").split(" ")[0];
    if (format === 4) return dateStrToFormatDate(value, "yyyy-MM-dd");
    if (format === 5)
      return dateStrToFormatDate(value, "yyyy-MM-dd'T'HH:mm:ss");
    if (format === 6) return new Date(value).toISOString();
    if (format === 7)
      ["lastChangeDate"].includes(key)
        ? (value = dateStrToFormatDate(value, "yyyy-MM-dd HH:mm:ss"))
        : (value = dateStrToFormatDate(value, "yyyy-MM-dd"));
    if (format === 8) value = dateStrToFormatDate(value, "yyyy-MM-dd");
    return value;
  }

