   *
   * @param {number} num - The number to be rounded.
   * @param {number} digits - The number of decimal places to round to.
   * @return {string} The rounded number as a string.
   */
  bankRound(num, digits = 3) {
    const multiplier = Math.pow(10, digits);
    let result = Math.round(num * multiplier) / multiplier;

    // Округляем до десятых, если последний знак после округления 5
    if (result.toFixed(digits).slice(-1) == 5) {
      result = Math.round(result / 0.1) * 0.1;
    }

    return result.toFixed(digits);
  }

