      const row = new Array(keys.length);

      // Предварительная обработка специальных полей для метода orders
      if (methodName === "orders") {
        this.preprocessOrdersItem(item, warehousesMapping);
      }

      // Предварительная обработка специальных полей для метода sales
      if (methodName === "sales") {
        this.preprocessSalesItem(item);
      }

      // Предварительная обработка специальных полей для метода reportDetailByPeriod
      if (methodName === "reportDetailByPeriod") {
        this.preprocessReportItem(item, options);
      }

      // Заполняем строку данными
      for (let j = 0; j < keys.length; j++) {
        const key = keys[j];
        let value = item?.[key];

        // Форматирование дат
        if (dateKeys.has(key)) {
          value = this.dateFormat(key, value, dateFormatType);
        }

        row[j] = value;
      }

      data[i] = row;
    }

    return data;
  }

  /**
   * Проверяет, требует ли ключ специальной обработки
   */
  requiresSpecialProcessing(key, methodName) {
    const specialKeysByMethod = {
      orders: [
        "warehouseType",
        "priceWithDisc",
        "countryName",
        "oblastOkrugName",
        "regionName",
        "quantityRows",
        "quantityWoCancel",
        "totalPriceWoCancel",
        "priceWithDiscWoCancel",
        "finishedPriceWoCancel",
        "date",
      ],
      sales: ["warehouseType", "quantityRows", "quantityWoReturns", "date"],
      reportDetailByPeriod: [
        "doc_type_name",
        "supplier_oper_name",
        "gi_id",
        "sticker_id",
        "currency_name",
        "site_country",
        "create_dt",
        "order_dt",
        "sale_dt",
      ],
    };

    return specialKeysByMethod[methodName]?.includes(key) || false;
  }

  /**
   * Предварительная обработка элемента для метода orders
   */
  preprocessOrdersItem(item, warehousesMapping) {
    // if (
    //   [
    //     "d1.130c3863b55748e7a2ac2ccf57567cf9.2.0",
    //     "dn.re4b67f8e861043a1be22a2e8ae0c301d.0.0",
    //     "dQ.i35f858051a24923d9650d5841ae54528.0.0",
    //     "d2.1fa4ce4fcf3149438be81f45218fb1e0.0.0",
    //     "dg.i53b9fd72aed3a409a977f4534e0bb5f4.0.0",
    //     "dK.ief3f40ee1603ff5a40b9f66c5d210bf1.0.0",
    //     "dn.rc2476de576604d8e8ca84779dc977bc7.0.0",
    //     "d2.i2d0e2027b256201e1eaabec027c23e71.0.0",
    //     "dp.i38b88c3ab435c6b4e48a5938260ce6b7.0.0",
    //   ].includes(item.srid)
    // ) {
    //   console.log("warehouseType", item.warehouseType);
    //   console.log(item);
    // }

    // Обработка warehouseType
    // if (item.warehouseType) {
    item.warehouseType =
      CONFIG.methods.statistica.warehousesType[item.warehouseType] ||
      item.warehouseType;
    // }

    // Обработка priceWithDisc для совместимости
    if (!item.priceWithDisc) {
      item.priceWithDisc =
        this.bankRound(item.totalPrice * (1 - item.discountPercent / 100)) * 1;
    }

    // Исправление регистра
    if (item.countryName) {
      item.countryName = capitalizeFirstLetter(item.countryName);
    }
    if (item.oblastOkrugName) {
      item.oblastOkrugName = capitalizeFirstLetter(item.oblastOkrugName);
    }
    if (item.regionName) {
      item.regionName = capitalizeFirstLetter(item.regionName);
    }

    if (warehousesMapping) {
      item.oblastOkrugName =
        FederalDistricts[item.oblastOkrugName] || item.oblastOkrugName;
      // ||
      // item.countryName;

      const warehouseName_ = item.warehouseName.toLowerCase();
      // .replace(" мп", "")
      // .replace("сц ", "")
      // .trim();

      // используем все склады и виртуальные быстрый поиск по слову
      // Сначала проверяем в warehousesMapping (динамические данные), затем в warehousesDistrictMapping (статические)
      item.warehouseDistrict =
        warehousesMapping[warehouseName_] ||
        findWarehouseDistrict(warehouseName_) ||
        (warehouseName_.includes("виртуальный") ? item.oblastOkrugName : null);

      // используем все склады
      // item.warehouseDistrict =
      // warehousesMapping[warehouseName_] ||
      // warehouseName_.includes("виртуальный")
      //   ? item.oblastOkrugName
      //   : null;
      // токлько ск
      // item.warehouseDistrict = warehousesMapping[warehouseName_];

      item.isLocalization =
        item.oblastOkrugName === item.warehouseDistrict ? 1 : null;
      //   ||
      // warehouseName_.includes("виртуальный")
      //   ? 1
      //   : 0;
    } else {
      item.oblastOkrugName =
        FederalDistricts[item.oblastOkrugName] || item.oblastOkrugName;
    }

    // if (item?.isSupply)
    item.isSupply = item?.isSupply ? "Да" : "Нет";
    // if (item?.isRealization)
    item.isRealization = item?.isRealization ? "Да" : "Нет";

    // Количество строк
    item.quantityRows = 1;

    const cancel_date = item.cancelDate;
    item.isCancel = item?.isCancel ? "Да" : "Нет";

    // Количество без отмен
    // item.quantityWoCancel = cancel_date === "0001-01-01T00:00:00" ? 1 : 0;

    // Обработка цен без отмен
    if (cancel_date !== "0001-01-01T00:00:00") {
      item.totalPriceWoCancel = -1 * item.totalPrice;
      item.priceWithDiscWoCancel = -1 * item.priceWithDisc;
      item.finishedPriceWoCancel = -1 * item.finishedPrice;
      item.quantityWoCancel = 0;
    } else {
      item.quantityWoCancel = 1;
    }

    // Обработка даты
    if (item.date) {
      item.hour = new Date(item.date).getHours();
      if (item?.croppedDate) item.croppedDate = dateStrToFormatDate(item.date);
    }
  }

  /**
   * Предварительная обработка элемента для метода sales
   */
  preprocessSalesItem(item) {
    // Обработка warehouseType
    if (item.warehouseType) {
      item.warehouseType =
        CONFIG.methods.statistica.warehousesType[item.warehouseType] ||
        item.warehouseType;
    }

    // Исправление регистра
    if (item.countryName) {
      item.countryName = capitalizeFirstLetter(item.countryName);
    }
    if (item.oblastOkrugName) {
      item.oblastOkrugName = capitalizeFirstLetter(item.oblastOkrugName);
    }
    if (item.regionName) {
      item.regionName = capitalizeFirstLetter(item.regionName);
    }

    if (item.oblastOkrugName) {
      item.oblastOkrugName =
        FederalDistricts[item.oblastOkrugName] || item.oblastOkrugName;
    }

    if (item?.isSupply) item.isSupply = item?.isSupply ? "Да" : "Нет";

    if (item?.isRealization)
      item.isRealization = item?.isRealization ? "Да" : "Нет";

    // Количество всего
    item.quantityRows = 1;

    // Количество без возвратов
    const sale_id = item?.saleID;
    if (sale_id) {
      item.quantityWoReturns = sale_id.startsWith("S")
        ? 1
        : sale_id.startsWith("R")
          ? -1
          : 0;
    }

    // Обработка даты
    if (item.date) {
      item.hour = new Date(item.date).getHours();
      if (item?.croppedDate) item.croppedDate = dateStrToFormatDate(item.date);
    }
  }

  /**
   * Предварительная обработка элемента для метода reportDetailByPeriod
   */
  preprocessReportItem(item, { returnSignConversion, logisticSignConversion }) {
    const document_type = item?.doc_type_name;
    const operation_name = item?.supplier_oper_name;

    // Исправление регистра
    if (document_type) {
      item.doc_type_name = capitalizeFirstLetter(document_type);
    }
    if (operation_name) {
      item.supplier_oper_name = capitalizeFirstLetter(operation_name);
    }

    // Номер поставки и стикер
    item.gi_id = !item?.gi_id || item?.gi_id === "0" ? null : item?.gi_id;
    item.sticker_id =
      !item?.sticker_id || item?.sticker_id === "0" ? null : item?.sticker_id;

    // Исправление знака у возвратов
    if (returnSignConversion) {
      if (document_type?.toLowerCase() === "возврат") {
        item.quantity = -1 * item?.quantity;
        item.retail_price = -1 * item?.retail_price;
        item.retail_amount = -1 * item?.retail_amount;
        item.retail_price_withdisc_rub = -1 * item?.retail_price_withdisc_rub;
        item.ppvz_sales_commission = -1 * item?.ppvz_sales_commission;
        item.ppvz_for_pay = -1 * item?.ppvz_for_pay;
        item.ppvz_reward = -1 * item?.ppvz_reward;
        item.ppvz_vw = -1 * item?.ppvz_vw;
        item.ppvz_vw_nds = -1 * item?.ppvz_vw_nds;
      }
    }

    // Исправление знака у логистики сторно
    if (logisticSignConversion) {
      if (operation_name?.toLowerCase() === "логистика сторно") {
        item.delivery_rub = -1 * item?.delivery_rub;
        item.delivery_amount = -1 * item?.delivery_amount;
      }
    }

    // Исправление процентных значений
    item = fixPercentValues(item);

    // Заменяем 0 и "0" на null
    item = normalizeZeroFields(item);

    // Исправление валюты
    if (item?.currency_name === "руб") {
      item.currency_name = "RUB";
    }

    // Исправление страны
    if (item?.site_country in CountriesEnum) {
      item.site_country = CountriesEnum[item.site_country];
    }

    // Дата формирования отчёта
    if (!item?.create_dt) {
      item.create_dt = getNextMonday(item?.rr_dt);
    }

    // Очистка дат для определенных операций
    if (!["Продажа", "Логистика", "Возврат"].includes(operation_name)) {
      item.order_dt = null;
      item.sale_dt = null;
    }
  }

  /**
   * Остатки по складам - ОПТИМИЗИРОВАННАЯ ВЕРСИЯ
   * @description Данные обновляются раз в сутки (точное время отображается в поле lastChangeDate).
   * Можно получить данные только на момент запроса к API.
   * lastChangeDate: Дата и время обновления информации в сервисе. Поле соответствует параметру dateFrom в запросе.
   * Если часовой пояс не указан, то берется Московское время UTC+3.
   * @param {string} dateFrom дата <RFC3339>, можно передать дату или дату и временя, время можно указывать с точностью до секунд или миллисекунд.
   * Z в конце строки означает, что время передается в UTC-часовом поясе. При ее отсутствии время считается в часовом поясе МСК (UTC+3).
   * @param {object} header словарь необходимых заголовков, где ключ равен ключю в ответе API, а значение заголовку.
   * @returns {Array.<object|[any]>} массив объектов или массив массивов.
   */
  stocks({
    dateFrom = dateFrom2004,
    header,
    dateFormatType = 1,
    filterKey = "nmId",
    filterList = [],
    filterKeysAboveZero = [],
    json = false,
  }) {
    let response = null;
    let code;
    let result = [];
    let dateOffset = dateFrom;

    // this.ping();

    do {
      response = this.makeRequest({
        endpointObject: Methods.STATISTICS.STOCKS,
        params: {
          dateFrom: dateOffset,
        },
        fixJson: true,
      });

      code = response.code;

      if (code === this.HTTP_STATUS.OK_200) {
        const jsonString = response.json;
        const isErrorJson = response.isErrorJson;

        try {
          const len = jsonString.length;
          result = result.concat(jsonString);

          if (
            len > 0 &&
            isErrorJson &&
            // len >= this.MAX_REQUEST_LENGTH_STOCKS &&
            jsonString[len - 1].lastChangeDate !== dateOffset
          ) {
            dateOffset = jsonString[len - 1].lastChangeDate;
          } else {
            break;
          }
        } catch (error) {
          console.error("[STOCKS] Ошибка парсинга JSON:", error.message);
          console.error("[STOCKS] Проблемный JSON:", jsonString);
        }
      }
    } while (!this.EXIT_STATES.includes(code));

    debugLog("Ответ:", result);

    if (result) {
      debugSaveFileToDrive(`wbStocks_${Date.now()}`, result);

      if (json) return result;
      if (filterList.length > 0)
        result = this.filterObjectArrayByValue(result, filterKey, filterList);
      if (filterKeysAboveZero.length > 0)
        result = this.filterObjectArrayAboveZero(result, filterKeysAboveZero);

      return this.processResult(
        result,
        header || CONFIG.methods.statistica.stocks.header,
        dateFormatType,
        "stocks",
      );
    } else return -1;
  }

