  /**
   * Отчет о продажах по реализации - ОПТИМИЗИРОВАННАЯ ВЕРСИЯ
   * @description В отчете доступны данные за последние 3 месяца. В случае отсутствия данных за указанный период метод вернет null.
   * @param {string} dateFrom – дата <RFC3339>, можно передать дату или дату и временя, время можно указывать с точностью до секунд или миллисекунд.
   * Z в конце строки означает, что время передается в UTC-часовом поясе. При ее отсутствии время считается в часовом поясе МСК (UTC+3).
   * @param {string} dateTo – конечная дата отчета.
   * @param {number} limit – максимальное количество строк отчета, возвращаемых методом. Не может быть более 100 000.
   * @param {number} rrdid – уникальный идентификатор строки отчета. Необходим для получения отчета частями.
   * Загрузку отчета нужно начинать с rrdid = 0, и при последующих вызовах API передавать максимальное значение rrdid полученное в результате предыдущего вызова.
   * Для загрузки одного отчета может понадобится вызывать API до тех пор, пока количество возвращаемых строк не станет равным нулю.
   * @param {ReportDetailByPeriod} period – периодичность отчёта: weekly — еженедельный, daily — ежедневный.
   * @param {object} header – словарь необходимых заголовков, где ключ равен ключю в ответе API, а значение заголовку.
   * @returns {Array.<object>|[any]} массив объектов или массив массивов.
   */
  reportDetailByPeriod({
    dateFrom,
    dateTo,
    limit = 30000,
    rrdid,
    period = ReportDetailByPeriod.WEEKLY,
    header,
    dateFormatType = 2,
    json = false,
    filterKey = "nm_id",
    filterList = [],
    filterKeysAboveZero = [],
    returnSignConversion = true,
    logisticSignConversion = true,
    excludeRefund = false,
    excludeOperationNames = [],
  }) {
    let result = [];

    const MAX_LIMIT = 30000;
    const pageLimit = Math.min(limit, MAX_LIMIT);
    const isWeeklyReport = isWeeklyPeriod(period);

    dateFrom =
      dateFrom && isWeeklyReport
        ? getPreviousSunday(dateFrom)
        : dateFrom || subtractDays(1);
    // Исправлено: если dateTo явно передан, используем его как есть (не заменяем на getPreviousSunday(subtractDays(0)))
    // Это позволяет получить только прошлую неделю, передав dateTo как воскресенье прошлой недели
    dateTo =
      isWeeklyReport && !dateTo
        ? getPreviousSunday(subtractDays(0))
        : dateTo
          ? dateTo
          : subtractDays(0);

    if (new Date(dateTo) < new Date("2024-01-29")) {
      const requestError = {
        name: "RequestError",
        message: `Получить данные можно с 2024-01-29, передано ${dateTo}, измените период.`,
      };
      throw new Error(typeError(requestError, this.constructor.name));
    }

    const dates = isWeeklyReport
      ? getWeeksArray(dateFrom, dateTo)
      : [[dateFrom, dateTo]];

    console.log(
      `Период: ${period} диапазон дат:\n${JSON.stringify(dates, null, 2)}`,
    );

    // this.ping();

    dates.forEach(([dateFrom, dateTo]) => {
      rrdid = 0;

      if (new Date(dateFrom) <= new Date("2024-01-28")) {
        dateFrom = "2024-01-29";
      }

      while (true) {
        var response = this.makeRequest({
          endpointObject: Methods.STATISTICS.REPORT_DETAIL_BY_PERIOD,
          params: { dateFrom, dateTo, period, rrdid, limit: pageLimit },
          fixJson: true,
        });

        const code = response.code;

        if (
          [this.HTTP_STATUS.OK_200, this.HTTP_STATUS.NO_CONTENT_204].includes(
            code,
          )
        ) {
          const json = response.json || [];
          const len = json?.length;

          if (json === null || json === undefined || len === 0) break;

          const isErrorJson = response.isErrorJson;

          try {
            result = result.concat(json);

            console.log(
              `Запрос: from: ${dateFrom} to ${dateTo}, rrdid=${rrdid} строк: ${len} всего: ${result.length}`,
            );

            if (len > 0 && isErrorJson && json[len - 1]?.rrd_id !== rrdid) {
              rrdid = json[len - 1]?.rrd_id;
            } else {
              if (len < pageLimit) break;
              rrdid = json[len - 1]?.rrd_id;
            }

            Utilities.sleep(1000);
          } catch (error) {
            console.error(
              "[REPORT_DETAIL_BY_PERIOD] Ошибка парсинга JSON:",
              error.message,
            );
            console.error("[REPORT_DETAIL_BY_PERIOD] Проблемный JSON:", json);
          }
        } else throw new Error(typeError(response, this.constructor.name));
      }
    });

    debugLog("Ответ:", result);

    if (result) {
      debugSaveFileToDrive(
        `wbReportDetailByPeriod_${period}_${Date.now()}`,
        result,
      );

      if (json) return result;
      if (filterList.length > 0)
        result = this.filterObjectArrayByValue(result, filterKey, filterList);
      if (filterKeysAboveZero.length > 0)
        result = this.filterObjectArrayAboveZero(result, filterKeysAboveZero);

      // Удаление элементов с определенными operation_name
      if (
        excludeRefund &&
        excludeOperationNames &&
        Array.isArray(excludeOperationNames) &&
        excludeOperationNames.length > 0
      ) {
        result = result.filter((item) => {
          const operationName = item?.supplier_oper_name;
          return !excludeOperationNames.includes(operationName);
        });
      }

      return this.processResult(
        result,
        header || CONFIG.methods.statistica.reportDetailByPeriod.header,
        dateFormatType,
        "reportDetailByPeriod",
        {
          returnSignConversion,
          logisticSignConversion,
        },
      );
    } else return -1;
  }
}

