/**
 * Calculate the weeks array based on the start and end dates.
 *
 * @param {string} startDate - The start date.
 * @param {string} endDate - The end date.
 * @return {Array<Array<string>>} The weeks array.
 */
function getWeeksArray(startDate, endDate) {
  let weeksArray = [];

  startDate = new Date(startDate);
  endDate = new Date(endDate);

  let currentDate = startDate;
  currentDate.setHours(3, 0, 0, 0);
  currentDate.setDate(currentDate.getDate() - currentDate.getDay() + 1);

  while (currentDate <= endDate) {
    let nextSunday = new Date(currentDate);
    nextSunday.setDate(nextSunday.getDate() + 6);
    nextSunday.setHours(20, 59, 59, 999);
    weeksArray.push([
      new Date(currentDate).toISOString().slice(0, 10),
      new Date(nextSunday).toISOString().slice(0, 10),
    ]);
    currentDate.setDate(currentDate.getDate() + 7);
  }

  return weeksArray;
}

function isWeeklyPeriod(period) {
  return period === ReportDetailByPeriod.WEEKLY ? true : false;
}

/**
 * Calculate the previous Sunday based on the input date string, adjusting for Moscow time.
 *
 * @param {string} dateString - The input date string.
 * @return {string} The previous Sunday formatted as "YYYY-MM-DD".
 */
function getPreviousSunday(dateString) {
  const date = new Date(dateString);
  const dayOfWeek = date.getDay();
  const diff = (dayOfWeek + 7) % 7; // Calculate the difference in days to Sunday (0 is Sunday, 6 is Saturday)
  const previousSunday = new Date(date.getTime() - diff * 24 * 60 * 60 * 1000); // Subtract the difference in milliseconds
  // Adjust the time to Moscow time
  const moscowTimeOffset = 3 * 60 * 60 * 1000; // Moscow time is 3 hours ahead of UTC
  previousSunday.setTime(previousSunday.getTime() + moscowTimeOffset);
  // Format the previous Sunday as "YYYY-MM-DD"
  return previousSunday.toISOString().split("T")[0];
}

/**
 * Универсальная функция для проверки и исправления процентных значений в массиве объектов
 * Исправляет значения, которые больше 1, деля их на 100
 * @param {number} item - поле с процентами
 * @returns {number} Поле с исправленными данными
 */
function fixPercentValues(item) {
  const percentFields = [
    "commission_percent",
    "sale_percent",
    "product_discount_for_report",
    "supplier_promo",
    "ppvz_spp_prc",
    "ppvz_kvw_prc_base",
    "ppvz_kvw_prc",
    "sup_rating_prc_up",
    "acquiring_percent",
    "wibes_wb_discount_percent",
  ];

  for (const field of percentFields) {
    if (field in item) {
      const value = item[field];
      if (typeof value === "number" && value) {
        if (field === "acquiring_percent" || value > 1) {
          item[field] = value / 100;
        }
      }
    }
  }

  return item;
}

/**
 * Нормализует значения полей объекта, заменяя 0 и "0" на null
 * @param {Object} item - объект для обработки
 * @param {Set} fieldsSet - Set с именами полей для нормализации
 * @returns {Object} - обработанный объект
 */
function normalizeZeroFields(item, fieldsSet) {
  const zeroFieldsSet = [
    "quantity",
    "delivery_amount",
    "return_amount",
    "retail_price_withdisc_rub",
    "retail_amount",
    "ppvz_for_pay",
    "delivery_rub",
    "acceptance",
    "storage_fee",
    "penalty",
    "additional_payment",
    "deduction",
    "commission_percent",
    "acquiring_fee",
  ];

  fieldsSet = fieldsSet || zeroFieldsSet;

  if (!item || !fieldsSet) return item;

  // Проходим по всем полям в Set
  fieldsSet.forEach((field) => {
    if (
      item.hasOwnProperty(field) &&
      (item[field] === 0 || item[field] === "0")
    ) {
      item[field] = null;
    }
  });

  return item;
}

