  /**
   * История по остаткам, данные по товарам
   * @description Метод формирует набор данных об остатках по товарам.
   * Можно получить данные как по отдельным товарам, так и в рамках всего отчёта — если в запросе отсутствуют фильтры: nmIDs, subjectID, brandName, tagID.
   * Максимум 3 запроса в минуту на один аккаунт продавца.
   * @returns {object|Error}
   */
  stocsHystoryProducts({
    start,
    end,
    nmIDs = null, // Array of integers
    subjectID = null, // Integer
    brandName = null, // String
    tagID = null, // Integer
    skipDeletedNm = false,
    stockType = StocsReportStockType.ALL,
    field = StocsReportFields.stockCount,
    mode = DirectionMode.DESC,
    availabilityFilters = StocsReportAvailabilityFilters.ALL, // Array of strings (AvailabilityFilters)
    offset = 0,
    limit = 1000,
  }) {
    const result = [];
    const MAX_LIMIT = 1000;
    let currentOffset = offset;

    // Убеждаемся, что limit не превышает максимально допустимое значение
    const pageLimit = Math.min(limit, MAX_LIMIT);

    do {
      const response = this.makeRequest({
        endpointObject: Methods.ANALYTICS.STOCKS_REPORT.PRODUCTS,
        body: {
          nmIDs,
          subjectID,
          brandName,
          tagID,
          currentPeriod: { start, end },
          stockType,
          skipDeletedNm,
          orderBy: { field, mode },
          availabilityFilters,
          limit: pageLimit,
          offset: currentOffset,
        },
      });

      if (response.code === this.HTTP_STATUS.OK_200) {
        // Парсим ответ один раз
        const main = response.json || [];

        if (!main?.length) {
          break;
        }

        result.push(...main);

        console.log(
          `Получение записей: ${
            Math.floor(currentOffset / MAX_LIMIT) + 1
          } строк: ${main.length} всего: ${result.length}`,
        );

