function jamDateRange(days = 365, full = false) {
  /**
   * Returns a tuple of the date range from 365 days ago to the current date
   *
   * @param {boolean} full - Whether to include time in the date range
   * @returns {array} - An array of two dates in the format "YYYY-MM-DD" or "YYYY-MM-DD HH:MM:SS" if full is true
   */
  const currentDate = new Date();
  const startDate = new Date(
    currentDate.getTime() - days * 24 * 60 * 60 * 1000,
  );
  const endDate = new Date(currentDate.getTime() - 1000);

  if (full) {
    return [
      startDate.toISOString().replace("T", " ").replace("Z", ""),
      endDate.toISOString().replace("T", " ").replace("Z", ""),
    ];
  }

  return [
    startDate.toISOString().split("T")[0],
    endDate.toISOString().split("T")[0],
  ];
}

