class Advert extends _Client {
  constructor({ apiKey, requestLog }) {
    super({ apiKey, requestLog });
    this.baseUrl = Urls.ADVERT;
    this.ItemStatWhithDates = ItemStatWhithDates;
    this.ItemStatWhithInterval = ItemStatWhithInterval;
    this.ItemStatWhithCompaignId = ItemStatWhithCompaignId;
  }

  info() {
    const info = {
      description: "Реклама",
      link: "https://dev.wildberries.ru/",
      baseUrl: this.baseUrl,
      methods: this.getMethods(Advert),
    };
    return this.log(info);
  }

  useTestCircuitUrl() {
    this.baseUrl = Urls.ADVERT_TEST_CIRCUIT;
  }

  // ####################################################################################################################################
  // ПРОДВИЖЕНИЕ
  // ####################################################################################################################################

  /**
   * Списки кампаний
   * @description Метод позволяет получать списки кампаний, сгруппированных по типу и статусу, с информацией о дате последнего изменения кампании.
   * Допускается максимум 300 запросов в минуту.
   * @returns {Array.<json>|Error}
   */
  count() {
    // this.ping();

    let response = null;

    const requestConfig = {
      endpointObject: Methods.ADVERT.CAMPAIGNS.COUNT,
    };

    do {
      response = this.makeRequest(requestConfig);
    } while (
      ![this.HTTP_STATUS.OK_200, this.HTTP_STATUS.NO_CONTENT_204].includes(
        response.code,
      )
    );
    return response?.json ? response.json : [];
  }

  /**
   * Информация о кампаниях
   * @description Метод позволяет получать информацию о кампаниях.
   * Допускается максимум 300 запросов в минуту.
   * @param {Array.<number>} ids идентификаторы РК
   * @param {AdvStatusPK} statuses статус РК
   * @param {AdvPaymentTypes} payment_type типы оплаты
   * @returns {json|Error}
   */
  compaignsInfo({ ids, statuses, payment_type }) {
    let response = null;

    const requestConfig = {
      endpointObject: Methods.ADVERT.CAMPAIGNS.INFO,
      params: {
        ids: ids ? ids.join(",") : null,
        statuses: statuses ? statuses.join(",") : null,
        payment_type: payment_type || null,
      },
    };

    do {
      response = this.makeRequest(requestConfig);
    } while (![this.HTTP_STATUS.OK_200].includes(response.code));
    return response?.json ? response.json : [];
  }

  // ####################################################################################################################################
  // СОЗДАНИЕ КОМПАНИЙ
  // ####################################################################################################################################

  /**
   * Создать кампанию
   * Метод создаёт кампанию:
   * - с ручной ставкой для продвижения товаров в поиске и/или рекомендациях
   * - с единой ставкой для продвижения товаров одновременно в поиске и рекомендация
   * @param {string} name название кампании
   * @param {Array.<number>} nms артикулы товаров
   * @param {AdvBidTypes} bid_type тип ставки manual — ручная, unified — единая
   * @param {AdvPaymentTypes} payment_type cpm — за показы cpc — за клик
   * @param {Array.<AdvPlacementTypes>} [placement_types] только для кампании с ручной ставкой,
   * зоны показов:
   * - search — в поиске
   * - recommendations — в рекомендациях
   * @returns {json|Error}
   */
  campaignCreate({ name, nms, bid_type, payment_type, placement_types }) {
    if (!Array.isArray(nms) || nms.length > 50) {
      throw new ValidationError("Передайте массив артикулов WB, max. 50\n");
    }

    if (
      placement_types &&
      (!Array.isArray(placement_types) ||
        placement_types.length > 2 ||
        placement_types.some(
          (type) => !["search", "recommendations"].includes(type),
        ))
    ) {
      throw new ValidationError(
        `Передайте массив зон показов ["search", "recommendations"], max. 2\n`,
      );
    }

    const response = this.makeRequest({
      endpointObject: Methods.ADVERT.CREATE.CAMPAIGN,
      body: {
        name,
        nms,
        bid_type,
        payment_type,
        placement_types,
      },
    });

    if (response.code === this.HTTP_STATUS.OK_200)
      return response?.text ? Number(response.text) : null;
    return new Error(typeError(response, this.constructor.name));
  }

  // ####################################################################################################################################
  // УПРАВЛЕНИЕ КОМПАНИЯМИ
  // ####################################################################################################################################

  /**
   * Изменение ставок в кампаниях
   * В запросе укажите место размещения в параметре placement:
   * - combined — в поиске и рекомендациях для кампаний с единой ставкой
   * - search или recommendations — в поиске или рекомендациях для кампаний с ручной ставкой
   * @param {[]} bids
    "bids": [
      {
        "advert_id": 6348555,
        "nm_bids": [
          {
            "nm_id": 3462354,
            "bid_kopecks": 500,
            "placement": "recommendations",
          }
        ]
      }
    ]
   * @returns {string|Error} OK в сдучае успеха
   */
  bidsCompanyUpdate({ bids }) {
    if (!Array.isArray(bids)) {
      throw new ValidationError("Передайте массив ставок <= 50 items\n");
    }
    if (bids.length > 50) throw new ValidationError("<= 50 items\n");
    const response = this.makeRequest({
      endpointObject: Methods.ADVERT.ACTIVITY.BIDS_COMPANY_UPDATE,
      body: { bids },
    });

    if (response.code === this.HTTP_STATUS.NO_CONTENT_204) return "OK";
    return new Error(typeError(response, this.constructor.name));
  }

  /**
