  /**
   * Статистика кампании +
   * @description Метод отдаёт статистику кампании.
   * Допускается 1 запрос в минуту.
   * Данные вернутся для кампаний в статусе 7, 9 и 11.
   * @param {number} ids идентификаторы кампаний
   * @param {string} beginDate начало периода
   * @param {string} endDate конец периода
   * @returns {Array.<json>|Error}
   */
  statFull({ ids, beginDate, endDate }) {
    // Обработка ошибок API
    const handleApiError = (text) => {
      // Проверка интервала статистики
      const intervalMatch = text.match(/\d+ суток/);
      if (intervalMatch) {
        const interval = parseInt(intervalMatch[0]);
        throw new Error(
          `Возможный интервал получения статистики: ${interval} суток.\nУстановите его на листе "⚙️ Поддержка", запуските скрипт повторно.\n`,
        );
      }

      // Проверка некорректных параметров
      const invalidParamsPattern =
        /max date range 31 days|некорректные параметры запроса: нет кампаний с корректными интервалами|invalid request parameters: нет кампаний с корректными интервалами|Invalid Params: there are no companies with correct intervals|there are no statistics for this advertising period/i;

      if (invalidParamsPattern.test(text)) {
        console.error(
          JSON.stringify({ text, ids, beginDate, endDate }, null, 2),
        );
        return true;
      }
      return false;
    };

    let response;
    let code = null;

    const requestConfig = {
      endpointObject: Methods.ADVERT.STAT.FULL,
      params: {
        ids: Array.isArray(ids) ? ids.join(",") : ids,
        beginDate,
        endDate,
      },
    };

    do {
      response = this.makeRequest(requestConfig);
      code = response.code;

      // Обработка ошибки 400
      if (code === this.HTTP_STATUS.BAD_REQUEST_400) {
        const text = response.text;
        if (handleApiError(text)) {
          return -1; // Возвращаем -1 при ошибке API
        }
      }
    } while (!this.SUCCESS_STATES.includes(code));
    return !response ? -1 : !response?.json ? [] : response.json;
  }

