  /**
   * Список акций
   * @description Возвращает список акций с датами и временем проведения
   * Максимум 20 запросов в минуту.
   * @param {string} startDateTime начало периода, формат YYYY-MM-DDTHH:MM:SSZ
   * @param {string} endDateTime конец периода, формат YYYY-MM-DDTHH:MM:SSZ
   * @param {boolean} allPromo false — доступные для участия, true — все акции
   * @param {number} limit количество акций
   * @param {number} offset после какого элемента выдавать данные
   * @returns {json|Error}
   */
  list({
    startDateTime,
    endDateTime,
    allPromo = false,
    limit = 1000,
    offset = 0,
  }) {
    let result = [];

    while (true) {
      var response = this.makeRequest({
        endpointObject: Methods.CALENDAR_PROMO.LIST,
        params: {
          startDateTime,
          endDateTime,
          allPromo,
          limit,
          offset,
        },
      });

      if (response.code === this.HTTP_STATUS.OK_200) {
        const main = response.json || [];
        if (!main) break;

        const len = main?.length;
        result = result.concat(main);
        console.log(`Получено: ${len} всего: ${result.length}`);

        if (len < limit) {
          break;
        }

        offset += 1e3;
      } else if (response.code === this.HTTP_STATUS.UNPROCESSABLE_ENTITY_422)
        break;
    }
    return result;
  }

  /**
   * Детальная информация по акциям
   * @description Возвращает подробную информацию о выбранных акциях, min 1 - max 100
   * @param {Array.<number|string>} promotionIDs - ID акций, по которым нужно вернуть информацию
   * @returns {json|Error}
   */
  details(promotionIDs) {
    if (!Array.isArray(promotionIDs))
      // use helper
      throw new ValidationError(
        "promotionIDs должен быть массив ID акций (max. 100)\n"
      );
    if (promotionIDs.length === 0 || promotionIDs.length > 100)
      throw new ValidationError(
        "promotionIDs должен быть массив ID акций (min. 1 - max. 100)\n"
      );

    let code;
    let response;

    // console.log("PromotionIDs:", promotionIDs.length);

    const requestConfig = {
      endpointObject: Methods.CALENDAR_PROMO.DETAILS,
      params: {
        join: promotionIDs
          .map((el) => `promotionIDs=${el.toString()?.trim()}`)
          .join("&"),
      },
    };

    do {
      response = this.makeRequest(requestConfig);
      code = response.code;

      if (code === this.HTTP_STATUS.OK_200) {
        response = response.json || [];
        break;
      } else if (code === this.HTTP_STATUS.UNPROCESSABLE_ENTITY_422) break;
    } while (![this.HTTP_STATUS.OK_200].includes(code));
    return !response || response === "" ? [] : response;
  }

