    };

    do {
      response = this.makeRequest(requestConfig);
    } while (response.code !== this.HTTP_STATUS.OK_200);
    return response.json;
  }

  /**
   * Список поставок
   * @description Метод возвращает список поставок. По умолчанию возвращает последние 1000 поставок.
   * @returns {json|Error}
   */
  list({
    offset = 0,
    limit = 1000,
    from,
    till,
    type = SupplyDateType.CREATE_DATE,
    statusIDs = [],
  } = {}) {
    const result = [];
    const MAX_LIMIT = 1000;
    let currentOffset = offset;

    // Убеждаемся, что limit не превышает максимально допустимое значение
    const pageLimit = Math.min(limit, MAX_LIMIT);

    const datesBody = {
      statusIDs: statusIDs.length ? statusIDs : null,
    };

    if (from && till) {
      datesBody.dates = [
        {
          from,
          till,
          type,
        },
      ];
    }

    do {
      const response = this.makeRequest({
        endpointObject: Methods.SUPPLYS.INFO.LIST,
        params: {
          limit: pageLimit,
          offset: currentOffset,
        },
        body: datesBody,
      });

      if (response.code === this.HTTP_STATUS.OK_200) {
        // Парсим ответ один раз
        const main = response?.json || [];
        const len = main.length;

        if (len) result.push(...main);

        const page = Math.floor(currentOffset / pageLimit) + 1;
        console.log(`Запрос: ${page} строк: ${len} всего: ${result.length}`);

        // Проверяем условия выхода
        if (len < pageLimit) {
          break;
        }

        currentOffset += pageLimit;
      }
    } while (true);
    return result;
  }

  /**
   * Детали поставки
   * @returns {string|Error} OK в сдучае успеха
   */
  detail({ supplyOrOrderId, isPreorderID }) {
    let response = null;
    let result = {};
    do {
      response = this.makeRequest({
        endpointObject: Methods.SUPPLYS.INFO.DETAIL,
        endpoint: Methods.SUPPLYS.INFO.DETAIL.name.replace(
          "%SUPPLY_OR_ORDER_ID%",
          supplyOrOrderId,
        ),
        params: { isPreorderID },
      });

      if (response.code === this.HTTP_STATUS.OK_200) {
        return Object.assign(response.json || {}, {
          supplyID: isPreorderID ? null : supplyOrOrderId,
          preorderID: isPreorderID ? supplyOrOrderId : 0,
        });
        // break;
      }
    } while (response.code !== this.HTTP_STATUS.OK_200);

    // result;
  }

  /**
   * Товары поставки
   * @description Метод возвращает информацию о товарах в поставке.
   * @returns {json|Error}
   */
  goods({ supplyOrOrderId, isPreorderID, offset = 0, limit = 1000 } = {}) {
    const result = [];

    do {
      const response = this.makeRequest({
        endpointObject: Methods.SUPPLYS.INFO.GOODS,
        endpoint: Methods.SUPPLYS.INFO.GOODS.name.replace(
          "%SUPPLY_OR_ORDER_ID%",
          supplyOrOrderId,
        ),
        params: { isPreorderID, offset, limit },
      });

      if (response.code === this.HTTP_STATUS.OK_200) {
        const main = response.json;
        if (!main) break;

        const lenght = main?.length;
        console.log(`Получено: ${lenght} всего: ${result.length}`);

        if (lenght > 0) {
          for (const item of main) {
            result.push({
              supplyID: isPreorderID ? null : supplyOrOrderId,
              preorderID: isPreorderID ? supplyOrOrderId : 0,
              ...item,
            });
          }
        }

        if (lenght < limit) break;
        offset += limit;
      }
    } while (true);
    return result;
  }

  /**
   * Упаковка поставки
   * @returns {string|Error} OK в сдучае успеха
   */
  package(supplyId) {
    const response = this.makeRequest({
      endpointObject: Methods.SUPPLYS.INFO.PACKAGE,
      endpoint: Methods.SUPPLYS.INFO.PACKAGE.name.replace(
        "%SUPPLY_ID%",
        supplyId,
      ),
    });

    if (response.code === this.HTTP_STATUS.OK_200) return response.json || [];
    else throw new Error(typeError(response, this.constructor.name));
  }
}

