class RateLimiter {
  constructor(requestLog) {
    this.requestLog = requestLog || false;
    this.debug = false;
    this.endpointStats = {};
  }

  /**
   * Добавление состояния в статистику
   * @param {string} endpoint - тип эндпоинта
   * @param {number} stateCode - код состояния (например, 429)
   * @param {string} message - сообщение о состоянии
   */
  addState(endpoint, stateCode, message) {
    if (!endpoint) return;

    if (!this.endpointStats[endpoint]) {
      this.endpointStats[endpoint] = {
        requests: 0,
        ok: 0,
        lastTimestamp: 0,
        prevTimestamp: 0,
        burstCount: 0,
        burstTimestamp: 0,
        tokens: 1,
        burst: 1,
        interval: 1000,
        lastRefillTime: Date.now(),
        requestTimestamps: [],
        configPeriod: 60000,
        configLimit: 1,
        configInterval: 1000,
        configSplash: 1,
        remaining: undefined,
        retry: undefined,
        reset: undefined,
        states: {}, // Объект для сбора состояний
      };
    }

    if (!this.endpointStats[endpoint].states[stateCode]) {
      this.endpointStats[endpoint].states[stateCode] = {
        count: 0,
        message: "",
      };
    }

    this.endpointStats[endpoint].states[stateCode].count++;
    this.endpointStats[endpoint].states[stateCode].message = message;

    if (this.debug) {
      console.log(
        `State ${stateCode} added for ${endpoint}: ${message} (total: ${this.endpointStats[endpoint].states[stateCode].count})`
      );
    }
  }

  /**
   * Получение статистики состояний для конкретного эндпоинта
   * @param {string} endpoint - тип эндпоинта
   * @returns {Object} объект с состояниями
   */
  getStates(endpoint) {
    if (!endpoint || !this.endpointStats[endpoint]) return {};
    return this.endpointStats[endpoint].states || {};
  }

  /**
   * Получение статистики состояний для всех эндпоинтов
   * @returns {Object} объект с состояниями всех эндпоинтов
   */
  getAllStates() {
    const allStates = {};
    for (const endpoint in this.endpointStats) {
      if (this.endpointStats[endpoint].states) {
        allStates[endpoint] = this.endpointStats[endpoint].states;
      }
    }
    return allStates;
  }

  /**
   * Очистка статистики состояний для конкретного эндпоинта
   * @param {string} endpoint - тип эндпоинта
   */
  clearStates(endpoint) {
    if (endpoint && this.endpointStats[endpoint]) {
      this.endpointStats[endpoint].states = {};
    }
  }

  /**
   * Очистка статистики состояний для всех эндпоинтов
   */
  clearAllStates() {
    for (const endpoint in this.endpointStats) {
      if (this.endpointStats[endpoint].states) {
        this.endpointStats[endpoint].states = {};
      }
    }
  }

  /**
   * Ожидание токена и лимита (с учётом headers, если есть)
   * @param {string} endpoint - тип эндпоинта (common, statistics, etc.)
   * @param {number} period - период в миллисекундах
   * @param {number} limit - лимит запросов за период
   * @param {number} interval - интервал между запросами в миллисекундах
   * @param {number} splash - максимальный всплеск запросов
   */
  waitForTokenAndPeriod({ endpoint, period, limit, interval, splash }) {
    if (!endpoint) return true;
    if (!this.endpointStats) this.endpointStats = {};
    if (!this.endpointStats[endpoint]) {
      this.endpointStats[endpoint] = {
        requests: 0,
        ok: 0,
        lastTimestamp: 0,
        prevTimestamp: 0,
        burstCount: 0,
        burstTimestamp: 0,
        tokens: splash || 1,
        burst: splash || 1, // Конфигурационное значение - НЕ ЗАМЕНЯЕМ!
        interval: interval || 1000, // Конфигурационное значение - НЕ ЗАМЕНЯЕМ!
        lastRefillTime: Date.now(),
        requestTimestamps: [],
        // Конфигурационные значения для fallback
        configPeriod: period || 60000,
        configLimit: limit || 1,
        configInterval: interval || 1000,
        configSplash: splash || 1,
        // Динамические значения из заголовков
        remaining: undefined,
        retry: undefined,
        reset: undefined,
        states: {}, // Объект для сбора состояний
      };
    }
    const now = Date.now();
    const stats = this.endpointStats[endpoint];

    // === WB HEADERS-BASED LIMITING ===
    if (stats.remaining !== undefined && stats.remaining !== null) {
      if (stats.remaining > 0) {
        // Если сервер говорит что можно делать запросы — проверяем, не слишком ли мало осталось
        // Если remaining <= 1, добавляем небольшую задержку, чтобы не превысить лимит
        if (stats.remaining <= 1) {
          // Если remaining = 1, после запроса станет 0, нужно быть осторожным
          // Добавляем минимальную задержку, чтобы дать серверу время обновить лимиты
          const minDelay = stats.configInterval || 1000;
          if (this.requestLog)
            console.log(
              `WB headers: remaining=${stats.remaining} for ${endpoint}. Adding min delay ${minDelay}ms to avoid 429...`
            );
          Utilities.sleep(minDelay);
        } else {
          // Если remaining > 1, можно делать запрос, но все равно проверяем interval
          // if (this.requestLog)
          //   console.log(
          //     `WB headers allow requests for ${endpoint}. remaining: ${stats.remaining}`
          //   );
        }
        return // здесь - продолжаем проверку token bucket и period/limit
      } else if (stats.remaining <= 0) {
        // Если есть retry или reset — ждём по ним
        let waitTime = 0;
        if (stats.retry !== undefined && stats.retry > 0) {
          waitTime = stats.retry * 1000;
        } else if (stats.reset !== undefined && stats.reset > 0) {
          waitTime = stats.reset * 1000;
        } else {
          waitTime = 1000; // fallback
        }
        if (this.requestLog)
          console.log(
            `WB header limit reached for ${endpoint}. Waiting ${Math.ceil(
              waitTime / 1000
            )}s...`
          );
        Utilities.sleep(waitTime);
        // После ожидания обновляем remaining (может быть обновлен в syncAfterRequest)
        // Но здесь мы не знаем новое значение, поэтому продолжаем проверку token bucket
      }
    }

    // === PERIOD/LIMIT ===
    const burst = stats.configSplash; // Используем конфигурационное значение
    const refillInterval = stats.configInterval; // Используем конфигурационное значение
    const periodMs = stats.configPeriod; // Используем конфигурационное значение
    const requestLimit = stats.configLimit; // Используем конфигурационное значение

    stats.requestTimestamps = stats.requestTimestamps.filter(
      (ts) => now - ts < periodMs
    );
    if (stats.requestTimestamps.length >= requestLimit) {
      const oldest = stats.requestTimestamps[0];
      const waitTime = periodMs - (now - oldest);
      if (waitTime > 0) {
        if (this.requestLog)
          console.log(
            `Period limit reached for ${endpoint}. Waiting ${Math.ceil(
              waitTime
            )} ms...`
          );
        Utilities.sleep(waitTime);
        const now2 = Date.now();
        stats.requestTimestamps = stats.requestTimestamps.filter(
          (ts) => now2 - ts < periodMs
        );
      }
    }

    // === TOKEN BUCKET ===
    const elapsed = now - stats.lastRefillTime;
    if (elapsed > 0) {
      const tokensToAdd = Math.floor(elapsed / refillInterval);
      if (tokensToAdd > 0) {
        stats.tokens = Math.min(stats.tokens + tokensToAdd, burst);
        stats.lastRefillTime += tokensToAdd * refillInterval;
      }
    }
    if (stats.tokens <= 0) {
      const waitTime = stats.lastRefillTime + refillInterval - now;
      if (waitTime > 0) {
        if (this.requestLog)
          console.log(
            `Token bucket empty for ${endpoint}. Waiting ${Math.ceil(
              waitTime
            )} ms...`
          );
        Utilities.sleep(waitTime);
        const now2 = Date.now();
        const tokensToAdd2 = Math.floor(
          (now2 - stats.lastRefillTime) / refillInterval
        );
        if (tokensToAdd2 > 0) {
          stats.tokens = Math.min(stats.tokens + tokensToAdd2, burst);
          stats.lastRefillTime += tokensToAdd2 * refillInterval;
        }
      }
    }
    // Не инкрементируем burstCount и не добавляем метку времени!
  }

  /**
   * Синхронизация и статистика после реального запроса
   * @param {string} endpoint - тип эндпоинта (common, statistics, etc.)
   * @param {number} period - период в миллисекундах
   * @param {number} limit - лимит запросов за период
   * @param {number} interval - интервал между запросами в миллисекундах
   * @param {number} splash - максимальный всплеск запросов
   */
  syncAfterRequest({ endpoint, period, limit, interval, splash, headers }) {
    if (!endpoint) return;
    if (!this.endpointStats) this.endpointStats = {};
    if (!this.endpointStats[endpoint]) {
      this.endpointStats[endpoint] = {
        requests: 0,
        ok: 0,
        lastTimestamp: 0,
        prevTimestamp: 0,
        burstCount: 0,
        burstTimestamp: 0,
        tokens: splash || 1,
        burst: splash || 1, // Конфигурационное значение - НЕ ЗАМЕНЯЕМ!
        interval: interval || 1000, // Конфигурационное значение - НЕ ЗАМЕНЯЕМ!
        lastRefillTime: Date.now(),
        requestTimestamps: [],
        // Конфигурационные значения для fallback
        configPeriod: period || 60000,
        configLimit: limit || 1,
        configInterval: interval || 1000,
        configSplash: splash || 1,
        // Динамические значения из заголовков
        remaining: undefined,
        retry: undefined,
        reset: undefined,
        states: {}, // Объект для сбора состояний
      };
    }
    const stats = this.endpointStats[endpoint];

    // После всех ожиданий — уменьшаем токены на 1 (делаем запрос)
    if (stats.tokens > 0) {
      stats.tokens--;
      // burstCount для статистики — только для реального запроса
      stats.prevTimestamp = stats.lastTimestamp;
      stats.lastTimestamp = Date.now();
      stats.burstCount++;
      stats.burstTimestamp = stats.lastTimestamp;
      // === PERIOD/LIMIT ===
      stats.requestTimestamps.push(stats.lastTimestamp);
      // === INCREMENT REQUESTS ===
      stats.requests++;
    }

    // === СИНХРОНИЗАЦИЯ С HEADERS ===
    if (headers) {
      const getHeaderValue = (name) => {
        const value = headers[name];
        if (value === undefined || value === null) return null;
        // Если заголовок - массив, берем первый элемент
        const strValue = Array.isArray(value) ? value[0] : value;
        const numValue = Number(strValue);
        return isNaN(numValue) ? null : numValue;
      };

      // Обновляем только динамические значения из заголовков
      const remaining = getHeaderValue("x-ratelimit-remaining");
      if (remaining !== null) {
        stats.remaining = remaining;
        if (this.requestLog)
          console.log(`Updated remaining for ${endpoint}: ${remaining}`);
      }

      const retry = getHeaderValue("x-ratelimit-retry");
      if (retry !== null) stats.retry = retry;

      const reset = getHeaderValue("x-ratelimit-reset");
      if (reset !== null) stats.reset = reset;

      // НЕ обновляем burst, interval, period, limit - они остаются конфигурационными!
      // Заголовки могут быть кривыми или отсутствовать
    }
  }
}

