    509: "509 Bandwidth Limit Exceeded («исчерпана пропускная ширина канала»)",
    510: "510 Not Extended («не расширено»)",
    511: "511 Network Authentication Required («требуется сетевая аутентификация»)",
    520: "520 Unknown Error («неизвестная ошибка»)",
    521: "521 Web Server Is Down («веб-сервер не работает»)",
    522: "522 Connection Timed Out («соединение не отвечает»)",
    523: "523 Origin Is Unreachable («источник недоступен»)",
    524: "524 A Timeout Occurred («время ожидания истекло»)",
    525: "525 SSL Handshake Failed («квитирование SSL не удалось»)",
    526: "526 Invalid SSL Certificate («недействительный сертификат SSL»)",
  });

  /**
   * Фильтрует коды по диапазону
   * @private
   * @param {number} start - Начальный код
   * @param {number} [end] - Конечный код (не включительно)
   * @return {Object} Отфильтрованные коды
   */
  function filterCodes(start, end) {
    var result = {};
    for (var code in STATUS_CODES) {
      var numCode = parseInt(code, 10);
      if (end ? numCode >= start && numCode < end : numCode >= start) {
        result[code] = STATUS_CODES[code];
      }
    }
    return Object.freeze(result);
  }

  // Создаем категории кодов один раз при инициализации (оптимизация производительности)
  const SUCCESS = filterCodes(200, 300);
  const INFORMATIONAL = filterCodes(100, 200);
  const REDIRECTION = filterCodes(300, 400);
  const CLIENT_ERROR = filterCodes(400, 500);
  const SERVER_ERROR = filterCodes(500);

  // OTHER - все коды кроме успешных (200-299), создаем из уже существующих категорий
  const OTHER = Object.freeze(
    Object.assign({}, INFORMATIONAL, REDIRECTION, CLIENT_ERROR, SERVER_ERROR)
  );

  return {
    /** @type {Object<number, string>} Успешные ответы (200-299) */
    SUCCESS: SUCCESS,
    /** @type {Object<number, string>} Информационные ответы (100-199) */
    INFORMATIONAL: INFORMATIONAL,
    /** @type {Object<number, string>} Перенаправления (300-399) */
    REDIRECTION: REDIRECTION,
    /** @type {Object<number, string>} Клиентские ошибки (400-499) */
    CLIENT_ERROR: CLIENT_ERROR,
    /** @type {Object<number, string>} Серверные ошибки (500-599) */
    SERVER_ERROR: SERVER_ERROR,
    /** @type {Object<number, string>} Все коды кроме успешных (200-299) */
    OTHER: OTHER,
    /** @type {Object<string, number>} Константы для часто используемых кодов */
    STATUS: STATUS,
    /** @type {Object<number, string>} Полная карта всех кодов состояния */
    STATUS_CODES: STATUS_CODES,

    /**
     * Получить описание HTTP статус кода
     * @param {number} code - HTTP статус код
     * @returns {string} Описание кода или "Unknown code {code}"
     * @example
     * HTTPResponseStatusCodes.message(200); // "200 OK («хорошо»)"
     * HTTPResponseStatusCodes.message(404); // "404 Not Found («не найдено»)"
     */
    message: function (code) {
      return STATUS_CODES[code] || `Unknown code ${code}`;
    },

    /**
     * Проверить, является ли код успешным (200-299)
     * @param {number} code - HTTP статус код
     * @returns {boolean} true если код успешный
     * @example
     * HTTPResponseStatusCodes.isSuccess(200); // true
     * HTTPResponseStatusCodes.isSuccess(404); // false
     */
    isSuccess: function (code) {
      return !!SUCCESS[code];
    },

    /**
     * Проверить, является ли код ошибкой (400-599)
     * @param {number} code - HTTP статус код
     * @returns {boolean} true если код ошибки
     * @example
     * HTTPResponseStatusCodes.isError(404); // true
     * HTTPResponseStatusCodes.isError(200); // false
     */
    isError: function (code) {
      return !!(CLIENT_ERROR[code] || SERVER_ERROR[code]);
    },

    /**
     * Проверить, можно ли повторить запрос при данном коде
     * @param {number} code - HTTP статус код
     * @returns {boolean} true если запрос можно повторить
     * @description Retryable коды: 408, 429, 500, 502, 503, 504
     * @example
     * HTTPResponseStatusCodes.isRetryable(429); // true
     * HTTPResponseStatusCodes.isRetryable(404); // false
     */
    isRetryable: function (code) {
      return [408, 429, 500, 502, 503, 504].includes(code);
    },

    /**
     * Получить категорию кода
     * @param {number} code - HTTP статус код
     * @returns {string|null} Название категории или null если код неизвестен
     * @example
     * HTTPResponseStatusCodes.getCategory(200); // "SUCCESS"
     * HTTPResponseStatusCodes.getCategory(404); // "CLIENT_ERROR"
     * HTTPResponseStatusCodes.getCategory(500); // "SERVER_ERROR"
     */
    getCategory: function (code) {
      if (SUCCESS[code]) return "SUCCESS";
      if (INFORMATIONAL[code]) return "INFORMATIONAL";
      if (REDIRECTION[code]) return "REDIRECTION";
      if (CLIENT_ERROR[code]) return "CLIENT_ERROR";
      if (SERVER_ERROR[code]) return "SERVER_ERROR";
      return null;
    },

    /**
     * Проверить, является ли код клиентской ошибкой (400-499)
     * @param {number} code - HTTP статус код
     * @returns {boolean} true если клиентская ошибка
     */
    isClientError: function (code) {
      return !!CLIENT_ERROR[code];
    },

    /**
     * Проверить, является ли код серверной ошибкой (500-599)
     * @param {number} code - HTTP статус код
     * @returns {boolean} true если серверная ошибка
     */
    isServerError: function (code) {
      return !!SERVER_ERROR[code];
    },
  };
})();

