    });
  }
}

/**
 * Бюджет РК Run ++
 * @param {object} [options] параметры запроса
 * @param {Advert} advertApi объект класса Advert
 */
function advBudgetRun(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  const script = advBudgetRun.name;

  const {
    advertApi,
    runInfo,
    service = context?.service,
    api = true,
    raw,
    debug = context?.debug,
    setHead,
  } = options;

  const formats = CONFIG.formats;

  const updated = dateStrToFormatDate(new Date(), formats.datehhmm);

  const storage =
    context?.storage ||
    (service && setStorage({ service, serviceType: context?.serviceType })) ||
    null;

  const json = runInfo || storage.getProperty("advBudgetRunInfo");
  let { start, index, total, payload, funcName, updatedAtRange } = json;

  const runFunc = options?.runFunc || json?.runFunc;

  try {
    deleteTriggersWithName(script);

    const main = CONFIG.methods.advert;
    const sheet = setSheetNew(main.budget.sheet, main.sheetColor, ss);

    const { delayPerSecond } = calculateDelay({
      requestsPerSecond: 4,
    });

    const result = [];
    let count_response = 1;
    while (true) {
      // console.log(
      //   `Request >>> ${index + 1} | ${total - index - 1} / ${total} `
      // );

      const advert = payload.pop();
      if (!advert) break;

      const atvertId = advert[0];

      // console.log(`Request >>> ${atvertId}`);

      const response = advertApi.budget(atvertId);

      if (response && Object.keys(response).length)
        result.push([updated, ...advert, response?.total ?? 0]);

      if (count_response === 300) {
        index++;
        break;
      }

      Utilities.sleep(delayPerSecond);
      index++;
      count_response++;
    }

    if (result.length) {
      const lastRow = sheet.getLastRow();
      const fromRow = lastRow;
      addDataToSheet({
        fromRow,
        lastRow,
        result,
        sheet,
        api,
        raw,
        script,
        start,
        setHead,
        debug,
      });
    }

    if (index === total) {
      storage.deleteProperty("advBudgetRunInfo");

      if (funcName && funcName.length > 0)
        funcName.forEach((name, index) => createTriggerRun(name, index + 1));

      sortDataBySheet(sheet, 1);
      sheet.getRangeList(main.budget.rangeDate).setNumberFormat(formats.date);

      console.log(`Данные Бюджет по РК (new) загружены`);
      CONFIG.func.endScript({
        script: "advBudget",
        start,
        sheet,
        message: "Бюджет по РК получили",
        runFunc,
      });
    } else {
      storage.setProperty("advBudgetRunInfo", {
        start,
        index,
        total,
        payload,
        funcName,
        updatedAtRange,
        runFunc,
      });
      createTriggerRun(script, 1);
    }
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

/**
 * Пополнение бюджета активных компаний
 * @param {object} [options] параметры запроса
 * @param {Advert} advertApi объект класса Advert
 */
function advBudgetTopUp(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  const start = CONFIG.func.start();
  const script = advBudgetTopUp.name;

  try {
    const { advertApi, requestsPerSecond } = options;
    let { minBalance = 0, topUpBalance = 1000 } = options;
    const { delayPerSecond } = calculateDelay({
      requestsPerSecond: requestsPerSecond || 4,
    });

    const adv = CONFIG.methods.advert;
    const budget = adv.budgetTopUp;
    const sheet = setSheetNew(budget.sheet, adv.sheetColor, ss);
    setSheetHead(sheet, true);

    sheet.appendRow(budget.header);

    const balance = advertApi.balance();
    const balance_data = {};
    const cashbacks = balance?.cashbacks ? balance.cashbacks[0] : {};

    if (balance) {
      balance_data.balance = balance?.balance ?? 0;
      balance_data.net = balance?.net ?? 0;
      balance_data.bonus = balance?.bonus ?? 0;
      balance_data.cashback_sum = cashbacks?.sum ?? 0;
      balance_data.cashback_percent = cashbacks?.percent ?? 0;
    }

    console.log({ balance_data });

    if (balance_data.net === 0) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет денег на балансе",
        messageType: 2,
      });
    }

    options.keysToKeep = ["advertId", "name", "type"];
    const adverts = advListProperties(options, true);

    if (!adverts.length > 0) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const updated_at = dateStrToFormatDate(new Date(), CONFIG.formats.datehhmm);

    const result = [];
    minBalance = Number(minBalance);
    topUpBalance = Number(topUpBalance);

    for (const { advertId, name, type } of adverts) {
      if (balance_data.net < topUpBalance) {
        console.log(`Пополните баланс`);
        break;
      }

      const response = advertApi.budget(advertId);
      if (response && response.total <= minBalance) {
        console.log(`Баланс: ${balance_data.net}`);

        const updated = advertApi.budgetTopUp({ advertId, topUpBalance });

        result.push([
          updated_at,
          advertId,
          name,
          adv.typePK[type] || type,
          response.total,
          // total,
          topUpBalance + response.total,
          updated,
        ]);
        balance_data.net = balance_data.net - topUpBalance;
      }
      Utilities.sleep(delayPerSecond);
    }

    console.log(`Остаток баланса: ${balance_data.net}`);

    if (!result.length > 0)
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });

    sheet
      .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
      .setValues(result);

    sortDataBySheet(sheet, 2);

    CONFIG.func.endScript({
      script: "advBudget",
      start,
      sheet,
      message: "Обновили балансы РК",
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

/**
 * @typedef {{
 *   advertApi: Advert; // объект класса Advert
 *   startDate?: string;
 *   requestsPerSecond?: number; // запросов в секунду
 *   sheetName?: string; // название листа для вставки данных
 *   emptyCols?: boolean;
 * }} AdvertUpdHistoryOptions
 */

/**
 * Получение истории затрат по дням за период ++
 * @param {AdvertUpdHistoryOptions} [options] параметры запроса
 */
function advUpdHistory(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  const start = CONFIG.func.start();
  const script = advUpdHistory.name;

  try {
    const {
      advertApi,
      dateFrom,
      setDateStartFirst,
      sheetName,
      formulas = [],
      debug = context?.debug,
    } = options;

    let { emptyCols } = options;

    const adv = CONFIG.methods.advert;
    const main = adv.updHistory;
    const sheet = setSheetNew(sheetName || main.sheet, adv.sheetColor, ss);

    let headers = Object.values(main.header);

    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    setSheetHead(sheet, true);
    sheet.appendRow(headers);

    let firstDayOfCurrentMonth = new Date();
    firstDayOfCurrentMonth.setDate(1);
    firstDayOfCurrentMonth.setHours(0, 0, 0, 0);

    const startDate_ = dateFrom || firstDayOfCurrentMonth;

    const datetsStart = getStartDatesOfMonths(startDate_, setDateStartFirst);

    const { advertList: advListJson } = advListProperties(options);

    const keysToRemove = [
      "create",
      "change",
      "start",
      "end",
      "type",
      "status",
      "statusName",
      // "paymentType",
      "params",
      "autoParams",
      "nm_settings",
      "dailyBudget",
      "endTime",
      "createTime",
      "changeTime",
      "startTime",
    ];

    Object.keys(advListJson).forEach((key) => {
      const object = advListJson[key];
      keysToRemove.forEach((k) => {
        delete object[k];
      });
    });

    let response = [];
    if (datetsStart && datetsStart.length > 0) {
      const formats = CONFIG.formats;
      const checkStartDate_ = new Date(startDate_);
      const datesArray = [];

      for (const date of datetsStart) {
        const currentDate = new Date(date);
        let endOfMonthDate = new Date(
          currentDate.getFullYear(),
          currentDate.getMonth() + 1,
          0,
        );

        if (startDate_ && currentDate < checkStartDate_) continue;

        datesArray.push([
          dateStrToFormatDate(currentDate, formats.dateyyyy_MM_dd),
          dateStrToFormatDate(endOfMonthDate, formats.dateyyyy_MM_dd),
        ]);
      }

      if (debug) console.log({ datesArray });

      datesArray.forEach(([from, to]) => {
        response.push(
          ...advertApi.updHistory({
            from,
            to,
          }),
        );
      });

      debugLog("Ответ:", response);

      if (!response.length > 0)
        return CONFIG.func.endScript({
          script,
          start,
          message: "Нет данных",
          messageType: 2,
        });

      const result = response.map((day) => {
        const {
          updNum,
          updTime,
          updSum,
          advertId,
          advert_id,
          campName,
          advertType,
          paymentType,
          advertStatus,
          // currency,
        } = day;

        const advertId_ = advertId || advert_id;

        return [
          dateStrToFormatDate(updTime, formats.date),
          dateStrToFormatDate(updTime, formats.datehhmm),
          updNum,
          advertId_,
          campName,
          advListJson[advertId_]?.typeName || advertType,
          adv.statusPK[advertStatus] || advertStatus,
          updSum,
          paymentType,
          // currency,
        ];
      });

      debugLog("Обработанный:", result);

      // sheet
      //   .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
      //   .setValues(result);

      // addDataToSheet({
      addDataToSheetOptimized({
        fromRow: 0,
        lastRow: 1,
        result,
        sheet,
        api: true,
        raw: true,
        script,
        start,
        debug,
      });

      sheet.getRangeList(main.formatDateRange).setNumberFormat(formats.date);
      sheet
        .getRangeList(main.formatDateTimeRange)
        .setNumberFormat(formats.datehhmm);
      sortDataBySheet(sheet, 2);

      CONFIG.func.endScript({
        script,
        start,
        sheet,
        message: "Историю затрат РК по дням получили",
        emptyCols,
        runFunc: options?.runFunc,
      });
    } else {
      CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

