      formulas = [],
      emptyCols,
      debug = context?.debug,
    } = options;

    const adv = CONFIG.methods.advert;
    const advList = adv.listWithNmIds;
    const sheet = setSheetNew(sheetName || advList.sheet, adv.sheetColor, ss);

    setSheetHead(sheet, true);

    let headers = check ? advList.headerCheck : advList.header;
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    sheet.appendRow(headers);

    options.resultWhithNmIds = true;

    const { result } = advListProperties(options);

    debugLog("Ответ:", result);

    if (!result.length > 0) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    // Эффективное удаление дубликатов с подсчетом
    const seen = new Map();
    const duplicates = new Map();

    const uniqueArray = result.filter((subArray) => {
      // Создаем ключ из массива более эффективно
      const key = subArray.join("|");

      if (seen.has(key)) {
        const count = duplicates.get(key) || 1;
        duplicates.set(key, count + 1);
        return false; // Это дубликат
      } else {
        seen.set(key, true);
        return true; // Это уникальный элемент
      }
    });

    // Получаем только те дубликаты, которые встречаются больше 1 раза
    const actualDuplicates = Object.fromEntries(
      Array.from(duplicates.entries()).map(([key, count]) => [key, count]),
    );

    if (debug) console.log({ actualDuplicates });

    // const uniqueArray = Array.from(
    //   new Set(result.map((row) => row.join("|")))
    // ).map((key) => key.split("|"));

    debugLog("Обработанный:", uniqueArray);

    sheet
      .getRange(
        sheet.getLastRow() + 1,
        1,
        uniqueArray.length,
        uniqueArray[0].length,
      )
      .setValues(uniqueArray);

    //  sheet
    //   .getRange(
    //     sheet.getLastRow() + 1,
    //     1,
    //     result.length,
    //    result[0].length
    //   )
    //   .setValues(result);

    setVerticalAlignmentWrapStrategy(sheet);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Список РК с NM получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

/**
 * Retrieves a list of advertisement properties based on the provided options and JSON data. ++
 *
 * @param {Object} advertApi - the promotion API object
 * @param {Object} options - the options for retrieving the advertisement properties
 * @param {Object} json - a flag to indicate whether to return the result as JSON
 * @return {Array|Object} - an array of advertisement properties or a JSON object containing advertisement properties
 */
function advListProperties(
  options = context?.config?.getConfigForCurrentFunction(),
  json,
) {
  const {
    advertApi,
    dateFrom,
    dateTo,
    statusFilter,
    statuses = [],
    statusesExclude = [],
    typeFilter,
    types = [],
    typesExclude = [],
    advertIdsExclude = [],
    advertsInfoCount,
    resultWhithNmIds,
    paymentType,
    keysToKeep = ["advertId", "name", "type", "status", "startTime"],
    debug = context?.debug,
  } = options;

  if (statuses && !Array.isArray(statuses))
    throw new ValidationError("параметр statuses должен быть Array<number>\n");

  if (statusesExclude && !Array.isArray(statusesExclude))
    throw new ValidationError(
      "параметр statusesExclude должен быть Array<number>\n",
    );

  if (types && !Array.isArray(types))
    throw new ValidationError("Параметр types должен быть Array<number>\n");

  if (typesExclude && !Array.isArray(typesExclude))
    throw new ValidationError(
      "параметр typesExclude должен быть Array<number>\n",
    );

  if (advertIdsExclude && !Array.isArray(advertIdsExclude))
    throw new ValidationError(
      "Параметр advertIdsExclude должен быть Array<number>\n",
    );

  if (statuses.length > 0 && statusesExclude.length > 0)
    throw new ValidationError(
      "Укажите один из параметров: statuses (Array<number>) || statusesExclude (Array<number>)\n",
    );

  if (types.length > 0 && typesExclude.length > 0)
    throw new ValidationError(
      "Укажите один из параметров: types (Array<number>) || typesExclude (Array<number>)\n",
    );

  const adv = CONFIG.methods.advert;
  const lists = advertApi.count();

  const compains = [];
  const compainTypes = {};
  if (lists && lists.length) {
    for (let i = 0; i < lists.length; i++) {
      const { status, type, advert_list } = lists[i];

      if (
        (statusFilter && status !== statusFilter) ||
        (statuses.length > 0 && !statuses.includes(status)) ||
        (statusesExclude.length > 0 && statusesExclude.includes(status)) ||
        (typeFilter && type !== typeFilter) ||
        (types.length > 0 && types.includes(type)) ||
        (typesExclude.length > 0 && typesExclude.includes(type))
      )
        continue;

      for (const advert of advert_list) {
        const { advertId, changeTime } = advert;
        // if (new Date(changeTime) < new Date(dateFrom)) continue;
        if (advertIdsExclude.length > 0 && advertIdsExclude.includes(advertId))
          continue;
        // if (type === 9) auction.push(advertId);
        // else promotion.push(advertId);

        compainTypes[advertId] = type;
        compains.push(advertId);
      }
    }
  }

  const advertList = [];

  // chunkArray(compains, advertsInfoCount || 50).forEach((ids) => {
  //   const tmp = advertApi.compaignsInfo({ ids });

  //   tmp.forEach((item) => {
  //     item.type = item?.bid_type;
  //     delete item.bid_type;

  //     item.advertId = item.id;
  //     delete item.id;

  //     const ts = item.timestamps || {};

  //     item.createTime = ts?.created;
  //     item.startTime = ts?.started;
  //     item.changeTime = ts?.updated;
  //     item.endTime = ts?.deleted;
  //     delete item.timestamps;

  //     const st = item.settings || {};
  //     item.name = st?.name;
  //     item.paymentType = st?.payment_type;

  //     const nm_settings = item?.nm_settings || [];
  //     nm_settings.forEach((el) => {
  //       el.placements = st.placements;
  //     });

  //     delete item.settings;
  //   });
  //   advertList.push(...tmp);
  // });

  const tmp = advertApi.compaignsInfo({ statuses });

  tmp.forEach((item) => {
    item.type = item?.bid_type;
    delete item.bid_type;

    item.advertId = item.id;
    delete item.id;

    const ts = item.timestamps || {};

    item.createTime = ts?.created;
    item.startTime = ts?.started;
    item.changeTime = ts?.updated;
    item.endTime = ts?.deleted;
    delete item.timestamps;

    const st = item.settings || {};
    item.name = st?.name;
    item.paymentType = st?.payment_type;

    const nm_settings = item?.nm_settings || [];
    nm_settings.forEach((el) => {
      el.placements = st.placements;
    });

    delete item.settings;
    advertList.push(item);
  });

  const checkFrom_ = new Date(dateFrom);
  const checkTo_ = dateTo
    ? new Date(dateTo)
    : new Date(addDays(0, false, true));

  if (json) {
    let jsonResult = advertList;

    // debugSaveFileToDrive("CampaignsList", advertList);

    if (dateFrom)
      jsonResult = jsonResult.filter(
        ({ changeTime, createTime, startTime, endTime, status }) => {
          return (
            !endTime ||
            new Date(endTime) > checkFrom_ ||
            new Date(createTime) >= checkFrom_ ||
            new Date(changeTime) >= checkFrom_ ||
            new Date(startTime) >= checkFrom_
          );

          // if (options.onlyChangeTime)
          //   changeTime && new Date(changeTime) >= checkFrom_;
          // else createTime && new Date(createTime) >= checkFrom_;
        },
      );

    const filteredJsonResult = jsonResult.map(({ ...rest }) => {
      const filteredObject = {};
      keysToKeep.forEach((key) => {
        if (key in rest) {
          filteredObject[key] = rest[key];
        }
      });
      return filteredObject;
    });

    console.log("Total advertising companies >>>", filteredJsonResult.length);
    return filteredJsonResult;
  }

  const result = [];
  const resultNmIds = [];
  const advJsonSave = {};
  const relevantCampaigns = [];

  if (advertList.length) {
    for (const advert of advertList) {
      const {
        advertId,
        name,
        type,
        status,
        createTime,
        changeTime,
        startTime,
        endTime,
        paymentType,
      } = advert;

      // if (debug && advert) console.log(JSON.stringify(advert, null, 2));

      const change = new Date(changeTime);
      const start = startTime ? new Date(startTime) : null;
      const create = new Date(createTime);
      const end_ = new Date(endTime);

      // 1. Пропустить, если кампания определенно завершилась ДО начала запрашиваемого периода.
      // (т.е. есть дата окончания кампании, и она строго меньше начальной даты периода)
      if (checkFrom_ && end_ < checkFrom_) continue;
      // 2. Пропустить, если кампания определенно началась ПОСЛЕ окончания запрашиваемого периода.
      // (т.е. есть дата начала кампании, и она строго больше конечной даты периода)
      if (checkTo_ && start && start > checkTo_) continue;

      // console.log("Compain type >>>", compainTypes[advertId]);

      const typeName =
        adv.bidTypes[type] || adv.typePK[compainTypes[advertId]] || type;
      const statusName = adv.statusPK[status] || status;
      const end = endTime === "2100-01-01T00:00:00+03:00" ? "" : end_;

      advJsonSave[advertId] = {
        name,
        type,
        typeName,
        status,
        statusName,
        create,
        change,
        start,
        end: end || checkTo_,
      };

      relevantCampaigns.push(advert);

      if (!resultWhithNmIds) {
        result.push([
          advertId,
          name,
          typeName,
          statusName,
          create,
          change,
          start,
          end,
          null,
        ]);
      }

      if (resultWhithNmIds) {
        const commonParams = [
          advertId,
          name,
          typeName,
          statusName,
          create,
          change,
          start,
          end,
          AdvPaymentType[paymentType] || paymentType,
        ];

        const nmIds = processAdvertNmIdsNew(advert, commonParams, debug);
        resultNmIds.push(...nmIds);
      }
    }
  }

  const resultToReturn = resultWhithNmIds ? resultNmIds : result;
  console.log("Result count >>>>", resultToReturn?.length);
  return { result: resultToReturn, advertList: advJsonSave, relevantCampaigns };
}

// Вспомогательная функция для создания массива с нужным количеством null значений
const createNullArray = (count) => Array(count).fill(null);

// Вынесем обработку NmIds в отдельные функции по типам
const processNmIdsHandlers = {
  // Тип 8 - Автоматические кампании
  processType8: (params, commonParams, debug = false) => {
    const { autoParams } = params;
    const { carousel, recom, booster } = autoParams?.active || {};

    const placement = [
      carousel ? "Карточка товара" : null,
      recom ? "Рекомендации на главной" : null,
      booster ? "Ручная ставка" : null,
    ]
      .filter(Boolean)
      .join(", ");

    const resultNmIds = [];

    const nmCPM = autoParams?.nmCPM || [];
    const nms = autoParams?.nms || [];

    if (nmCPM.length > 0) {
      // Обработка nmCPM
      const enrichedNmCPM = autoParams.nmCPM.map((nm) => ({
        ...nm,
        placement,
      }));

      // if (debug) console.log("autoParams.nmCPM", enrichedNmCPM);

      enrichedNmCPM.forEach((item) => {
        resultNmIds.push([
          ...commonParams,
          item.nm,
          item.cpm || item.bid,
          ...createNullArray(2),
          item.placement,
          ...createNullArray(1),
        ]);
      });
    } else if (nmCPM.length === 0 && nms.length > 0) {
      // Обработка nms
      const enrichedNms = nms.map((nm) => ({
        nm,
        cpm: autoParams.cpm,
        placement,
      }));

      // if (debug) console.log("autoParams.nms", enrichedNms);

      enrichedNms.forEach((item) => {
        resultNmIds.push([
          ...commonParams,
          item.nm,
          item.cpm,
          ...createNullArray(2),
          item.placement,
          ...createNullArray(1),
        ]);
      });
    } else {
      // Если нет данных
      resultNmIds.push([
        ...commonParams,
        ...createNullArray(4),
        placement,
        ...createNullArray(1),
      ]);
    }

    return resultNmIds;
  },

  // Тип 9 - Поисковые кампании
  processType9: (params, commonParams, debug = false) => {
    const { nm_settings } = params;
    const resultNmIds = [];

    if (nm_settings?.length > 0) {
      if (debug) console.log("nm_settings", nm_settings);
      nm_settings.forEach(({ nm_id, bids_kopecks, bids, placements }) => {
        const search = placements?.search;
        const recom = placements?.recommendations;
        const combined = search && recom;

        let placement;

        if (combined) {
          placement = "Поиск и рекомендации";
        } else if (search && !recom) {
          placement = "Поиск";
        } else {
          placement = "Рекомендации";
        }

        resultNmIds.push([
          ...commonParams,
          nm_id,
          null,
          bids_kopecks?.search
            ? bids_kopecks.search / 100
            : bids?.search || null,
          bids_kopecks?.recommendations
            ? bids_kopecks.recommendations / 100
            : bids?.recommendations || null,
          ...createNullArray(1),
          placement,
        ]);
      });
    } else {
      resultNmIds.push([...commonParams, ...createNullArray(6)]);
    }

    return resultNmIds;
  },

  // Тип 9
  processType9New: (params, commonParams, debug = false) => {
    const { nm_settings } = params;
    const resultNmIds = [];

    if (nm_settings) {
      // if (debug) console.log("nm_settings", nm_settings);
      nm_settings.forEach(({ nm_id, bids_kopecks, bids, placements }) => {
        const search = placements?.search;
        const recom = placements?.recommendations;
        const combined = search && recom;

        resultNmIds.push([
          ...commonParams,
          nm_id,
          bids_kopecks?.search
            ? bids_kopecks.search / 100
            : bids?.search || null,
          bids_kopecks?.recommendations
            ? bids_kopecks.recommendations / 100
            : bids?.recommendations || null,
          search ? "Да" : "Нет",
          recom ? "Да" : "Нет",
          combined ? "Да" : "Нет",
        ]);
      });
    } else {
      resultNmIds.push([...commonParams, ...createNullArray(6)]);
    }

    return resultNmIds;
  },

  // Типы 4,5,6,7 - Другие типы кампаний
  processTypes4567: (params, commonParams) => {
    const { params: campaignParams } = params;
    const resultNmIds = [];

    if (campaignParams?.length > 0) {
      campaignParams.forEach(({ nms, price }) => {
        if (nms?.length > 0) {
          nms.forEach(({ nm }) => {
            resultNmIds.push([
              ...commonParams,
              nm,
              price,
              ...createNullArray(4),
            ]);
          });
        } else {
          resultNmIds.push([...commonParams, ...createNullArray(6)]);
        }
      });
    } else {
      resultNmIds.push([...commonParams, ...createNullArray(6)]);
    }

    return resultNmIds;
  },
};

// Основная функция обработки NmIds
function processAdvertNmIds(advertData, commonParams, debug = false) {
  const { type } = advertData;

  console.log("advertData", JSON.stringify(advertData, null, 2));

  // Определяем обработчик по типу рекламной кампании
  if (type === 8) {
    return processNmIdsHandlers.processType8(advertData, commonParams, debug);
  } else if (
    Object.keys(AdvBidTypes9).includes(type) ||
    type === 9 ||
    type === "unknown"
  ) {
    // return processNmIdsHandlers.processType9(advertData, commonParams, debug);
    return processNmIdsHandlers.processType9New(
      advertData,
      commonParams,
      debug,
    );
  } else if ([4, 5, 6, 7].includes(type)) {
    return processNmIdsHandlers.processTypes4567(advertData, commonParams);
  }

  // Если тип не определен, возвращаем пустой результат
  // return [[...commonParams, ...createNullArray(6)]];
  return [[...commonParams, ...createNullArray(6)]];
}

function processAdvertNmIdsNew(params, commonParams, debug = false) {
  const { type } = params;

  if (debug) console.log("params:\n", JSON.stringify(params, null, 2));

  if ([9, ...Object.keys(AdvBidTypes9)].includes(type)) {
    const { nm_settings } = params;
    const resultNmIds = [];

    if (nm_settings?.length) {
      nm_settings.forEach(
        ({ nm_id, subject, bids_kopecks, bids, placements }) => {
          const { id: subjectId, name: subjectName } = subject;

          const search = placements?.search;
          const recom = placements?.recommendations;
          const combined = search && recom;

          resultNmIds.push([
            ...commonParams,
            subjectId,
            capitalizeFirstLetter(subjectName),
            nm_id,
            bids_kopecks?.search
              ? bids_kopecks.search / 100
              : bids?.search || null,
            bids_kopecks?.recommendations
              ? bids_kopecks.recommendations / 100
              : bids?.recommendations || null,
            search ? "Да" : "Нет",
            recom ? "Да" : "Нет",
            combined ? "Да" : "Нет",
          ]);
        },
      );
    } else {
      resultNmIds.push([...commonParams, ...createNullArray(8)]);
    }

    return resultNmIds;
  }

  return [[...commonParams, ...createNullArray(8)]];
}

/**
 * @typedef {{
 *   advertApi: Advert; // объект класса Advert
 *   statuses?: Array<number>; // включить статусы
 *   excludeStatuses?: Array<number>; // исключить статусы
 *   types?: Array<number>; // типы
 *   dateFrom?: string; // с
 *   dateTo?: string; // до
 *   group?: boolean; // группировать данные
 *   exceptId?: Array.<number>; // кроме этих advertId
 *   sheetName?: string; // название листа для вставки данных
 *   service?: PropertiesService; // the script properties service object
 *   scipError?: boolean; // пропускать ошибку
 *   emptyCols?: boolean;
 * }} AdvertStatOptions
 */

// ####################################################################################################################################
// СТАТИСТИКА
// ####################################################################################################################################

/**
 * Статистика кампании
 * @param {AdvertStatOptions} [options] параметры запроса
 */
function advStatFull(
  options = context?.config?.getConfigForCurrentFunction(),
  advertApi,
) {
  const start = CONFIG.func.start();
  const script = advStatFull.name;

  advertApi = advertApi || options?.advertApi;

  const {
    dateFrom = "2025-01-01",
    dateTo = addDays(0, false, true),
    statusesExclude,
    response: {
      chunkIdsSize = 50,
      group = "nms", // "nms" группировать данные: по nm_id "apps' по apps mn_id "days", по дням
      booster = false, // статистика по ср. позиции товара на стр. поисковой выдачи и каталога (для автоматических кампаний)
    } = {},
    sheetName,
    service = context?.service,
    scipError,
    formulas = [],
    updatedAtRange,
    funcName,
    emptyCols,
  } = options;

  try {
    const adv = CONFIG.methods.advert;
    const { headerDays, headerApps, headerNms } = adv.stat.full;
    const sheetName_ = sheetName || adv.stat.full.sheet;
    const sheet = setSheetNew(sheetName_, adv.sheetColor, ss);

    if (!statusesExclude || statusesExclude.length === 0)
      options.statusesExclude = [-1, 4, 8];

    // Получаем список рекламных кампаний
    const advListResult = advList({
      advertApi,
      dateFrom,
      dateTo,
      check: true,
      endLog: true,
      statusesExclude: options.statusesExclude,
      sheetRkName: sheetName_,
    });

    const advListJson = advListResult?.advListJson;

    if (!advListJson || typeof advListJson !== "object") {
      return;
    }

    const storage =
      context?.storage ||
      (service && setStorage({ service, serviceType: context?.serviceType })) ||
      null;

    ["advStatDates", "advStatErrors", "advList"].forEach((name) => {
      if (storage.getProperty(name)) {
        storage.deleteProperty(name);
      }
    });

    if (context.requestLog)
      console.log({
        dateFrom,
        dateTo,
        chunkIdsSize,
        group,
        booster,
      });

    const keysToRemove = [
      "create",
      "change",
      "start",
      "end",
      "type",
      "status",
      "statusName",
      // "paymentType",
      "params",
      "autoParams",
      "nm_settings",
      "dailyBudget",
      "endTime",
      "createTime",
      "changeTime",
      "startTime",
    ];

    Object.keys(advListJson).forEach((key) => {
      const object = advListJson[key];
      keysToRemove.forEach((k) => {
        delete object[k];
      });
    });

    storage.setProperty("advList", advListJson);
    if (context.requestLog) debugSaveFileToDrive("CampaignsList", advListJson);

    let payload = [];

    const _ = Object.keys(advListJson);

    console.log("Total advertising companies >>>", _.length);
    if (_.length === 0)
      return CONFIG.func.endScript({
        script,
        start,
        emptyCols,
        message: "Нет данных",
        messageType: 2,
      });

    debugSaveFileToDrive("RelevantCampaigns", _);
    let relevantCampaigns = chunkArray(_, chunkIdsSize || 50);

    debugSaveFileToDrive("RelevantCampaignsChunks", relevantCampaigns);

    const dates = splitDateRangeBy31Days(dateFrom, dateTo.slice(0, 10));

    dates.forEach(({ start, end }) => {
      relevantCampaigns.forEach((ids) => {
        payload.push({ ids: ids.map(Number), beginDate: start, endDate: end });
      });
    });

    console.log("Requests count by one >>>", payload.length);
    debugSaveFileToDrive("Payload", payload);

    const runInfo = {
      start,
      index: 0,
      total: payload.length,
      payload,
      funcName,
      runFunc: options?.runFunc,
      sheetName: sheetName_,
      updatedAtRange,
      emptyCols,
      booster,
      group,
    };

    storage.setProperty("advStatDates", runInfo);
    debugSaveFileToDrive("StatFullRunInfo", runInfo);

    let headers =
      group === "apps" ? headerApps : group === "nms" ? headerNms : headerDays;

    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    setSheetHead(sheet, true);
    sheet.appendRow(headers);

    if (booster) {
      // Создаем лист 🎉 Статистика РК по СПТ
      const bs = adv.stat.fullBooster;
      const sheetBooster = setSheetNew(bs.sheet, bs.sheetColor, ss);
      setSheetHead(sheetBooster, true);
      sheetBooster.appendRow(bs.header);
    }

    if (Object.keys(runInfo).length > 0) {
      return advStatFullRun({
        advertApi,
        runInfo,
        advListJson,
      });
    }
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
      scipError,
    });
  }
}

function advStatFullRun(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  const script = advStatFullRun.name;
  const {
    advertApi,
    advListJson,
    runInfo,
    service = context?.service,
    api = true,
    raw,
    sheetAddUrl,
    setHead,
  } = options;

  const storage =
    context?.storage ||
    (service && setStorage({ service, serviceType: context?.serviceType })) ||
    null;

  const advList = advListJson || storage.getProperty("advList");
  const json = runInfo || storage.getProperty("advStatDates");
  let {
    start,
    index,
    total,
    payload,
    sheetName,
    funcName,
    updatedAtRange,
    booster,
    group,
  } = json;

  const runFunc = options?.runFunc || json?.runFunc;
  const emptyCols = options?.emptyCols || json?.emptyCols;

  try {
    deleteTriggersWithName(script);

    const tz = CONFIG.settings.time.timeZone;
    const adv = CONFIG.methods.advert;
    const dateFormat = CONFIG.formats;
    const sheet = setSheetNew(sheetName, adv.sheetColor, ss);

    const bs = adv.stat.fullBooster;
    const sheetBooster = booster
      ? setSheetNew(bs.sheet, adv.sheetColor, ss)
      : null;

    const result = [];
    const params = payload.pop();

    let count_response = 0;
    while (count_response < 3) {
      // максимум 3 попытки
      const response = advertApi.statFull(params);

      if (response === -1) {
        break; // Ошибка API
      }

      if (response && response.length > 0) {
        result.push(...response);
        break; // Данные получены
      }

      count_response++;
    }

    console.log(
      `Request >>> ${index + 1} from ${total}`,
      "advertId in request >>>",
      Object.keys(params.ids).length,
      "advertId in response >>>",
      result?.length || "No data",
    );

    debugSaveFileToDrive(`statFullResult_${index + 1}`, result);

    index++;

    if (result && result.length > 0) {
      const { reportStats, boosterStats } = processAdvertData(result, {
        groupBy:
          group === "apps"
            ? ["appType", "nmId", "name"]
            : group === "nms"
              ? ["nmId", "name"]
              : [],
        includeReportStats: true,
        includeBoosterStats: booster,
        advList,
        tz,
        dateFormat: dateFormat.date,
        adv,
      });

      if (booster && boosterStats.length) {
        const lastRowBooster = sheetBooster.getLastRow();
        sheetBooster
          .getRange(
            lastRowBooster + 1,
            1,
            boosterStats.length,
            boosterStats[0].length,
          )
          .setValues(boosterStats);
      }

      if (reportStats && reportStats.length) {
        const lastRowStats = sheet.getLastRow();
        const fromRowStats = lastRowStats;
        // addDataToSheet({
        addDataToSheetOptimized({
          fromRow: fromRowStats,
          lastRow: lastRowStats,
          result: reportStats,
          sheet,
          api,
          raw,
          script,
          start,
          setHead,
        });
      }
    }

    if (index === total) {
      storage.deleteProperty("advList");
      storage.deleteProperty("advStatDates");

      if (funcName && funcName.length > 0)
        funcName.forEach((name, index) => createTriggerRun(name, index + 1));

      sortDataBySheet(sheet, 4);
      sheet
        .getRangeList(adv.stat.full.rangeDate)
        .setNumberFormat(dateFormat.date);

      if (booster) {
        sortDataBySheet(sheetBooster, 1);
        sheetBooster
          .getRangeList(bs.rangeDate)
          .setNumberFormat(dateFormat.date);
        cropToRange(sheetBooster.getDataRange());
      }

      if (sheetAddUrl) {
        SpreadsheetApp.flush();
        const range = sheet.getDataRange();

        cropToRange(range);

        const data = range
          .getValues()
          .map((el) => [el[3], el[0], el[6], el[7], el[8], el[9], el[10]]);

        const sheetAdd = SpreadsheetApp.openById(
          getIdFromUrl(sheetAddUrl),
        ).getSheetByName("Стат. по РК");

        sheetClear({ sheet: sheetAdd, contents: true });
        sheetAdd.getRange(1, 1, data.length, data[0].length).setValues(data);
        cropToRange(sheetAdd.getDataRange());
      }

      console.log(`Данные Статистика РК (new) загружены`);
      CONFIG.func.endScript({
        script: "advStatFull",
        start,
        sheet,
        emptyCols,
        message: "Статистика РК загружена",
        runFunc: options?.runFunc,
      });
    } else {
      storage.setProperty("advStatDates", {
        start,
        index,
        total,
        payload,
        sheetName,
        funcName,
        runFunc,
        updatedAtRange,
        group,
        booster,
      });
      createTriggerRun(script, 1);
    }
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

/**
 * Разбивает период между двумя датами на интервалы по 31 день
 * @param {string} startDate - Начальная дата в формате YYYY-MM-DD
 * @param {string} endDate - Конечная дата в формате YYYY-MM-DD
 * @returns {Array} Массив объектов с интервалами дат
 */
function splitDateRangeBy31Days(startDate, endDate) {
  // Валидация входных параметров
  if (!startDate || !endDate) {
    throw new Error("Начальная и конечная даты обязательны");
  }

  // Проверка формата дат
  const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
  if (!dateRegex.test(startDate) || !dateRegex.test(endDate)) {
    throw new Error("Даты должны быть в формате YYYY-MM-DD");
  }

  const start = new Date(startDate);
  const end = new Date(endDate);

  // Проверка корректности дат
  if (isNaN(start.getTime()) || isNaN(end.getTime())) {
    throw new Error("Некорректные даты");
  }

  // Проверка, что начальная дата не позже конечной
  if (start > end) {
    throw new Error("Начальная дата не может быть позже конечной");
  }

  /**
   * Форматирует дату в формат YYYY-MM-DD
   * @param {Date} date - Дата для форматирования
   * @returns {string} Отформатированная дата
   */
  function formatDate(date) {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, "0");
    const day = String(date.getDate()).padStart(2, "0");
    return `${year}-${month}-${day}`;
  }

  const intervals = [];
  let currentStart = new Date(start);

  while (currentStart <= end) {
    // Создаем конечную дату для текущего интервала (на 30 дней позже)
    let currentEnd = new Date(currentStart);
    currentEnd.setDate(currentEnd.getDate() + 30);

    // Если конечная дата интервала выходит за общую конечную дату,
    // используем общую конечную дату
    if (currentEnd > end) {
      currentEnd = new Date(end);
    }

    // Добавляем интервал в массив
    intervals.push({
      start: formatDate(currentStart),
      end: formatDate(currentEnd),
      days: Math.ceil((currentEnd - currentStart) / (1000 * 60 * 60 * 24)) + 1,
    });

    // Переходим к следующему интервалу (начинаем со следующего дня после текущего конца)
    currentStart = new Date(currentEnd);
    currentStart.setDate(currentStart.getDate() + 1);
  }

  return intervals;
}

/**
 * Альтернативная функция, которая возвращает массив дат (не интервалов)
 * @param {string} startDate - Начальная дата в формате YYYY-MM-DD
 * @param {string} endDate - Конечная дата в формате YYYY-MM-DD
 * @returns {Array} Массив дат, разбитых по 31 дню
 */
function getDateArrayBy31Days(startDate, endDate) {
  const intervals = splitDateRangeBy31Days(startDate, endDate);
  return intervals.map((interval) => interval.start);
}

/**
 * Processes the result data to generate statistics and information.
 *
 * @param {array} dataArray - The result data to process
 * @param {array} [options.groupBy=[]] - Whether to group the statistics days, apps, nms
 * @param {boolean} [options.includeReportStats=true] - Whether to include report statistics
 * @param {boolean} [options.includeBoosterStats=false] - Whether to include booster statistics
 * @param {object} options.advList- The properties of the advertisement list
 * @param {object} options.adv - The advertisement information
 * @param {string} options.tz - The time zone for date formatting
 * @param {string} options.dateFormat - The format for date display
 * @return {object} The processed report statistics and booster statistics
 */
function processAdvertData(dataArray, options = {}) {
  const {
    groupBy = [],
    includeReportStats = true,
    includeBoosterStats = false,
    advList,
    adv = CONFIG.methods.advert,
    tz,
    dateFormat = CONFIG.formats.date,
  } = options;

  // Создаем Map для быстрого доступа и группировки
  const reportStatsMap = new Map();
  const boosterStatsArray = [];

  // Предопределяем ключи для суммирования
  const sumKeys = [
    "views",
    "clicks",
    "sum",
    "atbs",
    "orders",
    "shks",
    "sum_price",
    "canceled",
  ];

  // Обрабатываем каждый объект в массиве
  for (const data of dataArray) {
    const advertId = data.advertId;
    const days = data.days || [];
    const boosterStats = data.boosterStats || [];

    // Обрабатываем каждый день
    for (const day of days) {
      const date = day.date;

      // Обрабатываем apps
      if (day.apps && includeReportStats) {
        for (const app of day.apps) {
          const appType = app.appType;

          if (app?.nms && app.nms.length > 0) {
            for (const nm of app.nms) {
              const nmId = nm.nmId;
              const name = nm.name;

              // Определяем ключ в зависимости от группировки
              let groupKey;
              if (
                groupBy.includes("appType") &&
                groupBy.includes("nmId") &&
                groupBy.includes("name")
              ) {
                groupKey = `${date}|${advertId}|${appType}|${nmId}|${name}`;
              } else if (groupBy.includes("nmId") && groupBy.includes("name")) {
                groupKey = `${date}|${advertId}|${nmId}|${name}`;
              } else {
                groupKey = `${date}|${advertId}`;
              }

              // Инициализируем или обновляем статистику
              if (!reportStatsMap.has(groupKey)) {
                reportStatsMap.set(groupKey, {
                  date: date,
                  advertId: advertId,
                  views: 0,
                  clicks: 0,
                  sum: 0,
                  atbs: 0,
                  orders: 0,
                  shks: 0,
                  sum_price: 0,
                  canceled: 0,
                  days: [],
                });

                // Добавляем дополнительные поля в зависимости от группировки
                if (
                  groupBy.includes("appType") &&
                  groupBy.includes("nmId") &&
                  groupBy.includes("name")
                ) {
                  reportStatsMap.get(groupKey).appType = appType;
                  reportStatsMap.get(groupKey).nmId = nmId;
                  reportStatsMap.get(groupKey).name = name;
                } else if (
                  groupBy.includes("nmId") &&
                  groupBy.includes("name")
                ) {
                  reportStatsMap.get(groupKey).nmId = nmId;
                  reportStatsMap.get(groupKey).name = name;
                }
              }

              const stats = reportStatsMap.get(groupKey);

              // Суммируем значения
              for (const key of sumKeys) {
                if (nm[key] !== undefined) {
                  stats[key] += nm[key] || 0;
                }
              }

              // Добавляем день если его еще нет
              let dayStats = stats.days.find((d) => d.date === date);
              if (!dayStats) {
                dayStats = {
                  date: date,
                  views: 0,
                  clicks: 0,
                  sum: 0,
                  atbs: 0,
                  orders: 0,
                  shks: 0,
                  sum_price: 0,
                  canceled: 0,
                };
                stats.days.push(dayStats);
              }

              // Обновляем статистику дня
              for (const key of sumKeys) {
                if (nm[key] !== undefined) {
                  dayStats[key] += nm[key] || 0;
                }
              }
            }
          }
        }
      }
    }

    // Обрабатываем boosterStats
    if (includeBoosterStats && boosterStats.length > 0) {
      for (const booster of boosterStats) {
        if (booster.avg_position > 0) {
          boosterStatsArray.push([
            Utilities.formatDate(new Date(booster.date), tz, dateFormat),
            advertId,
            booster.nm,
            booster.avg_position,
          ]);
        }
      }
    }
  }

  // Конвертируем Map в массив массивов и фильтруем
  const reportStatsArray = Array.from(reportStatsMap.values())
    .filter((stats) => sumKeys.some((key) => stats[key] > 0))
    .map((stats, _) => {
      if (_ === 0) console.log(JSON.stringify(stats, null, 2));

      // Вычисляем производные метрики
      const ctr =
        stats.views > 0
          ? parseFloat((stats.clicks / stats.views).toFixed(3))
          : 0;
      const cpc =
        stats.clicks > 0
          ? parseFloat((stats.sum / stats.clicks).toFixed(3))
          : 0;
      const cr =
        stats.views > 0
          ? parseFloat((stats.orders / stats.views).toFixed(3))
          : 0;

      // Формируем массив в зависимости от группировки
      if (
        groupBy.includes("appType") &&
        groupBy.includes("nmId") &&
        groupBy.includes("name")
      ) {
        return [
          stats.advertId,
          advList[stats.advertId]?.name,
          advList[stats.advertId]?.typeName,
          Utilities.formatDate(new Date(stats.date), tz, dateFormat),
          adv.appType[stats.appType] || stats.appType,
          stats.nmId,
          stats.name,
          stats.views,
          stats.clicks,
          parseFloat(stats.sum.toFixed(3)),
          stats.atbs,
          stats.orders,
          stats.shks,
          parseFloat(stats.sum_price.toFixed(3)),
          cpc,
          ctr,
          cr,
          stats.canceled,
          // advList[stats.advertId]?.paymentType,
          // advList[stats.advertId]?.placements,
        ];
      } else if (groupBy.includes("nmId") && groupBy.includes("name")) {
        return [
          stats.advertId,
          advList[stats.advertId]?.name,
          advList[stats.advertId]?.typeName,
          Utilities.formatDate(new Date(stats.date), tz, dateFormat),
          stats.nmId,
          stats.name,
          stats.views,
          stats.clicks,
          parseFloat(stats.sum.toFixed(3)),
          stats.atbs,
          stats.orders,
          stats.shks,
          parseFloat(stats.sum_price.toFixed(3)),
          cpc,
          ctr,
          cr,
          stats.canceled,
          // advList[stats.advertId]?.paymentType,
          // advList[stats.advertId]?.placements,
        ];
      } else {
        return [
          stats.advertId,
          advList[stats.advertId]?.name,
          advList[stats.advertId]?.typeName,
          Utilities.formatDate(new Date(stats.date), tz, dateFormat),
          stats.views,
          stats.clicks,
          parseFloat(stats.sum.toFixed(3)),
          stats.atbs,
          stats.orders,
          stats.shks,
          parseFloat(stats.sum_price.toFixed(3)),
          cpc,
          ctr,
          cr,
          stats.canceled,
          // advList[stats.advertId]?.paymentType,
          // advList[stats.advertId]?.placements,
        ];
      }
    });

  return {
    reportStats: reportStatsArray,
    boosterStats: boosterStatsArray,
  };
}

/**
 * @typedef {{
 *   advertIds?: Array<number>; // массив идентификаторов кампаний
 *   sheetName?: string; // название листа для вставки данных
 *   emptyCols?: boolean;
 * }} AdvertadvStatAutoOptions
 */

/**
 * Статистика кампании с единой ставкой по кластерам фраз
 * @param {AdvertadvStatAutoOptions} [options] параметры запроса
 */
function advStatFlatRateWords(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  const start = CONFIG.func.start();
  const script = advStatFlatRateWords.name;

  try {
    const { advertApi, sheetName, formulas = [], emptyCols } = options;
    let { advertIds } = options;

    const adv = CONFIG.methods.advert;
    const main = adv.stat.flatRateWords;
    const sheet = setSheetNew(sheetName || main.sheet, main.sheetColor, ss);

    const header = Object.values(main.header);
    let headers = Object.values(header);
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    setSheetHead(sheet, true);
    sheet.appendRow(headers);

    advertIds =
      advertIds ||
      setSheetNew(adv.sheetSettings, "RED", ss)
        .getDataRange()
        .getValues()
        .filter((_, i) => i > 4 && _[2])
        .map((el) => {
          return el[2];
        });

    if (!advertIds.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: `Выберите компанию(-и) на листе ${adv.sheetSettings}`,
        messageType: 2,
      });
    }

    let count = advertIds.length;
    console.log(`AdvertIds count >>> ${count}`);

    const results = [];
    const uniqueArray = [...new Set(advertIds)];
    chunkArray(uniqueArray, 1).forEach(([advertId], i) => {
      const response = advertApi.statFlatRateWords(advertId);
      if (response.hasOwnProperty("clusters")) {
        response.advertId = advertId;
        results.push(response);
      }

      console.log(`Remains to be done >>> ${(count -= 1)}`);
    });

    debugLog("Ответ:", results);

    if (!results.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const result = results.flatMap((item) =>
      item.clusters.map((el) => [
        item.advertId,
        item?.excluded ? truncateString(item.excluded.join("\n"), 50000) : null,
        el?.cluster,
        el?.count,
        el?.keywords
          ? truncateString(
              el.keywords
                .map((elem) => elem.replace(/\s+/g, " ").trim())
                .filter(Boolean)
                .join("\n"),
              50000,
            )
          : null,
      ]),
    );

    debugLog("Обработанный:", result);

    sheet
      .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
      .setValues(result);

    setVerticalAlignmentWrapStrategy(sheet);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Статистику РК с единой ставкой по кластерам фраз получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

/**
 * Статистика поисковых кластеров за период
 * @param {AdvertadvStatAutoOptions} [options] параметры запроса
 */
function advStatNormqueryPeriod(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  const start = CONFIG.func.start();
  const script = advStatNormqueryPeriod.name;

  try {
    const { advertApi, sheetName, formulas = [], emptyCols } = options;

    let { advertIds } = options;
    const adv = CONFIG.methods.advert;
    const main = adv.stat.normqueryPeriod;
    const sheet = setSheetNew(sheetName || main.sheet, main.sheetColor, ss);

    const header = Object.values(main.header);
    let headers = Object.values(header);
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    setSheetHead(sheet, true);
    sheet.appendRow(headers);

    const { dates, uniqueItems } = advertsByPeriod({
      adv,
      advertIds,
      options,
      cpmOnly: false,
      script,
      start,
    });

    const results = [];
    dates.forEach(([dateFrom, dateTo], i) => {
      console.log(
        `Date >>> ${dateFrom} - ${dateTo} ${i + 1} of ${dates.length}`,
      );
      chunkArray(uniqueItems, 100).forEach((items) => {
        const response = advertApi.statNormqueryPeriod({
          dateFrom,
          dateTo,
          items,
        });

        if (response.length) {
          response.forEach((item) => {
            item.period = `${dateFrom} | ${dateTo}`;
          });
        }

        results.push(...response);
      });
    });

    debugLog("Ответ:", results, 1);

    if (!results.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const result = [];
    for (let i = 0; i < results.length; i++) {
      const item = results[i];
      const stats = item.stats;

      for (let j = 0; j < stats.length; j++) {
        const stat = stats[j];

        result.push([
          item.period,
          item.advert_id,
          item.nm_id,
          stat.norm_query ? truncateString(stat.norm_query) : null,
          stat?.views,
          stat.clicks,
          stat.atbs,
          stat.avg_pos,
          stat.orders,
          stat.cpc,
          stat?.cpm,
          stat?.ctr,
        ]);
      }
    }

    debugLog("Обработанный:", result, 1);

    if (!result.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    sheet
      .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
      .setValues(result);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Статистику РК поисковых кластеров получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

/**
 * Статистика по поисковым кластерам с детализацией по дням
 * @param {AdvertadvStatAutoOptions} [options] параметры запроса
 */
function advStatNormqueryDays(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  const start = CONFIG.func.start();
  const script = advStatNormqueryDays.name;

  try {
    const { advertApi, sheetName, formulas = [], emptyCols } = options;

    let { advertIds } = options;
    const adv = CONFIG.methods.advert;
    const main = adv.stat.normqueryDays;
    const sheet = setSheetNew(sheetName || main.sheet, main.sheetColor, ss);

    const header = Object.values(main.header);
    let headers = Object.values(header);
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    setSheetHead(sheet, true);
    sheet.appendRow(headers);

    const { dates, uniqueItems } = advertsByPeriod({
      adv,
      advertIds,
      options,
      cpmOnly: false,
      script,
      start,
    });

    const results = [];
    dates.forEach(([dateFrom, dateTo], i) => {
      console.log(
        `Date >>> ${dateFrom} - ${dateTo} ${i + 1} of ${dates.length}`,
      );
      chunkArray(uniqueItems, 100).forEach((items) => {
        const response = advertApi.statNormqueryDays({
          dateFrom,
          dateTo,
          items: items.map(({ advert_id, nm_id }) => ({
            advertId: advert_id,
            nmId: nm_id,
          })),
        });

        results.push(...response);
      });
    });

    debugLog("Ответ:", results, 1);

    if (!results.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const result = [];

    for (let i = 0; i < results.length; i++) {
      const item = results[i];
      if (!item?.dailyStats) continue;

      for (let j = 0; j < item.dailyStats.length; j++) {
        const dailyStat = item.dailyStats[j];
        const stat = dailyStat.stat;

        result.push([
          dailyStat.date,
          item.advertId,
          item.nmId,
          stat.normQuery ? truncateString(stat.normQuery) : null,
          stat?.views,
          stat.clicks,
          stat.atbs,
          stat.avgPos,
          stat.orders,
          stat.cpc,
          stat?.cpm,
          stat?.ctr,
          stat.shks,
          stat.spend,
        ]);
      }
    }

    debugLog("Обработанный:", result, 1);

    if (!result.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    sheet
      .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
      .setValues(result);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Статистику РК поисковых кластеров получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

