function datesBetweenWithStepOneAndPrevDay(
  startDate,
  endDate,
  dateFormat = "%Y-%m-%d %H:%M:%S",
) {
  const dates = [];
  const start = new Date(startDate);
  const end = new Date(endDate);
  const today = new Date();

  let currentDate = new Date(start);
  while (currentDate <= end) {
    const startOfDay = new Date(currentDate);
    startOfDay.setHours(0, 0, 0, 0);

    let endOfDay = new Date(currentDate);
    endOfDay.setDate(endOfDay.getDate());

    if (currentDate.getDate() === today.getDate()) {
      //Set endOfDay to current time - 20 minutes if endDate is today.
      endOfDay.setMinutes(endOfDay.getMinutes() - 20);
      endOfDay = new Date();
    } else {
      endOfDay.setHours(23, 59, 59, 999);
    }

    // Дата "с - 1 день"
    const startOfDayPrev = new Date(startOfDay);
    startOfDayPrev.setDate(startOfDayPrev.getDate() - 1);

    // Дата "по - 1 день" - всегда конец предыдущего дня
    const endOfDayPrev = new Date(startOfDayPrev);
    endOfDayPrev.setHours(23, 59, 59, 999);

    dates.push([
      formatDate(startOfDay, dateFormat), // дата "с"
      formatDate(endOfDay, dateFormat), // дата "по"
      formatDate(startOfDayPrev, dateFormat), // дата "с - 1 день"
      formatDate(endOfDayPrev, dateFormat), // дата "по - 1 день"
    ]);

    currentDate.setDate(currentDate.getDate() + 1);
  }

  return dates;
}

function formatDate(date, format) {
  return format
    .replace(/%Y/g, date.getFullYear())
    .replace(/%m/g, padZero(date.getMonth() + 1))
    .replace(/%d/g, padZero(date.getDate()))
    .replace(/%H/g, padZero(date.getHours()))
    .replace(/%M/g, padZero(date.getMinutes()))
    .replace(/%S/g, padZero(date.getSeconds()));
}

function padZero(num) {
  return (num < 10 ? "0" : "") + num;
}

