      });
    }

    let result = response.map((item) => {
      return Object.keys(header).reduce((acc, key) => {
        let value = item[key];
        return [...acc, value];
      }, []);
    });

    debugLog("Обработанный:", result);

    if (short) {
      /**
       * Группирует данные по первым двум элементам и суммирует по третьему
       * @param {Array<Array>} data - массив массивов [key1, key2, value]
       * @returns {Array<Array>} сгруппированные данные [key1, key2, sum]
       */
      function groupAndSum(data, sep = "|") {
        if (!Array.isArray(data) || data.length === 0) {
          return [];
        }

        const res = new Map();

        data.forEach((row) => {
          if (!Array.isArray(row) || row.length < 3) {
            return;
          }

          const [key1, key2, key3, key4, value] = row;
          const groupKey = `${key1}${sep}${key2}${sep}${key3}${sep}${key4}`;

          const numValue = Number(value);
          if (isNaN(numValue)) {
            return;
          }

          // console.log(groupKey, numValue);

          if (res.has(groupKey)) {
            res.set(groupKey, res.get(groupKey) + numValue);
          } else {
            res.set(groupKey, numValue);
          }
        });

        return Array.from(res.entries()).map(([key, sum]) => {
          const [key1, key2, key3, key4] = key.split(sep);
          return [key1, Number(key2), key3, key4, sum];
        });
      }

      result = groupAndSum(result);
      debugLog("Короткий:", result);
    }

    // addDataToSheet({
    addDataToSheetOptimized({
      fromRow,
      lastRow,
      result,
      sheet,
      api,
      raw,
      setHead,
      script,
      start,
      debug,
    });

    sheet
      .getRangeList(short ? main.rangeFormatShort : main.rangeFormat)
      .setNumberFormat(formats.date);
    sortDataBySheet(sheet, short ? 1 : 2);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Отчёт Платное хранение получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

/**
 * @typedef {{
 *   analyticsApi: Analytics; // объект класса Analytics
 *   date: string; // дата начала отчётного периода, ГГГГ-ММ-ДД
 *   sheetName?: string; // название листа для вставки данных
 *   emptyCols?: boolean; // удалить пустые столбцы
 * }} AnalyticsAntifraudDetailsOptions
 */

// ####################################################################################################################################
// Отчёты об удержаниях
// ####################################################################################################################################

// Преобразование даты в формате YYYY-MM-DD в UTC с учётом московского времени (UTC+3)
const convertDateToUTC = (dateStr, isEndOfDay = false) => {
  if (!dateStr) return null;
  // Если дата в формате YYYY-MM-DD, добавляем время и московский часовой пояс
  if (/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {
    const time = isEndOfDay ? "23:59:59" : "00:00:00";
    // Создаём дату с московским временем (UTC+3)
    const mskDate = new Date(`${dateStr}T${time}+03:00`);
    return mskDate.toISOString();
  }
  // Если дата уже в другом формате, используем стандартное преобразование
  return new Date(dateStr).toISOString();
};

