 *   sheetName?: string; // название листа для вставки данных
 *   emptyCols?: boolean; // удалить пустые столбцы
 *   accumulate?: boolean; // накапливать данные, не удаляя старые
 *   api?: boolean; // вставлять данные через API или напрямую
 *   raw?: boolean; // вставлять необработанные данные (без формул и форматирования)
 *   setHead?: boolean; // устанавливать шапку таблицы
 *   runFunc?: Function; // функцию для запуска после получения данных
 *   nmIds: Array.<string>; // Артикулы WB max: 1000
 *   chrtIds: Array.<string>; // ID размеров. Используется только для указанных в массиве nmIds артикулов
 * }} AnalyticsStocksWbWarehouseOptions
 */

/**
 * Остатки на складах WB ++
 * @param {AnalyticsStocksWbWarehouseOptions} [options] параметры запроса
 */
function analyticsStocksWbWarehouses(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  const start = CONFIG.func.start();
  const script = analyticsStocksWbWarehouses.name;

  try {
    const {
      analyticsApi,
      formulas = [],
      accumulate = false,
      setHead,
      api = true,
      raw = true,
      updatedFormat,
      sheetName,
      emptyCols,
    } = options;

    const formats = CONFIG.formats;
    const analytics = CONFIG.methods.analytics;
    const main = analytics.stocksHystory.wbWarehouses;

    const header = main.header;

    const sheet = setSheetNew(
      sheetName || main.sheet,
      analytics.sheetColor,
      ss,
    );

    if (!accumulate) setSheetHead(sheet, true);

    let lastRow = sheet.getLastRow();
    let fromRow = lastRow;

    if (lastRow === 0) {
      let headers = Object.values(header);
      if (formulas.length > 0) {
        headers = headers.concat(formulas);
      }
      sheet.appendRow(headers);
    }

    const response = analyticsApi.stocksWbWarehouses(options);

    debugLog("Ответ:", response);

    if (!response.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const updatedFormat_ = updatedFormat || formats.datehhmm;

    const updated = dateStrToFormatDate(new Date(), updatedFormat_);

    const result = response.map((item) => {
      return Object.keys(main.header).reduce((acc, key) => {
        let value = item[key];
        if (key === "updateAt") value = updated;
        return [...acc, value];
      }, []);
    });

    debugLog("Обработанный:", result);

    addDataToSheet({
      fromRow,
      lastRow,
      result,
      sheet,
      api,
      raw,
      setHead,
      script,
      start,
    });

    sheet.getRangeList(main.rangeFormat).setNumberFormat(updatedFormat_);
    sortDataBySheet(sheet, 1);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Отчёт История по остаткам (по складам) получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

