/**
 * Воронка продаж (Джем) DETAIL_HISTORY_REPORT
 * @param {analyticsNmDetailHistoryRunOptions} [options] параметры запроса
 */
function jamNmDetailHistory(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  const start = CONFIG.func.start();
  const script = jamNmDetailHistory.name;

  try {
    const {
      analyticsApi,
      dateFrom,
      dateTo,
      sheetName,
      api = true,
      raw = true,
      formulas = [],
      debug = context?.debug,
      emptyCols,
      setHead,
    } = options;

    console.log(dateFrom, dateTo);
    jamValidateDates(dateFrom, dateTo);

    const formats = CONFIG.formats;
    const main = CONFIG.methods.analytics.jam.cardReport;

    const header = main.header;

    const sheet = setSheetNew(sheetName || main.sheet, main.sheetColor, ss);

    let headers = Object.values(header);
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    sheetClear({ sheet });
    sheet.appendRow(headers);

    if (!dateFrom || !dateTo) {
      const dates = jamDateRange();
      options.currentPeriodStart = dates[0];
      options.currentPeriodEnd = dates[1];
    } else {
      options.currentPeriodStart = dateStrToFormatDate(
        dateFrom,
        formats.dateyyyy_MM_dd,
      );
      options.currentPeriodEnd = dateStrToFormatDate(
        dateTo,
        formats.dateyyyy_MM_dd,
      );
    }

    delete options.dateFrom;
    delete options.dateTo;
    options.skipDeletedNm = options.skipDeletedNm || false;

    let result = [];

    options.reportType = JamReportTypes.DETAIL_HISTORY;
    const { downloadId, data } = analyticsApi.jamCsvReportCreate(options);
    console.log(`downloadId: ${downloadId}`, JSON.stringify(data, null, 2));
    if (downloadId) Utilities.sleep(60000);

    let status = analyticsApi.jamCsvReportList([downloadId])[0];
    if (status?.status === "FAILED") {
      console.log("Create error:", JSON.stringify(status, null, 2));
      const response = analyticsApi.jamCsvReportRetry(downloadId);
      console.log("Retry:", JSON.stringify(response, null, 2));
      if (response) Utilities.sleep(60000 * 2);
      status = analyticsApi.jamCsvReportList([downloadId])[0];
    }

    console.log("Status:", JSON.stringify(status, null, 2));

    if (status?.status === "SUCCESS") {
      const response = analyticsApi.jamCsvReportDownload(downloadId);
      result = dataFromZippedCsv(response.getContent());
    } else {
      const message = `Ошибка получения данных:\n${status}`;
      console.log(message);
      setSheetHead(sheet);
      return CONFIG.func.endScript({
        script,
        start,
        message,
        messageType: 2,
      });
    }

    debugSaveFileToDrive(`jamNmDetailHistory`, result);

    debugLog("Обработанный:", result);

    if (!result.length) {
      setSheetHead(sheet);
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    // for (let i = result.length; i--; ) {
    //   result[i].pop();
    // }

    for (let i = result.length; i--; ) {
      result[i].length = 14; // обрезаем до 14-го элемента
    }

    let lastRow = sheet.getLastRow();

    addDataToSheet({
      fromRow: 0,
      lastRow,
      result,
      sheet,
      api,
      raw,
      setHead,
      script,
      start,
      debug,
    });

    sheet.getRangeList(main.rangeDate).setNumberFormat(formats.date);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Воронка продаж (Джем) получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

/**
 * Воронка продаж (Джем) DETAIL_HISTORY_REPORT
 * @param {analyticsNmDetailHistoryRunOptions} [options] параметры запроса
 */
function jamStockHistoryDaily(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  const start = CONFIG.func.start();
  const script = jamStockHistoryDaily.name;

  try {
    const {
      analyticsApi,
      sheetName,
      api = true,
      raw = false,
      emptyCols,
      setHead,
      inStock = true,
      pivot = false,
    } = options;

    const main = CONFIG.methods.analytics.jam.stockHistoryDaily;
    const sheet = setSheetNew(sheetName || main.sheet, main.sheetColor, ss);
    sheetClear({ sheet });

    const dates = jamDateRange(90);
    options.currentPeriodStart = dates[0];
    options.currentPeriodEnd = dates[1];
    options.skipDeletedNm = options.skipDeletedNm || false;

    let result = [];

    options.reportType = JamReportTypes.STOCK_HISTORY_DAILY;
    const { downloadId, data } = analyticsApi.jamCsvReportCreate(options);
    console.log(`downloadId: ${downloadId}`, JSON.stringify(data, null, 2));
    if (downloadId) Utilities.sleep(60000);

    let status = analyticsApi.jamCsvReportList([downloadId])[0];
    if (status?.status === "FAILED") {
      console.log("Create error:", JSON.stringify(status, null, 2));
      const response = analyticsApi.jamCsvReportRetry(downloadId);
      console.log("Retry:", JSON.stringify(response, null, 2));
      if (response) Utilities.sleep(60000 * 2);
      status = analyticsApi.jamCsvReportList([downloadId])[0];
    }

    console.log("Status:", JSON.stringify(status, null, 2));

    if (status?.status === "SUCCESS") {
      const response = analyticsApi.jamCsvReportDownload(downloadId);
      result = dataFromZippedCsv(response.getContent(), false);
    } else {
      const message = `Ошибка получения данных:\n${status}`;
      console.log(message);
      setSheetHead(sheet);
      return CONFIG.func.endScript({
        script,
        start,
        message,
        messageType: 2,
      });
    }

    debugSaveFileToDrive(script, result);

    debugLog("Обработанный:", result, 2);

    if (!result.length) {
      setSheetHead(sheet);
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const headerValues = Object.values(main.header);
    const colCount = headerValues.length;
    result[0] = result[0].map((name, i) =>
      i < headerValues.length ? headerValues[i] : name,
    );

    if (inStock) {
      result = [
        result[0],
        ...result
          .slice(1)
          .filter((row) => row.slice(colCount).some((val) => Number(val) > 0)),
      ];
    }
    if (pivot) {
      const dateHeaders = result[0].slice(colCount);
      const newRows = [[...headerValues, "Дата", "Остаток"]];
      for (let i = 1; i < result.length; i++) {
        const row = result[i];
        const baseData = row.slice(0, colCount);
        for (let j = 0; j < dateHeaders.length; j++) {
          const val = Number(row[colCount + j]);
          if (val > 0) newRows.push([...baseData, dateHeaders[j], val]);
        }
      }
      result = newRows;
    }

    addDataToSheetOptimized({
      fromRow: -1,
      lastRow: 0,
      result,
      sheet,
      api,
      raw,
      setHead,
      script,
      start,
    });

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Отчёт по истории остатков (Джем) получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

