function validateDatesStocsReport(start, end) {
  // Преобразуем входные строки в объекты Date
  const startDate = new Date(start);
  const endDate = new Date(end);
  const currentDate = new Date();

  // Рассчитаем дату 3 месяца назад от текущей даты
  const threeMonthsAgo = new Date();
  threeMonthsAgo.setMonth(currentDate.getMonth() - 3);

  let correctedStart = startDate;
  let correctedEnd = endDate;

  // Проверка даты начала (start)
  if (startDate > endDate) {
    correctedStart = new Date(endDate); // Если start позже end, корректируем start чтобы он был равен end
    return {
      message:
        "Дата начала (start) невалидна. Условие: Не позднее end. Не ранее 3 месяцев от текущей даты.",
      correctedStart: correctedStart.toISOString().split("T")[0], // Возвращаем исправленную дату
      correctedEnd: end,
    };
  }
  if (startDate < threeMonthsAgo) {
    correctedStart = new Date(threeMonthsAgo); // Если start ранее чем 3 месяца назад, корректируем
    return {
      message:
        "Дата начала (start) невалидна. Условие: Не позднее end. Не ранее 3 месяцев от текущей даты.",
      correctedStart: correctedStart.toISOString().split("T")[0], // Возвращаем исправленную дату
      correctedEnd: end,
    };
  }

  // Проверка даты окончания (end)
  if (endDate < threeMonthsAgo) {
    correctedEnd = new Date(threeMonthsAgo); // Если end ранее чем 3 месяца назад, корректируем
    return {
      message:
        "Дата окончания (end) невалидна. Условие: Не ранее 3 месяцев от текущей даты.",
      correctedStart: start,
      correctedEnd: correctedEnd.toISOString().split("T")[0], // Возвращаем исправленную дату
    };
  }

  // Если все даты валидны
  return {
    message: "Даты периода валидны.",
    correctedStart: start, // Возвращаем исходную дату
    correctedEnd: end, // Возвращаем исходную дату
  };
}

function jamValidateDates(startDate, endDate) {
  if (!startDate || !endDate) {
    throw new Error("startDate and endDate required fields are not filled in");
  }

  const currentDate = new Date();
  currentDate.setHours(0, 0, 0, 0);

  const endDate_ = new Date(endDate);
  endDate_.setHours(0, 0, 0, 0);

  const startDate_ = new Date(startDate);
  startDate_.setHours(0, 0, 0, 0);

  const oneYearFromNow = new Date();
  oneYearFromNow.setHours(0, 0, 0, 0);
  oneYearFromNow.setFullYear(oneYearFromNow.getFullYear() - 1);

  // console.log({
  //   currentDate,
  //   endDate_,
  //   startDate_,
  //   oneYearFromNow,
  // });

  if (endDate_ > currentDate) {
    throw new Error("endDate cannot be greater than the current date");
  }

  if (startDate_ > currentDate || startDate_ < oneYearFromNow) {
    throw new Error(
      "startDate must be within the next 365 days from the current date",
    );
  }
}

