 */
function nomenclature(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  const start = CONFIG.func.start();
  const script = nomenclature.name;

  try {
    const {
      contentApi,
      request,
      sheetName,
      formulas = [],
      api = true,
      raw = false,
      emptyCols,
      setHead,
      // rangeStore,
      debug = context?.debug,
      showHosts = false,
    } = options;

    if (showHosts) return console.log(new GenerateUrl()._host());

    const formats = CONFIG.formats;
    const nomenclature = CONFIG.methods.content.cards;
    const shName = sheetName || nomenclature.sheet;
    const sheet = setSheetNew(shName, nomenclature.sheetColor, ss);

    let headers = nomenclature.header;
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    const cards = contentApi.list(request || {});
    const commission = new Tariffs({ apiKey: contentApi.apiKey }).commission();

    function transformSubjectData(dataArray) {
      return dataArray.reduce((acc, item) => {
        if (item.subjectID) {
          acc[item.subjectID] = {
            // subjectName: item.subjectName,
            // categoryId: item.parentID,
            categoryName: item.parentName,
          };
        }
        return acc;
      }, {});
    }

    const subjectData = transformSubjectData(commission);

    if (debug) {
      console.log(
        "Cards:",
        cards.length
          ? JSON.stringify(cards[0]?.wholesale, null, 2)
          : JSON.stringify(cards, null, 2),
      );
    }

    debugSaveFileToDrive(`nomenclatureCards`, cards);

    if (!cards.length) {
      setSheetHead(sheet);
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    sheetClear({ sheet });
    sheet.appendRow(headers);

    const updated = dateStrToFormatDate(new Date(), formats.datehhmm);

    let store;
    const goods = [];
    let isStore = false;

    // const sheetSettingsName = CONFIG.settings.sheetSettings;
    // const s_value = setSheetNew(sheetSettingsName, "BLACK", ss)
    //   .getRange(rangeStore || CONFIG.settings.settings.main.range.nomenclature)
    //   .getValue();

    cards.forEach((el, i) => {
      const imtId = el?.imtID;
      const nmId = el?.nmID;
      const vendorCode = el?.vendorCode;
      const title = el?.title;
      const subjectName = el?.subjectName;
      const subjectId = el?.subjectID;
      const brand = el?.brand;
      const tags = el?.tags ? el.tags.map(({ name }) => name).join(", ") : null;
      const { enabled, quantum } = el?.wholesale || {};

      const createdAt = dateStrToFormatDate(el?.createdAt, formats.datehhmm);
      const updateAt = dateStrToFormatDate(el?.updatedAt, formats.datehhmm);

      if (nmId && !isStore) {
        const sl_value = communicationsApi({
          apiKey: contentApi.apiKey,
        }).sellerInfo();

        store =
          // s_value
          //   ? s_value
          //   :
          sl_value?.tradeMark ? sl_value.tradeMark : sl_value?.name;

        if (store) isStore = true;
      }

      const { length, width, height, isValid, weightBrutto } = el?.dimensions;
      const volume =
        (length / 100 || 0) * (width / 100 || 0) * (height / 100 || 0) * 1000;

      const video = el?.video || null;
      const photos = el?.photos
        ? el.photos.map((item) => item?.big).join("\n")
        : null;

      const countPhotos = el?.photos?.length || 0;
      const photoImage = el?.photos ? el.photos[0]?.c246x328 : null;

      const image = !photoImage
        ? null
        : // : raw
          // ? photoImage
          `=HYPERLINK("https://www.wildberries.ru/catalog/"&${nmId}&"/detail.aspx";IMAGE("${photoImage}"))`;

      if (debug)
        photoImage
          ? null
          : console.log(
              "MEDIA NOT FOUND",
              nmId,
              JSON.stringify(el?.photos, null, 4),
            );

      function getVatValue(charElement, charName, charId) {
        // Проверяем наличие массива characteristics
        if (!charElement?.characteristics) {
          return null; // Возвращаем null, если нет характеристик
        }

        // Ищем элемент
        const foundItem = charElement.characteristics.find(
          (item) => item?.name === charName || item?.id === charId,
        );

        // Если find вернул undefined (элемент не найден), возвращаем null.
        // Иначе возвращаем найденный элемент.
        return foundItem === undefined ? null : foundItem;
      }

      const colorsObject = getVatValue(el, "Цвет", 14177449);
      const vatObject = getVatValue(el, "Ставка НДС", 15001405);

      if (debug) console.log(nmId, colorsObject, vatObject);

      const colors = colorsObject?.value ? colorsObject.value.join(", ") : null;
      const vat = vatObject?.value ? vatObject.value[0] : null;

      const sizes = el?.sizes;

      if (debug)
        console.log({ nmId: nmId, sizes: JSON.stringify(sizes, null, 2) });

      if ((sizes && sizes.length === 0) || !sizes) {
        goods.push([
          image,
          imtId,
          nmId,
          vendorCode,
          null,
          null,
          null,
          colors,
          title,
          subjectName,
          brand,
          createdAt,
          updateAt,
          length,
          width,
          height,
          volume,
          isValid,
          `https://www.wildberries.ru/catalog/${nmId}/detail.aspx`,
          updated,
          store,
          photoImage,
          photos,
          countPhotos,
          video,
          tags,
          vat,
          weightBrutto,
          enabled,
          quantum,
          subjectData[subjectId]?.categoryName,
        ]);
      } else {
        sizes.map((e) => {
          const techSize = e?.techSize;
          const chrtId = e?.chrtID;
          if (!e?.skus)
            goods.push([
              image,
              imtId,
              nmId,
              vendorCode,
              null,
              chrtId,
              techSize,
              colors,
              title,
              subjectName,
              brand,
              createdAt,
              updateAt,
              length,
              width,
              height,
              volume,
              isValid,
              `https://www.wildberries.ru/catalog/${nmId}/detail.aspx`,
              updated,
              store,
              photoImage,
              photos,
              countPhotos,
              video,
              tags,
              vat,
              weightBrutto,
              enabled,
              quantum,
              subjectData[subjectId]?.categoryName,
            ]);
          else
            e.skus.map((sku) => {
              goods.push([
                image,
                imtId,
                nmId,
                vendorCode,
                sku,
                chrtId,
                techSize,
                colors,
                title,
                subjectName,
                brand,
                createdAt,
                updateAt,
                length,
                width,
                height,
                volume,
                isValid,
                `https://www.wildberries.ru/catalog/${nmId}/detail.aspx`,
                updated,
                store,
                photoImage,
                photos,
                countPhotos,
                video,
                tags,
                vat,
                weightBrutto,
                enabled,
                quantum,
                subjectData[subjectId]?.categoryName,
              ]);
            });
        });
      }
    });

    if (!goods.length) {
      setSheetHead(sheet);
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    if (debug) goods.map((item, i) => console.log(item.length, i, "\n", item));
    // addDataToSheet({
    addDataToSheetOptimized({
      fromRow: 0,
      lastRow: 1,
      result: goods,
      sheet,
      api,
      raw,
      setHead,
      script,
      start,
    });

    sheet
      .getRangeList(nomenclature.rangeDate)
      .setNumberFormat(formats.datehhmm);

    if (!raw)
      sheet.getRangeList(nomenclature.rangeText).setNumberFormat(formats.text);

    if (raw) {
      fixFormulasInColumn(shName, "A", 2);
