/**
 * Функция nomenclatureUniqueNmIds получает уникальные nmID из списка элементов, полученных от contentApi.
 * @param {Object} contentApi - объект, предоставляющий доступ к списку элементов
 * @param {Object} pricesDiscountsApi - объект, предоставляющий доступ к списку элементов
 * @param {Object} options - объект с опциями, по умолчанию { withPhoto: 1 }
 * @param {number} options.chunks - количество частей, на которые нужно разделить список nmID
 * @returns {Array} - массив уникальных nmID, возможно, разделенный на части
 */
function nomenclatureUniqueNmIds(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  const {
    contentApi,
    pricesDiscountsApi,
    chunks = 1000,
    withPhoto = 1,
  } = options;

  options.withPhoto = withPhoto;

  let nmIdsList = [];
  if (contentApi) {
    nmIdsList = contentApi.list(options).map(({ nmID }) => nmID);
  } else if (pricesDiscountsApi) {
    nmIdsList = pricesDiscountsApi.list({}).map(({ nmID }) => nmID);
  }

  const uniqueNmIds = [...new Set(nmIdsList)];

  if (chunks && chunks > 0) return chunkArray(uniqueNmIds, chunks);
  return uniqueNmIds;
}

