function fromZip(jsonData) {
  let result = [];

  var fileName = jsonData.fileName;
  var extension = jsonData.extension;
  var document = jsonData.document;

  var bytes = Utilities.base64Decode(document);
  var blob = Utilities.newBlob(bytes, "application/zip");

  var file = DriveApp.createFile(blob);
  file.setName(fileName);
  file.setDescription("Zip file");

  Logger.log("File saved to Google Drive: " + file.getUrl());

  const files = getZipFileContents(blob);
  console.log(JSON.stringify(files, null, 5));
  files.forEach((report, item) => {
    console.log(`Report ${item + 1} of ${files.length}`);
    // let data = parseCsv(report.content, ";");
    // result.push(...data);
  });

  return result;
}

