/**
 * @typedef {{
 *   feedbacksApi: FeedbacksQuestions; // объект класса FeedbacksQuestions
 *   isAnswered: boolean;
 *   take: number;
 *   skip: number;
 *   dateFrom: string;
 *   dateTo: string;
 *   sheetName?: string; // название листа для вставки данных
 *   emptyCols?: boolean; // удалить пустые столбцы
 * }} FeedbacksQuestionsOptions
 */

/**
 * Список вопросов (отвеченные)
 * @param {FeedbacksQuestionsOptions} [options] параметры запроса
 */
function questionsList(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  const start = CONFIG.func.start();
  const script = questionsList.name;

  try {
    const {
      feedbacksApi,
      dateFrom,
      dateTo,
      isAnswered = true,
      additionalInfo,
      timeZone,
      formulas = [],
      emptyCols,
    } = options;

    const tz = timeZone || CONFIG.settings.time.timeZone;
    const dateFormat = CONFIG.formats;
    const main = CONFIG.methods.fq.questions.list;

    const sheet = setSheetNew(
      isAnswered ? main.sheet : main.sheetUnanswered,
      main.sheetColor,
      ss,
    );

    const { header, headerStat } = main;
    let headers = additionalInfo ? headerStat : header;
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    setSheetHead(sheet, true);
    sheet.appendRow(headers);

    const response = feedbacksApi.questionsList({
      isAnswered,
      dateFrom: dateFrom ? dateMoscow(dateFrom) : "2023-01-01",
      dateTo: dateTo ? dateMoscow(dateTo, 1) : addDays(1),
    });

    debugLog("Ответ:", response);

    let result = response.map((question) => {
      const {
        id,
        text,
        createdDate,
        state,
        answer,
        productDetails,
        wasViewed,
      } = question;

      const formattedDate = dateStrToFormatDate(
        createdDate,
        dateFormat.datehhmm,
        tz,
      );

      const formattedAnswerDate = dateStrToFormatDate(
        answer?.createDate,
        dateFormat.datehhmm,
        tz,
      );

      return [
        id,
        formattedDate,
        FeedbacksStates[state],
        text ? text?.trim() : null,
        answer?.text ? answer?.text?.trim() : null,
        answer?.editable,
        formattedAnswerDate,
        // productDetails.imtId,
        productDetails.nmId,
        productDetails.supplierArticle,
        productDetails.productName,
        // productDetails.supplierName,
        productDetails.brandName,
        wasViewed ? "Да" : "Нет",
      ];
    });

    if (!result.length > 0)
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });

    debugLog("Обработанный:", result);

    sheet
      .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
      .setValues(result);

    setVerticalAlignmentWrapStrategy(sheet, main.rangeFormatted);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Вопросы получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

