function feedbacksPreparation(feedbacksApi, options) {
  const {
    start,
    script,
    isAnswered,
    dateFrom,
    dateTo,
    isNegative,
    timeZone,
    stat,
    sheetName,
    main,
    reasons,
    formulas = [],
    setHead = true,
    emptyCols,
  } = options;

  const tz = timeZone || CONFIG.settings.time.timeZone;
  const dateFormat = CONFIG.formats;

  const { header, headerStat } = main;
  const sheet = setSheetNew(sheetName, main.sheetColor, ss);

  let headers = stat ? headerStat : header;
  if (formulas.length > 0) {
    headers = headers.concat(formulas);
  }

  setSheetHead(sheet, true);
  sheet.appendRow(headers);

  // const valuations = feedbacksApi.feedbacksValuationsFeedback();
  // if (debug) console.log(JSON.stringify(valuations, null, 2));

  const response /** @type {Wilberries.Feedbacks}*/ =
    feedbacksApi.feedbacksList({
      isAnswered,
      dateFrom: dateFrom ? dateMoscow(dateFrom) : "2023-01-01",
      dateTo: dateTo ? dateMoscow(dateTo, 1) : addDays(1),
    });

  debugLog("Ответ:", response);

  let result = response.map((feedbak) => {
    const {
      id,
      pros,
      cons,
      userName,
      text,
      matchingSize,
      productValuation,
      createdDate,
      state,
      answer,
      productDetails,
      photoLinks,
      video,
      wasViewed,
      isAbleSupplierFeedbackValuation,
      // supplierFeedbackValuation,
      isAbleSupplierProductValuation,
      // supplierProductValuation,
      isAbleReturnProductOrders,
      returnProductOrdersDate,
      bables,
      lastOrderShkId,
      lastOrderCreatedAt,
      // color,
      // subjectId,
      subjectName,
      // parentFeedbackId,
      // childFeedbackId,
      orderStatus,
    } = feedbak;

    const formattedDate = dateStrToFormatDate(
      createdDate !== "0001-01-01T00:00:00Z" ? createdDate : null,
      dateFormat.datehhmm,
      tz,
    );

    const formattedLastOrderCreatedAt = dateStrToFormatDate(
      lastOrderCreatedAt !== "0001-01-01T00:00:00Z" ? lastOrderCreatedAt : null,
      dateFormat.datehhmm,
      tz,
    );

    const formattedReturnProductOrdersDate = dateStrToFormatDate(
      returnProductOrdersDate !== "0001-01-01T00:00:00Z"
        ? returnProductOrdersDate
        : null,
      dateFormat.datehhmm,
      tz,
    );

    const date = dateStrToFormatDate(createdDate, dateFormat.date, tz);

    const fullSizePhotos = photoLinks
      ?.map((photo) => photo.fullSize)
      .join(",\n");

    const feedback_ = [
      id,
      formattedDate,
      text ? text?.trim() : null,
      productValuation,
      pros,
      cons,
      userName,
      FeedbacksStates[state],
      answer?.text ? answer.text?.trim() : null,
      FeedbacksAnswers[answer?.state],
      lastOrderShkId,
      formattedLastOrderCreatedAt,
      subjectName,
      // productDetails.imtId,
      productDetails.nmId,
      productDetails.supplierArticle,
      productDetails.productName,
      // productDetails.supplierName,
      productDetails.brandName,
      productDetails.size,
      FeedbacksMatchingSize[matchingSize],
      fullSizePhotos,
      video?.uri,
      wasViewed ? "Да" : "Нет",
      isAbleSupplierFeedbackValuation,
      // reasons[supplierFeedbackValuation] || supplierFeedbackValuation,
      isAbleSupplierProductValuation,
      // valuations?.productValuations[supplierProductValuation],
      isAbleReturnProductOrders,
      formattedReturnProductOrdersDate,
      Array.isArray(bables) ? bables.join(",\n") : null,
      FeedbacksOrderStatus[orderStatus],
    ];

    if (stat) {
      const date_ = new Date(createdDate);
      const year = date_.getFullYear();
      const month = date_.getMonth() + 1;
      const weekNum = getWeekNumber(date_);
      const weekNumISO = getISOWeekNumber(date_);
      const hour = date_.getHours();
      feedback_.push(date, year, month, weekNum, weekNumISO, hour);
    }

    return feedback_;
  });

  if (isNegative) result = result.filter((el) => el[3] < 5);

  debugLog("Обработанный:", result);

  if (!result.length > 0)
    return CONFIG.func.endScript({
      script,
      start,
      message: "Нет данных",
      messageType: 2,
    });

  // sheet
  //   .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
  //   .setValues(result);

  const lastRowStats = sheet.getLastRow();
  const fromRowStats = lastRowStats;
  addDataToSheetOptimized({
    fromRow: fromRowStats,
    lastRow: lastRowStats,
    result: result,
    sheet,
    api: true,
    raw: false,
    script,
    start,
    setHead,
  });

  setVerticalAlignmentWrapStrategy(sheet, main.rangeFormatted);

  CONFIG.func.endScript({
    script,
    start,
    sheet,
    message: "Отзывы получили",
    emptyCols,
    runFunc: options?.runFunc,
  });
}

/**
 * Ответить на отзыв
 * @param {FeedbacksQuestionsOptions} [options] параметры запроса
 */
function feedbacksAnswer(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  const start = CONFIG.func.start();
  const script = feedbacksAnswer.name;

  try {
    const {
      feedbacksApi,
      sheetName,
      idIndex = 0,
      textIndex = 8,
      resultColumn = 10,
      debug = context?.debug,
    } = options;

    const main = CONFIG.methods.fq.feedbacks.list;

    const sheet = setSheetNew(
      sheetName || main.sheetUnanswered,
      main.sheetColor,
      ss,
    );

    const answers = sheet
      .getDataRange()
      .getValues()
      .slice(1)
      .filter((e) => e[idIndex] && e[textIndex])
      .map((e) => [e[idIndex], e[textIndex]]);

    if (!answers.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Не заполнены ответы",
        messageType: 2,
      });
    }

    answers.forEach(([id, text], i) => {
      // if (debug) console.log({ i: i + 1, id, text });
      const result = feedbacksApi.feedbacksAnswerFeedback({ id, text });
      if (debug) console.log({ i: i + 1, id, text, result });
      sheet.getRange(i + 2, resultColumn).setValue(result);
      // sheet.getRange(i + 2, resultColumn).setValue("Ok");
    });

    CONFIG.func.endScript({
      script,
      start,
      message: "Ответили на вопросы",
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

