        video?.uri,
        wasViewed ? "Да" : "Нет",
        isAbleSupplierFeedbackValuation,
        // reasons[supplierFeedbackValuation] ||
        //   valuations?.feedbackValuations[supplierFeedbackValuation],
        //  || supplierFeedbackValuation,
        isAbleSupplierProductValuation,
        // valuations?.productValuations[supplierProductValuation],
        isAbleReturnProductOrders,
        formattedReturnProductOrdersDate,
        Array.isArray(bables) ? bables.join(",\n") : null,
        FeedbacksOrderStatus[orderStatus],
      ];

      if (stat) {
        const date_ = new Date(createdDate);
        const year = date_.getFullYear();
        const month = date_.getMonth() + 1;
        const weekNum = getWeekNumber(date_);
        const weekNumISO = getISOWeekNumber(date_);
        const hour = date_.getHours();
        feedback_.push(date, year, month, weekNum, weekNumISO, hour);
      }

      return feedback_;
    });

    if (isNegative) result = result.filter((el) => el[3] < 5);

    if (!result.length > 0)
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });

    debugLog("Обработанный:", result);

    addDataToSheet({
      result,
      fromRow,
      lastRow,
      sheet,
      api,
      raw,
      setHead,
      script,
      start,
      debug,
    });

    // sheet
    //   .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
    //   .setValues(result);

    setVerticalAlignmentWrapStrategy(sheet, main.rangeFormatted);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Список архивных отзывов получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

