    ) {
      const requestError = {
        name: "RequestError",
        message: `Получить данные можно с 2025-01-01, передано ${dateFrom} - ${dateTo}, измените период.`,
      };
      throw new Error(typeError(requestError, this.constructor.name));
    }

    const { financeApi, period, formulas = [], emptyCols } = options;
    const formats = CONFIG.formats;
    const finance = CONFIG.methods.finance;
    const main = finance.salesReports.list;

    sheetName =
      sheetName ??
      (period === FinanceSalesReportPeriod.WEEKLY
        ? main.sheetWeekly
        : main.sheetDaily);

    const sheet = setSheetNew(sheetName, finance.sheetColor, ss);

    const header = main.header;
    let headers = Object.values(header);
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
