    setSheetHead(sheet, true);
    sheet.appendRow(headers);

    console.log(
      `Период запроса: ${dateFrom} по ${dateTo ? dateTo : "воскресенье"}`,
    );

    const response = financeApi.salesReportsList(options);
    debugSaveFileToDrive(script, response);
    debugLog("Ответ:", response);

    if (!response.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const reportType = main.reportType;
    const floatFields = main.floatFields;

    const result = response.map((item) => {
      return Object.keys(header).reduce((acc, key) => {
        let value = item[key];
        if (key === "reportType") value = reportType[value] || value;
        if (floatFields.includes(key)) {
          value = isNumeric(value) ? Number(value) : value;
        }
        return [...acc, value];
      }, []);
    });

    debugLog("Обработанный:", result);
    sheet
      .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
      .setValues(result);

    sheet.getRangeList(main.rangeDate).setNumberFormat(formats.date);

    CONFIG.func.endScript({
      script,
