/**
 * Детализация отчётов о реализации
 * @param {object} [options] параметры запроса
 */
function financeSalesReportsDetailed(
  options = context?.config?.getConfigForCurrentFunction(),
) {
  const start = CONFIG.func.start();
  const script = financeSalesReportsWeekly.name;

  try {
    let { sheetName, dateFrom, dateTo } = options;

    if (
      new Date(dateFrom) < new Date("2024-01-29") ||
      new Date(dateTo) < new Date("2024-01-29")
    ) {
      const requestError = {
        name: "RequestError",
        message: `Получить данные можно с 2024-01-29, передано ${dateFrom} - ${dateTo}, измените период.`,
      };
      throw new Error(typeError(requestError, this.constructor.name));
    }

    const {
      financeApi,
      limit,
      period,
      fields,
      excludeRefund = false,
      excludeOperationNames = [
        "Возмещение издержек по перевозке/по складским операциям с товаром",
        "Возмещение за выдачу и возврат товаров на ПВЗ",
        "Компенсация скидки по программе лояльности",
      ],
      accumulate = false,
      lastDateColumn = 1, // колонка createDate
      setFilter = false,
      deleteEmpty = true,
      formulas = [],
    } = options;

    const formats = CONFIG.formats;
    const finance = CONFIG.methods.finance;
    const main = finance.salesReports.detailed;

    sheetName =
      sheetName ??
      (period === FinanceSalesReportPeriod.WEEKLY
        ? main.sheetWeekly
        : main.sheetDaily);

    const builder = requestBuilder.setSheetName(sheetName);

    const header = main.headerMin;
    let headers = Object.values(header);
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    const { headersRange, headerChar } = builder.headersRange(headers);

    let { lastRow, lastChangeDate } = builder.getDataBounds(
      accumulate ? lastDateColumn : null,
    );

    if (accumulate && lastRow > 0 && lastChangeDate) {
      dateFrom = lastChangeDate;
      if (dateTo && new Date(dateTo) < new Date(dateFrom)) dateTo = null;
    }

    console.log(
      `Период запроса: ${dateFrom} по ${dateTo ? dateTo : "воскресенье"}`,
    );

    const response = financeApi.salesReportsDetailed({
      dateFrom,
      dateTo,
      period,
      fields: fields?.length ? fields : main.fieldsMin,
      limit,
    });

    debugSaveFileToDrive(script, response);
    debugLog("Ответ:", response);

    const keys = Object.keys(header);
    const floatFields = main.floatFields;
    const result = response
      .filter((item) => {
        if (
          excludeRefund &&
          Array.isArray(excludeOperationNames) &&
          excludeOperationNames.includes(item.sellerOperName)
        )
          return false;
        return true;
      })
      .map((item) => {
        const sellerOperName = item.sellerOperName;
        const docTypeName = item.docTypeName;

        // Исправление знака у возвратов
        if (docTypeName?.toLowerCase() === "возврат") {
          item.quantity = -1 * item?.quantity;
          item.retailPrice = -1 * item?.retailPrice;
          item.retailAmount = -1 * item?.retailAmount;
          item.retailPriceWithDisc = -1 * item?.retailPriceWithDisc;
          item.ppvzSalesCommission = -1 * item?.ppvzSalesCommission;
          item.forPay = -1 * item?.forPay;
          item.ppvzReward = -1 * item?.ppvzReward;
          item.vw = -1 * item?.vw;
          item.vwNds = -1 * item?.vwNds;
        }

        if (!["Продажа", "Логистика", "Возврат"].includes(sellerOperName)) {
          item.orderDt = null;
          item.saleDt = null;
        }

        return keys.map((key) => {
          let value = item[key] ?? "";
          if (floatFields.includes(key))
            value = isNumeric(value) ? Number(value) : value;

          if (["orderDt", "saleDt"].includes(key))
            value = dateStrToFormatDate(value);

          if (
            ["giId", "stickerId", "nmId", "shkId"].includes(key) &&
            (!value || value === "0")
          )
            value = null;

          return value;
        });
      });

    debugLog("Обработанный:", result);

    builder.createSheetIfNotExist({
      rowCount: result.length || 1000,
      columnCount: headers.length,
      frozenRowCount: 1,
      tabColor: finance.sheetColor,
    });

    if (!accumulate) {
      builder.executeValuesClear();
    }

    lastRow = builder.getDataBounds().lastRow;
    if (lastRow === 0) {
      builder
        .setRange(headersRange)
        .setValues([headers])
        .setValueInputOption(ValueInputOption.USER_ENTERED)
        .setInsertDataOption(InsertDataOption.OVERWRITE)
        .executeValuesAppend();

      builder.refreshSheetMetadata();
    }

    if (!result.length) {
      console.log("📝 Нет данных...");
      builder.resetSheetName();
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const { needsMoreRows, dataRowsToAdd, rowsToAdd, targetStartRow } =
      builder.checkRowsNeeded(sheetName, result.length, accumulate);

    if (needsMoreRows) {
      console.log(`📝 Добавляем ${rowsToAdd} строк...`);
      builder.requestAddRowsAtEnd(rowsToAdd);
      builder.execute();
      builder.refreshSheetMetadata();
    }

    if (!accumulate) {
      builder.setRange(`A2:${headerChar}${dataRowsToAdd + 1}`);
    } else {
      builder.setRange(
        `A${targetStartRow}:${headerChar}${targetStartRow + dataRowsToAdd - 1}`,
      );
    }

    console.log("📝 Вставляем данные:", result.length);
    builder
      .setValueInputOption(ValueInputOption.USER_ENTERED)
      .createAndSendBatches(result, sheetName, targetStartRow);
    builder.refreshSheetMetadata();

    if (deleteEmpty) {
      const deleteResponse = builder.requestDeleteEmptyRowsAndColumns();
      if (deleteResponse.resource) {
        console.log("📝 Удаляем пустые строки и столбцы...");
        builder.execute();
      }
    }

    if (setFilter) {
      console.log("📝 Устанавливаем фильтр...");
      builder.requestSetFilter();
      builder.execute();
    }

    builder.resetSheetName();

    CONFIG.func.endScript({
      script,
      start,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

