/**
 * @typedef {{
 *   marketplaceApi: объект класса Marketplace
 *   dateFrom?: string;
 *   dateTo?: string;
 *   cut?: boolean; // без информации о клиенте
 *   sheetName?: string; // название листа для вставки данных
 *   oneBar?: boolean; // одинарный бар-код
 *   supplierStatus?: Array.<string>; // статус сборочного задания
 *   wbStatus?: Array.<string>; // wbStatus: статус в системе WB
 *   rangeSku?: Array.<string>; // столбц с бар-кодами
 *   api?: boolean; // использовать Sheets API v4
 *   raw?: boolean; // вставлять данные в RAW формате
 *   emptyCols?: boolean;
 * }} OrdersOptions
 */

/**
 * Получить информацию по сборочным заданиям
 * @see https://openapi.wb.ru/#tag/Marketplace-Sborochnye-zadaniya/paths/~1api~1v3~1orders/get
 * @param {OrdersOptions} [options] параметры запроса
 */
function ordersFbs(options = context?.config?.getConfigForCurrentFunction()) {
  const start = CONFIG.func.start();
  const script = ordersFbs.name;

  try {
    const {
      marketplaceApi,
      sheetName,
      cut,
      api = true,
      raw = true,
      oneBar,
      wbStatus,
      supplierStatus,
      rangeSku,
      getOrdersStatuses = true,
      formulas = [],
      setHead,
      emptyCols = false,
      debug = context?.debug,
    } = options;

    const formats = CONFIG.formats;
    const main = CONFIG.methods.marketplace.orders;
    const ordersAll = main.all;
    const shName = sheetName || ordersAll.sheet;
    const sheet = setSheetNew(shName, main.sheetColor, ss);

    sheetClear({ sheet });

    let headers = Object.values(cut ? ordersAll.headerShort : ordersAll.header);
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    sheet.appendRow(headers);

    const days = getDatesWithInterval(
      options.dateFrom,
      options?.dateTo || addDays(1)
    );

    console.log(days);

    let response = [];
    days.forEach(([dateFrom, dateTo]) => {
      console.log(`Запрос ${dateFrom} - ${dateTo}`);

      response.push(
        ...marketplaceApi.ordersFbs({ dateFrom, dateTo }),
        // ...marketplaceApi.ordersDbs({ dateFrom, dateTo })
      );
    });

    console.log("Получено всего заказов:", response.length);

    if (debug) console.log(JSON.stringify(response, null, 2));

    if (response.length) {
      let ordersStatuses = {};

      if (getOrdersStatuses) {
        const ordersId = response.map((el) => el?.id);
        const chunkId = chunkArray(ordersId, 1000);

        let tmp = [];
        chunkId.map((item) => {
          tmp.push(
            ...marketplaceApi.ordersFbsStatus(item),
          );
        });

        ordersStatuses = tmp.reduce((acc, { id, supplierStatus, wbStatus }) => {
          return {
            ...acc,
            [id]: {
              supplierStatus: main.supplierStatus[supplierStatus],
              wbStatus: main.wbStatus[wbStatus],
            },
          };
        }, {});
      }

      let result = response.map((el) => {
        const commonFields = [
          el.id,
          el.rid,
          dateStrToFormatDate(el?.createdAt, formats.datehhmm),
          ordersStatuses[el.id]?.supplierStatus || null,
          ordersStatuses[el.id]?.wbStatus || null,
          el.warehouseId,
          el.supplyId,
          el?.offices ? el.offices.join("; ") : null,
          el?.price ? el.price / 100 : 0,
          el.convertedPrice ? el.convertedPrice / 100 : 0,
          el.currencyCode,
          el.convertedCurrencyCode,
          el.orderUid,
          el.deliveryType,
          el.nmId,
          el.article,
          el.chrtId,
          oneBar ? String(el?.skus[0]) : el?.skus?.join("; "),
          el?.colorCode || null,
          CargoType[el?.cargoType] || el?.cargoType,
          el?.scanPrice ? el.scanPrice / 100 : 0,
          el.isZeroOrder,
          el.options.isB2B,
          el?.comment || null,
          el?.officeId || null,
        ];

        if (cut) {
          return commonFields;
        } else {
          return [
            ...commonFields,
            el?.address?.fullAddress,
            el?.address?.longitude,
            el?.address?.latitude,
          ];
        }
      });

      if (supplierStatus)
        result = result.filter((e) => supplierStatus.includes(e[3]));
      if (wbStatus) result = result.filter((e) => wbStatus.includes(e[4]));

      if (result && result.length > 0) {
        addDataToSheet({
          fromRow: 0,
          lastRow: 1,
          result,
          sheet,
          api,
          raw,
          script,
          start,
          setHead,
          debug,
