/**
 * @typedef {{
 *   marketplaceApi: объект класса Marketplace
 *   oneBar?: boolean; // одинарный бар-код
 *   header?: object;
 *   sheetName?: string;
 *   api?: boolean;
 *   raw?: boolean;
 *   json?: boolean;
 *   clearPasteRange?: string;
 *   emptyCols?: boolean;
 * }} OrdersNewOptions
 */

/**
 * Получить список новых сборочных заданий
 * @see https://openapi.wb.ru/#tag/Marketplace-Sborochnye-zadaniya/paths/~1api~1v3~1orders~1new/get
 * @param {OrdersNewOptions} [options] параметры запроса
 */
function ordersFbsNew(
  options = context?.config?.getConfigForCurrentFunction()
) {
  const start = CONFIG.func.start();
  const script = ordersFbsNew.name;

  try {
    const {
      marketplaceApi,
      header,
      sheetName,
      json,
      formulas = [],
      oneBar,
      emptyCols,
      debug = context?.debug,
    } = options;

    const formats = CONFIG.formats;
    const main = CONFIG.methods.marketplace.orders.new;
    const shName = sheetName || main.sheet;
    const sheet = setSheetNew(shName, main.sheetColor, ss);

    setSheetHead(sheet, true);

    let headers = Object.values(header || main.header);
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    sheet.appendRow(headers);
    const jsonData = [
      ...marketplaceApi.ordersFbsNew(),
      // ...marketplaceApi.ordersDbsNew(),
    ];

    if (debug) console.log(JSON.stringify(jsonData, null, 2));

    if (json) return jsonData;

    const result = jsonData.map((item) => {
      const keys = header ? header : main.header;
      return Object.keys(keys).reduce((acc, key) => {
        let value = item[key];
        if (["createdAt", "ddate", "dTimeFrom", "dTimeTo"].includes(key)) {
          value = dateStrToFormatDate(value, formats.datehhmm);
        }

        if (["offices", "requiredMeta"].includes(key)) {
          value = value?.join("; ");
        }

        if (key === "skus") {
          value = oneBar ? String(value[0]) : value?.join("; ");
        }

        if (["price", "convertedPrice", "salePrice"].includes(key)) {
          value = value / 100;
        }

        if (key === "quantity") {
          value = 1;
        }

        if (key === "cargoType") {
          value = CargoType[value] || value;
        }

        if (key === "isB2B") {
          value = item.options.isB2B;
        }

        if (
          ["fullAddress", "longitude", "latitude"].includes(key) &&
          item?.address
        ) {
          value = item.address[key];
        }

        return [...acc, value];
      }, []);
    });

    if (result && result.length) {
      sheet
        .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
        .setValues(result);

      sheet.getRangeList(main.formatRange).setNumberFormat(formats.date);

      CONFIG.func.endScript({
        script,
        start,
        sheet,
        emptyCols,
        message: "Заказы получили",
        runFunc: options?.runFunc,
      });
    } else {
      CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

function getDatesWithInterval(startDate, endDate) {
  const dates = [];
  const oneDay = 24 * 60 * 60 * 1000; // количество миллисекунд в одном дне

  startDate = new Date(startDate); // преобразование строки даты начала в объект Date
  endDate = new Date(endDate); // преобразование строки даты окончания в объект Date

  // функция для преобразования объекта Date в timestamp с смещением в 3 часа
  function dateToTimestampWithOffset(date, endOfDay = false) {
    const offsetDate = new Date(date);
    if (endOfDay) {
      offsetDate.setHours(23, 59, 59, 999); // установка времени на конец дня
    } else {
      offsetDate.setHours(0, 0, 0, 0); // установка времени на начало дня
    }
    return Math.floor(offsetDate.getTime() / 1000); // возвращение timestamp
  }

  function dateToTimestampWithOffsetFirst(date) {
    const offsetDate = new Date(date);
    offsetDate.setHours(3, 0, 0, 0); // установка времени на начало дня
    return Math.floor(offsetDate.getTime() / 1000); // возвращение timestamp
  }

  // добавление дат с интервалом в 30 календарных дней в массив
  let currentDate = new Date(startDate.getTime());
  let isFirstElement = true;

  while (currentDate <= endDate) {
    const endIntervalDate = new Date(currentDate.getTime() + 29 * oneDay);

    // if (isFirstElement) {
    //   dates.push([dateToTimestampWithOffsetFirst(currentDate), dateToTimestampWithOffset(endIntervalDate, true)]);
    //   isFirstElement = false;
    // }

    dates.push([
      dateToTimestampWithOffset(currentDate),
      dateToTimestampWithOffset(endIntervalDate, true),
    ]);
    currentDate.setDate(currentDate.getDate() + 30);
  }

  return dates;
}

/**
 * @typedef {{
 *   marketplaceApi: объект класса Marketplace
