 *   sheetName?: string; // название листа для вставки данных
 *   sheetOrdersName?: string; // название листа c данными по заказам
 *   indexId?: number; // номер столбца с ID сборочного задания
 *   raw?: boolean; // вставлять данные в RAW формате
 *   emptyCols?: boolean;
 * }} OrdersStickersOptions
 */

/**
 * Получить этикетки для сборочных заданий
 * @see https://openapi.wb.ru/marketplace/api/ru/#tag/Sborochnye-zadaniya/paths/~1api~1v3~1orders~1stickers/post
 * @param {OrdersStickersOptions} [options] параметры запроса
 */
function ordersFbsStickers(
  options = context?.config?.getConfigForCurrentFunction()
) {
  const start = CONFIG.func.start();
  const script = ordersFbsStickers.name;

  try {
    const {
      marketplaceApi,
      type = "png", // тип этикетки
      sheetName,
      sheetOrdersName,
      indexId,
      emptyCols,
    } = options;

    const main = CONFIG.methods.marketplace.orders.sticker;
    const shName = sheetName || main.sheet;

    const sheet = setSheetNew(shName, main.sheetColor, ss);
    setSheetHead(sheet, true);
    sheet.appendRow(Object.values(main.header));

    const sheetData = sheet
      .getParent()
      .getSheetByName(
        sheetOrdersName || CONFIG.methods.marketplace.orders.all.sheet
      );

    let values = sheetData.getDataRange().getValues();

    if (sheetOrdersName)
      values = values.slice(1).map((col) => col[indexId || 0]);
    else
      values = values
        .filter((col) =>
          [
            // "В доставке",
            "На сборке",
          ].includes(col[3])
        )
        .map((col) => col[indexId || 0]);

    if (values && values.length) {
      let result = [];
      const chunk = chunkArray(values, 100);

      for (const orders of chunk) {
        marketplaceApi
          .ordersFbsStickers({ orders, ...options })
          .map(({ orderId, partA, partB, barcode, file }) => {
            // console.log(partA, partB);
            // partB = String(partB).padStart(4, "0");
            fileName = `${partB}_${partA}.${type}`;
            result.push([
              orderId,
              String(partA),
              String(partB),
              barcode,
              file,
              fileName,
            ]);
          });
      }

      if (result.length > 0) {
        sheet
          .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
          .setValues(result);

        CONFIG.func.endScript({
          script,
          start,
          sheet,
          message: "Этикетки получили",
          runFunc: options?.runFunc,
        });
      } else {
        CONFIG.func.endScript({
          script,
          start,
          message: "Нет данных",
          messageType: 2,
          emptyCols,
        });
      }
    } else {
      CONFIG.func.endScript({
        script,
        start,
        message: `Сборочных заданий в статусе "На сборке" нет, обновите "🛒 Заказы fbs"`,
        messageType: 2,
      });
    }
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

/**
