 */
function ordersFbsSetStickerId(
  options = context?.config?.getConfigForCurrentFunction()
) {
  const start = CONFIG.func.start();
  const script = ordersFbsSetStickerId.name;

  try {
    const {
      marketplaceApi,
      sheetName,
      indexId = 0,
      debug = context?.debug,
    } = options;

    const sheet = ss.getSheetByName(
      sheetName || CONFIG.methods.marketplace.orders.all.sheet
    );

    const rows = {};
    const values = sheet
      .getDataRange()
      .getValues()
      .slice(1)
      .map((col, index) => {
        const orderId = col[indexId];
        rows[orderId] = index + 2;
        return orderId;
      })
      .filter(Boolean);

    if (!values.length)
      CONFIG.func.endScript({
        script,
        start,
        message: `Сборочных заданий нет, обновите "🛒 Заказы FBS"`,
        messageType: 2,
        emptyCols,
      });

    const chunkedOrders = chunkArray(values, 100);

    const stickers = {};
    for (const orders of chunkedOrders) {
      const response = marketplaceApi.ordersFbsStickers({ orders, ...options });
      for (const { orderId, partA, partB } of response) {
        stickers[orderId] = String(partA) + String(partB);
      }
    }

    if (debug) console.log({ rows });
    if (debug) console.log({ stickers });

    // Обновляем лист с полученными наклейками
    const updates = [{ row: 1, sticker: "ID стикера" }];
    for (const orderId of values) {
      const row = rows[orderId];
      const sticker = stickers[orderId] || null; // Если наклейки нет, используем null
      updates.push({ row, sticker });
    }

    if (debug) console.log({ updates });

    const lastColumn = sheet.getLastColumn();
    const lc = lastColumn <= 25 ? lastColumn + 1 : lastColumn;

    // Если есть обновления, то вставляем их единым вызовом
    sheet.getRange(1, lc, sheet.getLastRow(), 1).clearContent();
    const range = sheet.getRange(1, lc, updates.length, 1);
    const valuesToUpdate = updates.map(({ sticker }) => [sticker]); // Формируем массив для вставки
    range.setValues(valuesToUpdate);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Этикетки получили",
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

