/**
 * Converts a base64 encoded string to a file and uploads it to Google Drive.
 * @param {string} base64String - The base64 encoded string representing the file data.
 * @param {string} fileName - The name of the file to be created on Google Drive.
 * @return {string} The ID of the created file on Google Drive.
 */
function base64ToFile(base64String, fileName) {
  var decodedData = Utilities.base64Decode(base64String);
  var blob = Utilities.newBlob(
    decodedData,
    "application/octet-stream",
    fileName
  );

  var file = DriveApp.createFile(blob);
  file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);

  return file.getId(); // id файла
}

