/**
 * @typedef {{
 *   marketplaceApi: Marketplace,
 *   contentApi: Content,
 *   pricesDiscountsApi?: PricesDiscounts,
 *   warehouse?: string;
 *   skus?: Array.<number>;
 *   sheetName?: string; // название листа для вставки данных
 *   notZero?: boolean; // остаток > 0
 *   update?: boolean; // true, добавить столбец для обновления
 *   stocksPrices?: boolean; //  true, получить отстаки и цены
 *   api?: boolean; // использовать Sheets API v4
 *   raw?: boolean; // вставлять данные в RAW формате
 *   emptyCols?: boolean;
 * }} StocksOptions
 */

/**
 * Получить остатки товаров
 * @see https://openapi.wb.ru/#tag/Marketplace-Ostatki/paths/~1api~1v3~1stocks~1{warehouse}/post
 * @param {StocksOptions} [options] параметры запроса
 */
function stocksFbs(options = context?.config?.getConfigForCurrentFunction()) {
  const start = CONFIG.func.start();
  const script = stocksFbs.name;

  try {
    const {
      notZero,
      sheetName,
      update,
      stocksPrices,
      formulas = [],
      api = true,
      raw = true,
      setHead,
      emptyCols,
      marketplaceApi,
      contentApi,
      pricesDiscountsApi,
      newStocksSheet = true,
    } = options;

    const formats = CONFIG.formats;

    const main = CONFIG.methods.marketplace.stocks.info;
    const shName = sheetName
      ? sheetName
      : update
      ? main.sheetUpdate
      : main.sheet;

    const sheet = setSheetNew(shName, main.sheetColor, ss);

    sheetClear({ sheet });

    if (update)
      rangeClear({
        sheet,
        dataValidations: true,
        clearRange: main.rangeDataValidations,
      });

    let headers = update
      ? main.headerUpdate
      : stocksPrices
      ? main.headerStocksPrices
      : main.header;

    if (update && newStocksSheet) {
      headers[10] = main.formula;
    }

    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    sheet.appendRow(headers);

    let pricesInfo = {};
    if (stocksPrices) {
      const prices = pricesDiscountsApi.list({});
      // debugLog("Ответ [prices]:", prices, 1);

      prices.flatMap(({ nmID: nmId, discount, sizes }) =>
        sizes.map(
          ({ sizeID: chrtId, price, discountedPrice: priceWithDiscount }) => {
            return (pricesInfo[chrtId] = {
              price,
              discount,
              priceWithDiscount,
              nmId,
            });
          }
        )
      );
      // debugLog("Обработанный [pricesInfo]:", pricesInfo, 1);
    }

    const cards = contentApi.list({ ascending: true, withPhoto: 1 });
    // debugLog("Ответ [cards]:", cards, 1);

    if (!cards.length) {
      setSheetHead(sheet);
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const chrtIds = [];
    const skusObject = {};
    cards.forEach((row) => {
      const nmId = row.nmID;
      const vendorCode = row.vendorCode;
      const title = row.title;

      row?.sizes.map((size) => {
        const chrtId = size.chrtID;
        chrtIds.push(chrtId);

        const { price, discount, priceWithDiscount } = pricesInfo[chrtId] || {};
        skusObject[chrtId] = {
          vendorCode,
          chrtId,
          nmId,
          title,
          price,
          discount,
          priceWithDiscount,
        };

        // size?.skus.map((sku) => {
        //   skusObject[chrtId] = {
        //     vendorCode,
        //     chrtId,
        //     sku,
        //     nmId,
        //     title,
        //     price,
        //     discount,
        //     priceWithDiscount,
        //   };
        // });
      });
    });

    // debugLog("Обработанный [skusObject]:", skusObject, 1);

    const chunkChrtIds = chunkArray(chrtIds, 1000);
    // debugLog("Обработанный [chunkChrtIds]:", chunkChrtIds);

    const whsSeller = marketplaceApi
      .warehousesSeller()
      .map(({ id, officeId, name }) => {
        return [id, officeId, name];
      });

    // debugLog("Ответ [whsSeller]:", whsSeller, 1);

    const whsWildberries = marketplaceApi
      .warehousesWildberries()
      .reduce((acc, { id, name }) => {
        return { ...acc, [id]: name };
      }, {});

    // debugLog("Ответ [whsWildberries]:", whsWildberries, 1);

    let stocksArray = [];
    whsSeller.forEach((item) => {
      chunkChrtIds.map((chrtIds) => {
        stocksArray = stocksArray.concat(
          marketplaceApi
            .stocksFbs({ warehouseId: item[0], chrtIds })
            .map((el) =>
              Object.assign(el, {
                warehouse: item[0],
                office: item[1],
                name: item[2],
              })
            )
        );
      });
    });

    debugLog("Ответ [stocksArray]:", stocksArray);

    if (!stocksArray.length) {
      setSheetHead(sheet);
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const updated = dateStrToFormatDate(new Date(), formats.datehhmm);

    let result = [];
    for (let i in stocksArray) {
      const chrtId = stocksArray[i].chrtId;
      const { nmId, vendorCode, title, price, discount, priceWithDiscount } =
        skusObject[chrtId];
      // } = skusObject[String(chrtId)];

      if (update)
        result.push([
          updated,
          stocksArray[i].office,
          whsWildberries[stocksArray[i].office],
          stocksArray[i].warehouse,
          stocksArray[i].name,
          nmId,
          vendorCode,
          // stocksArray[i].sku,
          chrtId,
          title,
          stocksArray[i].amount,
          null,
        ]);
      else if (stocksPrices) {
        result.push([
          updated,
          stocksArray[i].office,
          whsWildberries[stocksArray[i].office],
          stocksArray[i].warehouse,
          stocksArray[i].name,
          nmId,
          vendorCode,
          // stocksArray[i].sku,
          chrtId,
          title,
          stocksArray[i].amount,
          price || 0,
          discount || 0,
          priceWithDiscount || 0,
        ]);
      } else
        result.push([
          updated,
          stocksArray[i].office,
          whsWildberries[stocksArray[i].office],
          stocksArray[i].warehouse,
          stocksArray[i].name,
          nmId,
          vendorCode,
          // stocksArray[i].sku,
          chrtId,
          title,
          stocksArray[i].amount,
        ]);
    }

    if (notZero) result = result.filter((e) => e[9] > 0);
    debugLog("Обработанный:", result);

    if (!result.length) {
      setSheetHead(sheet);
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    addDataToSheetOptimized({
      fromRow: 0,
      lastRow: 1,
      result,
      sheet,
      api,
      raw,
      setHead,
      script,
      start,
    });

    if (update) {
      sheet
        .getRange(main.rangeCheckBox + sheet.getLastRow())
        .insertCheckboxes();

      const filter = sheet.getFilter();
      if (filter) filter.remove();
      if (sheet.getLastRow() > 1) {
        cropToRange(sheet.getDataRange());
        sheet.getDataRange().createFilter();
      }
      sheet.getRangeList(main.rangeFormat).setNumberFormat(formats.datehhmm);
      return;
    }

    sheet.getRangeList(main.rangeFormat).setNumberFormat(formats.date);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Остатки получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

/**
 * @typedef {{
 *   marketplaceApi: Marketplace,
 *   contentApi: Content,
 *   sheetName?: string; // название листа для вставки данных
 * }} StocksUpgradeOptions
 */

/**
 * Обновить остатки
 * @param {StocksUpgradeOptions} [options] параметры запроса
 */
function stocksFbsUpdate(
  options = context?.config?.getConfigForCurrentFunction()
) {
  const start = CONFIG.func.start();
  const script = stocksFbsUpdate.name;

  try {
    const { marketplaceApi, sheetName } = options;

    stocksFbs(options);

    SpreadsheetApp.flush();

    const main = CONFIG.methods.marketplace.stocks.info;

    const sheet = setSheetNew(sheetName || main.sheetUpdate, main.sheetColor);

    const values = sheet
      .getDataRange()
      .getValues()
      .slice(1)
      .reduce((acc, row) => {
        const warehouseId = row[3];
        const chrtId = row[7];
        const oldStock = row[9];
        const newStock = row[10];

        if (newStock >= 0 && newStock !== "" && newStock !== oldStock) {
          acc.push([warehouseId, chrtId, newStock]);
        }

        return acc;
      }, []);

    debugLog("Данные [values]:", { values });

    if (!values.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Остатки не добавлены",
        messageType: 2,
      });
    }

    const InfoMap = new Map();
    values.map((item) => {
      InfoMap.set(item[0], [
        ...(InfoMap.get(item[0]) || []),
        new ItemStocksUpdate([item[1], item[2]]),
