/**
 * Получить список складов WB
 * @param {object} [options] параметры запроса
 */
function warehousesWildberriesDistricts(apiKey) {
  try {
    const marketplace = new Marketplace({ apiKey });

    // marketplace.ping();

    const response = marketplace.warehousesWildberries();

    // Проверяем структуру ответа
    if (!response) {
      console.error("Неверная структура ответа API:", response);
      return {};
    }

    // Создаем объект маппинга складов на регионы
    const warehouseMapping = {};

    response.forEach((warehouse) => {
      const district =
        FederalDistricts[warehouse.federalDistrict] ||
        warehouse.federalDistrict;

      // Оптимизированная очистка названия склада
      let wh_name = warehouse?.name?.toLowerCase();

      // Извлекаем конкретное название склада из скобок для Москвы
      if (wh_name.includes("москва")) {
        const match = wh_name.match(/москва\s*\(([^)]+)\)/);
        if (match) {
          wh_name = match[1].toLowerCase().trim();
        } else {
          wh_name = "москва";
        }
      } else {
        // Улучшенное регулярное выражение для всех остальных вариантов названий складов
        wh_name = wh_name
          .toString()
          // Сначала заменяем дефис с числом на пробел + число (Смоленск - 2 -> Смоленск 2)
          .replace(/\s*-\s*(\d+)/gi, " $1")
          // Затем удаляем остальные паттерны
          .replace(/\s*(кгт\+?|сгт|_сгт|_кгт\+?|сц\s+)/gi, "")
          .replace(/\s+/g, " ") // убираем множественные пробелы
          .trim();
        // .split(" ")[0];
      }

      if (wh_name && district) {
        warehouseMapping[wh_name] = district;
      }
    });

    debugLog("Маппинг складов:", warehouseMapping);
    return warehouseMapping;
  } catch (error) {
    console.error(
      "Ошибка в warehousesWildberriesFederalDistricts:",
      error.stack
    );
    return {};
  }
}

