function priceHistory(
  options = context?.config?.getConfigForCurrentFunction()
) {
  const {
    pricesDiscountsApi,
    formulas = [],
    emptyCols,
    sheetName,
    debug = context?.debug,
  } = options;

  let { token } = options;

  if (!token) {
    const storage =
      context?.storage ||
      (service && setStorage({ service, serviceType: context?.serviceType })) ||
      null;

    token = storage.getProperty("SiteToken");
  }

  const timeZone = CONFIG.settings.time.timeZone;
  const format = CONFIG.formats.dateddmmyy;

  const urlGenerator = getUrlGenerator();

  const priceNms = pricesDiscountsApi.list({}).reduce((acc, { nmID }) => {
    return { ...acc, [nmID]: urlGenerator.priceHistory(nmID) };
  }, {});

  if (debug) console.log({ priceNms });

  const requestOptions = {
    headers: {
      "Content-Type": "application/json",
      "User-Agent":
        "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/140.0.0.0 Safari/537.36",
    },
    followRedirects: true,
    muteHttpExceptions: true,
  };

  if (token) requestOptions.headers.Authorization = `Bearer ${token}`;

  const result = [];
  for (const [nmId, url] of Object.entries(priceNms)) {
    // console.log({ nmId, url });
    try {
      const response = UrlFetchApp.fetch(url, requestOptions);
      const text = response.getContentText();

      if (response.getResponseCode() === 200) {
        const json = JSON.parse(text);
        // console.log({ nmId, url, json });

        // Проверка на массив
        if (Array.isArray(json)) {
          json.forEach(({ dt, price }) => {
            // Проверка на существование price.RUB
            // console.log("price", price);
            if (price && typeof price === "object" && price.RUB !== undefined) {
              result.push([
                Utilities.formatDate(new Date(dt * 1000), timeZone, format), // Умножение на 1000, если dt в секундах
                nmId,
                price.RUB / 100,
              ]);
            } else {
              console.warn(`Price object is incorrect for dt: ${dt}`, price);
            }
          });
        }
      }
    } catch (error) {
      console.warn(`Error fetching data for nmId: ${nmId}`, error);
      continue;
    }
  }

  debugLog("Обработанный:", result);

  if (!result.length) return;

  const sheet = setSheetNew("История цен (12 дней)", null, ss);
  setSheetHead(sheet, true);
  sheet.appendRow(["Дата", "Артикул WB", "Цена"]);
  sheet.getRange(2, 1, result.length, result[0].length).setValues(result);

  return result;
}

/**
 * @typedef {{
 *   pricesDiscountsApi?: PricesDiscounts; // полчение nmId по api Цены и скидки
 *   spp?: number; // цифровое занчение spp по умолчанию 30
 *   accumulate?: boolean; // true, для накопления
 *   sheetName?: string; // название листа для вставки данных
 *   api?: boolean; // использовать Sheets API v4
 *   raw?: boolean; // вставлять данные в RAW формате
 *   debug?: boolean; // режим отладки, логи
 *   setHead?: boolean; // форматировать заголвоок, по умолчанию true
 *   v2?: boolean; // новая верси api v2, по умолчанию true
 *   emptyCols?: boolean;
 * }} SppOptions
 */

/**
 * Получение spp
 * @param {SppOptions} [options] параметры запроса
 */
function spp(options = context?.config?.getConfigForCurrentFunction()) {
  const start = CONFIG.func.start();
  const script = spp.name;

  try {
    const {
      pricesDiscountsApi,
      version = 4,
      dest = [-1257786],
      appType = 1,
      spp = 30,
      ignoreStocks,
      dateFormat,
      inStock = true,
      formulas = [],
      accumulate,
      api = true,
      raw = true,
      emptyCols,
      setHead,
      sheetName,
      debug = context?.debug,
    } = options;

    let { token } = options;

    // if (!token) {
    //   const storage =
    //     context?.storage ||
    //     (service &&
    //       setStorage({ service, serviceType: context?.serviceType })) ||
    //     null;

    //   token = storage.getProperty("SiteToken");
    // }

    const { formats, methods } = CONFIG;
    const sppInfo = methods.other.spp;

    let data;
    const tmp = {};

    const response = pricesDiscountsApi.list({});

    if (response.length == 0) {
      return CONFIG.func.endScript({
        script,
        start,
        message: `Ключ Цены и с кидки не установлен!!!`,
        messageType: 2,
      });
    }

    response.flatMap(({ nmID, discount, clubDiscount, sizes, vendorCode }) =>
      sizes.map(
        ({
          sizeID,
          price,
          discountedPrice,
          clubDiscountedPrice,
          techSizeName,
        }) => {
          return (tmp[Number(sizeID)] = {
            vendorCode,
            techSizeName,
            discountedPrice,
            price,
            discount,
            clubDiscount,
            clubDiscountedPrice,
          });
        }
      )
    );

    data = response.map(({ nmID }) => nmID);
    const pricesObj = Object.assign({}, tmp);
    const uniqueNmIds = [...new Set(data)];
    const shAddName = sheetName || sppInfo.sheet;
    const sheet = setSheetNew(shAddName, sppInfo.sheetColor, ss);

    // if (debug) console.log(JSON.stringify(pricesObj, null, 2));

    let result = [];
    for (let x = 0; x < uniqueNmIds.length; x += STEP) {
      const nms = uniqueNmIds.slice(x, x + STEP);
      dest.forEach((destination) => {
        const country = DestList[destination];
        result.push(
          ...fetchCustom({
            nms: nms.join(";"),
            spp,
            destination,
            prices: pricesObj,
            version,
            appType,
            ignoreStocks,
            country,
            token,
            dateFormat: dateFormat || formats.date,
            debug,
          })
        );
        Utilities.sleep(200);
      });
    }

    if (inStock) result = result.filter((el) => el[7] > 0);

    if (!accumulate) sheetClear({ sheet });

    if (sheet.getLastRow() === 0) {
      let headers = sppInfo.header;
      if (formulas.length > 0) {
        headers = headers.concat(formulas);
      }
      sheet.appendRow(headers);
    }

    debugLog("Обработанный:", result);

    if (!result.length > 0) {
      setSheetHead(sheet);
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    lastRow = sheet.getLastRow();
    addDataToSheet({
      fromRow: lastRow,
      lastRow,
      result,
      sheet,
      api,
      raw,
      setHead,
      script,
      start,
      debug,
    });

    sheet
      .getRangeList(sppInfo.rangePercentages)
      .setNumberFormat(formats.percentages);

    sheet
      .getRangeList(sppInfo.rangeDate)
      .setNumberFormat(dateFormat || formats.date);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "💵 Цены с СПП получили",
      emptyCols,
      removeDuplicates: true,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

