function fetchCustom(options) {
  const {
    nms,
    spp = 30,
    destination,
    appType = 1,
    ignoreStocks,
    prices,
    ratings,
    warehouses,
    version,
    country,
    dateFormat,
    urlGenerator,
    token,
    debug,
  } = options;

  let url = `https://card.wb.ru/cards/v${version}/detail`;

  if (version === 2) {
    url = `${url}?appType=${appType}&curr=rub&dest=${destination}&spp=${spp}&nm=${nms}`;
  }

  if (version === 4) {
    url = `${url}?appType=${appType}&curr=rub&dest=${destination}&spp=${spp}&hide_dtype=13&lang=ru&ab_testing=false&ignore_stocks=${
      ignoreStocks ? true : false
    }&nm=${nms}`;
  }

  // &hide_dflags=131072

  const optionsRequest = {
    headers: {
      Accept:
        "text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,image/apng,*/*;q=0.8,application/signed-exchange;v=b3;q=0.7",
      "User-Agent":
        "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/140.0.0.0 Safari/537.36",
      "x-client-name": "site",
    },
    followRedirects: true,
    muteHttpExceptions: true,
  };

  // const firstRequest = UrlFetchApp.fetch(
  //   "https://www.wildberries.ru/",
  //   optionsRequest
  // );

  // if (debug) console.log("First request headers", firstRequest.getAllHeaders());

  // optionsRequest.headers["Content-Type"] = "application/json";
  optionsRequest.headers["Accept"] = "*/*";
  optionsRequest.headers["Accept-Encoding"] = "gzip, deflate, br, zstd";
  optionsRequest.headers["Accept-Language"] =
    "ru,ru-RU;q=0.9,en-US;q=0.8,en;q=0.7";
  delete optionsRequest.headers["x-client-name"];

  if (token) optionsRequest.headers.authorization = `Bearer ${token}`;

  if (debug)
    console.log("Options request", JSON.stringify(optionsRequest, null, 2));

  let response;
  try {
    if (debug) checkUrlLength(url);
    if (debug) console.log({ url });
    response = UrlFetchApp.fetch(url, optionsRequest);
    if (response.getResponseCode() !== 200) {
      throw new Error("Error response code\n" + response.getResponseCode());
    }
  } catch (error) {
    console.warn("Error UrlFetchApp:\n", error.stack);

    url = url.replace(
      "https://card.wb.ru/",
      "https://www.wildberries.ru/__internal/card/"
    );

    if (debug) checkUrlLength(url);
    if (debug) console.log({ url });

    response = UrlFetchApp.fetch(url, optionsRequest);
  }

  // if (debug) console.log("Response headers", response.getAllHeaders());

  const parsedResponse = JSON.parse(response);
  const products =
    version === 2
      ? parsedResponse?.data?.products || []
      : parsedResponse?.products || [];

  if (debug) console.log("Total products >>>", products.length);

  // if (debug) console.log(JSON.stringify(products, null, 2));
  // const promo = products.map(
  //   ({ panelPromoId, promoTextCat, promoTextCard, promotions }) => {
  //     return { panelPromoId, promoTextCat, promoTextCard, promotions };
  //   }
  // );

  // console.log({ promo });

  const parseOptions = {
    products,
    warehouses,
    ratings,
    prices,
    destination,
    country,
    dateFormat,
    urlGenerator,
    debug,
  };

  const parsers = {
    prices: parseSpp,
    warehouses: parseStocks,
    ratings: parseRatings,
  };

  const operationType = Object.keys(parsers).find((key) => parseOptions[key]);
  if (!operationType) {
    throw new Error("Unknown function to parse");
  }

  return parsers[operationType](parseOptions);
}

function parseSpp(options) {
  const {
    products,
    prices: pricesObj,
    dateFormat,
    destination,
    country,
    debug,
  } = options;
  const result = [];
  const timeZone = CONFIG.settings.time.timeZone;

  if (products) {
    const updated = Utilities.formatDate(new Date(), timeZone, dateFormat);

    for (const product of products) {
      const {
        //  root: imtId,
        id: nmId,
        name,
        sizes,
      } = product;

      const link = `https://www.wildberries.ru/catalog/${nmId}/detail.aspx`;

      for (const size of sizes) {
        const {
          optionId: chrtId, // origName: techSize,
          price: priceObj,
        } = size;

        const basicPrice = priceObj ? priceObj.basic / 100 : 0;
        let productPrice = priceObj ? priceObj.product / 100 : 0;
        const productLogistics = priceObj ? priceObj.logistics / 100 : 0;

        // if (debug) {
        //   console.log({ nmId, basicPrice, productPrice, productLogistics });
        // }

        if (country !== "ru") productPrice = productPrice + productLogistics;

        if (productPrice < 1) {
          productPrice = 0;
        }

        // if (debug) {
        //   console.log({ productPrice });
        // }

        const {
          vendorCode,
          techSizeName,
          discountedPrice,
          price,
          discount,
          clubDiscount,
          clubDiscountedPrice,
        } = pricesObj[chrtId];

        if (Object.keys(pricesObj).length > 0) {
          const priceDiscount = discountedPrice || 0;
          const sppRub = productPrice === 0 ? 0 : priceDiscount - productPrice;
          const sppPercent =
            priceDiscount && sppRub > 0
              ? // ? Math.round(parseFloat(sppRub / priceDiscount))
                parseFloat(sppRub / priceDiscount)
                  .toFixed(3)
                  .replace(".", ",")
              : 0;

          // if (!priceObj?.product) {
          //   console.log({ priceObj });
          // }

          // if (priceObj?.product) {
          //   const spp =
          //     100 *
          //     (1 -
          //       (priceObj?.product - priceObj.logistics) /
          //         100 /
          //         price /
          //         (1 - discount / 100));

          //   console.log({
          //     spp,
          //     sppPercent,
          //   });
          // }

          //   "price": {
          //     "basic": 189700,
          //     "product": 87600,
          //     "total": 87600,
          //     "logistics": 0,
          //     "return": 0
          // },

          result.push([
            updated,
            // imtId,
            nmId,
            vendorCode,
            chrtId,
            techSizeName,
            name,
            link,
            basicPrice,
            productPrice,
            price,
            discount,
            clubDiscountedPrice,
            clubDiscount,
            priceDiscount,
            sppRub,
            sppPercent,
            destination,
            country,
          ]);
        } else {
          result.push([
            updated,
            link,
            name,
            nmId,
            vendorCode,
            chrtId,
            techSizeName,
            basicPrice,
            productPrice,
            clubDiscountedPrice,
            clubDiscount,
            null,
            null,
            null,
            null,
            null,
            destination,
            country,
          ]);
        }
      }
    }
  }

  return result;
}

function parseRatings(options) {
  const { products, dateFormat, destination, country, debug } = options;
  const result = [];
  const timeZone = CONFIG.settings.time.timeZone;

  if (products) {
    const updated = Utilities.formatDate(new Date(), timeZone, dateFormat);

    for (const product of products) {
      const {
        id: nmId,
        reviewRating,
        nmReviewRating,
        feedbacks,
        nmFeedbacks,
      } = product;

      result.push([
        updated,
        nmId,
        nmReviewRating,
        nmFeedbacks,
        reviewRating,
        feedbacks,
        destination,
        country,
      ]);
    }
  }

  return result;
}

function parseStocks(options) {
  const {
    products,
    warehouses,
    dateFormat,
    destination,
    country,
    urlGenerator,
    debug,
  } = options;
  const result = [];
  const timeZone = CONFIG.settings.time.timeZone;

  if (products) {
    const updated = Utilities.formatDate(new Date(), timeZone, dateFormat);

    for (const product of products) {
      const {
        supplierId,
        supplier,
        supplierRating,
        root: imtId,
        id: nmId,
        name,
        brand,
        // brandId,
        pics,
        // rating,
        reviewRating,
        feedbacks,
        promotions,
        // volume,
        entity,
        colors: colors_,
        sizes,
      } = product;

      const colors = colors_.length
        ? colors_.map((t) => t["name"]).join(", ")
        : "";

      for (const size of sizes) {
        const {
          optionId: chrtId,
          origName: techSize,
          name: wbSize,
          price: priceObj,
          stocks,
        } = size;

        const basicPrice = priceObj ? priceObj.basic / 100 : 0;
        const productPrice = priceObj ? priceObj.product / 100 : 0;
        let totalPrice = priceObj ? priceObj.total / 100 : 0;
        const logisticsPrice =
          priceObj && priceObj.logistics > 0 ? priceObj.logistics / 100 : 0;
        const returnPrice =
          priceObj && priceObj.hasOwnProperty("return") && priceObj.return > 0
            ? priceObj.return / 100
            : 0;

        totalPrice =
          country === "ru"
            ? productPrice
            : totalPrice || productPrice + logisticsPrice; // + returnPrice;

        // const image = new GenerateUrl(nmId).hyperlink();

        const image = urlGenerator.hyperlink(nmId);

        if (stocks && stocks.length) {
          stocks.map((el) => {
            const whId = el?.wh;

            const { formattedStoreName: warehous, warehousType } =
              warehouses[String(whId)] || whId;

            // if (debug)
            //   console.log({ whId: String(whId), wh: warehouses[String(whId)] });

            const time1 = el?.time1;
            const time2 = el?.time2;
            const totalTime = time1 && time2 ? time1 + time2 : 0; // / 24

            result.push([
              updated,
              supplierId,
              supplier,
              supplierRating,
              imtId,
              nmId,
              chrtId,
              name,
              techSize,
              wbSize,
              colors,
              brand,
              image,
              basicPrice,
              productPrice,
              logisticsPrice,
              returnPrice,
              promotions ? promotions?.join(", ") : null,
              pics,
              reviewRating,
              feedbacks,
              warehous,
              el?.qty,
              whId,
              time1,
              time2,
              totalTime,
              warehousType,
              totalPrice,
              destination,
              country,
              capitalizeFirstLetter(entity),
            ]);
          });
        } else {
          result.push([
            updated,
            supplierId,
            supplier,
            supplierRating,
            imtId,
            nmId,
            chrtId,
            name,
            techSize,
            wbSize,
            colors,
            brand,
            image,
            basicPrice,
            productPrice,
            logisticsPrice,
            returnPrice,
            promotions ? promotions?.join(", ") : null,
            pics,
            reviewRating,
            feedbacks,
            null,
            null,
            null,
            null,
            null,
            null,
            null,
            totalPrice,
            destination,
            country,
            capitalizeFirstLetter(entity),
          ]);
        }
      }
    }
  }
  return result;
}

function warehouses(options = {}) {
  const start = CONFIG.func.start();
  const script = warehouses.name;

  try {
    const {
      whNew = false,
      formulas = [],
      debug = context?.debug,
      api,
      raw,
      sheetName,
      emptyCols,
    } = options;

    const { formats, methods } = CONFIG;
    const main = methods.other.warehouses;

    const shAddName = sheetName || main.sheet;
    const sheet = setSheetNew(shAddName, main.sheetColor, ss);

    setSheetHead(sheet, true);

    let headers = main.header;
    if (formulas.length) {
      headers = headers.concat(formulas);
    }

    sheet.appendRow(headers);

    const response = whNew
      ? warehousesListNew({ toList: true, debug })
      : warehousesList({ toList: true, debug });

    if (!response.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    if (api) {
      const startRow = sheet.getLastRow() + 1;
      addDataToSheetIS_(1, response, sheet, raw, script, startRow);
    } else {
      addDataToSheetIS_(0, response, sheet, raw, script);
    }

    sheet.getRangeList(main.rangeDate).setNumberFormat(formats.datehhmm);
    // sheet.getRangeList(main.rangeText).setNumberFormat(formats.text);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Склады WB получили",
      emptyCols,
      removeDuplicates: true,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

function warehousesList({ toList = false, debug = false } = {}) {
  const url = configOther.urlWarehousesListNames;
  const response = JSON.parse(
    UrlFetchApp.fetch(url, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "User-Agent":
          "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/89.0.142.86 Safari/537.36",
      },
      muteHttpExceptions: true,
    })
  );

  if (debug)
    console.log(
      "Response headers >>>\n",
      response.getAllHeaders(),
      response.getResponseCode()
    );

  const json = JSON.parse(response.getContentText())?.value?.times || [];
  // if (debug) console.log(JSON.stringify(json, null, 2));

  const timeZone = CONFIG.settings.time.timeZone;
  const formatWarehouse = (warehous) => {
    const {
      storeId,
      deliveryOption,
      closestDeliveryDate,
      priority,
      deliveryOptionId,
      isSupposedDate,
      inDays,
      inMinutes,
      isCargo,
      officeId,
      extraDays,
      pickupAvailable,
      storeName,
      isSellerStore,
      deliveryMinutes,
      storeType,
    } = warehous;

    let formattedStoreName = storeName;

    if (storeType === 1) {
      if (storeName.includes("WB"))
        formattedStoreName = formattedStoreName?.replace(/WB/gi, "").trim(); // + " WB";
      if (storeName.includes("СЦ"))
        formattedStoreName = formattedStoreName.trim();
      if (storeName.toLowerCase().includes("склад"))
        formattedStoreName = formattedStoreName?.replace(/склад/gi, "").trim();
      formattedStoreName = formattedStoreName + " WB";
    }

    if (storeType === 2) {
      if (
        storeName.toLowerCase().includes("склад продавца") ||
        storeName.toLowerCase().includes("склад поставщика")
      ) {
        formattedStoreName = storeName
          ?.replace(/склад продавца/gi, "")
          .replace(/склад поставщика/gi, "")
          .trim();
      }

      if (storeName.includes("СЦ"))
        formattedStoreName = formattedStoreName.trim();

      formattedStoreName = formattedStoreName + " СП";
    }

    if (storeType === 18) {
      if (storeName.toLowerCase().includes("склад продавца"))
        formattedStoreName = formattedStoreName
          ?.replace(/склад продавца/gi, "")
          .trim();

      formattedStoreName = formattedStoreName + " СП";
    }

    if (storeName.toLowerCase().includes("пвз")) {
      formattedStoreName =
        formattedStoreName
          ?.replace(/пвз - /gi, "")
          .replace(/пвз/gi, "")
          .trim() + " ПВЗ";
    }

    const warehousType = isSellerStore
      ? "fbs"
      : storeType === 1
      ? "fbo"
      : typeof formattedStoreName === "number"
      ? "???"
      : formattedStoreName.includes("WB")
      ? "fbo"
      : formattedStoreName.includes("СП")
      ? "fbs"
      : formattedStoreName.includes("ПВЗ")
      ? "pvz"
      : !/ПВЗ|СП|WB/g.test(formattedStoreName)
      ? "fbo"
      : "other";

    const formattedClosestDeliveryDate = Utilities.formatDate(
      new Date(closestDeliveryDate),
      timeZone,
      CONFIG.formats.datehhmmss
    );

    // const duration = deliveryMinutes / 60 / 24;

    return [
      storeId,
      storeName,
      formattedStoreName.replace(/\s\s+/g, " "),
      deliveryOption,
      formattedClosestDeliveryDate,
      // closestDeliveryDate,
      priority,
      deliveryOptionId,
      isSupposedDate,
      inDays,
      inMinutes,
      isCargo,
      officeId,
      extraDays,
      pickupAvailable,
      isSellerStore,
      deliveryMinutes,
      storeType,
      // duration,
      warehousType,
    ];
  };

  if (toList) {
    return json.map(formatWarehouse);
  } else {
    return json.reduce((acc, warehous) => {
      const [
        storeId,
        storeName,
        formattedStoreName,
        deliveryOption,
        formattedClosestDeliveryDate,
        // closestDeliveryDate,
        priority,
        deliveryOptionId,
        isSupposedDate,
        inDays,
        inMinutes,
        isCargo,
        officeId,
        extraDays,
        pickupAvailable,
        isSellerStore,
        deliveryMinutes,
        storeType,
        warehousType,
      ] = formatWarehouse(warehous);

      return {
        ...acc,
        [storeId]: {
          formattedStoreName,
          storeNameOriginal: storeName,
          storeName: formattedStoreName
            .replace(/ СП/i, "")
            .replace(/ ПВЗ/i, "")
            .replace(/ WB/i, "")
            ?.trim(),
          storeId,
          deliveryOption,
          formattedClosestDeliveryDate,
          // closestDeliveryDate,
          priority,
          deliveryOptionId,
          isSupposedDate,
          inDays,
          inMinutes,
          isCargo,
          officeId,
          extraDays,
          pickupAvailable,
          isSellerStore,
          deliveryMinutes,
          storeType,
          warehousType,
        },
