/**
 * @typedef {{
 *   pricesDiscountsApi: объект класса PricesDiscounts
 *   update?: boolean; обновление цен
 *   newPricesSheet: boolean; // новые цена и скидка с листа Новые цены (Артикул, Цена, Скидка)
 *   sheetName?: string; // название листа для вставки данных
 *   api?: boolean; // использовать Sheets API v4
 *   raw?: boolean; // вставлять данные в RAW формате
 *   emptyCols?: boolean;
 * }} PricesOptions
 */

/**
 * Получение информации о ценах
 * @param {PricesOptions} [options] параметры запроса
 */
function prices(options = context?.config?.getConfigForCurrentFunction()) {
  const start = CONFIG.func.start();
  const script = prices.name;

  try {
    const {
      pricesDiscountsApi,
      update,
      newPricesSheet,
      useSizes = false,
      sheetName,
      formulas = [],
      api = false,
      raw = false,
      setHead,
      debug = context?.debug,
      emptyCols,
    } = options;

    const main = CONFIG.methods.prices.info;
    const shName = sheetName
      ? sheetName
      : update
      ? main.sheetUpload
      : main.sheet;

    const sheet = setSheetNew(shName, main.sheetColor, ss);

    sheetClear({ sheet });

    if (update)
      rangeClear({
        sheet,
        dataValidations: true,
        clearRange: main.rangeDataValidations,
      });

    let headers = update ? main.headerUpdate : main.header;
    headers = Object.values(headers);
    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    sheet.appendRow(headers);

    const response = useSizes
      ? pricesDiscountsApi.listSize(options) // не рабоатет надо передавать nmID список
      : pricesDiscountsApi.list(options);

    debugLog("Ответ:", response);

    if (!response.length) {
      setSheetHead(sheet);
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const urlGenerator = getUrlGenerator();
    const updated = dateStrToFormatDate(new Date(), CONFIG.formats.datehhmm);

    let result = [];

    if (useSizes) {
      result = response.map(
        ({
          nmID: nmId,
          vendorCode,
          sizeID,
          currencyIsoCode4217,
          discount,
          clubDiscount,
          editableSizePrice,
          price,
          discountedPrice,
          clubDiscountedPrice,
          techSizeName,
          isBadTurnover,
        }) => {
          const image = urlGenerator.hyperlink(nmId);

          const commonFields = [
            updated,
            nmId,
            vendorCode,
            sizeID,
            techSizeName,
            price,
            discountedPrice,
            discount,
            clubDiscountedPrice,
            clubDiscount,
            currencyIsoCode4217,
            editableSizePrice ? "Да" : "Нет",
            isBadTurnover ? "Да" : "Нет",
          ];

          if (update) {
            commonFields.push(null, null, null, null, null, image);
          } else {
            commonFields.push(image);
          }

          return commonFields;
        }
      );
    } else {
      result = response.flatMap(
        ({
          nmID: nmId,
          vendorCode,
          sizes,
          currencyIsoCode4217,
          discount,
          clubDiscount,
          editableSizePrice,
          isBadTurnover,
        }) =>
          sizes.map(
            ({
              sizeID,
              price,
              discountedPrice,
              clubDiscountedPrice,
              techSizeName,
            }) => {
              const image = urlGenerator.hyperlink(nmId);

              const commonFields = [
                updated,
                nmId,
                vendorCode,
                sizeID,
                techSizeName,
                price,
                discountedPrice,
                discount,
                clubDiscountedPrice,
                clubDiscount,
                currencyIsoCode4217,
                editableSizePrice ? "Да" : "Нет",
                isBadTurnover ? "Да" : "Нет",
              ];

              if (update) {
                commonFields.push(null, null, null, null, null, image);
              } else {
                commonFields.push(image);
              }

              return commonFields;
            }
          )
      );
    }

    debugLog("Обработанный:", result);

    addDataToSheet({
      fromRow: 0,
      lastRow: 1,
      result,
      sheet,
      api,
      raw,
      setHead,
      script,
      start,
      debug,
    });

    if (update) {
      sheet
        .getRange(main.rangeCheckBox + sheet.getLastRow())
        .insertCheckboxes();

      if (newPricesSheet) {
        sheet.getRange(main.rangeFormulas).setFormulas(main.formulas);
      }

      return;
    }

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Цены получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

/**
 * @typedef {{
 *   pricesDiscountsApi: объект класса PricesDiscounts
 *   newPricesSheet?: boolean; // новые цена и скидка с листа Новые цены (Артикул, Цена, Скидка)
 *   sheetName?: string; // название листа для вставки данных
 * }} PricesUploadOptions
 */

/**
 * Установить цены и скидки (обновление)
 * @param {PricesUploadOptions} [options] параметры запроса
 */
function pricesDiscountsUpload(
  options = context?.config?.getConfigForCurrentFunction()
) {
  const start = CONFIG.func.start();
  const script = pricesDiscountsUpload.name;

  try {
    const {
      pricesDiscountsApi,
      newPricesSheet,
      sheetName,
      debug = context?.debug,
    } = options;

    prices(options);

    SpreadsheetApp.flush();

    const pricesInfo = CONFIG.methods.prices.info;
    const sName = sheetName || pricesInfo.sheetUpload;
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = ss.getSheetByName(sName);

    let values = sheet
      .getDataRange()
      .getValues()
      .slice(1)
      .reduce((acc, row) => {
        const nmID = row[1];
        const price = row[13];
        const discount = row[14];
        3;
        if (isNumeric(price) || isNumeric(discount)) {
          acc.push([nmID, price, discount]);
        }

        return acc;
      }, []);

    if (debug) console.log({ values });

    if (values.length === 0) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Цены не добавлены",
        messageType: 2,
      });
    }

    const uniqueValues = Array.from(
      new Set(values.map(JSON.stringify)),
      JSON.parse
    );

    if (debug) console.log({ uniqueValues });

    values = uniqueValues.map((item) => new ItemPricesUpload(item));

    if (debug) console.log({ values });

    // Оставляем только уникальные объекты по nmID
    values = Object.values(
      values.reduce((acc, item) => {
        const { nmID, price, discount } = item;

        // Проверяем, есть ли уже объект с таким nmID
        if (!acc[nmID]) {
          acc[nmID] = item; // Если нет, добавляем
        } else {
          // Если объект с таким nmID уже существует:
          // Оставляем объект, у которого заполнены оба свойства - price и discount
          if (price !== undefined && discount !== undefined) {
            acc[nmID] = item;
          }
        }

        return acc;
      }, {})
    );
    if (debug) console.log({ filtered: values });

    const chunk = chunkArray(values, 1000);

    const uploadIds = [];
    for (const item of chunk) {
      const response = pricesDiscountsApi.upload(item);
      console.log(
        `${item.length} >>> ${JSON.stringify(response, null, 2)}\n`,
        item
      );
      uploadIds.push([
        new Date(),
        response?.message?.data?.id,
        // JSON.stringify(item[0]),
        response?.message?.error || response?.status,
        response?.message?.errorText,
        script,
      ]);
    }

    const uploadIds_ = ss.getSheetByName(pricesInfo.sheetUploadId);
    const uploadIdsIr = uploadIds_.getLastRow();
    if (uploadIdsIr === 0)
      uploadIds.unshift([
        "Изменено",
        "ID загрузки",
        // "Товары",
        "Ошибка",
        "Описание ошибки",
        "Скрипт",
      ]);

    uploadIds_
      .getRange(uploadIdsIr + 1, 1, uploadIds.length, uploadIds[0].length)
      .setValues(uploadIds);

    Utilities.sleep(60000);
    prices(options);

    CONFIG.func.endScript({
      script,
      start,
      message: "Цены обновили",
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

