/**
 * @typedef {{
 *   calendarPromoApi?: CalendarPromo;
 *   allPromo?: boolean;
 *   sheetName?: string; // название листа для вставки данных
 *   emptyCols?: boolean; // удалить пустые столбцы
 * }} CalendarPromoListOptions
 */

/**
 * Список акций
 * @param {CalendarPromoListOptions} [options] параметры запроса
 */
function calendarPromoList(
  options = context?.config?.getConfigForCurrentFunction()
) {
  const start = CONFIG.func.start();
  const script = calendarPromoList.name;

  try {
    const {
      calendarPromoApi,
      allPromo,
      sheetName,
      debug = context?.debug,
      emptyCols,
    } = options;
    const { datehhmm } = CONFIG.formats;
    const main = CONFIG.methods.calendarPromo.list;

    const response = [];
    const startDateTime = "2004-01-01T00:00:00Z";
    const endDateTime = addDays(180) + "T23:59:59Z";
    response.push(
      ...calendarPromoApi.list({ startDateTime, endDateTime, allPromo })
    );

    if (options?.info)
      return response.reduce(
        (acc, { id, name, type, startDateTime, endDateTime }) => {
          return {
            ...acc,
            [id]: {
              startDateTime,
              endDateTime,
              promotionId: id,
              name,
              type,
              typeName: CalendarPromoActionType[type],
            },
          };
        },
        {}
      );

    const sheet = setSheetNew(sheetName || main.sheet, main.sheetColor, ss);
    const header = main.header;
    const headers = Object.values(header);
    setSheetHead(sheet, true);
    sheet.appendRow(headers);

    debugLog("Ответ:", response);

    if (!response.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    let result = allPromo ? response : [];

    if (debug) console.log("Len", response.length);

    if (!allPromo) {
      const now = new Date();
      result = response.filter((e) => new Date(e.endDateTime) >= now);
      if (debug) console.log("Filtered", result.length);
    }

    result = result.map((item) => {
      return Object.keys(header).reduce((acc, key) => {
        let value = item[key];

        if (["startDateTime", "endDateTime"].includes(key))
          value = dateStrToFormatDate(value, datehhmm);

        if (key === "type") value = CalendarPromoActionType[value];

        return [...acc, value];
      }, []);
    });

    debugLog("Обработанный:", result);

    // sheet
    //   .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
    //   .setValues(result);

    // addDataToSheet({
    addDataToSheetOptimized({
      result,
      fromRow: 1,
      // lastRow: 1,
      sheet,
      api: true,
      // raw: false,
      setHead: false,
      script,
      start,
      debug,
    });

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Список акций получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

/**
 * Детальная информация по акциям
 * @param {CalendarPromoListOptions} [options] параметры запроса
 */
function calendarPromoDetails(
  options = context?.config?.getConfigForCurrentFunction()
) {
  const start = CONFIG.func.start();
  const script = calendarPromoDetails.name;

  try {
    const { calendarPromoApi, sheetName, emptyCols } = options;
    let { promotionIDs } = options;

    const { datehhmm } = CONFIG.formats;
    const main = CONFIG.methods.calendarPromo.details;
    const sheet = setSheetNew(sheetName || main.sheet, main.sheetColor, ss);

    const header = main.header;
    const headers = Object.values(header);

    sheetClear({
      sheet,
      contents: true,
    });

    setSheetHead(sheet);

    sheet.appendRow(headers);

    if (!promotionIDs) {
      const startDateTime = "2004-01-01T00:00:00Z";
      const endDateTime = addDays(180) + "T23:59:59Z";
      const promo = calendarPromoApi.list({
        startDateTime,
        endDateTime,
        allPromo: true,
      });
      promotionIDs = promo.map((item) => item.id);
    }

    if (Array.isArray(promotionIDs)) {
      promotionIDs = chunkArray(promotionIDs, 100);
    } else {
      promotionIDs = chunkArray(promotionIDs.split(","), 100);
    }

    const response = [];
    promotionIDs.forEach((item) => {
      const items = calendarPromoApi.details(item);
      // console.log("Response:", items.length);
      response.push(...items);
    });

    debugLog("Ответ:", response);
    console.log("Total rows:", response.length);

    if (!response.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const result = response.map((item) => {
      return Object.keys(header).reduce((acc, key) => {
        let value = item[key];
        if (key === "type") {
          value = CalendarPromoActionType[value];
        }

        if (["startDateTime", "endDateTime"].includes(key))
          value = dateStrToFormatDate(value, datehhmm);

        if (key === "advantages" && value) {
          value = value?.join(", ");
        }

        if (key === "ranging" && value && value.length > 0) {
          value = value
            .map(({ condition, participationRate, boost }) => {
              return `${CalendarPromoCondition[condition]}\nКол-во товаров для перехода на следующий уровень ранжирования, %: ${participationRate}\nТекущий уровень поднятия в поиске, %: ${boost}`;
            })
            .join("\n\n");
        }

        return [...acc, value];
      }, []);
    });

    debugLog("Обработанный:", result);

    sheet
      .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
      .setValues(result);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Детальную информацию по акциям получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

/**
 * Список товаров для участия в акции
 * @param {CalendarPromoListOptions} [options] параметры запроса
 */
function calendarPromoNomenclatures(
  options = context?.config?.getConfigForCurrentFunction()
) {
  const start = CONFIG.func.start();
  const script = calendarPromoNomenclatures.name;

  try {
    const {
      calendarPromoApi,
      regularOnly = true,
      sheetName,
      debug = context?.debug,
      emptyCols,
    } = options;
    let { promotionIDs } = options;

    const { datehhmm } = CONFIG.formats;
    const main = CONFIG.methods.calendarPromo.nomenclatures;
    const sheet = setSheetNew(sheetName || main.sheet, main.sheetColor, ss);

    const header = main.header;
    const headers = Object.values(header);
    setSheetHead(sheet, true);
    sheet.appendRow(headers);

    if (debug) console.log("promotionIDs:", promotionIDs);

    // if (!promotionIDs) throw new Error("Не переданы идентификаторы акций");

    const promoInfo = calendarPromoList({
      calendarPromoApi,
      allPromo: true,
      info: true,
    });

    if (debug) console.log("promoInfo", JSON.stringify(promoInfo[0], null, 2));

    const currentDate = new Date();
    // Если promotionIDs предоставлен, разобьём его, иначе выбираем из promoInfo
    promotionIDs = promotionIDs
      ? chunkArray(promotionIDs.split(",").map(Number), 1)
      : Object.values(promoInfo)
          .filter(({ type, endDateTime }) => {
            const isEndDateValid = new Date(endDateTime) >= currentDate;
            return regularOnly
              ? type === "regular" && isEndDateValid
              : isEndDateValid;
          })
          .map(({ promotionId }) => [promotionId]);

    if (debug) console.log("promotionIDs:", promotionIDs);

    const response = [];
    promotionIDs.forEach(([promotionID]) => {
      console.log(promotionID);
      response.push(
        ...calendarPromoApi.nomenclatures({
          promotionID,
          inAction: true,
        })
      );
    });

    promotionIDs.forEach(([promotionID]) => {
      console.log(promotionID);
      response.push(
        ...calendarPromoApi.nomenclatures({
          promotionID,
        })
      );
    });

    debugLog("Ответ:", response);

    if (!response.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const result = response.map((item) => {
      return Object.keys(header).reduce((acc, key) => {
        let value = item[key];

        // Проверяем, есть ли совпадение с promotionId
        const promotionData = promoInfo[String(item.promotionId)];

        if (key === "name") value = promotionData.name;
        if (key === "typeName") value = promotionData.typeName;

        if (key === "startDateTime")
          value = dateStrToFormatDate(promotionData.startDateTime, datehhmm);

        if (key === "endDateTime")
          value = dateStrToFormatDate(promotionData.endDateTime, datehhmm);

        return [...acc, value];
      }, []);
    });

    debugLog("Обработанный:", result);

    sheet
      .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
      .setValues(result);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Список товаров для участия в акции получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

/**
 * Склад.
 * @type  {Object} options
 * @property {Statistics} options.statisticsApi объект класса Statistics.
 * @property {string} options.dateFrom дата <RFC3339>.
 * @property {object} [options.header] словарь необходимых заголовков, где ключ равен ключю в ответе API, а значение заголовку.
 * @property {number} [options.dateFormatType] тип обработки даты в ответе.
 * @property {string} [options.sheetName] имя листа для вставки данных.
 * @property {boolean} [options.setFilter] установить фильтр после вставки занчений.
 * @property {boolean} [options.setHead] установить форматированный заголовок.
 */
function statStocks(options = context?.config?.getConfigForCurrentFunction()) {
  const {
    statisticsApi,
    test = false,
    dateFrom,
    header,
    accumulate = false,
    dateFormatType = 7,
    setFilter = true,
    setHead = true,
    deleteEmpty = true,
    formulas = [],
    filterKey,
    filterList,
    filterKeysAboveZero,
  } = options;

  let { sheetName } = options;

  const start = CONFIG.func.start();
  const script = statStocks.name;
  const stat = CONFIG.methods.statistica;
  const main = stat.stocks;

  sheetName = sheetName || main.sheet;
  const builder = requestBuilder.setSheetName(sheetName);

  let headers = Object.values(header || main.header);
  if (accumulate) headers = headers.concat("Наличие", "Обновлено");
  if (formulas.length > 0) {
    headers = headers.concat(formulas);
  }

  const { headersRange, headerChar } = builder.headersRange(headers);

  try {
    console.log(`Дата запроса: ${dateFrom}`);

    if (test) statisticsApi.useTestCircuitUrl();

    const result = statisticsApi.stocks({
      header,
      dateFrom,
      dateFormatType,
      filterKey,
      filterList,
      filterKeysAboveZero,
    });

    debugLog("Обработанный:", result);

    builder.createSheetIfNotExist({
      rowCount: result.length || 1000,
      columnCount: headers.length,
      frozenRowCount: 1,
      tabColor: stat.sheetColor,
    });

    if (!accumulate) {
      builder.executeValuesClear();
    }

    const lastDataRow = builder.getDataBounds().lastRow;
    if (lastDataRow === 0) {
      // console.log("📝 Добавляем заголовки...");
      builder
        .setRange(headersRange)
        .setValues([headers])
        .setValueInputOption(ValueInputOption.USER_ENTERED)
        .setInsertDataOption(InsertDataOption.OVERWRITE)
        .executeValuesAppend();
      builder.refreshSheetMetadata();
    }

    if (result === -1 || !result.length) {
      console.log("📝 Нет данных...");
      builder.resetSheetName();
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    if (accumulate) {
      const updateAt = dateStrToFormatDate(new Date());
      result.forEach((arr) => arr.push(1, updateAt));
    }

    const { needsMoreRows, dataRowsToAdd, rowsToAdd, targetStartRow } =
      builder.checkRowsNeeded(sheetName, result.length, accumulate);

    // Если нужны дополнительные строки - добавляем их
    if (needsMoreRows) {
      console.log(`📝 Добавляем ${rowsToAdd} строк...`);
      builder.requestAddRowsAtEnd(rowsToAdd);
      builder.execute();
      builder.refreshSheetMetadata();
    }

    // Определяем диапазон для вставки данных
    if (!accumulate) {
      builder.setRange(`A2:${headerChar}${dataRowsToAdd + 1}`);
    } else {
      // Добавляем - вставляем после последних данных
      builder.setRange(
        `A${targetStartRow}:${headerChar}${targetStartRow + dataRowsToAdd - 1}`,
      );
    }

    console.log("📝 Вставляем данные:", result.length);
    builder
      .setValueInputOption(ValueInputOption.USER_ENTERED)
      .createAndSendBatches(result, sheetName, targetStartRow);
    builder.refreshSheetMetadata();

    if (deleteEmpty) {
      // Удаляем пустые строки и столбцы
      const deleteResponse = builder.requestDeleteEmptyRowsAndColumns();
      if (deleteResponse.resource) {
        console.log("📝 Удаляем пустые строки и столбцы...");
        builder.execute();
      }
    }

    if (setFilter) {
      console.log("📝 Устанавливаем фильтр...");
      builder.requestSetFilter();
      builder.execute();
    }

    // builder.refreshSheetMetadata();
    builder.resetSheetName();

    CONFIG.func.endScript({
      script,
      start,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

/**
 * Закзаы.
 * @type  {Object} options
 * @property {Statistics} options.statisticsApi объект класса Statistics.
 * @property {string} options.dateFrom дата <RFC3339>, можно передать дату или дату и временя, время можно указывать с точностью до секунд или миллисекунд.
 * Z в конце строки означает, что время передается в UTC-часовом поясе. При ее отсутствии время считается в часовом поясе МСК (UTC+3).
 * @property {Object} [options.header] словарь необходимых заголовков, где ключ равен ключю в ответе API, а значение заголовку.
