      flag,
      dateFormatType,
      filterKey,
      filterList,
      filterKeysAboveZero,
    });

    debugLog("Обработанный:", result);

    builder.createSheetIfNotExist({
      rowCount: result.length || 1000,
      columnCount: headers.length,
      frozenRowCount: 1,
      tabColor: stat.sheetColor,
    });

