        .setInsertDataOption(InsertDataOption.OVERWRITE)
        .executeValuesAppend();

      builder.refreshSheetMetadata();
    }

    if (result === -1 || !result.length) {
      console.log("📝 Нет данных...");
      builder.resetSheetName();
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const { newRows, updateRows } = processCheckUpdates(
      checkUpdates,
      result,
      forUpdate,
      accumulate,
    );

    const { needsMoreRows, dataRowsToAdd, rowsToAdd, targetStartRow } =
      builder.checkRowsNeeded(sheetName, newRows.length, accumulate);

    // Если нужны дополнительные строки - добавляем их
    if (needsMoreRows) {
      console.log(`📝 Добавляем ${rowsToAdd} строк...`);
      builder.requestAddRowsAtEnd(rowsToAdd);
      builder.execute();
      builder.refreshSheetMetadata();
    }

    // Определяем диапазон для вставки данных
    if (!accumulate) {
      builder.setRange(`A2:${headerChar}${dataRowsToAdd + 1}`);
    } else {
      builder.setRange(
        `A${targetStartRow}:${headerChar}${targetStartRow + dataRowsToAdd - 1}`,
      );
    }

    const updateRowsCount = Object.keys(updateRows).length;

    // console.log("📝 newRows:", newRows.length);
    // console.log("📝 updateRows:", updateRowsCount);
    // console.log("📝 updateRows:", updateRowsCount, {
    //   updateRows,
    // });

    if (newRows.length > 0) {
      // Вставляем данные
      console.log("📝 Вставляем данные:", result.length);
      builder
        .setValueInputOption(ValueInputOption.USER_ENTERED)
        .createAndSendBatches(newRows, sheetName, targetStartRow);
      builder.refreshSheetMetadata();
    }

    if (updateRowsCount > 0) {
      const { ranges, values } = createUpdateRanges(updateRows, sheetName);

      // console.log("📝 ranges:", ranges);
      // console.log("📝 values:", values);

      console.log("📝 Обновляем строки:", updateRowsCount);
      builder
        .setRanges(ranges)
        .setValues(values)
        .setValueInputOption(ValueInputOption.USER_ENTERED)
        .requestValuesBatchUpdate();
      builder.execute();
      builder.refreshSheetMetadata();
    }

    if (deleteEmpty) {
      // Удаляем пустые строки и столбцы
      const deleteResponse = builder.requestDeleteEmptyRowsAndColumns();
      if (deleteResponse.resource) {
        console.log("📝 Удаляем пустые строки и столбцы...");
        builder.execute();
      }
    }

    if (setFilter) {
      console.log("📝 Устанавливаем фильтр...");
      builder.requestSetFilter();
      builder.execute();
    }

    // builder.refreshSheetMetadata();
    builder.resetSheetName();

    CONFIG.func.endScript({
      script,
      start,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

