/**
 * Check if technical maintenance is needed and end the script if necessary.
 *
 * @param {string} script - The script to be checked for technical maintenance.
 * @return {boolean} if true
 */
function technicalBreak_({
  message,
  script,
  start,
  day = 1,
  hourTo = 16,
  hourFrom = 2,
}) {
  const dateTime = new Date();
  if (
    dateTime.getDay() === day &&
    dateTime.getHours() < hourTo &&
    dateTime.getHours() >= hourFrom
  ) {
    message =
      message ||
      `Технические работы с ${hourFrom}:00 до ${hourTo}:00 (загрузка будет доступна после ${hourTo}:00)`;

    console.error(message);

    CONFIG.func.endScript({
      script,
      start,
      message,
      messageType: 2,
    });

    return true;
  }
  return false;
}

/**
 * Преобразование массива в объект для проверки обновлений накопления Orders
 * @param {Array} dataArray - массив данных
 * @param {Object} options - параметры
 * @returns {Map} Map обновлений
 */
function transformArrayToObject(dataArray, options = {}) {
  const { keyIndex = 3, dateIndex = 0, saleIdIndex } = options;
  const result = new Map();

  dataArray.shift();

  dataArray.forEach((row, index) => {
    if (!saleIdIndex && row[keyIndex]) {
      result.set(row[keyIndex], {
        updated_at: row[dateIndex], //.replace(/\s+/g, "T"),
        row: index + 2, // +2, 1 строка шапка, индексы с 0
      });
    } else if (saleIdIndex && row[keyIndex] && row[saleIdIndex]) {
      result.set(`${row[keyIndex]}_${row[saleIdIndex]}`, {
        updated_at: row[dateIndex], //.replace(/\s+/g, "T"),
        row: index + 2, // +2, 1 строка шапка, индексы с 0
      });
    }
  });

  return result;
}

/**
 * Обработка обновлений для накопления Orders
 * @param {Object} checkUpdates - объект обновлений
 * @param {Array} newData - новые данные
 * @param {Object} forUpdate - параметры
 * @param {boolean} accumulate - накопление
 * @returns {Object} результат обработки
 */
function processCheckUpdates(
  checkUpdates,
  newData,
  forUpdate,
  accumulate = false,
) {
  const { keyIndex = 3, dateIndex = 0, saleIdIndex } = forUpdate;

  // Если не накопление - возвращаем все как новые строки
  if (!accumulate) {
    return { newRows: newData || [], updateRows: {} };
  }

  const newRows = [];
  const updateRows = {};

  newData.forEach((row, index) => {
    const srid = row[keyIndex];
    const newDate = row[dateIndex]; //.replace(/\s+/g, "T");
    const saleId = row[saleIdIndex];

    if (!saleIdIndex && checkUpdates && checkUpdates.has(srid)) {
      // srid есть в checkUpdates - проверяем дату
      const existingData = checkUpdates.get(srid);
      // console.log("existingData:", existingData);
      // console.log("newDate:", newDate);
      // console.log(
      //   "existingData.updated_at !== newDate:",
      //   existingData.updated_at !== newDate
      // );

      if (existingData.updated_at !== newDate) {
        // Дата изменилась - добавляем в обновления
        updateRows[existingData.row] = row;
      }
    } else if (
      saleIdIndex &&
      checkUpdates &&
      checkUpdates.has(`${srid}_${saleId}`)
    ) {
      const existingData = checkUpdates.get(`${srid}_${saleId}`);
      if (existingData.updated_at !== newDate) {
        // Дата изменилась - добавляем в обновления
        updateRows[existingData.row] = row;
      }
    } else {
      // srid нет в checkUpdates - новый элемент
      newRows.push(row);
    }
  });

  return { newRows, updateRows };
}

/**
 * Создание диапазонов для обновления
 * @param {Object} updateRows - объект обновлений
 * @param {string} sheetName - имя листа
 * @returns {Object} диапазоны и значения
 */
function createUpdateRanges(updateRows, sheetName) {
  const ranges = [];
  const values = [];

  Object.entries(updateRows).forEach(([rowNumber, rowData]) => {
    // Создаем диапазон для строки (например, "Sheet1!5:5" для строки 5)
    const range = `${sheetName}!${rowNumber}:${rowNumber}`;
    ranges.push(range);

    // Добавляем данные для этой строки
    values.push(rowData);
  });

  return { ranges, values };
}

