/**
 * Список поставок FBW
 * @param {object} [options] параметры запроса
 */
function suppliesList(
  options = context?.config?.getConfigForCurrentFunction()
) {
  const start = CONFIG.func.start();
  const script = suppliesList.name;

  try {
    const {
      suppliesApi,
      formulas = [],
      setFilter = true,
      deleteEmpty = true,
    } = options;

    let { sheetName } = options;

    const formats = CONFIG.formats;
    const supplys = CONFIG.methods.supplys.info;
    const main = supplys.list;

    sheetName = sheetName || main.sheet;
    const builder = requestBuilder.init().setSheetName(sheetName);

    const header = main.header;
    let headers = ["Обновлено", ...Object.values(header)];

    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    // console.log(builder.sheetExists(sheetName));

    builder.createSheetIfNotExist({
      rowCount: 1000,
      columnCount: headers.length,
      frozenRowCount: 1,
      tabColor: main.sheetColor,
    });

    const { headersRange, headerChar } = builder.headersRange(headers);

    const { values } = builder.getDataBounds(
      null,
      `${supplys.sheetSettings}!C3:D5`
    );

    if (values.length > 0) {
      // Получаем значения из C3:D3 (строка 2, индексы 1-2)
      const [from, till] = values[0].map((el) => el.trim());
      // Получаем значение из C4 (строка 3, индекс 1)
      const dateType = values[1];

      if (from && till) {
        if (from.includes(".")) {
          const fromDate = new Date(from.split(".").reverse().join("-"));
          options.from = fromDate.toISOString().split("T")[0]; // "2025-09-22"
        } else {
          options.from = dateStrToFormatDate(from);
        }

        if (till.includes(".")) {
          // Преобразуем даты из формата "22.09.2025" в ISO формат
          const tillDate = new Date(till.split(".").reverse().join("-"));
          options.till = tillDate.toISOString().split("T")[0]; // "2025-09-27"
        } else {
          options.till = dateStrToFormatDate(till);
        }

        if (new Date(options.till) < new Date(options.from))
          throw new Error("Дата начала больше даты конца");

        options.type = dateType && dateType.length ? dateType[0].split("-")[0].trim() : undefined;
      }

      // Получаем значение из D4 (строка 4, индекс 1)
      let status = values[2];
      options.statusIDs = status && status.length
        ? status[0]
            .replaceAll(" ", "")
            .split(",")
            .map((el) => Number(el.split("-")[0].trim()))
        : undefined;
    }

    const response = suppliesApi.list(options);

    debugLog("Ответ:", response);

    if (!response.length) {
      console.log("Нет данных...");
      builder.resetSheetName();
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const startDate = [dateStrToFormatDate(new Date(), formats.datehhmm)];

    const result = response.map((item) => {
      return Object.keys(header).reduce((acc, key) => {
        let value = item[key];

        if ("supplyDate" === key)
          value = dateStrToFormatDate(value, formats.date);

        if (["createDate", "updatedDate", "factDate"].includes(key) && value)
          value = dateStrToFormatDate(value, formats.datehhmm);

        if ("statusID" === key) value = SupplyStatus[value] || value;
        if ("phone" === key) value = value?.replaceAll("+", "");

        return [...acc, value];
      }, startDate);
    });

    debugLog("Обработанный:", result);

    builder.executeValuesClear();

    console.log("📝 Вставляем заголовок...");
    builder
      .setRange(headersRange)
      .setValues([headers])
      .setValueInputOption(ValueInputOption.USER_ENTERED)
      .setInsertDataOption(InsertDataOption.OVERWRITE)
      .executeValuesAppend();
    builder.refreshSheetMetadata();

    const { needsMoreRows, rowsToAdd } = builder.checkRowsNeeded(
      sheetName,
      result.length
    );

    // Если нужны дополнительные строки - добавляем их
    if (needsMoreRows) {
      console.log(`📝 Добавляем ${rowsToAdd} строк...`);
      builder.requestAddRowsAtEnd(rowsToAdd);
      builder.execute();
    }

    // Вставляем данные
    console.log("📝 Вставляем данные...");
    builder
      .setRange(`A2:${headerChar}${result.length + 1}`)
      .setValueInputOption(ValueInputOption.USER_ENTERED)
      .createAndSendBatches(result, sheetName);
    builder.refreshSheetMetadata();

    if (deleteEmpty) {
      // Удаляем пустые строки и столбцы
      const deleteResponse = builder.requestDeleteEmptyRowsAndColumns();
      if (deleteResponse.resource) {
        console.log("📝 Удаляем пустые строки и столбцы...");
        builder.execute();
      }
    }

    if (setFilter) {
      console.log("📝 Устанавливаем фильтр...");
      builder.requestSetFilter();
      builder.execute();
    }

    builder.refreshSheetMetadata();
    builder.resetSheetName();

    CONFIG.func.endScript({
      script,
      start,
      message: "Список поставок, получили",
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

