/**
 * Коэффициенты приёмки на ближайшие 14 дней FBW
 * @param {object} [options] параметры запроса
 */
function suppliesTransitTariffs(
  options = context?.config?.getConfigForCurrentFunction()
) {
  const start = CONFIG.func.start();
  const script = suppliesTransitTariffs.name;

  try {
    const { suppliesApi, formulas = [], sheetName, emptyCols } = options;

    const main = CONFIG.methods.supplys.create.transitTariffs;

    const sheet = setSheetNew(sheetName || main.sheet, main.sheetColor, ss);

    const header = main.header;
    let headers = Object.values(header);

    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    setSheetHead(sheet, true);
    sheet.appendRow(headers);

    const response = suppliesApi.transitTariffs();

    debugLog("Ответ:", response);

    if (!response.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const startDate = [
      dateStrToFormatDate(new Date(), CONFIG.formats.datehhmm),
    ];

    const result = [];

    response.forEach((item) => {
      const baseData = {
        activeFrom: dateStrToFormatDate(
          item.activeFrom,
          CONFIG.formats.datehhmm
        ),
        transitWarehouseName: item.transitWarehouseName,
        destinationWarehouseName: item.destinationWarehouseName,
        palletTariff: item.palletTariff,
      };

      // Получаем тарифы для коробов (только value)
      let boxTariffValueTo1500 = null; // тариф до 1500 литров
      let boxTariffValueFrom1500 = null; // тариф от 1500 литров

      if (
        item.boxTariff &&
        Array.isArray(item.boxTariff) &&
        item.boxTariff.length > 0
      ) {
        // Ищем тариф до 1500 литров (0-й элемент)
        if (item.boxTariff[0]) {
          boxTariffValueTo1500 = item.boxTariff[0].value;
        }

        // Ищем тариф от 1500 литров (1-й элемент)
        if (item.boxTariff[1]) {
          boxTariffValueFrom1500 = item.boxTariff[1].value;
        }
      }

      // Создаем одну строку для каждого склада
      result.push([
        ...startDate,
        baseData.activeFrom,
        baseData.transitWarehouseName,
        baseData.destinationWarehouseName,
        baseData.palletTariff,
        boxTariffValueTo1500 || "-", // тариф до 1500
        boxTariffValueFrom1500 || "-", // тариф от 1500
      ]);
    });

    debugLog("Обработанный:", result);

    sheet
      .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
      .setValues(result);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Транзитные направления, получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

