/**
 * Generate tariffs data and populate the corresponding spreadsheet.
 *
 * @param {object} options - the options object containing date, emptyCols, and setFilter
 * @return {undefined} This function does not return anything
 */
function tariffs(options = context?.config?.getConfigForCurrentFunction()) {
  const start = CONFIG.func.start();
  const script = tariffs.name;

  try {
    // https://openapi.wb.ru/tariffs/api/ru/
    const { tariffsApi, date, locale, emptyCols, setFilter } = options;

    const dateFormat = CONFIG.formats.dateyyyy_MM_dd;
    const date_ = date || dateStrToFormatDate(new Date(), dateFormat);
    const config = CONFIG.methods.tariffs;

    const tariff_ = {
      commission: {
        response: tariffsApi.commission(locale),
        ...config.commission,
      },
      box: {
        response: tariffsApi.box(date_),
        ...config.box,
      },
      pallet: {
        response: tariffsApi.pallet(date_),
        ...config.pallet,
      },
      return: {
        response: tariffsApi.return(date_),
        ...config.return,
      },
    };

    Object.values(tariff_).forEach((tariff) => {
      const { sheetName, response, header, name } = tariff;

      const sheet = setSheetNew(sheetName, "BLACK", ss);
      const list = Object.keys(header);
      const header_ = Object.values(header);

      debugLog("Ответ:", response);

      if (name !== "commission") {
        const warehouseList = response.warehouseList;
        let dataOne, dateTwo, dateThree, d1, d2, d3;
        if (name === "return") {
          [dataOne, dateTwo, dateThree, _] = list;
          [d1, d2, d3] = [
            response[dataOne],
            response[dateTwo],
            response[dateThree],
          ];
        } else {
          [dataOne, dateTwo, _] = list;
          [d1, d2] = [response[dataOne], response[dateTwo]];
        }

        const result = warehouseList.map((obj) => {
          obj[dataOne] = d1;
          obj[dateTwo] = d2;
          if (name === "return") obj[dateThree] = d3;

          return list.reduce((acc, key) => {
            const c = obj[key];
            return [...acc, isNumeric(c) ? Number(c) : c];
            // return [...acc, isNumeric(c) ? Number(c) : c === "-" ? null : c];
          }, []);
        });

        debugLog("Обработанный:", result);

        result.unshift(header_);
        sheetClear({ sheet });
        addDataToSheetOptimized({
          result,
          fromRow: -1,
          sheet,
          api: true,
          setHead: true,
          script,
          start,
        });
      } else {
        const startDate = date_ ? [date_] : [];
        const result = response.map((obj) => {
          return list.reduce((acc, key) => {
            const c = obj[key];
            return [...acc, isNumeric(c) ? Number(c) : c];
            // return [...acc, isNumeric(c) ? Number(c) : c === "-" ? null : c];
          }, startDate);
        });

        debugLog("Обработанный:", result, 1);

        result.unshift(["Обновлено", ...header_]);
        sheetClear({ sheet });
        addDataToSheetOptimized({
          result,
          fromRow: -1,
          sheet,
          api: true,
          setHead: true,
          script,
          start,
        });
      }

      CONFIG.func.endScript({
        script,
        start,
        sheet,
        emptyCols,
        setFilter,
        runFunc: options?.runFunc,
      });
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

