 * @return {undefined} This function does not return anything
 */
function tariffsBox(options = context?.config?.getConfigForCurrentFunction()) {
  const start = CONFIG.func.start();
  const script = tariffsBox.name;

  const { formulas = [], timeZone } = CONFIG.settings.time;

  const { tariffsApi, date, emptyCols, setFilter } = options;

  const dateFormat = CONFIG.formats.dateyyyy_MM_dd;
  const date_ = date || dateStrToFormatDate(new Date(), dateFormat, timeZone);
  const config = CONFIG.methods.tariffs;

  const tariff_ = {
    box: {
      response: tariffsApi.box(date_),
      ...config.box,
    },
  };

  Object.values(tariff_).forEach((tariff) => {
    const { sheetName, response, header } = tariff;

    debugLog("Ответ:", response);

    const sheet = setSheetNew(sheetName, "BLACK", ss);
    const list = Object.keys(header);
    const header_ = Object.values(header);

    const warehouseList = response.warehouseList;

    const [dataOne, dateTwo, _] = list;
    const [d1, d2] = [response[dataOne], response[dateTwo]];

    const result = warehouseList.map((obj) => {
      obj[dataOne] = d1;
      obj[dateTwo] = d2;

      return list.reduce((acc, key) => {
        let c = obj[key];
        if (key === "geoName") c = FederalDistricts[c] || c;
        return [...acc, isNumeric(c) ? Number(c) : c];
      }, []);
    });

    debugLog("Обработанный:", result);

    let headers = header_;

    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    setSheetHead(sheet, true);
    sheet.appendRow(headers);

    if (!result.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
        emptyCols,
      });
    }

    sheet
      .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
      .setValues(result);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      emptyCols,
      setFilter,
      runFunc: options?.runFunc,
    });
  });
}

/**
 * Тарифы для коробов - возвращает объект с маппингом складов на регионы
 * @param {object} tariffsApi - API объект для получения тарифов
 * @return {object} Объект в формате {"Коледино": "Центральный федеральный округ", ...}
 */
function warehousesBoxFederalDistricts(apiKey) {
  const date_ = dateStrToFormatDate(new Date());

  try {
    const tariffs = new Tariffs({ apiKey });

    // tariffs.ping();

    const response = tariffs.box(date_);

    // Проверяем структуру ответа
    if (
      !response ||
      !response.warehouseList ||
      !Array.isArray(response.warehouseList)
    ) {
      console.error("Неверная структура ответа API:", response);
      return {};
    }

    // Создаем объект маппинга складов на регионы
    const warehouseMapping = {};

    response.warehouseList.forEach((warehouse) => {
      const district = FederalDistricts[warehouse.geoName] || warehouse.geoName;
      let wh_name = warehouse?.warehouseName?.toLowerCase();
      if (wh_name && district) {
        warehouseMapping[wh_name] = district;
      }
    });

    debugLog("Маппинг складов:", warehouseMapping);
    return warehouseMapping;
  } catch (error) {
    console.error("Ошибка в warehousesBoxFederalDistricts:", error.stack);
    return {};
  }
}

