/**
 * Коэффициенты приёмки на ближайшие 14 дней FBW (Тарифы на поставку)
 * @param {object} [options] параметры запроса
 */
function tariffsAcceptanceCoefficients(
  options = context?.config?.getConfigForCurrentFunction()
) {
  const start = CONFIG.func.start();
  const script = tariffsAcceptanceCoefficients.name;

  try {
    const {
      tariffsApi,
      formulas = [],
      warehouseIDs = null,
      sheetName,
      emptyCols,
    } = options;

    const main = CONFIG.methods.tariffs.acceptanceCoefficients;

    const sheet = setSheetNew(sheetName || main.sheet, main.sheetColor, ss);

    const header = main.header;
    let headers = ["Обновлено", ...Object.values(header)];

    if (formulas.length > 0) {
      headers = headers.concat(formulas);
    }

    setSheetHead(sheet, true);
    sheet.appendRow(headers);

    const response = tariffsApi.acceptanceCoefficients(warehouseIDs);

    debugLog("Ответ:", response);

    if (!response.length) {
      return CONFIG.func.endScript({
        script,
        start,
        message: "Нет данных",
        messageType: 2,
      });
    }

    const startDate = [
      dateStrToFormatDate(new Date(), CONFIG.formats.datehhmm),
    ];

    const result = response.map((item) => {
      return Object.keys(header).reduce((acc, key) => {
        let value = item[key];
        if (key === "date")
          value = dateStrToFormatDate(value, CONFIG.formats.date);

        if (
          [
            "storageCoef",
            "deliveryCoef",
            "deliveryBaseLiter",
            "deliveryAdditionalLiter",
            "storageBaseLiter",
            "storageAdditionalLiter",
          ].includes(key) &&
          value
        )
          value = value?.replace(".", ",");

        if (key === "boxTypeName")
          value = SupplyBoxTypeName[item.boxTypeID] || value;

        if (key === "isSortingCenter") value = value ? "СЦ" : "Обычный";
        return [...acc, value];
      }, startDate);
    });

    debugLog("Обработанный:", result);

    sheet
      .getRange(sheet.getLastRow() + 1, 1, result.length, result[0].length)
      .setValues(result);

    CONFIG.func.endScript({
      script,
      start,
      sheet,
      message: "Коэффициенты приёмки, на ближайшие 14 дн., получили",
      emptyCols,
      runFunc: options?.runFunc,
    });
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

