      .setSpreadsheetId(SpreadsheetApp.getActiveSpreadsheet().getId())
      .setSheetName("Тест Поиск")
      .init();

    // Тест 1: Простая замена
    console.log("\n📝 Тест 1: Простая замена");
    const simpleReplace = builder.requestFindReplace({
      find: "старый_текст",
      replacement: "новый_текст",
    });

    console.log(
      "Запрос простой замены:",
      JSON.stringify(simpleReplace, null, 2)
    );

    // Тест 2: Замена с учетом регистра
    console.log("\n📝 Тест 2: Замена с учетом регистра");
    const caseSensitiveReplace = builder.requestFindReplace({
      find: "ТЕКСТ",
      replacement: "текст",
      matchCase: true,
    });

    console.log(
      "Запрос замены с учетом регистра:",
      JSON.stringify(caseSensitiveReplace, null, 2)
    );

    // Тест 3: Замена в определенном диапазоне
    console.log("\n📝 Тест 3: Замена в диапазоне");
    const rangeReplace = builder.requestFindReplace({
      find: "найти",
      replacement: "заменить",
      range: "A1:C10",
    });

    console.log(
      "Запрос замены в диапазоне:",
      JSON.stringify(rangeReplace, null, 2)
    );

    // Тест 4: Замена с регулярными выражениями
    console.log("\n📝 Тест 4: Замена с регулярными выражениями");
    const regexReplace = builder.requestFindReplace({
      find: "\\d{4}-\\d{2}-\\d{2}", // Паттерн для даты YYYY-MM-DD
      replacement: "ДАТА",
      searchByRegex: true,
    });

    console.log(
      "Запрос замены с regex:",
      JSON.stringify(regexReplace, null, 2)
    );

    // Тест 5: Замена с совпадением всей ячейки
    console.log("\n📝 Тест 5: Замена с совпадением всей ячейки");
    const entireCellReplace = builder.requestFindReplace({
      find: "точное_совпадение",
      replacement: "замена",
