/**
 * Тест для проверки системы лимитов запросов Google Sheets API
 */

function testRateLimiting() {
  console.log("🧪 Тестируем систему лимитов запросов...");

  try {
    // Получаем начальную статистику
    const initialStats = SheetsApiRequestBuilder.getRequestStats();
    console.log(
      "📊 Начальная статистика:",
      JSON.stringify(initialStats, null, 2)
    );

    // Проверяем, что статистика работает
    if (
      typeof initialStats.read.current !== "number" ||
      typeof initialStats.write.current !== "number"
    ) {
      throw new Error("Статистика запросов работает некорректно");
    }

    console.log("✅ Статистика запросов работает");

    // Проверяем лимиты
    const limits = SheetsApiRequestBuilder.LIMITS;
    console.log("📋 Лимиты API:", {
      readPerMinute: limits.READ_PER_MINUTE,
      writePerMinute: limits.WRITE_PER_MINUTE,
      userReadPerMinute: limits.USER_READ_PER_MINUTE,
      userWritePerMinute: limits.USER_WRITE_PER_MINUTE,
    });

    console.log("✅ Лимиты настроены правильно");

    // Сбрасываем счетчики для чистого теста
    SheetsApiRequestBuilder.resetRequestCounts();

    const resetStats = SheetsApiRequestBuilder.getRequestStats();
    if (resetStats.read.current !== 0 || resetStats.write.current !== 0) {
      throw new Error("Сброс счетчиков не работает");
    }

    console.log("✅ Сброс счетчиков работает");

    console.log("🎯 Результат: ✅ ВСЕ ТЕСТЫ ПРОШЛИ");
    return true;
  } catch (error) {
    console.error("❌ Ошибка при тестировании лимитов:", error.message);
    console.log("🎯 Результат: ❌ ТЕСТ НЕ ПРОШЕЛ");
    return false;
  }
}

function testRequestCounting() {
  console.log("🧪 Тестируем подсчет запросов...");

  try {
    // Сбрасываем счетчики
    SheetsApiRequestBuilder.resetRequestCounts();

    // Симулируем увеличение счетчиков
    SheetsApiRequestBuilder._incrementRequestCount("read");
    SheetsApiRequestBuilder._incrementRequestCount("read");
    SheetsApiRequestBuilder._incrementRequestCount("write");

    const stats = SheetsApiRequestBuilder.getRequestStats();

    if (stats.read.current !== 2) {
      throw new Error(`Ожидали 2 read запроса, получили ${stats.read.current}`);
    }

    if (stats.write.current !== 1) {
      throw new Error(
        `Ожидали 1 write запрос, получили ${stats.write.current}`
      );
    }

    console.log("✅ Подсчет запросов работает корректно");

    // Проверяем проверку лимитов
    const canMakeRead = SheetsApiRequestBuilder._checkRequestLimits("read");
    const canMakeWrite = SheetsApiRequestBuilder._checkRequestLimits("write");

    if (!canMakeRead || !canMakeWrite) {
      throw new Error("Проверка лимитов работает некорректно");
    }

    console.log("✅ Проверка лимитов работает");

    console.log("🎯 Результат: ✅ ВСЕ ТЕСТЫ ПРОШЛИ");
    return true;
  } catch (error) {
    console.error("❌ Ошибка при тестировании подсчета:", error.message);
    console.log("🎯 Результат: ❌ ТЕСТ НЕ ПРОШЕН");
    return false;
  }
}

function testRateLimitExceeded() {
  console.log("🧪 Тестируем превышение лимитов...");

  try {
    // Сбрасываем счетчики
    SheetsApiRequestBuilder.resetRequestCounts();

    // Симулируем превышение лимита read запросов
    for (
      let i = 0;
      i < SheetsApiRequestBuilder.LIMITS.READ_PER_MINUTE + 1;
      i++
    ) {
      SheetsApiRequestBuilder._incrementRequestCount("read");
    }

    const canMakeRead = SheetsApiRequestBuilder._checkRequestLimits("read");

    if (canMakeRead) {
      throw new Error("Лимит read запросов должен быть превышен");
    }

    console.log("✅ Обнаружение превышения лимита работает");

    const stats = SheetsApiRequestBuilder.getRequestStats();
    console.log("📊 Статистика после превышения:", {
      read: `${stats.read.current}/${stats.read.limit} (осталось: ${stats.read.remaining})`,
      write: `${stats.write.current}/${stats.write.limit} (осталось: ${stats.write.remaining})`,
    });

    console.log("🎯 Результат: ✅ ВСЕ ТЕСТЫ ПРОШЛИ");
    return true;
  } catch (error) {
    console.error("❌ Ошибка при тестировании превышения:", error.message);
    console.log("🎯 Результат: ❌ ТЕСТ НЕ ПРОШЕН");
    return false;
  }
}

