// Тест для проверки исправления UTC конвертации

function testUTCFix() {
  try {
    console.log("🔧 Тестируем исправление UTC конвертации...");

    // Инициализируем русскую локаль
    SheetsApiRequestBuilder.initializeMomentLocale();

    // Тестируем конвертацию даты '2025-01-15'
    const testDate = "2025-01-15";
    console.log(`📅 Тестируем дату: "${testDate}"`);

    // Парсим дату
    const parsed = SheetsApiRequestBuilder.parseMomentDate(testDate);
    console.log(`   Парсинг: ${parsed.toISOString()}`);

    // Конвертируем в serial date
    const serialDate = SheetsApiRequestBuilder.momentDateToFloatDate(parsed);
    console.log(`   Serial date: ${serialDate}`);

    // Обратно конвертируем в дату
    const backToDate =
      SheetsApiRequestBuilder.floatDateToMomentDate(serialDate);
    console.log(`   Обратно: ${backToDate.toISOString()}`);

    // Проверяем, что дата корректная (должна быть 2025-01-15 00:00:00 UTC)
    const expected = new Date("2025-01-15T00:00:00.000Z");
    const isCorrect = Math.abs(parsed.getTime() - expected.getTime()) < 1000; // 1 секунда погрешности

    if (isCorrect) {
      console.log("✅ Дата корректно обработана в UTC!");
    } else {
      console.log("❌ Дата обработана некорректно!");
      console.log(`   Ожидалось: ${expected.toISOString()}`);
      console.log(`   Получилось: ${parsed.toISOString()}`);
    }

    return isCorrect;
  } catch (error) {
    console.error("❌ Ошибка при тестировании UTC:", error.message);
    return false;
  }
}

