    if (firstCell.userEnteredValue.numberValue !== undefined) {
      console.log("✅ Дата конвертирована в numberValue!");
      console.log(`   Serial date: ${firstCell.userEnteredValue.numberValue}`);

      // Проверяем, что serial date соответствует 2025-01-15 00:00:00 UTC
      const expectedSerial = 45671; // Примерно для 2025-01-15
