/**
 * @fileoverview Google Sheets API Request Builder
 * @description Библиотека для создания запросов к Google Sheets API с использованием паттерна Builder
 * @author Wildberries API Integration
 * @version 1.0.0
 * @see {@link https://developers.google.com/workspace/sheets/api/reference/rest Google Sheets API Documentation}
 * https://developers.google.com/resources/api-libraries/documentation/sheets/v4/java/latest/com/google/api/services/sheets/v4/package-tree.html
 * https://developers.google.com/resources/api-libraries/documentation/sheets/v4/java/latest/allclasses-noframe.html
 * /


/**
 * Основной класс для построения запросов к Google Sheets API
 * Использует паттерн Builder для создания сложных запросов
 *
 * @example
 * const request = new SheetsApiRequestBuilder()
 *   .setSpreadsheetId('1BxiMVs0XRA5nFMdKvBdBZjgmUUqptlbs74OgvE2upms')
 *   .setRange('A1:C3')
 *   .setValueInputOption(ValueInputOption.RAW)
 *   .setValues([['Name', 'Age', 'City'], ['John', 25, 'New York']])
 *   .requestUpdate();
 *
 * @see {@link https://developers.google.com/workspace/sheets/api/reference/rest/v4/spreadsheets.values/update}
 */
class SheetsApiRequestBuilder {
  constructor() {
    this.reset();
  }

  // Статические свойства для Google Apps Script
  static get requestCounts() {
    if (!this._requestCounts) {
      this._requestCounts = {
        read: { count: 0, resetTime: Date.now() + 60000 },
        write: { count: 0, resetTime: Date.now() + 60000 },
      };
    }
    return this._requestCounts;
  }

  static get LIMITS() {
    return {
      READ_PER_MINUTE: 300,
      WRITE_PER_MINUTE: 300,
      USER_READ_PER_MINUTE: 60,
      USER_WRITE_PER_MINUTE: 60,
      MAX_REQUEST_TIME: 180000, // 180 секунд в миллисекундах
    };
  }

  /**
   * Проверяет и обновляет счетчики запросов
   * @param {string} requestType - Тип запроса ('read' или 'write')
   * @returns {boolean} true если можно выполнить запрос, false если нужно подождать
   */
  static _checkRequestLimits(requestType) {
    const now = Date.now();
    const counters = SheetsApiRequestBuilder.requestCounts[requestType];

    // Сбрасываем счетчик если прошла минута
    if (now >= counters.resetTime) {
      counters.count = 0;
      counters.resetTime = now + 60000;
    }

    const limit =
      requestType === "read"
        ? this.LIMITS.READ_PER_MINUTE
        : this.LIMITS.WRITE_PER_MINUTE;

    return counters.count < limit;
  }

  /**
   * Увеличивает счетчик запросов
   * @param {string} requestType - Тип запроса ('read' или 'write')
   */
  static _incrementRequestCount(requestType) {
    const counters = SheetsApiRequestBuilder.requestCounts[requestType];
    counters.count++;
  }

  /**
   * Выполняет задержку с экспоненциальным backoff
   * @param {number} attempt - Номер попытки (начинается с 1)
   * @param {number} maxAttempts - Максимальное количество попыток
   */
  static _exponentialBackoff(attempt, maxAttempts = 5) {
    if (attempt > maxAttempts) {
      throw new Error(
        `Превышено максимальное количество попыток (${maxAttempts})`
      );
    }

    const baseDelay = Math.min(Math.pow(2, attempt) * 1000, 32000); // Максимум 32 секунды
    const randomDelay = Math.random() * 1000; // До 1 секунды случайной задержки
    const totalDelay = baseDelay + randomDelay;

    console.log(
      `⏳ Задержка ${Math.round(totalDelay)}мс перед попыткой ${attempt + 1}`
    );

    Utilities.sleep(totalDelay);
  }

  /**
   * Извлекает HTTP код ответа из сообщения об ошибке
   * @param {string} errorMessage - Сообщение об ошибке
   * @returns {number|null} HTTP код ответа или null если не найден
   */
  static _extractHttpCode(errorMessage) {
    if (!errorMessage) return null;

    // Ищем паттерны типа "Код ответа: 502" или "502" или "Error 502"
    const codePatterns = [
      /Код ответа:\s*(\d{3})/i,
      /(\d{3})\s*\(Server Error\)/i,
      /Error\s+(\d{3})/i,
      /\b(\d{3})\b/,
    ];

    for (const pattern of codePatterns) {
      const match = errorMessage.match(pattern);
      if (match) {
        const code = parseInt(match[1], 10);
        if (code >= 100 && code <= 599) {
          return code;
        }
      }
    }

    return null;
  }

  /**
   * Выполняет запрос с учетом лимитов и повторными попытками
   * @param {Function} requestFunction - Функция для выполнения запроса
   * @param {string} requestType - Тип запроса ('read' или 'write')
   * @param {number} maxAttempts - Максимальное количество попыток
   * @returns {*} Результат выполнения запроса
   */
  static _executeWithLimits(requestFunction, requestType, maxAttempts = 5) {
    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
      try {
        // Проверяем лимиты
        if (!this._checkRequestLimits(requestType)) {
          const waitTime =
            this.requestCounts[requestType].resetTime - Date.now();
          console.log(
            `⏳ Превышен лимит ${requestType} запросов. Ожидание ${Math.round(
              waitTime / 1000
            )}с`
          );
          Utilities.sleep(waitTime);
        }

        // Выполняем запрос
        const result = requestFunction();

        // Увеличиваем счетчик только при успешном запросе
        this._incrementRequestCount(requestType);

        return result;
      } catch (error) {
        const errorMessage = error.message || "";
        const errorCode = this._extractHttpCode(errorMessage);

        console.error(
          `❌ Попытка ${attempt} не удалась: Код ответа: ${
            errorCode || "N/A"
          }. Сообщение: ${errorMessage.substring(0, 200)}`
        );

        // Проверяем, является ли это серверной ошибкой (500, 502, 503, 504) - повторяем запрос
        if (errorCode && [500, 502, 503, 504].includes(errorCode)) {
          if (attempt < maxAttempts) {
            console.log(
              `🔄 Серверная ошибка ${errorCode}. Повторная попытка ${
                attempt + 1
              }/${maxAttempts}...`
            );
            this._exponentialBackoff(attempt, maxAttempts);
            continue;
          }
        }

        // Проверяем, является ли это ошибкой лимита
        if (
          errorCode === 429 ||
          errorMessage.includes("429") ||
          errorMessage.includes("Too many requests")
        ) {
          if (attempt < maxAttempts) {
            this._exponentialBackoff(attempt, maxAttempts);
            continue;
          }
        }

        // Если это не ошибка сервера/лимита или превышены попытки, пробрасываем ошибку
        throw error;
      }
    }
  }

  /**
   * Получает статистику использования API
   * @returns {Object} Статистика запросов
   */
  static getRequestStats() {
    const now = Date.now();
    const readCounters = this.requestCounts.read;
    const writeCounters = this.requestCounts.write;

    return {
      read: {
        current: readCounters.count,
        limit: this.LIMITS.READ_PER_MINUTE,
        remaining: this.LIMITS.READ_PER_MINUTE - readCounters.count,
        resetIn: Math.max(0, Math.round((readCounters.resetTime - now) / 1000)),
      },
      write: {
        current: writeCounters.count,
        limit: this.LIMITS.WRITE_PER_MINUTE,
        remaining: this.LIMITS.WRITE_PER_MINUTE - writeCounters.count,
        resetIn: Math.max(
          0,
          Math.round((writeCounters.resetTime - now) / 1000)
        ),
      },
    };
  }

  /**
   * Сбрасывает счетчики запросов
   */
  static resetRequestCounts() {
    const now = Date.now();
    this.requestCounts.read = { count: 0, resetTime: now + 60000 };
    this.requestCounts.write = { count: 0, resetTime: now + 60000 };
    console.log("🔄 Счетчики запросов сброшены");
  }

  /**
   * Сбрасывает все параметры билдера
   * @returns {SheetsApiRequestBuilder} Текущий экземпляр билдера
   */
  reset() {
    this.debug = context?.debug;
    this._spreadsheetId = null;
    this._requestType = null;
    this._sheetName = null;
    this._metadata = null;
    this._sheetNames = new Set();
    this._cacheKey = null;
    this._range = null;
    this._headers = [];
    // update, append, clear, get, batchUpdate, batchGet, batchClear
    this._valueInputOption = ValueInputOption.RAW;
    this._valueRenderOption = ValueRenderOption.FORMATTED_VALUE;
    this._dateTimeRenderOption = DateTimeRenderOption.SERIAL_NUMBER;
    this._includeValuesInResponse = false;
    this._responseValueRenderOption = ValueRenderOption.FORMATTED_VALUE;
    this._responseDateTimeRenderOption = DateTimeRenderOption.SERIAL_NUMBER;
    this._insertDataOption = InsertDataOption.OVERWRITE;
    this._majorDimension = Dimension.ROWS;
    // batchUpdate, batchGet, batchClear
    this._ranges = [];
    this._includeSpreadsheetInResponse = false;
    this._responseRanges = [];
    this._responseIncludeGridData = false;
    this._responseExcludeTablesInBandedRanges = false;
    // request
    this._addSheetOptions = null;
    this._dataFilters = [];
    this._requests = [];
    this._columnFormats = [];
    this._insertRowsRequest = null;
    this._addRowsRequest = null;
    this._addRowsAtEndRequest = null;
    this._addSheetRequest = null;
    this._deleteSheetRequest = null;
    this._copyToRequest = null;
    this._updateRequest = null;
    this._updateWithFormatRequest = null;
    this._appendWithFormatRequest = null;
    this._deleteEmptyRowsAndColumnsRequest = null;
    this._deleteEmptyRowsRequest = null;
    this._deleteEmptyColumnsRequest = null;
    this._formatRequest = null;
    this._clearRequest = null;
    this._findReplaceRequest = null;
    this._valuesBatchGetRequest = null;
    this._valuesBatchClearRequest = null;
    this._valuesBatchUpdateRequest = null;
    this._setFilterRequest = null;
    // response append, update
    this._values = null;
    this._valueRanges = null;
    this._valueClearedRanges = null;

    return this;
  }

  // ==================== УСТАНОВКА ПАРАМЕТРОВ ====================

  /**
   * Устанавливает ID таблицы
   * @param {string} spreadsheetId - ID Google Sheets таблицы
   * @returns {SheetsApiRequestBuilder} Текущий экземпляр билдера
   * @see {@link https://developers.google.com/workspace/sheets/api/reference/rest/v4/spreadsheets#Spreadsheet}
   */
  setSpreadsheetId(spreadsheetId) {
    if (!spreadsheetId || typeof spreadsheetId !== "string") {
      throw new Error("SpreadsheetId должен быть непустой строкой");
    }
    this._spreadsheetId = spreadsheetId;
    this._cacheKey = `metadata_${spreadsheetId}`;
    return this;
  }

  /**
   * Устанавливает название листа
   * @param {string} sheetName - Название листа
   * @returns {SheetsApiRequestBuilder} Текущий экземпляр билдера
   */
  setSheetName(sheetName) {
    if (!sheetName || typeof sheetName !== "string") {
      throw new Error("SheetName должен быть непустой строкой");
    }
    this._sheetName = sheetName;
    return this;
  }

  /**
   * Сбрасывает название листа
   * @returns {SheetsApiRequestBuilder} Текущий экземпляр билдера
   */
  resetSheetName() {
    this._sheetName = null;
    return this;
  }

  /**
   * Устанавливает диапазон ячеек
   * @param {string} range - Диапазон в формате A1 notation (например, 'A1:C3', 'Sheet1!A1:C3')
   * @returns {SheetsApiRequestBuilder} Текущий экземпляр билдера
   * @see {@link https://developers.google.com/workspace/sheets/api/reference/rest/v4/spreadsheets.values/get#range}
   */
  setRange(range) {
    if (!range || typeof range !== "string") {
      throw new Error("Range должен быть непустой строкой");
    }
    this._range = this._normalizeRange(range);
    return this;
  }

  /**
   * Добавляет диапазон для batch операций
   * @param {string} range - Диапазон в формате A1 notation
   * @returns {SheetsApiRequestBuilder} Текущий экземпляр билдера
   */
  addRange(range) {
    if (!range || typeof range !== "string") {
      throw new Error("Range должен быть непустой строкой");
    }
    this._ranges.push(this._normalizeRange(range));
    return this;
  }

  /**
   * Устанавливает множественные диапазоны
   * @param {string[]} ranges - Массив диапазонов
   * @returns {SheetsApiRequestBuilder} Текущий экземпляр билдера
   */
  setRanges(ranges) {
    if (!Array.isArray(ranges)) {
      throw new Error("Ranges должен быть массивом");
    }
    this._ranges = ranges.map((range) => this._normalizeRange(range));
    return this;
  }

  /**
   * Устанавливает значения для записи
   * @param {Array<Array<any>>} values - Двумерный массив значений
   * @returns {SheetsApiRequestBuilder} Текущий экземпляр билдера
