  /**
   * Устанавливает формат столбцов для batchUpdate запроса
   * @param {Array|Object} columnFormats - Массив объектов с настройками столбцов или объект {range: format}
   * @param {string} sheetName - Название листа (опционально)
   * @returns {SheetsApiRequestBuilder} Текущий экземпляр билдера
   *
   * @example
   * // Массив объектов
   * .setColumnsFormat([
   *   { range: "A1:A100", format: "dd.mm.yyyy", type: "DATE_TIME" },
   *   { range: "B1:B100", format: "dd.mm.yyyy hh:mm", type: "DATE_TIME" }
   * ])
   */
  setColumnsFormat(columnFormats, sheetName = null) {
    // Поддерживаемые типы форматирования
    const validTypes = [
      "TEXT", // Форматирование текста, например 1000.12
      "NUMBER", // Форматирование чисел, например, 1,000.12
      "PERCENT", // Процентное форматирование, например 10.12%
      "CURRENCY", // Форматирование валюты, например $1,000.12
      "DATE", // Форматирование даты, например 9/26/2008
      "TIME", // Форматирование времени, например 3:59:00 PM
      "DATE_TIME", // Форматирование даты и времени, например 9/26/08 15:59:00
      "SCIENTIFIC", // Научное форматирование чисел, например 1.01E+03
    ];

    const processFormats = (formats) => {
      return formats.map((config) => {
        const { range, format, type = "DATE_TIME" } = config;

        // Проверяем валидность типа
        if (!validTypes.includes(type)) {
          throw new Error(
            `Неверный тип форматирования "${type}". Поддерживаемые типы: ${validTypes.join(
              ", "
            )}`
          );
        }

        return { range, format, type };
      });
    };

    this._columnFormats = Array.isArray(columnFormats)
      ? processFormats(columnFormats)
      : processFormats(
          Object.entries(columnFormats).map(([range, format]) => ({
            range,
            format,
            type: "DATE_TIME",
          }))
        );

    this._sheetName = sheetName;
    return this;
  }

  /**
   * Создает запрос для добавления нового листа
   * @param {Object} options - Параметры для создания листа
