   * @param {number} options.index - Индекс листа (по умолчанию 0)
   * @param {number} options.rowCount - Количество строк (по умолчанию 1000)
   * @param {number} options.columnCount - Количество столбцов (по умолчанию 26)
   * @param {number} options.frozenRowCount - Количество замороженных строк (по умолчанию 1)
   * @param {number} options.frozenColumnCount - Количество замороженных столбцов (по умолчанию 0)
   * @param {boolean} options.hideGridlines - Скрыть сетку (по умолчанию false)
   * @param {Object} options.tabColor - Цвет вкладки {red, green, blue, alpha}
   * @returns {SheetsApiRequestBuilder} Текущий экземпляр билдера
   */
  setAddSheetOptions(options) {
    const {
      title,
      index = 0,
      rowCount = 1000,
      columnCount = 26,
      frozenRowCount = 0,
      frozenColumnCount = 0,
      hideGridlines = false,
      rowGroupControlAfter = false,
      columnGroupControlAfter = false,
      tabColor = null,
    } = options;

    if (!title) {
      throw new Error("Название листа (title) обязательно для создания листа");
    }

    this._addSheetOptions = {
      title,
      index,
      rowCount,
      columnCount,
      frozenRowCount,
      frozenColumnCount,
      hideGridlines,
      rowGroupControlAfter,
      columnGroupControlAfter,
      tabColor,
    };

    return this;
