  // ==================== СОЗДАНИЕ ЗАПРОСОВ ====================

  /**
   * Создает запрос для добавления листа
   * @returns {Object} Объект запроса для batchUpdate с добавлением листа
   * @throws {Error} Если не указаны обязательные параметры
   */
  requestAddSheet() {
    this._validateRequired(["_spreadsheetId"]);
    this._requestType = "addSheet";

    if (!this._addSheetOptions) {
      throw new Error(
        "Необходимо указать параметры листа через setAddSheetOptions()"
      );
    }

    const {
      title,
      index,
      rowCount,
      columnCount,
      frozenRowCount,
      frozenColumnCount,
      hideGridlines,
      rowGroupControlAfter,
      columnGroupControlAfter,
      tabColor,
    } = this._addSheetOptions;

    const addSheetRequest = {
      addSheet: {
        properties: {
          title,
          index,
          gridProperties: {
            rowCount,
            columnCount,
            frozenRowCount,
            frozenColumnCount,
            hideGridlines,
            rowGroupControlAfter,
            columnGroupControlAfter,
          },
        },
      },
    };

    // Добавляем цвет вкладки если указан
    if (tabColor) {
      let rgbColor;

      // Если tabColor - это строка (hex), конвертируем в RGB
      if (typeof tabColor === "string") {
        rgbColor = this._hexToRgb(tabColor);
      } else {
        // Если tabColor - это объект, используем как есть
        rgbColor = {
          red: tabColor.red || 0,
          green: tabColor.green || 0,
          blue: tabColor.blue || 0,
        };
      }

      addSheetRequest.addSheet.properties.tabColorStyle = {
        rgbColor: rgbColor,
      };
    }

    this._addSheetRequest = {
      requests: [addSheetRequest],
      includeSpreadsheetInResponse: this._includeSpreadsheetInResponse,
      responseRanges: this._responseRanges,
      responseIncludeGridData: this._responseIncludeGridData,
    };

    return {
      spreadsheetId: this._spreadsheetId,
      resource: this._addSheetRequest,
    };
  }

