   * @param {number} afterRowIndex - Индекс строки, после которой вставлять (0-based, включающий)
   * @param {number} numRows - Количество строк для вставки
   * @param {number|null} sheetId - ID листа (если null, используется _sheetName)
   * @returns {Object} Объект запроса для Sheets.Spreadsheets.batchUpdate
   */
  insertRowsAfterRequest(afterRowIndex, numRows, sheetId = null) {
    this._validateRequired(["_spreadsheetId"]);
    this._requestType = "insertRows";

    if (typeof afterRowIndex !== "number" || afterRowIndex < 0) {
      throw new Error("afterRowIndex должен быть неотрицательным числом");
    }

    if (typeof numRows !== "number" || numRows <= 0) {
      throw new Error("numRows должен быть положительным числом");
    }

    const targetSheetId =
      sheetId || (this._sheetName ? this.getSheetId(this._sheetName) : null);

    if (targetSheetId === null) {
      throw new Error(
        "Необходимо указать sheetId или установить sheetName через setSheetName()"
      );
    }

    // Получаем текущие размеры листа для проверки
    const dimensions = this.getSheetDimensions(this._sheetName);
    const currentRowCount = dimensions.rowCount;

    // Для inheritFromBefore: false, startIndex должен быть меньше размера сетки
    // Поэтому ограничиваем afterRowIndex + 1 максимальным значением currentRowCount - 1
    const startIndex = Math.min(afterRowIndex + 1, currentRowCount - 1);

    console.log("Вставка строк:");
    console.log("- afterRowIndex:", afterRowIndex);
    console.log("- numRows:", numRows);
    console.log("- currentRowCount:", currentRowCount);
    console.log("- startIndex:", startIndex);
    console.log("- endIndex:", startIndex + numRows);

    const insertRowsOptions = {
      insertDimension: {
        range: {
          sheetId: targetSheetId,
          dimension: "ROWS",
          startIndex: startIndex, // Вставляем после указанной строки или в конец
          endIndex: startIndex + numRows, // Конечный индекс (эксклюзивный)
        },
        inheritFromBefore: false, // Наследовать форматирование от строки выше
      },
    };

    this._insertRowsRequest = {
      requests: [insertRowsOptions],
      includeSpreadsheetInResponse: this._includeSpreadsheetInResponse,
      responseRanges: this._responseRanges,
      responseIncludeGridData: this._responseIncludeGridData,
