    return {
      spreadsheetId: this._spreadsheetId,
      resource: this._insertRowsRequest,
    };
  }

  /**
   * Создает запрос на добавление строк в конец таблицы
   * @param {number} numRows - Количество строк для добавления
   * @param {number|null} sheetId - ID листа (если null, используется _sheetName)
   * @returns {Object} Объект запроса для Sheets.Spreadsheets.batchUpdate
   */
  requestAddRows(numRows, sheetId = null) {
    this._validateRequired(["_spreadsheetId"]);
    this._requestType = "addRows";

    if (typeof numRows !== "number" || numRows <= 0) {
      throw new Error("numRows должен быть положительным числом");
    }

    const targetSheetId =
      sheetId || (this._sheetName ? this.getSheetId(this._sheetName) : null);

    if (targetSheetId === null) {
      throw new Error(
        "Необходимо указать sheetId или установить sheetName через setSheetName()"
      );
    }

    // Получаем текущие размеры листа
    const dimensions = this.getSheetDimensions(this._sheetName);
    const currentRowCount = dimensions.rowCount;

    // Для inheritFromBefore: false, startIndex должен быть меньше размера сетки
    // Поэтому используем currentRowCount - 1 (последняя существующая строка)
    const startIndex = Math.max(0, currentRowCount - 1);

    const addRowsOptions = {
      insertDimension: {
        range: {
          sheetId: targetSheetId,
          dimension: "ROWS",
          startIndex: startIndex, // Вставляем после последней строки
          endIndex: startIndex + numRows, // Конечный индекс (эксклюзивный)
        },
        inheritFromBefore: false, // Наследовать форматирование от строки выше
      },
    };

    this._addRowsRequest = {
      requests: [addRowsOptions],
      includeSpreadsheetInResponse: this._includeSpreadsheetInResponse,
      responseRanges: this._responseRanges,
      responseIncludeGridData: this._responseIncludeGridData,
    };

    return {
      spreadsheetId: this._spreadsheetId,
      resource: this._addRowsRequest,
    };
  }

