  /**
   * Создает запрос на добавление данных с форматированием
   * @param {Array<Array<any>>} values - Двумерный массив значений
   * @param {string} range - Диапазон для добавления (A1 notation)
   * @param {Object} formatOptions - Опции форматирования
   * @param {Object} formatOptions.columns - Форматирование по столбцам {0: {numberFormat: "dd.mm.yyyy", numberFormatType: "DATE"}, 2: {numberFormat: "#,##0.00"}}
   * @param {Object} formatOptions.global - Глобальное форматирование для всех ячеек
   * @param {string} sheetName - Название листа (опционально)
   * @returns {Object} Объект запроса для Sheets.Spreadsheets.batchUpdate
   */
  requestAppendWithFormat(values, range, formatOptions = {}, sheetName = null) {
    this._validateRequired(["_spreadsheetId"]);
    this._requestType = "appendWithFormat";

    if (!Array.isArray(values) || values.length === 0) {
      throw new Error("Values должен быть непустым массивом");
    }

    if (!range || typeof range !== "string") {
      throw new Error("Range должен быть непустой строкой");
    }

    const targetSheetName = sheetName || this._sheetName;
    if (!targetSheetName) {
      throw new Error("Необходимо указать sheetName");
    }

    const targetSheetId = this.getSheetId(targetSheetName);
    const normalizedRange = this._normalizeRange(range);
    const parsedRange = this._parseRange(normalizedRange);

    // Получаем текущие размеры листа для определения позиции вставки
    const dimensions = this.getSheetDimensions(targetSheetName);
    const insertRowIndex = dimensions.rowCount; // Вставляем в конец

    // Создаем массив строк для добавления
    const rows = values.map((row, rowIndex) => {
      const cells = row.map((value, colIndex) => {
        const cell = {};

        // Определяем тип значения и создаем userEnteredValue
        if (value === null || value === undefined || value === "") {
          cell.userEnteredValue = { stringValue: "" };
        } else if (typeof value === "number") {
          cell.userEnteredValue = { numberValue: value };
        } else if (value instanceof Date) {
          // Для дат используем serial number через Moment.js
          const serialDate = DateUtils.momentDateToFloatDate(value);
          cell.userEnteredValue = { numberValue: serialDate };
        } else if (typeof value === "boolean") {
          // Для булевых значений с кастомным форматированием используем stringValue
          const columnFormat = formatOptions.columns?.[colIndex];
          if (columnFormat && columnFormat.numberFormat) {
            cell.userEnteredValue = { stringValue: value ? "Да" : "Нет" };
          } else {
            cell.userEnteredValue = { boolValue: value };
          }
        } else {
          // Проверяем, является ли строка датой для форматирования
          const columnFormat = formatOptions.columns?.[colIndex];
          if (
            columnFormat &&
            (columnFormat.numberFormatType === "DATE" ||
              columnFormat.numberFormatType === "DATE_TIME") &&
            typeof value === "string"
          ) {
            // Пытаемся распарсить дату из строки с помощью Moment.js
            try {
              const dateValue = DateUtils.parseMomentDate(value, null);
              const serialDate = DateUtils.momentDateToFloatDate(dateValue);
              cell.userEnteredValue = { numberValue: serialDate };
            } catch (error) {
              cell.userEnteredValue = { stringValue: value.toString() };
            }
          } else {
            cell.userEnteredValue = { stringValue: value.toString() };
          }
        }

        // Применяем форматирование по столбцам
        const columnFormat = formatOptions.columns?.[colIndex];
        const globalFormat = formatOptions.global;

        if (columnFormat || globalFormat) {
          cell.userEnteredFormat = {};

          // Форматирование из настроек столбца
          if (columnFormat) {
            if (columnFormat.numberFormat || columnFormat.numberFormatType) {
              cell.userEnteredFormat.numberFormat = {
                type: columnFormat.numberFormatType || "TEXT",
                pattern: columnFormat.numberFormat || "",
              };
            }
            if (columnFormat.textFormat) {
              cell.userEnteredFormat.textFormat = columnFormat.textFormat;
            }
            if (columnFormat.backgroundColor) {
              cell.userEnteredFormat.backgroundColor =
                columnFormat.backgroundColor;
            }
            if (columnFormat.borders) {
              cell.userEnteredFormat.borders = columnFormat.borders;
            }
          }

          // Глобальное форматирование (перезаписывает форматирование столбца)
          if (globalFormat) {
            if (globalFormat.numberFormat || globalFormat.numberFormatType) {
              cell.userEnteredFormat.numberFormat = {
                type: globalFormat.numberFormatType || "TEXT",
                pattern: globalFormat.numberFormat || "",
              };
            }
            if (globalFormat.textFormat) {
              cell.userEnteredFormat.textFormat = globalFormat.textFormat;
            }
            if (globalFormat.backgroundColor) {
              cell.userEnteredFormat.backgroundColor =
                globalFormat.backgroundColor;
            }
            if (globalFormat.borders) {
              cell.userEnteredFormat.borders = globalFormat.borders;
            }
          }
        }

        return cell;
      });

      return { values: cells };
    });

    const appendCellsRequest = {
      appendCells: {
        sheetId: targetSheetId,
        rows: rows,
        fields: "userEnteredValue,userEnteredFormat",
      },
    };

    this._appendWithFormatRequest = {
      requests: [appendCellsRequest],
      includeSpreadsheetInResponse: this._includeSpreadsheetInResponse,
      responseRanges: this._responseRanges,
      responseIncludeGridData: this._responseIncludeGridData,
    };

    return {
      spreadsheetId: this._spreadsheetId,
      resource: this._appendWithFormatRequest,
    };
  }

  /**
   * Создает запрос на удаление всех пустых строк и столбцов
   * @param {string} [sheetName] - Название листа (опционально)
   * @returns {Object} Объект запроса для Sheets.Spreadsheets.batchUpdate
   */
  requestDeleteEmptyRowsAndColumns(sheetName = null) {
    this._validateRequired(["_spreadsheetId"]);
    this._requestType = "deleteEmptyRowsAndColumns";

    const targetSheetName = sheetName || this._sheetName;
    if (!targetSheetName) {
      throw new Error("Необходимо указать sheetName");
    }

    const targetSheetId = this.getSheetId(targetSheetName);

    // Получаем границы данных
    const dataBounds = this.getDataBounds(null, null, targetSheetName);
    const dimensions = this.getSheetDimensions(targetSheetName);

    if (!dataBounds.hasData) {
      if (this.debug) console.warn("Лист пустой, нечего удалять");
      return {
        spreadsheetId: this._spreadsheetId,
        resource: null,
      };
    }

    const requests = [];

    // Удаляем пустые строки ПОСЛЕ данных (снизу)
    if (dataBounds.lastRow < dimensions.rowCount) {
      requests.push({
        deleteDimension: {
          range: {
            sheetId: targetSheetId,
            dimension: "ROWS",
            startIndex: dataBounds.lastRow, // Начинаем с конца данных
            endIndex: dimensions.rowCount, // До конца листа
          },
        },
      });
    }

    // Удаляем пустые столбцы ПОСЛЕ данных (справа)
    if (dataBounds.lastColumn < dimensions.columnCount) {
      requests.push({
        deleteDimension: {
          range: {
            sheetId: targetSheetId,
            dimension: "COLUMNS",
            startIndex: dataBounds.lastColumn, // Начинаем с конца данных
            endIndex: dimensions.columnCount, // До конца листа
          },
        },
      });
    }

    // Если нет запросов, возвращаем ошибку
    if (requests.length === 0) {
      // throw new Error("Нет пустых строк или столбцов для удаления");
      if (this.debug)
        console.warn("Нет пустых строк или столбцов для удаления");
      return {
        spreadsheetId: this._spreadsheetId,
        resource: null,
      };
    }

    this._deleteEmptyRowsAndColumnsRequest = {
      requests: requests,
      includeSpreadsheetInResponse: this._includeSpreadsheetInResponse,
      responseRanges: this._responseRanges,
      responseIncludeGridData: this._responseIncludeGridData,
    };

    return {
      spreadsheetId: this._spreadsheetId,
      resource: this._deleteEmptyRowsAndColumnsRequest,
    };
  }

