  /**
   * Создает запрос на установку фильтра на весь лист
   * @param {string} [sheetName] - Название листа (если не указано, используется текущий)
   * @param {Object} [options] - Опции фильтра
   * @param {number} [options.startRowIndex=0] - Начальная строка для фильтра (0-based)
   * @param {number} [options.endRowIndex] - Конечная строка для фильтра (0-based, по умолчанию - до конца данных)
   * @param {number} [options.startColumnIndex=0] - Начальный столбец для фильтра (0-based)
   * @param {number} [options.endColumnIndex] - Конечный столбец для фильтра (0-based, по умолчанию - до конца данных)
   * @returns {Object} Объект запроса для Sheets.Spreadsheets.batchUpdate
   */
  requestSetFilter(sheetName = null, options = {}) {
    this._validateRequired(["_spreadsheetId"]);
    this._requestType = "setFilter";

    const targetSheetName = sheetName || this._sheetName;
    if (!targetSheetName) {
      throw new Error("Необходимо указать sheetName");
    }

    const targetSheetId = this.getSheetId(targetSheetName);

    // Получаем границы данных для определения диапазона фильтра
    const dataBounds = this.getDataBounds(null, null, targetSheetName);

    // Определяем диапазон для фильтра
    const startRowIndex =
      options.startRowIndex !== undefined ? options.startRowIndex : 0;
    const endRowIndex =
      options.endRowIndex !== undefined
        ? options.endRowIndex
        : dataBounds.hasData
        ? dataBounds.lastRow
        : 1;
    const startColumnIndex =
      options.startColumnIndex !== undefined ? options.startColumnIndex : 0;
    const endColumnIndex =
      options.endColumnIndex !== undefined
        ? options.endColumnIndex
        : dataBounds.hasData
        ? dataBounds.lastColumn
        : 1;

    if (!dataBounds.hasData) {
      console.warn("Лист пустой, устанавливаем фильтр на первую строку");
    }

    const requests = [
      {
        setBasicFilter: {
          filter: {
            range: {
              sheetId: targetSheetId,
              startRowIndex: startRowIndex,
              endRowIndex: endRowIndex,
              startColumnIndex: startColumnIndex,
              endColumnIndex: endColumnIndex,
            },
          },
        },
      },
    ];

    this._setFilterRequest = {
      requests: requests,
      includeSpreadsheetInResponse: this._includeSpreadsheetInResponse,
      responseRanges: this._responseRanges,
      responseIncludeGridData: this._responseIncludeGridData,
    };

    return {
      spreadsheetId: this._spreadsheetId,
      resource: this._setFilterRequest,
    };
  }

  /**
   * Создает запрос для поиска и замены текста
   * @param {Object} options - Опции поиска и замены
   * @param {string} options.find - Текст для поиска
   * @param {string} options.replacement - Текст для замены
   * @param {string} [options.sheetName] - Название листа (если не указано, используется текущий)
   * @param {string} [options.range] - Диапазон для поиска (A1 notation)
   * @param {boolean} [options.matchCase=false] - Учитывать регистр
   * @param {boolean} [options.matchEntireCell=false] - Совпадение всей ячейки
   * @param {boolean} [options.includeFormulas=false] - Включать формулы
   * @param {boolean} [options.searchByRegex=false] - Использовать регулярные выражения
   * @returns {Object} Запрос для batchUpdate
   */
  requestFindReplace(options) {
    this._validateRequired(["_spreadsheetId"]);

    if (!options || !options.find || !options.replacement) {
      throw new Error("Необходимо указать find и replacement");
    }

    const targetSheetName = options.sheetName || this._sheetName;
    if (!targetSheetName) {
      throw new Error("Необходимо указать sheetName");
    }

    const targetSheetId = this.getSheetId(targetSheetName);

    const findReplaceRequest = {
      findReplace: {
        find: options.find,
        replacement: options.replacement,
        sheetId: targetSheetId,
        matchCase: options.matchCase || false,
        matchEntireCell: options.matchEntireCell || false,
        includeFormulas: options.includeFormulas || false,
        searchByRegex: options.searchByRegex || false,
      },
    };

    // Если указан диапазон, добавляем его
    if (options.range) {
      const normalizedRange = this._normalizeRange(options.range);
      const parsedRange = this._parseRange(normalizedRange);

      findReplaceRequest.findReplace.range = {
        sheetId: targetSheetId,
        startRowIndex: parsedRange.startRowIndex,
        endRowIndex: parsedRange.endRowIndex,
        startColumnIndex: parsedRange.startColumnIndex,
        endColumnIndex: parsedRange.endColumnIndex,
      };
    }

    this._findReplaceRequest = {
      spreadsheetId: this._spreadsheetId,
      resource: {
        requests: [findReplaceRequest],
      },
    };

    return this._findReplaceRequest;
  }

