  /**
   * Создает запрос для batch обновления значений
   * @returns {Object} Объект запроса для метода batchUpdate
   * @see {@link https://developers.google.com/workspace/sheets/api/reference/rest/v4/spreadsheets.values/batchUpdate}
   */
  requestValuesBatchUpdate() {
    this._validateRequired(["_spreadsheetId"]);
    if (this._ranges.length === 0 && this._range) {
      this._ranges = [this._range];
    }
    if (this._ranges.length === 0 || !this._values) {
      throw new Error("Необходимо указать диапазоны и значения");
    }
    this._requestType = "valuesBatchUpdate";

    const data = this._ranges.map((range, index) => ({
      range: range,
      values: [this._values[index]],
      majorDimension: this._majorDimension,
    }));

    this._valuesBatchUpdateRequest = {
      data: data,
      valueInputOption: this._valueInputOption,
      includeValuesInResponse: this._includeValuesInResponse,
      responseValueRenderOption: this._responseValueRenderOption,
      responseDateTimeRenderOption: this._responseDateTimeRenderOption,
    };

    return {
      spreadsheetId: this._spreadsheetId,
      request: this._valuesBatchUpdateRequest,
      resource: {
        data: data,
      },
    };
  }

  /**
   * Создает запрос для batch очистки значений
   * @returns {Object} Объект запроса для метода batchClear
   * @see {@link https://developers.google.com/workspace/sheets/api/reference/rest/v4/spreadsheets.values/batchClear}
   */
  requestValuesBatchClear() {
    this._validateRequired(["_spreadsheetId"]);
    if (this._ranges.length === 0 && this._range) {
      this._ranges = [this._range];
    }
    if (this._ranges.length === 0) {
      throw new Error("Необходимо указать хотя бы один диапазон");
    }
    this._requestType = "valuesBatchClear";

    this._valuesBatchClearRequest = {
      ranges: this._ranges,
    };

    return {
      spreadsheetId: this._spreadsheetId,
      resource: this._valuesBatchClearRequest,
    };
  }

  /**
   * Создает запрос для форматирования столбцов
   * @returns {Object} Объект запроса для batchUpdate с форматированием
   * @throws {Error} Если не указаны обязательные параметры
   */
  requestFormat() {
    this._validateRequired(["_spreadsheetId"]);
    if (!this._columnFormats || this._columnFormats.length === 0) {
      throw new Error(
        "Необходимо указать форматы столбцов через setColumnsFormat()"
      );
    }
    this._requestType = "format";

    const requests = this._columnFormats.map((config) => {
      const { range, format, type } = config;
      const rangeInfo = this._parseRange(range);

      return {
        repeatCell: {
          range: {
            sheetId: this._sheetName ? this.getSheetId(this._sheetName) : 0,
            startRowIndex: rangeInfo.startRowIndex,
            endRowIndex: rangeInfo.endRowIndex,
            startColumnIndex: rangeInfo.startColumnIndex,
            endColumnIndex: rangeInfo.endColumnIndex,
          },
          cell: {
            userEnteredFormat: {
              numberFormat: {
                type: type,
                pattern: format,
              },
            },
          },
          fields: "userEnteredFormat.numberFormat",
        },
      };
    });

    this._formatRequest = {
      requests: requests,
      includeSpreadsheetInResponse: this._includeSpreadsheetInResponse,
      responseRanges: this._responseRanges,
      responseIncludeGridData: this._responseIncludeGridData,
    };

    return {
      spreadsheetId: this._spreadsheetId,
      resource: this._formatRequest,
    };
  }

