      includeGridData: this._responseIncludeGridData,
      excludeTablesInBandedRanges: this._responseExcludeTablesInBandedRanges,
    };

    if (fields) requestOptions.fields = fields;

    if (ranges && !this._responseRanges.length)
      requestOptions.ranges = Array.isArray(ranges) ? ranges : [ranges];

    if (this._responseRanges && !requestOptions.ranges) {
      requestOptions.ranges = this._responseRanges;
