  /**
   * Создает TextFinder-подобный объект для удобного поиска и замены
   * @param {string} findText - Текст для поиска
   * @param {string} [sheetName] - Название листа
   * @returns {Object} TextFinder-подобный объект
   */
  createTextFinder(findText, sheetName = null) {
    const targetSheetName = sheetName || this._sheetName;
    if (!targetSheetName) {
      throw new Error("Необходимо указать sheetName");
    }

    const finder = {
      _findText: findText,
      _sheetName: targetSheetName,
      _range: null,
      _matchCase: false,
      _matchEntireCell: false,
      _includeFormulas: false,
      _searchByRegex: false,
      _replacement: null,

      /**
       * Устанавливает диапазон для поиска
       * @param {string} range - Диапазон (A1 notation)
       * @returns {Object} TextFinder объект
       */
      range: function (range) {
        this._range = range;
        return this;
      },

      /**
       * Устанавливает учет регистра
       * @param {boolean} matchCase - Учитывать регистр
       * @returns {Object} TextFinder объект
       */
      matchCase: function (matchCase = true) {
        this._matchCase = matchCase;
        return this;
      },

      /**
       * Устанавливает совпадение всей ячейки
       * @param {boolean} matchEntireCell - Совпадение всей ячейки
       * @returns {Object} TextFinder объект
       */
      matchEntireCell: function (matchEntireCell = true) {
        this._matchEntireCell = matchEntireCell;
        return this;
      },

      /**
       * Включает поиск в формулах
       * @param {boolean} includeFormulas - Включать формулы
       * @returns {Object} TextFinder объект
       */
      includeFormulas: function (includeFormulas = true) {
        this._includeFormulas = includeFormulas;
        return this;
      },

      /**
       * Использует регулярные выражения
       * @param {boolean} useRegex - Использовать regex
       * @returns {Object} TextFinder объект
       */
      useRegularExpression: function (useRegex = true) {
        this._searchByRegex = useRegex;
        return this;
      },

      /**
       * Заменяет найденный текст
       * @param {string} replacement - Текст замены
       * @returns {Object} Результат выполнения
       */
      replaceAllWith: function (replacement) {
        this._replacement = replacement;

        const options = {
          find: this._findText,
          replacement: replacement,
          sheetName: this._sheetName,
          matchCase: this._matchCase,
          matchEntireCell: this._matchEntireCell,
          includeFormulas: this._includeFormulas,
          searchByRegex: this._searchByRegex,
        };

        if (this._range) {
          options.range = this._range;
        }

        // Создаем новый билдер для выполнения
        const builder = new SheetsApiRequestBuilder()
          .setSpreadsheetId(
            this._spreadsheetId || SpreadsheetApp.getActiveSpreadsheet().getId()
          )
          .setSheetName(this._sheetName)
          .init();

        builder.requestFindReplace(options);
        return builder.executeFindReplace();
      },

      /**
       * Находит все совпадения (возвращает информацию о найденных ячейках)
       * @returns {Array} Массив найденных ячеек
       */
      findAll: function () {
        // Для findAll нужно использовать другой подход - получить данные и найти совпадения
        const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(
          this._sheetName
        );
        const range = this._range
          ? sheet.getRange(this._range)
          : sheet.getDataRange();
        const values = range.getValues();

        const matches = [];
        for (let row = 0; row < values.length; row++) {
          for (let col = 0; col < values[row].length; col++) {
            const cellValue = values[row][col];
            if (this._searchByRegex) {
              const regex = new RegExp(
                this._findText,
                this._matchCase ? "g" : "gi"
              );
              if (regex.test(cellValue)) {
                matches.push({
                  row: row + 1,
                  column: col + 1,
                  value: cellValue,
                  range: sheet.getRange(row + 1, col + 1).getA1Notation(),
                });
              }
            } else {
              const searchText = this._matchCase
                ? this._findText
                : this._findText.toLowerCase();
              const cellText = this._matchCase
                ? cellValue
                : cellValue.toString().toLowerCase();

              if (this._matchEntireCell) {
                if (cellText === searchText) {
                  matches.push({
                    row: row + 1,
                    column: col + 1,
                    value: cellValue,
                    range: sheet.getRange(row + 1, col + 1).getA1Notation(),
                  });
                }
              } else {
                if (cellText.includes(searchText)) {
                  matches.push({
                    row: row + 1,
                    column: col + 1,
                    value: cellValue,
                    range: sheet.getRange(row + 1, col + 1).getA1Notation(),
                  });
                }
              }
            }
          }
        }

        return matches;
      },
    };

    // Сохраняем ссылку на билдер
    finder._spreadsheetId = this._spreadsheetId;

    return finder;
  }

