  /**
   * Получает метаданные листов таблицы
   * @param {string} spreadsheetId - ID таблицы
   * @param {string} [sheetName] - Название листа для фильтрации (опционально)
   * @returns {Object} Метаданные листов
   */
  getMetadata(sheetName = null, fields = null) {
    try {
      fields =
        fields ||
        "spreadsheetId,spreadsheetUrl,sheets(properties(title,sheetId,index,sheetType,gridProperties))";
      const response = this.executeGet(sheetName, fields);
      const sheets = response.sheets || [];

      // Обновляем Set с именами листов (только если получаем все листы)
      if (!sheetName) {
        this._updateSheetNames({ sheets });
      }

      if (sheetName) {
        // Фильтруем по названию листа
        const filteredSheets = sheets.filter(
          (sheet) => sheet.properties.title === sheetName
        );
        return {
          sheets: filteredSheets,
          spreadsheetId: response.spreadsheetId,
          properties: response.properties,
          spreadsheetUrl: response.spreadsheetUrl,
        };
      }

      return {
        sheets: sheets,
        spreadsheetId: response.spreadsheetId,
        properties: response.properties,
        spreadsheetUrl: response.spreadsheetUrl,
      };
    } catch (error) {
      console.error("Ошибка при получении метаданных листов:", error.stack);
      throw error;
    }
  }

  // ==================== УТИЛИТЫ ====================
  // Примечание: Методы для работы с датами (Moment.js) вынесены в отдельный класс DateUtils

  /**
   * Обновляет Set с именами листов из метаданных
   * @param {Object} metadata - Метаданные листов
   * @private
   */
  _updateSheetNames(metadata) {
    this._sheetNames.clear();
    if (metadata && metadata.sheets) {
      metadata.sheets.forEach((sheet) => {
        this._sheetNames.add(sheet.properties.title);
      });
    }
  }

  /**
   * Проверяет, существует ли лист
   * @param {string} sheetName - Название листа
   * @returns {boolean} true, если лист существует
   */
  sheetExists(sheetName) {
    return this._sheetNames.has(sheetName);
  }

  /**
   * Получает ID листа по названию
   * @private
   * @param {string} [sheetName] - Название листа
   * @returns {number} ID листа
   */
  getSheetId(sheetName = null) {
    sheetName = sheetName || this._sheetName;

    if (!sheetName) {
      throw new Error("Название листа не указано");
    }

    // Быстрая проверка существования листа через Set
    if (!this.sheetExists(sheetName)) {
      // throw new Error(`Лист "${sheetName}" не найден`);
      console.warn(`Лист "${sheetName}" не найден`);
      return;
    }

    if (!this._metadata || !this._metadata.sheets) {
      console.warn(
        "Метаданные листов не загружены. Используйте getMetadata() для инициализации."
      );
      return;
    }

    const sheet = this._metadata.sheets.find(
      (s) => s.properties.title === sheetName
    );
    return sheet ? sheet.properties.sheetId : 0;
  }

  /**
   * Нормализует диапазон в стандартный формат
   * @private
   * @param {string} range - Исходный диапазон
   * @returns {string} Нормализованный диапазон
   */
  _normalizeRange(range) {
    // Убираем лишние пробелы
    range = range.trim();

    // Если диапазон не содержит имя листа, добавляем 'Sheet1'
    if (!range.includes("!")) {
      range = `${this._sheetName}!${range}`;
    }

    return range;
  }

  /**
   * Парсит диапазон и возвращает индексы строк и столбцов
   * @private
   * @param {string} range - Диапазон в формате "A1:B10"
   * @returns {Object} Объект с индексами
   */
  _parseRange(range) {
    // Проверяем базовые ошибки
    if (!range || range.trim() === "") {
      throw new Error(`Неверный формат диапазона: ${range}`);
    }

    // Убираем имя листа если есть
    const cleanRange = range.includes("!") ? range.split("!")[1] : range;

    // Проверяем что после удаления имени листа остался валидный диапазон
    if (!cleanRange || cleanRange.trim() === "") {
      throw new Error(`Неверный формат диапазона: ${range}`);
    }

    // Получаем размеры листа для определения границ
    const dimensions = this.getSheetDimensions();
    const maxRow = dimensions.rowCount;
    const maxCol = dimensions.columnCount;

    // Парсим различные форматы A1 notation
    const patterns = [
      // A1:B10 - конкретный диапазон
      /^([A-Z]+)(\d+):([A-Z]+)(\d+)$/,
      // A:A - весь столбец
      /^([A-Z]+):([A-Z]+)$/,
      // 1:2 - весь ряд
      /^(\d+):(\d+)$/,
      // A1:B - от ячейки A1 до конца столбца B
      /^([A-Z]+)(\d+):([A-Z]+)$/,
      // A1 - одна ячейка
      /^([A-Z]+)(\d+)$/,
    ];

    for (const pattern of patterns) {
      const match = cleanRange.match(pattern);
      if (match) {
        if (pattern === patterns[0]) {
          // A1:B10
          const [, startCol, startRow, endCol, endRow] = match;
          return {
            startRowIndex: parseInt(startRow) - 1,
            endRowIndex: parseInt(endRow),
            startColumnIndex: this._columnLetterToIndex(startCol),
            endColumnIndex: this._columnLetterToIndex(endCol) + 1,
          };
        } else if (pattern === patterns[1]) {
          // A:A
          const [, startCol, endCol] = match;
          return {
            startRowIndex: 0,
            endRowIndex: maxRow,
            startColumnIndex: this._columnLetterToIndex(startCol),
            endColumnIndex: this._columnLetterToIndex(endCol) + 1,
          };
        } else if (pattern === patterns[2]) {
          // 1:2
          const [, startRow, endRow] = match;
          return {
            startRowIndex: parseInt(startRow) - 1,
            endRowIndex: parseInt(endRow),
            startColumnIndex: 0,
            endColumnIndex: maxCol,
          };
        } else if (pattern === patterns[3]) {
          // A1:B - от ячейки A1 до конца столбца B
          const [, startCol, startRow, endCol] = match;
          return {
            startRowIndex: parseInt(startRow) - 1,
            endRowIndex: maxRow,
            startColumnIndex: this._columnLetterToIndex(startCol),
            endColumnIndex: this._columnLetterToIndex(endCol) + 1,
          };
        } else if (pattern === patterns[4]) {
          // A1
          const [, col, row] = match;
          return {
            startRowIndex: parseInt(row) - 1,
            endRowIndex: parseInt(row),
            startColumnIndex: this._columnLetterToIndex(col),
            endColumnIndex: this._columnLetterToIndex(col) + 1,
          };
        }
      }
    }

    throw new Error(`Неверный формат диапазона: ${range}`);
  }

  /**
   * Преобразует букву столбца в индекс
   * @private
   * @param {string} letter - Буква столбца (A, B, C, ...)
   * @returns {number} Индекс столбца (0-based)
   */
  _columnLetterToIndex(letter) {
    let index = 0;
    for (let i = 0; i < letter.length; i++) {
      index = index * 26 + (letter.charCodeAt(i) - 64);
    }
    return index - 1;
  }

  /**
   * Преобразует индекс столбца в букву
   * @private
   * @param {number} index - Индекс столбца (0-based)
   * @returns {string} Буква столбца (A, B, C, ...)
   */
  _indexToColumnLetter(index) {
    let result = "";
    while (index >= 0) {
      result = String.fromCharCode(65 + (index % 26)) + result;
      index = Math.floor(index / 26) - 1;
    }
    return result;
  }

  /**
   * Конвертирует hex-цвет в RGB значения для tabColorStyle
   * @param {string} hexColor - Hex цвет (например, "#B411A1" или "B411A1")
   * @returns {Object} Объект с RGB значениями {red, green, blue}
   * @private
   */
  _hexToRgb(hexColor) {
    // Проверяем входные данные
    if (!hexColor || typeof hexColor !== "string") {
      console.warn(
        `_hexToRgb: Некорректный цвет "${hexColor}", используется BLACK`
      );
      hexColor = "#000000";
    }

    if (!hexColor.startsWith("#")) {
      hexColor = this._colorNameToHex(hexColor);
    }

    const hex = hexColor.slice(1);

    // Валидация hex формата (6 символов, только 0-9, A-F, a-f)
    if (!/^[0-9A-Fa-f]{6}$/.test(hex)) {
      console.warn(
        `_hexToRgb: Некорректный hex формат "${hexColor}", используется BLACK`
      );
      return {
        red: 0,
        green: 0,
        blue: 0,
      };
    }

    // Парсим hex значения
    const r = parseInt(hex.substring(0, 2), 16);
    const g = parseInt(hex.substring(2, 4), 16);
    const b = parseInt(hex.substring(4, 6), 16);

    // Конвертируем в значения от 0 до 1 (как в Google Sheets API)
    return {
      red: r / 255,
      green: g / 255,
      blue: b / 255,
    };
  }

  /**
   * Преобразует название цвета в hex значение
   * @param {string} colorName - Название цвета (например, "RED", "GREEN", "BLUE")
   * @returns {string} Hex цвет (например, "#FF0000")
   * @private
   */
  _colorNameToHex(colorName) {
    const colorMap = {
      // Основные цвета
      RED: "#FF0000",
      GREEN: "#00FF00",
      BLUE: "#0000FF",
      BLACK: "#000000",
      WHITE: "#FFFFFF",
      YELLOW: "#FFFF00",

      // Дополнительные цвета
      ORANGE: "#FFA500",
      PURPLE: "#800080",
      PINK: "#FFC0CB",
      CYAN: "#00FFFF",
      MAGENTA: "#FF00FF",
      LIME: "#00FF00",
      GRAY: "#808080",
      GREY: "#808080",
      BROWN: "#A52A2A",
      NAVY: "#000080",
      TEAL: "#008080",
      OLIVE: "#808000",
      MAROON: "#800000",
      SILVER: "#C0C0C0",
      GOLD: "#FFD700",

      // Светлые оттенки
      LIGHT_RED: "#FFB6C1",
      LIGHT_GREEN: "#90EE90",
      LIGHT_BLUE: "#ADD8E6",
      LIGHT_YELLOW: "#FFFFE0",
      LIGHT_GRAY: "#D3D3D3",
      LIGHT_GREY: "#D3D3D3",

      // Темные оттенки
      DARK_RED: "#8B0000",
      DARK_GREEN: "#006400",
      DARK_BLUE: "#00008B",
      DARK_YELLOW: "#B8860B",
      DARK_GRAY: "#A9A9A9",
      DARK_GREY: "#A9A9A9",
    };

    const upperColorName = colorName.toUpperCase();
    return colorMap[upperColorName] || colorName; // Возвращаем исходное значение, если цвет не найден
  }

  /**
   * Конвертирует RGB значения в hex-цвет
   * @param {Object} rgbColor - Объект с RGB значениями {red, green, blue} (0-1)
   * @returns {string} Hex цвет (например, "#B411A1")
   * @private
   */
  _rgbToHex(rgbColor) {
    const red = Math.floor((rgbColor.red || 0) * 255);
    const green = Math.floor((rgbColor.green || 0) * 255);
    const blue = Math.floor((rgbColor.blue || 0) * 255);

    const rgbNumber = (red << 16) | (green << 8) | blue;
    const hexString = rgbNumber.toString(16).toUpperCase();
    const missingZeros = 6 - hexString.length;
    const resultBuilder = ["#"];

    for (let i = 0; i < missingZeros; i++) {
      resultBuilder.push("0");
    }
    resultBuilder.push(hexString);

    return resultBuilder.join("");
  }

  /**
   * Инициализирует метаданные листов с кэшированием
   * @param {string} [sheetName] - Название листа для фильтрации (опционально)
   * @param {boolean} [useCache=true] - Использовать кэш метаданных
   * @returns {SheetsApiRequestBuilder} Текущий экземпляр билдера
   */
  init(sheetName = null, useCache = true) {
    if (!this._spreadsheetId) {
      throw new Error(
        "Необходимо указать spreadsheetId перед инициализацией метаданных"
      );
    }

    // Проверяем глобальный кэш метаданных
    if (useCache && globalMetadataCache[this._cacheKey]) {
      // Используем кэшированные метаданные
      const allMetadata = globalMetadataCache[this._cacheKey];
      this._metadata = this._filterMetadataBySheetName(allMetadata, sheetName);

      // Обновляем Set с именами листов (только если получаем все листы)
      if (!sheetName) {
        this._updateSheetNames(allMetadata);
      }
    } else {
      // Загружаем метаданные и кэшируем их
      this._metadata = this.getMetadata(sheetName);

      // Если загружаем все листы, кэшируем
      if (!sheetName) {
        globalMetadataCache[this._cacheKey] = this._metadata;
      } else {
        // Если загружаем конкретный лист, но нет кэша всех листов
        if (!globalMetadataCache[this._cacheKey]) {
          const allMetadata = this.getMetadata(); // Загружаем все
          globalMetadataCache[this._cacheKey] = allMetadata;
        }
      }
    }

    return this;
  }

  /**
   * Фильтрует метаданные по названию листа
   * @private
   * @param {Object} allMetadata - Все метаданные
   * @param {string} [sheetName] - Название листа для фильтрации
   * @returns {Object} Отфильтрованные метаданные
   */
  _filterMetadataBySheetName(allMetadata, sheetName = null) {
    if (!sheetName) {
      return allMetadata;
    }

    const sheets = allMetadata.sheets || [];
    const filteredSheets = sheets.filter(
      (sheet) => sheet.properties.title === sheetName
    );

    return {
      sheets: filteredSheets,
      spreadsheetId: allMetadata.spreadsheetId,
      properties: allMetadata?.properties,
      spreadsheetUrl: allMetadata.spreadsheetUrl,
    };
  }

  /**
   * Обновляет метаданные листов (принудительно загружает заново)
   * @returns {SheetsApiRequestBuilder} Текущий экземпляр билдера
   */
  refresh() {
    if (!this._spreadsheetId) {
      throw new Error(
        "Необходимо указать spreadsheetId перед обновлением метаданных"
      );
    }

    // Принудительно загружаем метаданные заново
    this._metadata = this.getMetadata();
    globalMetadataCache[this._cacheKey] = this._metadata;

    return this;
  }

  /**
   * Обновляет метаданные конкретного листа в уже загруженном кэше
   * @param {string} [sheetName] - Название листа для обновления
   * @returns {SheetsApiRequestBuilder} Текущий экземпляр билдера
   */
  refreshSheetMetadata(sheetName = null) {
    if (!this._spreadsheetId) {
      throw new Error(
        "Необходимо указать spreadsheetId перед обновлением метаданных"
      );
    }

    sheetName = sheetName || this._sheetName;

    if (!sheetName) {
      throw new Error("Необходимо указать sheetName для обновления");
    }

    // Получаем метаданные только конкретного листа
    const updatedSheetMetadata = this.getMetadata(sheetName);

    if (globalMetadataCache[this._cacheKey]) {
      // Обновляем конкретный лист в кэше
      const allMetadata = globalMetadataCache[this._cacheKey];

      if (
        updatedSheetMetadata.sheets &&
        updatedSheetMetadata.sheets.length > 0
      ) {
        const updatedSheet = updatedSheetMetadata.sheets[0];

        // Находим и обновляем лист в кэше
        const sheetIndex = allMetadata.sheets.findIndex(
          (sheet) => sheet.properties.title === sheetName
        );

        if (sheetIndex !== -1) {
          // Обновляем существующий лист
          allMetadata.sheets[sheetIndex] = updatedSheet;
        } else {
          // Добавляем новый лист (например, если его создали)
          allMetadata.sheets.push(updatedSheet);
          // Обновляем Set с именами листов
          this._sheetNames.add(sheetName);
        }

        // Обновляем кэш
        globalMetadataCache[this._cacheKey] = allMetadata;

        // Обновляем текущие метаданные билдера
        this._metadata = this._filterMetadataBySheetName(
          allMetadata,
          sheetName
        );
      }
    } else {
      // Если нет кэша, создаем новый с одним листом
      globalMetadataCache[this._cacheKey] = {
        sheets: updatedSheetMetadata.sheets,
        spreadsheetId: updatedSheetMetadata.spreadsheetId,
        properties: updatedSheetMetadata.properties,
        spreadsheetUrl: updatedSheetMetadata.spreadsheetUrl,
      };

      this._metadata = updatedSheetMetadata;
      this._updateSheetNames(globalMetadataCache[this._cacheKey]);
    }

    return this;
  }

  /**
   * Создает лист, если он не существует
   * @param {string} [sheetName] - Название листа для создания
   * @param {Object} [options] - Опции создания листа
   * @param {number} [options.rowCount=1000] - Количество строк
   * @param {number} [options.columnCount=26] - Количество столбцов
   * @returns {SheetsApiRequestBuilder} Текущий экземпляр билдера
   */
  createSheetIfNotExist(options = {}) {
    if (!this._spreadsheetId) {
      throw new Error("Необходимо указать spreadsheetId перед созданием листа");
    }

    const sheetName = options?.title || this._sheetName;

    if (!sheetName) {
      throw new Error(
        "Необходимо указать sheetName или установить его через setSheetName()"
      );
    }

    if (!options?.title) options.title = sheetName;

    // Проверяем, существует ли лист
    if (this.sheetExists(sheetName)) {
      if (this.debug) console.log(`Лист "${sheetName}" уже существует`);
      return this;
    }

    // Используем существующие методы для создания листа
    this.setAddSheetOptions(options);
    // Создаем и выполняем запрос
    this.requestAddSheet();
    this.execute();
    // Обновляем метаданные после создания листа
    this.refreshSheetMetadata(sheetName);
    SpreadsheetApp.flush();

    if (this.debug) console.log(`Лист "${sheetName}" успешно создан`);
    return this;
  }

  /**
   * Получает информацию о листе по названию
   * @param {string} [sheetName] - Название листа
   * @returns {Object|null} Информация о листе или null
   */
  getSheetInfo(sheetName = null) {
    sheetName = sheetName || this._sheetName;
    if (!sheetName) {
      throw new Error(
        "Название листа не указано, используйте setSheetName() или укажите sheetName"
      );
    }

    if (!this._metadata || !this._metadata.sheets) {
      return null;
    }

    return (
      this._metadata.sheets.find((s) => s.properties.title === sheetName) ||
      null
    );
  }

  /**
   * Получает диапазон заголовков
   * @param {Array<string>} [headers] - Массив заголовков
   * @returns {string} Диапазон заголовков
   */
  headersRange(headers, fromRow = 1) {
    headers = headers || this._headers;
    const headerChar = this._indexToColumnLetter(headers.length - 1);
    const headersRange = this._normalizeRange(
      `A${fromRow}:${headerChar}${fromRow}`
    );
    return {
      headersRange,
      headerChar,
    };
  }

  /**
   * Создает батчи данных и отправляет их с минимальными задержками
   * @param {Array<Array>} data - Данные для вставки
   * @param {string} [sheetName] - Название листа
   * @param {number} [startRow=1] - Начальная строка для вставки
   * @param {string} [range] - Диапазон для вставки
   * @param {number} [chunkSize] - Размер чанка (если не указан, вычисляется автоматически)
   * @returns {Object} Информация о созданных батчах
   */
  createAndSendBatches(
    data,
    sheetName = null,
    startRow = 1,
    range = null,
    chunkSize = null
  ) {
    if (!this._spreadsheetId) {
      throw new Error("Необходимо указать spreadsheetId");
    }

    sheetName = sheetName || this._sheetName;
    if (!sheetName) {
      throw new Error("Необходимо указать sheetName");
    }

    if (!Array.isArray(data) || data.length === 0) {
      throw new Error("Данные должны быть непустым массивом");
    }

    // Дополнительная валидация данных
    for (let i = 0; i < data.length; i++) {
      if (!Array.isArray(data[i])) {
        throw new Error(`Строка ${i} данных не является массивом`);
      }
      if (data[i].length === 0) {
        throw new Error(`Строка ${i} данных пуста`);
      }
    }

    // Вычисляем размер чанка автоматически, если не указан
    if (chunkSize === null) {
      chunkSize = this.getChunkSize(data);
      if (this.debug) console.log(`Размер одного чанка: ${chunkSize}`);
    }

    // Создаем массив батчей для отправки
    const ranges = [];
    const batches = [];
    let currentRow = startRow;

    if (data.length > chunkSize * 2) {
      if (this.debug) console.log("📝 Вставляем данные чанками...");
      // Разбиваем данные на чанки
      for (let i = 0; i < data.length; i += chunkSize) {
        const chunk = data.slice(i, i + chunkSize);
        const chunkLength = chunk.length;
        const endCol = chunk[0].length;
        const endRow = currentRow + chunkLength - 1;
        const range = `'${sheetName}'!${this._range2A1(
          1,
          currentRow,
          endCol,
          endRow
        )}`;

        // Валидация диапазона
        if (
          !range ||
          typeof range !== "string" ||
          range.includes("undefined") ||
          range.includes("null")
        ) {
          throw new Error(
            `Невалидный диапазон создан: ${range} для чанка ${
              i / chunkSize + 1
            }`
          );
        }

        if (this.debug) {
          console.log(
            `Создание батча для диапазона: ${range}, строк: ${chunkLength}, столбцов: ${endCol}`
          );
        }

        // Создаем батч
        const batch = {
          range: range,
          values: chunk,
          majorDimension: this._majorDimension,
        };

        ranges.push(range);
        batches.push(batch);
        currentRow += chunk.length;
      }
      // Отправляем все батчи с минимальными задержками
      this._sendBatches(batches);
    } else {
      if (this.debug) console.log("📝 Вставляем данные...");
      this.setRange(range || this._range);
      this.setValues(data);
      this.requestValuesUpdate();
      this.execute();
    }

    return {
      totalBatches: batches.length || 1,
      totalRows: data.length,
      startRow: startRow,
      endRow: startRow + data.length - 1,
      chunkSize: chunkSize,
      ranges: ranges.length > 0 ? ranges : [range || this._range],
    };
  }

  /**
   * Отправляет батчи с минимальными задержками для избежания лимитов API
   * @param {Array<Object>} batches - Массив батчей для отправки
   * @private
   */
  _sendBatches(batches) {
    batches.forEach((batch, index) => {
      try {
        // Создаем корректный запрос для API
        const request = {
          data: [
            {
              range: batch.range,
              values: batch.values,
              majorDimension: this._majorDimension,
            },
          ],
          valueInputOption: this._valueInputOption,
          includeValuesInResponse: this._includeValuesInResponse,
          responseValueRenderOption: this._responseValueRenderOption,
          responseDateTimeRenderOption: this._responseDateTimeRenderOption,
        };

        // if (this.debug)
        console.log(`Отправка батча ${index + 1}:`, {
          range: batch.range,
          rows: batch.values.length,
          columns: batch.values[0]?.length || 0,
          majorDimension: this._majorDimension,
          valueInputOption: this._valueInputOption,
        });

        this.executeValuesBatchUpdateChunk(request);

        if (this.debug) {
          console.log(`Батч ${index + 1} отправлен успешно: ${batch.range}`);
        }
      } catch (error) {
        console.error(
          `Ошибка при отправке батча ${index + 1} (${batch.range}):`,
          error
        );
        // Не прерываем выполнение, продолжаем с следующим батчем
      }

      // Небольшая задержка между батчами для избежания лимитов API
      if (index < batches.length - 1) {
        Utilities.sleep(100); // 100мс задержка между батчами
      }
    });

    if (this.debug) {
      console.log(`Отправлено ${batches.length} батчей`);
    }
  }

  /**
   * Конвертирует координаты в A1 notation
   * @param {number} startCol - Начальный столбец (1-based)
   * @param {number} startRow - Начальная строка (1-based)
   * @param {number} endCol - Конечный столбец (1-based)
   * @param {number} endRow - Конечная строка (1-based)
   * @returns {string} Диапазон в A1 notation
   * @private
   */
  _range2A1(startCol, startRow, endCol, endRow) {
    const startColLetter = this._indexToColumnLetter(startCol - 1);
    const endColLetter = this._indexToColumnLetter(endCol - 1);
    return `${startColLetter}${startRow}:${endColLetter}${endRow}`;
  }

  /**
   * Получение размера чанка на основе размера данных
   * @param {Array} data - данные
   * @returns {number} размер чанка
   */
  getChunkSize(data) {
    if (!data || data.length === 0) return 1000;

    let round = (a, b) => a - (a % b);
    return 10000 + round((data[0].length * 10000) / 26, 1000);
  }

  /**
   * Получает метаданные листа по названию
   * @param {string} sheetName - Название листа
   * @param {boolean} [useCache=true] - Использовать кэш метаданных
   * @returns {Object|null} Метаданные листа или null, если лист не найден
   * @throws {Error} Если не указан spreadsheetId или sheetName
   */
  getSheetByName(sheetName, useCache = true) {
    if (!this._spreadsheetId) {
      throw new Error(
        "Необходимо указать spreadsheetId перед получением метаданных листа"
      );
    }

    if (!sheetName || typeof sheetName !== "string") {
      throw new Error("Название листа должно быть непустой строкой");
    }

    // Проверяем глобальный кэш метаданных
    if (useCache && globalMetadataCache[this._cacheKey]) {
      // Используем кэшированные метаданные
      const allMetadata = globalMetadataCache[this._cacheKey];
      const sheets = allMetadata.sheets || [];
      const sheet = sheets.find((s) => s.properties.title === sheetName);
      return sheet || null;
    } else {
      // Загружаем метаданные конкретного листа
      try {
        const response = this.executeGet();
        const sheets = response.sheets || [];
        const sheet = sheets.find((s) => s.properties.title === sheetName);

        // Если лист найден и есть кэш, обновляем его
        if (sheet && globalMetadataCache[this._cacheKey]) {
          const allMetadata = globalMetadataCache[this._cacheKey];
          const sheetIndex = allMetadata.sheets.findIndex(
            (s) => s.properties.title === sheetName
          );
          if (sheetIndex !== -1) {
            allMetadata.sheets[sheetIndex] = sheet;
          } else {
            allMetadata.sheets.push(sheet);
          }
          globalMetadataCache[this._cacheKey] = allMetadata;
        }

        return sheet || null;
      } catch (error) {
        console.error(
          `Ошибка при получении метаданных листа "${sheetName}":`,
          error.stack
        );
        return null;
      }
    }
  }

  /**
   * Получает размеры листа (количество строк и столбцов)
   * @param {string} [sheetName] - Название листа
   * @returns {Object} Объект с размерами {rowCount, columnCount, range, startIndex, endIndex}
   */
  getSheetDimensions(sheetName = null) {
    const _ = this.getSheetInfo(sheetName);
    if (!_ || !_.properties.gridProperties) {
      const defaultRowCount = 1000;
      const defaultColumnCount = 26;
      return {
        name: sheetName || this._sheetName,
        rowCount: defaultRowCount,
        columnCount: defaultColumnCount,
        range: this._normalizeRange(
          `A1:${this._indexToColumnLetter(
            defaultColumnCount - 1
          )}${defaultRowCount}`
        ),
        startIndex: { row: 0, column: 0 },
        endIndex: { row: defaultRowCount, column: defaultColumnCount },
      };
    }

    const rowCount = _.properties.gridProperties.rowCount;
    const columnCount = _.properties.gridProperties.columnCount;
    const endColumnLetter = this._indexToColumnLetter(columnCount - 1);

    return {
      name: sheetName || this._sheetName,
      rowCount: rowCount,
      columnCount: columnCount,
      range: this._normalizeRange(`A1:${endColumnLetter}${rowCount}`),
      startIndex: { row: 0, column: 0 },
      endIndex: { row: rowCount, column: columnCount },
    };
  }

  /**
   * Получает реальные границы данных в листе (lastRow, lastColumn)
   * @param {number} lastDateColumn - Номер столбца с датой (опционально)
   * @param {string} [sheetName] - Название листа (опционально)
   * @returns {Object} Объект с реальными границами данных {lastRow, lastColumn, hasData}
   */
  getDataBounds(lastDateColumn, range = null, sheetName = null) {
    const targetSheetName = sheetName || this._sheetName;
    if (!targetSheetName) {
      throw new Error("Название листа не указано");
    }

    if (!this.sheetExists(targetSheetName)) {
      return {
        name: targetSheetName,
        lastRow: 0,
        lastColumn: 0,
        hasData: false,
        range: `${targetSheetName}!A1`,
        startIndex: { row: 0, column: 0 },
        endIndex: { row: 0, column: 0 },
        values: [],
        lastChangeDate: null,
      };
    }

    try {
      // Получаем все данные из листа
      range = range ? this._normalizeRange(range) : `${targetSheetName}!A:ZZZ`;
      const values = this.executeValuesGet(range);

      const valuesLength = values.length;

      if (valuesLength === 0) {
        return {
          name: targetSheetName,
          lastRow: 0,
          lastColumn: 0,
          hasData: false,
          range: `${targetSheetName}!A1`,
          startIndex: { row: 0, column: 0 },
          endIndex: { row: 0, column: 0 },
          values,
          lastChangeDate: null,
        };
      }

      // Sheets API возвращает только данные без пустых строк/столбцов
      const lastRow = valuesLength; // Количество строк
      const lastColumn = valuesLength > 0 ? values[0].length : 0; // Длина первой строки (количество столбцов)

      let lastChangeDate;

      if (lastDateColumn) {
        const rawDate = values[lastRow - 1][lastDateColumn - 1];

        // Проверяем, что rawDate не undefined перед передачей в lastUpdateDateCheck
        if (rawDate !== undefined) {
          lastChangeDate = this.lastUpdateDateCheck(rawDate);
        } else {
          lastChangeDate = null;
        }

        if (this.debug) console.log("lastChangeDate after:", lastChangeDate);
      }

      return {
        name: targetSheetName,
        lastRow: lastRow,
        lastColumn: lastColumn,
        hasData: lastRow > 0 && lastColumn > 0,
        // A1 notation диапазон данных
        range:
          lastRow > 0 && lastColumn > 0
            ? `${targetSheetName}!A1:${this._indexToColumnLetter(
                lastColumn - 1
              )}${lastRow}`
            : `${targetSheetName}!A1`,
        // Индексы (0-based, endIndex exclusive)
        startIndex: { row: 0, column: 0 },
        endIndex: { row: lastRow, column: lastColumn },
        // Данные для повторного использования
        values,
        lastChangeDate,
      };
    } catch (error) {
      console.error("Ошибка при получении границ данных:", error.stack);
      return {
        name: targetSheetName,
        lastRow: 0,
        lastColumn: 0,
        hasData: false,
        range: `${targetSheetName}!A1`,
        startIndex: { row: 0, column: 0 },
        endIndex: { row: 0, column: 0 },
        values: [],
        error: error.message,
        lastChangeDate: null,
      };
    }
  }

  /**
   * Проверяет, нужно ли добавлять строки для вставки данных в конец таблицы
   * @param {string} sheetName - Название листа
   * @param {number} dataRowsToAdd - Количество строк данных для добавления
   * @param {boolean} [accumulate=false] - Режим накопления (true) или перезаписи (false)
   * @returns {Object} Информация о необходимости добавления строк
   */
  checkRowsNeeded(sheetName, dataRowsToAdd, accumulate = false) {
    // Получаем размеры листа и границы данных
    const dimensions = this.getSheetDimensions(sheetName);
    const bounds = this.getDataBounds(null, null, sheetName);

    // console.log("checkRowsNeeded dimensions:", dimensions);
    // console.log("checkRowsNeeded bounds:", bounds);

    // Данные есть - продолжаем обработку
    const currentRows = dimensions.rowCount;
    const lastDataRow = bounds.lastRow; // Последняя строка с данными

    let needsMoreRows = false;
    let rowsToAdd = 0;
    let targetStartRow = 1;

    if (!accumulate) {
      // Перезаписываем - очищаем данные и вставляем с начала
      const requiredRows = dataRowsToAdd + 1; // +1 для заголовков
      if (requiredRows > currentRows) {
        needsMoreRows = true;
        rowsToAdd = requiredRows - currentRows;
      }
      targetStartRow = 2; // Начинаем с 2-й строки (после шапки)
    } else {
      // Добавляем - вставляем после последних данных
      const requiredRows = lastDataRow + dataRowsToAdd;
      if (requiredRows > currentRows) {
        needsMoreRows = true;
        rowsToAdd = requiredRows - currentRows;
      }
      targetStartRow = lastDataRow + 1;
    }

    if (this.debug)
      console.log("checkRowsNeeded rowsCheck:", {
        needsMoreRows,
        currentRows,
        lastDataRow,
        dataRowsToAdd,
        rowsToAdd,
        targetStartRow,
      });

    return {
      needsMoreRows,
      currentRows,
      lastDataRow,
      dataRowsToAdd,
      rowsToAdd,
      targetStartRow,
      dimensions,
      bounds,
    };
  }

  /**
   * Проверяет, существует ли лист
   * @param {string} sheetName - Название листа
   * @param {Object} metadata - Метаданные листов (опционально, если не переданы, используются инициализированные)
   * @returns {boolean} true если лист существует, false если нет
   */
  isSheetExists(sheetName, metadata = null) {
    sheetName = sheetName || this._sheetName;
    if (!sheetName) {
      throw new Error(
        "Название листа не указано, используйте setSheetName() или укажите sheetName"
      );
    }

    const targetMetadata = metadata || this._metadata;

    if (!targetMetadata?.sheets) {
      console.warn(
        "Метаданные листов не доступны для проверки существования листа"
      );
      return false;
    }

    return targetMetadata.sheets.some(
      (sheet) => sheet?.properties?.title === sheetName
    );
  }

  /**
   * Валидирует обязательные параметры
   * @private
   * @param {string[]} requiredFields - Массив обязательных полей
   * @throws {Error} Если какое-то поле не установлено
   */
  _validateRequired(requiredFields) {
    for (const field of requiredFields) {
      if (!this[field]) {
        throw new Error(
          `Обязательное поле ${field.replace("_", "")} не установлено`
        );
      }
    }
  }

  /**
   * Возвращает тип последнего созданного запроса
   * @returns {string|null} Тип запроса или null
   */
  getRequestType() {
    return this._requestType;
  }

  /**
   * Универсальный метод для выполнения запроса в зависимости от его типа
   * @returns {Object|Array|string|number|boolean} Результат выполнения запроса из Google Sheets API
   * @throws {Error} Если тип запроса неизвестен или запрос не создан
   */
  execute() {
    if (!this._requestType) {
      throw new Error(
        "Сначала создайте запрос с помощью соответствующего метода request*()"
      );
    }

    switch (this._requestType) {
      // Запросы с форматированием
      case "updateWithFormat":
        return this.executeUpdateWithFormat();
      case "appendWithFormat":
        return this.executeAppendWithFormat();

      // Запросы для работы со строками
      case "insertRows":
        return this.executeInsertRows();
      case "addRows":
        return this.executeAddRows();
      case "addRowsAtEnd":
        return this.executeAddRowsAtEnd();

      // Запросы для удаления пустых строк/столбцов
      case "deleteEmptyRowsAndColumns":
        return this.executeDeleteEmptyRowsAndColumns();
      case "deleteEmptyRows":
        return this.executeDeleteEmptyRows();
      case "deleteEmptyColumns":
        return this.executeDeleteEmptyColumns();

      // Запросы для работы с фильтрами
      case "setFilter":
        return this.executeSetFilter();

      // Запросы для работы с листами
      case "addSheet":
        return this.executeAddSheet();

      // Запросы для поиска и замены
      case "findReplace":
        return this.executeFindReplace();

      // Запросы для работы со значениями
      case "valuesGet":
        return this.executeValuesGet();
      case "valuesUpdate":
        return this.executeValuesUpdate();
      case "valuesAppend":
        return this.executeValuesAppend();
      case "valuesClear":
        return this.executeValuesClear();
      case "valuesBatchGet":
        return this.executeValuesBatchGet();
      case "valuesBatchUpdate":
        return this.executeValuesBatchUpdate();
      case "valuesBatchClear":
        return this.executeValuesBatchClear();

      // Запросы для batch операций
      case "batchUpdate":
        return this.executeBatchUpdate(this._requests, this._spreadsheetId);

      // Запросы для форматирования
      case "format":
        return this.executeBatchUpdate(
          this._formatRequest,
          this._spreadsheetId
        );

      // Запросы для копирования
      case "copyTo":
        return Sheets.Spreadsheets.Sheets.copyTo(
          this._spreadsheetId,
          this._sheetName ? this.getSheetId(this._sheetName) : 0,
          this._copyToRequest
        );

      // Запросы для получения метаданных
      case "getMetadata":
        return this.executeGet();

      // Запросы для удаления листов
      case "deleteSheet":
        return this.executeBatchUpdate(
          this._deleteSheetOptions,
          this._spreadsheetId
        );

      default:
        throw new Error(`Неизвестный тип запроса: ${this._requestType}`);
    }
  }

  /**
   * Возвращает все установленные параметры
   * @returns {Object} Объект с текущими параметрами
   */
  getCurrentParams() {
    return Object.fromEntries(
      Object.entries(this)
        .filter(([key]) => key.startsWith("_"))
        .map(([key, value]) => [key.slice(1), value])
    );
  }

  /**
   * Проверяет и нормализует дату последнего обновления
   * @param {string} dateString - Строка с датой в различных форматах
   * @returns {string|null} Нормализованная дата в формате yyyy-MM-ddTHH:mm:ss или null
   */
  lastUpdateDateCheck(dateString) {
    if (dateString === undefined || dateString === null) {
      // Не выводим предупреждение для undefined/null - это нормально
      return null;
    }

    if (typeof dateString !== "string") {
      console.warn(
        `lastUpdateDateCheck: Невалидный тип данных: "${typeof dateString}", значение: "${dateString}"`
      );
      return null;
    }

    const trimmedDate = dateString.trim();
    if (trimmedDate === "") {
      console.warn("lastUpdateDateCheck: Пустая строка даты");
      return null;
    }

    if (this.debug) console.log("lastUpdateDateCheck before:", trimmedDate);

    const format = "yyyy-MM-dd HH:mm:ss";

    // 1. Если дата уже в формате yyyy-MM-dd, возвращаем как есть
    if (/^\d{4}-\d{2}-\d{2}$/.test(trimmedDate)) {
      if (this.debug)
        console.log(
          "lastUpdateDateCheck: Дата в формате yyyy-MM-dd, возвращаем как есть"
        );
      return trimmedDate;
    }

    // 2. Если дата в формате dd.mm.yyyy (без времени), преобразуем в yyyy-MM-dd
    if (/^\d{2}\.\d{2}\.\d{4}$/.test(trimmedDate)) {
      const [day, month, year] = trimmedDate.split(".");
      const result = `${year}-${month}-${day}`;
      if (this.debug)
        console.log(
          "lastUpdateDateCheck: Дата в формате dd.mm.yyyy, преобразуем в yyyy-MM-dd:",
          result
        );
      return result;
    }

    // 3. Если дата в формате dd.mm.yyyy с временем (h:mm, h:mm:ss, hh:mm, hh:mm:ss)
    if (/^\d{2}\.\d{2}\.\d{4}\s+\d{1,2}:\d{2}(:\d{2})?$/.test(trimmedDate)) {
      const parts = trimmedDate.split(" ");
      const datePart = parts[0]; // dd.mm.yyyy
      const timePart = parts[1]; // h:mm или h:mm:ss или hh:mm или hh:mm:ss

      const [day, month, year] = datePart.split(".");
      const timeParts = timePart.split(":");
      const hours = timeParts[0];
      const minutes = timeParts[1];
      const seconds = timeParts[2] || "00"; // Если секунды не указаны, используем 00

      // Создаем дату
      const date = new Date(year, month - 1, day, hours, minutes, seconds);

      if (!isNaN(date.getTime())) {
        // Добавляем 1 секунду к дате
        date.setSeconds(date.getSeconds() + 1);
        const result = dateStrToFormatDate(date, format).replace(/\s+/g, "T");
        if (this.debug) {
          console.log(
            "lastUpdateDateCheck converted from dd.mm.yyyy h:mm:",
            result
          );
        }
        return result;
      } else {
        console.warn(
          `lastUpdateDateCheck: Некорректная дата в формате dd.mm.yyyy h:mm "${trimmedDate}"`
        );
        return null;
      }
    }

    // 4. Обрабатываем другие форматы через стандартный Date
    const date = new Date(trimmedDate);
    if (!isNaN(date.getTime())) {
      // Добавляем 1 секунду к дате
      date.setSeconds(date.getSeconds() + 1);
      const result = dateStrToFormatDate(date, format).replace(/\s+/g, "T");
      if (this.debug)
        console.log("lastUpdateDateCheck converted from other format:", result);
      return result;
    } else {
      console.warn(`lastUpdateDateCheck: Некорректная дата "${trimmedDate}"`);
      return null;
    }
  }
}

