// Функция глубокого клонирования для Google Apps Script
function deepClone(obj) {
  if (obj === null || typeof obj !== "object") {
    return obj;
  }

  if (obj instanceof Date) {
    return new Date(obj.getTime());
  }

  if (Array.isArray(obj)) {
    return obj.map((item) => deepClone(item));
  }

  const cloned = {};
  for (const key in obj) {
    if (obj.hasOwnProperty(key)) {
      cloned[key] = deepClone(obj[key]);
    }
  }

  return cloned;
}

// Функция для обновления undefined значений в объекте
function updateUndefinedValues(targetObj, sourceObj) {
  if (
    !targetObj ||
    !sourceObj ||
    typeof targetObj !== "object" ||
    typeof sourceObj !== "object"
  ) {
    return;
  }

  for (const key in sourceObj) {
    if (sourceObj.hasOwnProperty(key)) {
      const sourceValue = sourceObj[key];

      // Если в targetObj[key] undefined, а в sourceObj[key] есть значение
      if (
        targetObj[key] === undefined &&
        sourceValue !== undefined &&
        sourceValue !== null &&
        sourceValue !== ""
      ) {
        targetObj[key] = sourceValue;
      }
      // Если оба значения - объекты, рекурсивно обновляем
      else if (
        typeof targetObj[key] === "object" &&
        targetObj[key] !== null &&
        typeof sourceValue === "object" &&
        sourceValue !== null &&
        !Array.isArray(targetObj[key]) &&
        !Array.isArray(sourceValue)
      ) {
        updateUndefinedValues(targetObj[key], sourceValue);
      }
    }
  }
}

