// Утилиты для работы с декларативной конфигурацией
const configUtils = {
  // Хранилище кастомных конфигураций
  _customConfigs: {},

  // Контекст для работы с настройками
  _context: null,

  // Хранилище функций библиотеки
  _libraryFunctions: {},

  // Хранилище конфликтующих функций
  _conflictingFunctions: [],

  // Хранилище исключенных функций
  _excludedFunctions: new Set(),

  // Хранилище API классов
  _apiClasses: null,

  /**
   * Установить контекст для работы с настройками
   * @param {Object} context - контекст с настройками
   */
  setContext: (context) => {
    configUtils._context = context;
  },

  /**
   * Заменить строковые ссылки на API классы на актуальные объекты
   * @param {Object} config - конфигурация для обработки
   * @param {Object} apiClasses - объект с API классами
   */
  replaceApiClassReferences: (config, apiClasses, methodName = null) => {
    if (!config || typeof config !== "object") return;

    Object.keys(config).forEach((key) => {
      const value = config[key];

      if (typeof value === "string") {
        if (value.startsWith("WB") && value.length <= 5) {
          // Пропускаем функции moysklad - они не должны получать API классы
          if (methodName && methodName.toLowerCase().includes("moysklad")) {
            return;
          }

          // Заменяем простую строковую ссылку на API класс (WBF, WBS, WBM и т.д.)
          const apiClassName = value;

          // Если API класс не загружен, загружаем только его
          if (!apiClasses || !apiClasses[apiClassName]) {
            try {
              const specificApiClasses = globalThis.apiClasses({
                service: configUtils._context?.service,
                requestLog: configUtils._context?.requestLog,
                check: configUtils._context?.check,
                specificClass: apiClassName,
              });
              if (specificApiClasses && specificApiClasses[apiClassName]) {
                config[key] = specificApiClasses[apiClassName];
                // Обновляем кэш API классов
                if (!configUtils._apiClasses) {
                  configUtils._apiClasses = {};
                }
                configUtils._apiClasses[apiClassName] =
                  specificApiClasses[apiClassName];

                if (configUtils._context?.configLog) {
                  console.log(
                    `API класс ${apiClassName} загружен для ${methodName}:`,
                    typeof specificApiClasses[apiClassName],
                  );
                }
              }
            } catch (error) {
              if (configUtils._context?.configLog) {
                console.warn(
                  `Не удалось загрузить API класс ${apiClassName} для ${methodName}:`,
                  error.message,
                );
              }
            }
          } else {
            config[key] = apiClasses[apiClassName];
          }
        } else if (value.includes("WB") && value.includes("'")) {
          // Заменяем строковые ссылки в динамических значениях
          let updatedValue = value;
          if (apiClasses) {
            Object.keys(apiClasses).forEach((apiClassName) => {
              const regex = new RegExp(`'${apiClassName}'`, "g");
              updatedValue = updatedValue.replace(regex, apiClassName);
            });
          }
          config[key] = updatedValue;
        }
      } else if (typeof value === "object" && value !== null) {
        // Рекурсивно обрабатываем вложенные объекты
        configUtils.replaceApiClassReferences(value, apiClasses, methodName);
      }
    });
  },

  /**
   * Получить конфигурацию для API метода с применением настроек
   * @param {string} methodName - название метода API
   * @returns {Object} конфигурация для API
   */
  getConfig: (methodName) => {
    // Сначала проверяем кастомную конфигурацию
    let config = configUtils._customConfigs[methodName];

    const configLog = configUtils._context?.configLog;

    // Если кастомной нет, используем базовую
    if (!config) {
      config = configWildberriesApi[methodName];
    }

    if (!config) {
      throw new Error(`Метод ${methodName} не найден в конфигурации`);
    }

    // Клонируем конфигурацию, чтобы не изменять оригинал
    const result = deepClone(config);
    result.name = methodName;

    if (configLog) {
      console.log("methodName", methodName);
      console.log("config", JSON.stringify(result, null, 2));
    }

    // Заменяем строковые ссылки на API классы на актуальные объекты
    // Загружаем только нужные API классы для конкретной функции
    configUtils.replaceApiClassReferences(
      result,
      configUtils._apiClasses,
      methodName,
    );

    const hasCustom = result?.custom || false;

    // Применяем настройки если они есть
    if (result?.settings) {
      const settings = result.settings;

      const excludedKeys = [
        "formulas",
        "settings",
        "name",
        "custom",
        "runFunc",
      ];

      if (configLog) {
        console.log({ triggerRange: configUtils._context?.triggerRange });
        console.log({ row: configUtils._context?.triggerRange?.[methodName] });
        console.log({
          scriptRange: configUtils._context?.scriptRange?.[methodName],
        });
      }

      // Применяем func.main если нужно
      let funcMainResult = null;
      if (settings.useFuncMain && configUtils._context) {
        try {
          const funcMainArgs = settings?.funcMainArgs || {};
          funcMainResult = settingsMain({
            funcName: methodName,
            ...funcMainArgs,
            row: configUtils._context?.triggerRange?.[methodName],
            range: configUtils._context?.scriptRange?.[methodName],
          });

          if (configLog) {
            console.log("Config keys:\n", Object.keys(result));
            console.log("hasCustom", hasCustom);
            console.log("funcMainResult:\n", funcMainResult);
          }

          // Проверяем, что funcMainResult содержит нужные поля
          const hasRequiredFields = ["dateFrom", "dateTo"].some(
            (key) => key in funcMainResult,
          );

          if (hasRequiredFields)
            // Применяем все значения из funcMainResult, которые есть
            Object.keys(funcMainResult).forEach((key) => {
              if (!key.includes("Api") && !excludedKeys.includes(key)) {
                const value = funcMainResult[key];
                if (configLog) console.log(`Значение ${key}:`, value);

                if (
                  result[key] === undefined &&
                  value !== undefined &&
                  value !== "" &&
                  value !== null
                ) {
                  if (configLog)
                    console.log(`Заменен ${key} для ${methodName}:`, value);
                  result[key] = value;
                }
              }
            });
        } catch (error) {
          if (configLog) {
            console.warn(
              `Ошибка получения настроек для ${methodName}:`,
              error.message,
            );
          }
        }
      }

      // Применяем func.serch если нужно
      if (settings.useFuncSerch && configUtils._context) {
        try {
          const funcSerchArgs = settings?.funcSerchArgs || {};
          const funcSerchResult = settingsSerchReport({
            funcName: methodName,
            ...funcSerchArgs,
          });

          if (configLog) console.log("funcSerchResult:\n", funcSerchResult);

          // Не перезаписываем существующие значения
          Object.keys(funcSerchResult).forEach((key) => {
            if (!key.includes("Api") && !excludedKeys.includes(key)) {
              const value = funcSerchResult[key];
              console.log(`Значение ${key}:`, value);
              if (
                result[key] === undefined &&
                value !== undefined &&
                value !== "" &&
                value !== null
              ) {
                console.log(`Заменен ${key} для ${methodName}:`, value);
                result[key] = value;
              }
            }
          });
        } catch (error) {
          if (configLog) {
            console.warn(
              `Ошибка получения настроек поиска для ${methodName}:`,
              error.message,
            );
          }
        }
      }

      // Применяем кастомный парсер настроек
      const customSettingsParser = config?.settings?.customSettingsParser;

      // Используем уже полученный результат из funcMainResult
      const settingsResultValue = funcMainResult?.settings;

      const hasSignificantValue = (value) => {
        if (value === undefined) return false;
        if (value === false) return true;
        // if (value === null) return true; // null может быть значимым
        if (Array.isArray(value)) return value.length > 0;
        if (typeof value === "object") return Object.keys(value).length > 0;
        return true; // для примитивов
      };

      if (configLog)
        console.log(`Проверка customSettingsParser для ${methodName}:\n`, {
          hasCustomSettingsParser: !!customSettingsParser,
          settingsResultValue: settingsResultValue,
          valueType: typeof settingsResultValue,
          isArray: Array.isArray(settingsResultValue),
        });

      if (customSettingsParser && hasSignificantValue(settingsResultValue)) {
        try {
          const parsedSettings = customSettingsParser(settingsResultValue);
          if (configLog)
            console.log(`parsedSettings для ${methodName}:\n`, parsedSettings);

          Object.keys(parsedSettings).forEach((key) => {
            if (!key.includes("Api") && !excludedKeys.includes(key)) {
              const value = parsedSettings[key];
              if (configLog) console.log(`Значение ${key}:`, value);

              if (value !== undefined && value !== "" && value !== null) {
                // Если result[key] - объект, обновляем undefined значения
                if (
                  typeof result[key] === "object" &&
                  result[key] !== null &&
                  !Array.isArray(result[key])
                ) {
                  updateUndefinedValues(result[key], value);
                  if (configLog)
                    console.log(
                      `Обновлены undefined значения в объекте ${key} для ${methodName}:`,
                      value,
                    );
                }
                // Если result[key] === undefined, заменяем полностью
                else if (!result[key]) {
                  if (configLog)
                    console.log(`Заменен ${key} для ${methodName}:`, value);
                  result[key] = value;
                }
              }
            }
          });
        } catch (error) {
          if (configLog) {
            console.warn(
              `Ошибка парсинга настроек для ${methodName}:`,
              error.message,
            );
          }
        }
      } else {
        if (configLog)
          console.warn(
            `customSettingsParser НЕ вызывается для ${methodName}:`,
            {
              reason: !customSettingsParser
                ? "нет customSettingsParser"
                : "нет settingsResultValue",
            },
          );
      }

      // Применяем динамические значения только если в результате еще нет значений
      if (settings.dynamicDateFrom && !result.dateFrom) {
        try {
          result.dateFrom = eval(settings.dynamicDateFrom);
        } catch (error) {
          if (configLog) {
            console.warn(
              `Ошибка вычисления dynamicDateFrom для ${methodName}:`,
              error.message,
            );
          }
        }
      }
      // Применяем динамические значения только если в результате еще нет значений
      if (settings.dynamicDateTo && !result.dateTo) {
        try {
          result.dateTo = eval(settings.dynamicDateTo);
        } catch (error) {
          if (configLog) {
            console.warn(
              `Ошибка вычисления dynamicDateTo для ${methodName}:`,
              error.message,
            );
          }
        }
      }

      // Применяем динамические значения только если в результате еще нет значений
      if (settings.dynamicNmIDs) {
        try {
          // Безопасная обработка dynamicNmIDs без использования eval()
          let dynamicValue = settings.dynamicNmIDs;

          // Если это строка с API классами, заменяем их на реальные объекты
          if (typeof dynamicValue === "string" && configUtils._apiClasses) {
            Object.keys(configUtils._apiClasses).forEach((apiClassName) => {
              // Заменяем строковые ссылки типа 'WBS' на реальные объекты
              const regex = new RegExp(`'${apiClassName}'`, "g");
              dynamicValue = dynamicValue.replace(
                regex,
                `configUtils._apiClasses['${apiClassName}']`,
              );
            });

            // Безопасное вычисление только для известных паттернов
            if (dynamicValue.includes("configUtils._apiClasses")) {
              // Создаем безопасный контекст для вычисления
              const safeContext = {
                configUtils: {
                  _apiClasses: configUtils._apiClasses,
                },
              };

              // Используем Function constructor вместо eval для безопасности
              const safeEval = new Function(
                "configUtils",
                `return ${dynamicValue}`,
              );
              result.nmIDs = safeEval(safeContext.configUtils);
            } else {
              // Если нет API классов, просто используем значение как есть
              result.nmIDs = dynamicValue;
            }
          } else {
            // Если это не строка, используем как есть
            result.nmIDs = dynamicValue;
          }
        } catch (error) {
          if (configLog) {
            console.warn(
              `Ошибка обработки dynamicNmIDs для ${methodName}:`,
              error.message,
            );
          }
          // В случае ошибки используем значение по умолчанию
          result.nmIDs = settings.dynamicNmIDs;
        }
      }
    }

    // Удаляем служебные поля
    delete result.settings;

    if (configLog)
      console.log(`Итоговая конфигурация для ${methodName}:`, result);

    return result;
  },

  /**
   * Получить список всех доступных методов API
   * @returns {string[]} массив названий методов
   */
  getAvailableMethods: () => {
    const baseMethods = Object.keys(configWildberriesApi);
    const customMethods = Object.keys(configUtils._customConfigs);
    return [...new Set([...baseMethods, ...customMethods])];
  },

  /**
   * Проверить существование метода в конфигурации
   * @param {string} methodName - название метода
   * @returns {boolean} существует ли метод
   */
  hasMethod: (methodName) => {
    return (
      methodName in configWildberriesApi ||
      methodName in configUtils._customConfigs
    );
  },

  /**
   * Получить базовую конфигурацию метода (без кастомных переопределений)
   * @param {string} methodName - название метода
   * @returns {Object|null} базовая конфигурация или null
   */
  getBaseConfig: (methodName) => {
    return configWildberriesApi[methodName] || null;
  },

  /**
   * Получить кастомную конфигурацию метода
   * @param {string} methodName - название метода
   * @returns {Object|null} кастомная конфигурация или null
   */
  getCustomConfig: (methodName) => {
    return configUtils._customConfigs[methodName] || null;
  },

  /**
   * Удалить кастомную конфигурацию для метода
   * @param {string} methodName - название метода
   */
  removeCustomConfig: (methodName) => {
    delete configUtils._customConfigs[methodName];
    if (configUtils._context?.configLog) {
      console.log(`Кастомная конфигурация для ${methodName} удалена`);
    }
  },

  /**
   * Очистить все кастомные конфигурации
   */
  clearCustomConfigs: () => {
    configUtils._customConfigs = {};
    if (configUtils._context?.configLog) {
      console.log("Все кастомные конфигурации очищены");
    }
  },

  /**
   * Получить список методов с кастомными конфигурациями
   * @returns {string[]} массив названий методов
   */
  getCustomMethods: () => {
    return Object.keys(configUtils._customConfigs);
  },

  /**
   * Экспортировать все кастомные конфигурации
   * @returns {Object} объект с кастомными конфигурациями
   */
  exportCustomConfigs: () => {
    return JSON.parse(JSON.stringify(configUtils._customConfigs));
  },

  /**
   * Импортировать кастомные конфигурации
   * @param {Object} configs - объект с конфигурациями
   * @param {boolean} merge - объединить с существующими (по умолчанию false)
   */
  importCustomConfigs: (configs, merge = false) => {
    if (!merge) {
      configUtils._customConfigs = {};
    }

    Object.entries(configs).forEach(([methodName, customConfig]) => {
      configUtils._customConfigs[methodName] = customConfig;
    });

    if (configUtils._context?.configLog) {
      console.log(
        `Импортировано ${Object.keys(configs).length} кастомных конфигураций`,
      );
    }
  },

  /**
   * Получить все функции библиотеки с проверкой конфликтов
   * @param {Object} libraryInstance - экземпляр библиотеки (например, WB)
   * @param {Object} tableContext - контекст таблицы (this)
   * @param {Array} excludeFunctions - функции для исключения
   * @returns {Object} объект с функциями библиотеки
   */
  getAllFunctions: (libraryInstance, tableContext, excludeFunctions = []) => {
    const libraryFunctions = {};
    const conflictingFunctions = [];
    const excludedSet = new Set(excludeFunctions);

    // Получаем все функции из библиотеки
    const allLibraryFunctions = Object.keys(libraryInstance).filter((key) => {
      return (
        typeof libraryInstance[key] === "function" && !excludedSet.has(key)
      );
    });

    // // Получаем все функции из библиотеки через allFunctions()
    // const allLibraryFunctions = libraryInstance.allFunctions().filter((key) => {
    //   return !excludedSet.has(key);
    // });

    allLibraryFunctions.forEach((funcName) => {
      // Проверяем конфликты с функциями таблицы
      if (tableContext && typeof tableContext[funcName] === "function") {
        conflictingFunctions.push(funcName);
        if (configUtils._context?.configLog) {
          console.warn(
            `Конфликт функций: ${funcName} существует и в библиотеке, и в таблице`,
          );
        }
        // Даже при конфликте создаем обертку для функций библиотеки
        libraryFunctions[funcName] = configUtils.createFunctionWrapper(
          libraryInstance[funcName],
          funcName,
          libraryInstance,
        );
      } else {
        // Создаем обертку функции с автоматической передачей конфигурации
        libraryFunctions[funcName] = configUtils.createFunctionWrapper(
          libraryInstance[funcName],
          funcName,
          libraryInstance,
        );
      }
    });

    // Сохраняем информацию о конфликтах
    configUtils._conflictingFunctions = conflictingFunctions;
    configUtils._libraryFunctions = libraryFunctions;

    if (conflictingFunctions.length > 0) {
      throw new Error(
        `Обнаружены конфликтующие функции: ${conflictingFunctions.join(
          ", ",
        )}. ` +
          `Используйте excludeFunctions для их исключения или переименуйте функции в таблице.`,
      );
    }

    if (configUtils._context?.configLog) {
      console.log(
        `Загружено ${Object.keys(libraryFunctions).length} функций библиотеки`,
      );
      // console.log("Функции библиотеки:", Object.keys(libraryFunctions));
    }

    return libraryFunctions;
  },

  /**
   * Создать обертку функции с автоматической передачей конфигурации
   * @param {Function} originalFunction - оригинальная функция
   * @param {string} functionName - название функции
   * @param {Object} libraryInstance - экземпляр библиотеки
   * @returns {Function} обернутая функция
   */
  createFunctionWrapper: (originalFunction, functionName, libraryInstance) => {
    return function (...args) {
      // Получаем конфигурацию для этой функции
      const config = configUtils.getConfigForFunction(functionName);

      // Если первый аргумент - объект options, объединяем с конфигурацией
      if (args.length > 0 && typeof args[0] === "object" && args[0] !== null) {
        args[0] = { ...config, ...args[0] };
      } else {
        // Если нет объекта options, добавляем конфигурацию как первый аргумент
        args.unshift(config);
      }

      // Вызываем оригинальную функцию с обновленными аргументами
