      return configUtils.getConfig(functionName);
    } catch (error) {
      if (configUtils._context?.configLog) {
        console.warn(
          `Не удалось получить конфигурацию для ${functionName}:`,
          error.message,
        );
      }
      return {};
    }
  },

  /**
   * Получить конфигурацию для текущей функции (автоматически определяет имя)
