  getConfigForCurrentFunction: () => {
    try {
      // Получаем имя текущей функции через arguments.callee.name
      const functionName = arguments.callee.name;
      return configUtils.getConfig(functionName);
    } catch (error) {
      if (configUtils._context?.configLog) {
        console.warn(
