  // Хранилище разрешенных функций для экспорта
  _allowedFunctions: new Set(),

  // Дополнительные функции для добавления к списку из configWildberriesApi
  _additionalAllowedFunctions: [
    // Здесь можно добавить дополнительные функции вручную
    // Например: "myCustomFunction", "anotherFunction"
    "wildberriesSetMultipleAccess",
    "wildberriesSetSiteToken",
    "moyskladSetToken",
    "wildberriesLibraryVersion",
    "wildberriesJwtTokenInfo",
  ],

  /**
   * Получить список всех функций из configWildberriesApi
   * @returns {Array} массив названий функций из configWildberriesApi
   */
  _getConfigWildberriesApiFunctions: () => {
    return Object.keys(configWildberriesApi);
  },

  /**
   * Получить полный дефолтный список (configWildberriesApi + дополнительные)
   * @returns {Array} массив всех дефолтных функций
   */
  _getFullDefaultAllowedFunctions: () => {
    const apiFunctions = configUtils._getConfigWildberriesApiFunctions();
    return [...apiFunctions, ...configUtils._additionalAllowedFunctions];
  },

  /**
   * Добавить функции в список разрешенных для экспорта
   * @param {Array|string} functionNames - названия функций или массив названий
   */
  allowFunctions: (functionNames) => {
    const functions = Array.isArray(functionNames)
      ? functionNames
      : [functionNames];
    functions.forEach((funcName) => {
      configUtils._allowedFunctions.add(funcName);
    });

    if (configUtils._context?.configLog) {
      console.log(
        `Добавлено ${functions.length} функций в список разрешенных:`,
        functions,
      );
    }
  },

  /**
   * Удалить функции из списка разрешенных для экспорта
   * @param {Array|string} functionNames - названия функций или массив названий
   */
  disallowFunctions: (functionNames) => {
    const functions = Array.isArray(functionNames)
      ? functionNames
      : [functionNames];
    functions.forEach((funcName) => {
      configUtils._allowedFunctions.delete(funcName);
    });

    if (configUtils._context?.configLog) {
      console.log(
        `Удалено ${functions.length} функций из списка разрешенных:`,
        functions,
      );
    }
  },

  /**
   * Получить список разрешенных функций для экспорта
   * @returns {Array} массив названий разрешенных функций
   */
  getAllowedFunctions: () => {
    return Array.from(configUtils._allowedFunctions);
  },

  /**
   * Проверить, разрешена ли функция для экспорта
   * @param {string} functionName - название функции
   * @returns {boolean} true если функция разрешена
   */
  isFunctionAllowed: (functionName) => {
    // Если список разрешенных пуст, то все функции разрешены
    if (configUtils._allowedFunctions.size === 0) {
      return true;
    }
    return configUtils._allowedFunctions.has(functionName);
  },

  /**
   * Установить дефолтный список разрешенных функций
   */
  setDefaultAllowedFunctions: () => {
    configUtils._allowedFunctions.clear();
    const fullDefaultList = configUtils._getFullDefaultAllowedFunctions();

    fullDefaultList.forEach((funcName) => {
      configUtils._allowedFunctions.add(funcName);
    });

    if (configUtils._context?.configLog) {
      console.log(
        `Установлен дефолтный список разрешенных функций: ${fullDefaultList.length} функций`,
      );
      console.log(
        `Из configWildberriesApi: ${
          configUtils._getConfigWildberriesApiFunctions().length
        } функций`,
      );
      console.log(
        `Дополнительных: ${configUtils._additionalAllowedFunctions.length} функций`,
      );
    }
  },

  /**
   * Получить дефолтный список разрешенных функций
   * @returns {Array} массив названий дефолтных функций
   */
  getDefaultAllowedFunctions: () => {
    return configUtils._getFullDefaultAllowedFunctions();
  },

  /**
   * Получить отфильтрованный список функций для экспорта
   * @param {Object} allFunctions - объект со всеми функциями
   * @returns {Object} объект с отфильтрованными функциями
   */
  getFilteredFunctions: (allFunctions) => {
    const filtered = {};

    Object.keys(allFunctions).forEach((funcName) => {
      if (configUtils.isFunctionAllowed(funcName)) {
        filtered[funcName] = allFunctions[funcName];
      }
    });

    if (configUtils._context?.configLog) {
      console.log(
        `Отфильтровано функций: ${Object.keys(filtered).length} из ${
          Object.keys(allFunctions).length
        }`,
      );
    }

    return filtered;
  },
};

