/**
 * Класс для работы с датами и временными зонами
 * Предоставляет методы для конвертации между различными форматами дат
 * и работы с временными зонами в контексте Google Sheets
 */
class DateUtils {
  /**
   * Инициализирует moment.js с русской локалью
   */
  static initializeMomentLocale() {
    // Устанавливаем русскую локаль для moment.js
    moment.locale("ru");

    // Настраиваем русские форматы дат
    moment.updateLocale("ru", {
      longDateFormat: {
        L: "DD.MM.YYYY",
        LL: "D MMMM YYYY г.",
        LLL: "D MMMM YYYY г., H:mm",
        LLLL: "dddd, D MMMM YYYY г., H:mm",
      },
    });
  }

  /**
   * Конвертирует float дату (Excel/Google Sheets) в Date объект с помощью Moment.js
   * @param {number} floatDate - Float значение даты из Excel/Google Sheets
   * @param {string} [timezone="Europe/Moscow"] - Временная зона для отображения
   * @returns {Date} JavaScript Date объект
   */
  static floatDateToMomentDate(floatDate, timezone = "Europe/Moscow") {
    if (typeof floatDate !== "number") {
      throw new Error("floatDate должен быть числом");
    }

    // Базовая дата для Excel/Google Sheets (30 декабря 1899 года)
    const baseDate = moment.utc("1899-12-30");

    // Разделяем на дни и дробную часть
    const days = Math.floor(floatDate);
    const fractionalPart = floatDate - days;

    // Создаем дату, добавляя дни к базовой дате
    let resultDate = baseDate.clone().add(days, "days");

    // Добавляем время из дробной части
    if (fractionalPart > 0) {
      const millisecondsPerDay = 24 * 60 * 60 * 1000;
      const timeInMillis = fractionalPart * millisecondsPerDay;
      resultDate = resultDate.clone().add(timeInMillis, "milliseconds");
    }

    return resultDate.tz(timezone).toDate();
  }

  /**
   * Конвертирует Date объект в float дату для Excel/Google Sheets
   * @param {Date|string} date - Дата для конвертации
   * @param {string} [timezone="Europe/Moscow"] - Временная зона (не используется, всегда UTC)
   * @returns {number} Float значение даты
   */
  static momentDateToFloatDate(date, timezone = "Europe/Moscow") {
    if (!date) {
      throw new Error("Дата не может быть пустой");
    }

    // Всегда используем UTC для конвертации в serial date
    const momentDate = moment.utc(date);
    const baseDate = moment.utc("1899-12-30");

    // Вычисляем разность в днях с дробной частью
    const diffInDays = momentDate.diff(baseDate, "days", true);

    return diffInDays;
  }

  /**
   * Форматирует дату с помощью Moment.js
   * @param {Date|string|number} date - Дата для форматирования
   * @param {string} format - Формат даты (например, "DD.MM.YYYY")
   * @param {string} [timezone="Europe/Moscow"] - Временная зона
   * @returns {string} Отформатированная дата
   */
  static formatMomentDate(date, format, timezone = "Europe/Moscow") {
    if (!date || !format) {
      throw new Error("Дата и формат обязательны");
    }

    let momentDate;
    if (typeof date === "number" && date > 1) {
      // Это float дата
      momentDate = moment(this.floatDateToMomentDate(date, timezone));
    } else {
      // Это обычная дата
      momentDate = moment.tz(date, timezone);
    }

    return momentDate.format(format);
  }

  /**
   * Парсит строку даты с помощью Moment.js
   * @param {string} dateString - Строка с датой
   * @param {string} [format=null] - Ожидаемый формат (если null, пробует несколько форматов)
   * @param {string} [timezone="Europe/Moscow"] - Временная зона (не используется, всегда UTC)
   * @returns {Date} JavaScript Date объект
   */
  static parseMomentDate(
    dateString,
    format = null,
    timezone = "Europe/Moscow"
  ) {
    if (!dateString || typeof dateString !== "string") {
      throw new Error("dateString должен быть непустой строкой");
    }

    let momentDate;
    if (format) {
      // Парсим с указанным форматом
      momentDate = moment.utc(dateString, format);
    } else {
      // Пробуем различные форматы
      const formats = [
        "DD.MM.YYYY",
        "DD.MM.YY",
        "D.MM.YYYY",
        "D.M.YYYY",
        "DD/MM/YYYY",
        "DD/MM/YY",
        "D/MM/YYYY",
        "D/M/YYYY",
        "YYYY-MM-DD",
        "YYYY-MM-DD HH:mm:ss",
        "YYYY-MM-DD HH:mm",
        "DD.MM.YYYY HH:mm:ss",
        "DD.MM.YYYY HH:mm",
        "D.MM.YYYY HH:mm:ss",
        "D.M.YYYY HH:mm:ss",
        "DD/MM/YYYY HH:mm:ss",
        "DD/MM/YYYY HH:mm",
        "D/MM/YYYY HH:mm:ss",
        "D/M/YYYY HH:mm:ss",
      ];

      momentDate = moment.utc(dateString, formats);
    }

    if (!momentDate.isValid()) {
      throw new Error(`Не удалось распарсить дату: ${dateString}`);
    }

    return momentDate.toDate();
  }

  /**
   * Выполняет арифметические операции с датами
   * @param {Date|string|number} date - Исходная дата
   * @param {number} amount - Количество для добавления/вычитания
   * @param {string} unit - Единица измерения (days, months, years, etc.)
   * @param {string} [timezone="Europe/Moscow"] - Временная зона
   * @returns {Date} Новая дата
   */
  static addMomentDate(date, amount, unit, timezone = "Europe/Moscow") {
    if (!date || !amount || !unit) {
      throw new Error("Дата, количество и единица измерения обязательны");
    }

    let momentDate;
    if (typeof date === "number" && date > 1) {
      // Это float дата
      momentDate = moment(this.floatDateToMomentDate(date, timezone));
    } else {
      // Это обычная дата
      momentDate = moment.tz(date, timezone);
    }

    return momentDate.add(amount, unit).toDate();
  }

  /**
   * Вычисляет разность между двумя датами
   * @param {Date|string|number} date1 - Первая дата
   * @param {Date|string|number} date2 - Вторая дата
   * @param {string} unit - Единица измерения (days, months, years, etc.)
   * @param {string} [timezone="Europe/Moscow"] - Временная зона
   * @returns {number} Разность в указанных единицах
   */
  static diffMomentDates(date1, date2, unit, timezone = "Europe/Moscow") {
    if (!date1 || !date2 || !unit) {
      throw new Error("Обе даты и единица измерения обязательны");
    }

    let momentDate1, momentDate2;

    if (typeof date1 === "number" && date1 > 1) {
      // Это float дата
      momentDate1 = moment(this.floatDateToMomentDate(date1, timezone));
    } else {
      // Это обычная дата
      momentDate1 = moment.tz(date1, timezone);
    }

    if (typeof date2 === "number" && date2 > 1) {
      // Это float дата
      momentDate2 = moment(this.floatDateToMomentDate(date2, timezone));
    } else {
      // Это обычная дата
      momentDate2 = moment.tz(date2, timezone);
    }

    return momentDate1.diff(momentDate2, unit);
  }

  /**
   * Проверяет, находится ли дата в указанном диапазоне
   * @param {Date|string|number} date - Проверяемая дата
   * @param {Date|string|number} startDate - Начало диапазона
   * @param {Date|string|number} endDate - Конец диапазона
   * @param {string} [timezone="Europe/Moscow"] - Временная зона
   * @returns {boolean} true, если дата в диапазоне
   */
  static isMomentDateInRange(
    date,
    startDate,
    endDate,
    timezone = "Europe/Moscow"
  ) {
    if (!date || !startDate || !endDate) {
      return false;
    }

    let momentDate, momentStart, momentEnd;

    if (typeof date === "number" && date > 1) {
      // Это float дата
      momentDate = moment(this.floatDateToMomentDate(date, timezone));
    } else {
      // Это обычная дата
      momentDate = moment.tz(date, timezone);
    }

    if (typeof startDate === "number" && startDate > 1) {
      // Это float дата
      momentStart = moment(this.floatDateToMomentDate(startDate, timezone));
    } else {
      // Это обычная дата
      momentStart = moment.tz(startDate, timezone);
    }

    if (typeof endDate === "number" && endDate > 1) {
      // Это float дата
      momentEnd = moment(this.floatDateToMomentDate(endDate, timezone));
    } else {
      // Это обычная дата
      momentEnd = moment.tz(endDate, timezone);
    }

    return momentDate.isBetween(momentStart, momentEnd, null, "[]"); // включительно
  }

  /**
   * Получает начало или конец периода для даты
   * @param {Date|string|number} date - Исходная дата
   * @param {string} period - Период (day, week, month, year, etc.)
   * @param {string} [bound="start"] - "start" или "end"
   * @param {string} [timezone="Europe/Moscow"] - Временная зона
   * @returns {Date} Начало или конец периода
   */
  static getMomentDateBoundary(
    date,
    period,
    bound = "start",
    timezone = "Europe/Moscow"
  ) {
    if (!date || !period) {
      throw new Error("Дата и период обязательны");
    }

    let momentDate;
    if (typeof date === "number" && date > 1) {
      // Это float дата
      momentDate = moment(this.floatDateToMomentDate(date, timezone));
    } else {
      // Это обычная дата
      momentDate = moment.tz(date, timezone);
    }

    if (bound === "start") {
      return momentDate.startOf(period).toDate();
    } else {
      return momentDate.endOf(period).toDate();
    }
  }
}

