function getRangeA1NotationApiV4(sheet, result, startRow) {
  return sheet
    .getRange(startRow || 1, 1, result.length, result[0].length)
    .getA1Notation();
}

class Sheet {
  constructor(spreadsheetId, sheetName, range) {
    this.spreadsheetId = String(spreadsheetId);
    this.sheetName = String(sheetName);
    this.range = String(range);
  }
}

