function sheetConstructor(spreadsheetId, sheetName, dataRange) {
  return new Sheet(spreadsheetId, sheetName, dataRange);
}

class ValueRange {
  constructor(range, values, majorDimension) {
    this.range = String(range);
    this.values = values;
    this.majorDimension = String(majorDimension || "ROWS");
  }

  create() {
    if (this.range && this.values)
      return new ValueRange(this.range, this.values, this.majorDimension);
  }
}

class SheetBatch {
  constructor(spreadsheetId, ranges) {
    this.spreadsheetId = String(spreadsheetId);
    this.data = ranges.map((el) => new ValueRange(...el).create());
  }
}

function sheetBatchConstructor(spreadsheetId, ranges) {
  return new SheetBatch(spreadsheetId, ranges);
}

/**
 * Создает Spreadsheet по API
 * @see https://developers.google.com/sheets/api/reference/rest/v4/spreadsheets/create
 * @param {object} requestOptions объект с параметрами книги
 * @return {(object|null)} объект с описание параметров созданной книги
 */
function createSpreadsheet(requestOptions) {
  try {
    const response = Sheets.Spreadsheets.create(requestOptions);
    return response || null;
  } catch (error) {
    console.error(error.stack);
  }
}

/**
 * Создает Sheet по API
 * @see https://developers.google.com/workspace/sheets/api/reference/rest/v4/spreadsheets/batchUpdate
 * @param {object} requestOptions объект с параметрами
 * @return {(object|null)} объект с описание параметров созданного листа
 */
function createSheet(sheet, requestOptions = {}) {
  try {
    const response = Sheets.Spreadsheets.batchUpdate(
      {
        requests: [
          {
            addSheet: {
              properties: {
                title: sheet.sheetName,
                index: requestOptions.index || 0,
                gridProperties: {
                  rowCount: requestOptions.rowCount || 1000,
                  columnCount: requestOptions.columnCount || 26,
                  frozenRowCount: requestOptions.frozenRowCount || 0,
                  frozenColumnCount: requestOptions.frozenColumnCount || 0,
                  hideGridlines: requestOptions.hideGridlines || false,
                  rowGroupControlAfter:
                    requestOptions.rowGroupControlAfter || false,
                  columnGroupControlAfter:
                    requestOptions.columnGroupControlAfter || false,
                },
              },
              hidden: requestOptions.hidden || false,
              tabColorStyle: {
                rgbColor: {
                  red: requestOptions.tabColorStyle.rgbColor.red || 1.0, // 1.0 = максимальный красный
                  green: requestOptions.tabColorStyle.rgbColor.green || 0.0, // 0.0 = нет зеленого
                  blue: requestOptions.tabColorStyle.rgbColor.blue || 0.0, // 0.0 = нет синего
                  alpha: requestOptions.tabColorStyle.rgbColor.alpha || 1.0, // 1.0 = полностью непрозрачный
                },
                themeColor:
                  requestOptions.tabColorStyle.themeColor ||
                  SheetsAPIThemeColorType.THEME_COLOR_TYPE_UNSPECIFIED,
              },
            },
          },
        ],
      },
      sheet.spreadsheetId
    );
    return response || null;
  } catch (e) {
    console.error(e.stack);
  }
}

/**
 * Создает Sheet по API
 * @see https://developers.google.com/workspace/sheets/api/reference/rest/v4/spreadsheets/batchUpdate
 * @param {object} requestOptions объект с параметрами
