 */
function updateSheetRange(sheet, requestOptions = {}) {
  try {
    const response = Sheets.Spreadsheets.batchUpdate(
      {
        requests: [
          {
            updateSheetProperties: {
              properties: {
                sheetId: sheet.sheetId,
                title: sheet.sheetName,
                gridProperties: {
                  rowCount: requestOptions.rowCount || 1000,
                  columnCount: requestOptions.columnCount || 26,
                  frozenRowCount: requestOptions.frozenRowCount || 0,
                  frozenColumnCount: requestOptions.frozenColumnCount || 0,
                  hideGridlines: requestOptions.hideGridlines || false,
                  rowGroupControlAfter:
                    requestOptions.rowGroupControlAfter || false,
                  columnGroupControlAfter:
                    requestOptions.columnGroupControlAfter || false,
                },
              },
              fields: "*",
            },
          },
        ],
      },
      sheet.spreadsheetId
    );
    return response || null;
  } catch (e) {
    console.error(e.stack);
  }
}

/**
 * Добавляет данные в таблицу по API.
 * @see https://developers.google.com/sheets/api/reference/rest/v4/spreadsheets.values/append
 * @type {Object} options
 * @property {Sheet} options.sheet объект: id книги, название листа, диапазон
 * @property {(string|number)[]} options.data массив данных
 * @property {string} [options.valueInputOption] "USER_ENTERED", "RAW", по умолчанию "USER_ENTERED"
 * @property {string} [options.insertDataOption] "OVERWRITE", "INSERT_ROWS", по умолчанию "INSERT_ROWS"
 * @property {boolean} [options.includeValuesInResponse] по умолчанию false
 * @property {string} [options.responseValueRenderOption] "UNFORMATTED_VALUE", "FORMULA", "FORMATTED_VALUE", null
 * @property {string} [options.responseDateTimeRenderOption] "SERIAL_NUMBER", "FORMATTED_STRING", null
 */
function appendData({
  sheet,
  data,
  valueInputOption,
  insertDataOption,
  includeValuesInResponse,
  responseValueRenderOption,
  responseDateTimeRenderOption,
}) {
  try {
    const response = Sheets.Spreadsheets.Values.append(
      {
        values: data,
      },
      sheet.spreadsheetId,
      `${sheet.sheetName}!${sheet.range}`,
      {
        valueInputOption: valueInputOption || "USER_ENTERED",
        insertDataOption: insertDataOption || "INSERT_ROWS",
        includeValuesInResponse: includeValuesInResponse || false,
        responseValueRenderOption: responseValueRenderOption || null,
        responseDateTimeRenderOption: responseDateTimeRenderOption || null,
      }
    );
    return response || null;
  } catch (e) {
    console.error(e.stack);
  }
}

