/**
 * Установка формата столбцов Sheets API V4
 * @type {Object} options
 * @property {string} options.spreadsheetId идентификатор Google-таблицы, в которую мы хотим внести изменения
 * @property {number} options.sheetId идентификатор листа этой таблицы, на котором хотим применить форматирование столбцов
 * @property {Array.<string|number} options.columnFormats массив, содержащий информацию о тех столбцах, которые нам нужно отформатировать
 * Каждый элемент этого массива содержит:
 * - `startRowIndex` - индекс строк для начала выбора столбца;
 * - `startColumnIndex` - индекс колонки для начала выбора столбца;
 * - `endColumnIndex` - индекс колонки, следующий за последней колонкой, которую мы хотим отформатировать;
 * - `type` - {userEnteredFormatNumberFormatType}, тип формата, такой как "NUMBER", "CURRENCY", "DATE" и т.д.;
 * - `format` - опциональный парамет.
 * @property {boolean} [options.includeSpreadsheetInResponse] ответ на обновление включает ресурс электронной таблицы
 * @property {Array} [options.responseRanges] ограничивает диапазоны, включенные в электронную таблицу ответов, если includeSpreadsheetInResponse: true
 * @property {boolean} [options.responseIncludeGridData] true, если должны быть возвращены данные сетки, если includeSpreadsheetInResponse: true
 * @property {boolean} [options.requestLog] true, печать запроса в лог
 */
function setColumnFormat({
  spreadsheetId,
  sheetId,
  columnFormats,
  includeSpreadsheetInResponse,
  responseRanges,
  responseIncludeGridData,
  requestLog,
}) {
  try {
    let request = [];
    columnFormats.map((format) => {
      const tmp = {
        repeatCell: {
          cell: {
            // Устанавливаем форматирование
            userEnteredFormat: {
              numberFormat: {
                type: format[4],
                pattern: format[5],
              },
            },
          },
          range: {
            sheetId: sheetId,
            startRowIndex: format[0], // columnFormats[0] - 1,
            endRowIndex: format[1] + 1, // columnFormats[1],
            startColumnIndex: format[2], // columnFormats[2] -1,
            endColumnIndex: format[3] + 1, // columnFormats[3],
          },
          fields: "userEnteredFormat.numberFormat",
        },
      };

      request.push(tmp);
    });

    const batchUpdateRequest = {
      requests: request,
      includeSpreadsheetInResponse: includeSpreadsheetInResponse
        ? includeSpreadsheetInResponse
        : false,
      responseRanges: responseRanges ? responseRanges : [],
      responseIncludeGridData: responseIncludeGridData
        ? responseIncludeGridData
        : false,
    };

    if (requestLog) console.log(JSON.stringify(request, null, 10));

    if (batchUpdateRequest) {
      const response = Sheets.Spreadsheets.batchUpdate(
        batchUpdateRequest,
        spreadsheetId
      );
      console.log(JSON.stringify(response, null, 5));
    } else {
      console.log("batchUpdateRequest invalid, set requestLog: true");
    }
  } catch (e) {
    console.error(e.stack);
  }
}

function clearSheetsData(ss, sheetsToClear) {
  const spreadsheetId = ss.getId();
  const requests = [];

  sheetsToClear.forEach((sheetName) => {
    const sheet = ss.getSheetByName(sheetName);
    if (sheet) {
      const sheetId = sheet.getSheetId();
      requests.push({
        updateCells: {
          rows: [],
          fields: "*",
          range: {
            sheetId: sheetId,
            startRowIndex: 0,
            endRowIndex: sheet.getMaxRows(),
            startColumnIndex: 0,
            endColumnIndex: sheet.getMaxColumns(),
          },
        },
      });
    } else {
      console.log(`Лист с названием "${sheetName}" не найден.`);
    }
  });

  if (requests.length) {
    Sheets.Spreadsheets.batchUpdate({ requests }, spreadsheetId);
    console.log("Данные на листах очищены.");
  } else {
    console.log("Нет листов для очистки.");
  }
}

function clearAllSheetsExcept(ss, sheetsToKeep) {
  const ssId = ss.getId();
  const rqs = [];
  const allSheets = ss.getSheets();

  allSheets.forEach((sheet) => {
    const sheetName = sheet.getName();
    if (!sheetsToKeep.includes(sheetName)) {
      const sheetId = sheet.getSheetId();
      rqs.push({
        updateCells: {
          rows: [], // Пустой массив указывает на то, что мы хотим очистить содержимое
          fields: "*", // Устанавливаем все поля в пустое состояние
          range: {
            sheetId: sheetId,
            startRowIndex: 0,
            endRowIndex: sheet.getMaxRows(),
            startColumnIndex: 0,
            endColumnIndex: sheet.getMaxColumns(),
          },
        },
      });
    }
  });

  if (rqs.length) {
    Sheets.Spreadsheets.batchUpdate({ requests: rqs }, ssId);
    console.log(
      "Содержимое очищено на всех листах, кроме указанных исключений."
    );
  } else {
    console.log("Нет листов для очистки.");
  }
}

function expandAllGroups(ssId, sheetsToExpand) {
  const initial = Sheets.Spreadsheets.get(ssId, {
    fields: "sheets(columnGroups,properties(sheetId,title),rowGroups)",
  });

  const rqs = [];
  // https://developers.google.com/workspace/sheets/api/reference/rest/v4/spreadsheets/request#UpdateDimensionGroupRequest
  initial.sheets.forEach(function (sheet) {
    if (sheetsToExpand.includes(sheet.properties.title)) {
      const sId = sheet.properties.sheetId;

      if (sheet.rowGroups) {
        sheet.rowGroups.forEach(function (group) {
          if (group.depth && group.collapsed) {
            rqs.push({
              updateDimensionGroup: {
                dimensionGroup: {
                  range: {
                    sheetId: sId,
                    dimension: "ROWS",
                    startIndex: group.startIndex,
                    endIndex: group.endIndex,
                  },
                  depth: group.depth,
                  collapsed: false,
                },
                fields: "*",
              },
            });
          }
        });
      }

      if (sheet.columnGroups) {
        sheet.columnGroups.forEach(function (group) {
          if (group.depth && group.collapsed) {
            rqs.push({
              updateDimensionGroup: {
                dimensionGroup: {
                  range: {
                    sheetId: sId,
                    dimension: "COLUMNS",
                    startIndex: group.startIndex,
                    endIndex: group.endIndex,
                  },
                  depth: group.depth,
                  collapsed: false,
                },
                fields: "*",
              },
            });
          }
        });
      }
    }
  });

  console.log(JSON.stringify(rqs, null, 2));

  if (rqs.length) {
    Sheets.Spreadsheets.batchUpdate({ requests: rqs }, ssId);
    console.log({ message: "Groups expanded", sheetId: ssId });
  }
}
function removeAllGroups(ssId) {
  const initial = Sheets.Spreadsheets.get(ssId, {
    fields: "sheets(columnGroups,properties(sheetId,title),rowGroups)",
  });

  // Determine the maximum depth of row & column groups on each sheet in the workbook.
  const maxDepths = { row: {}, col: {} };
  initial.sheets.forEach(function (s) {
    // if (s.properties.title ... (could write logic to do this only for certain sheets)
    var sId = s.properties.sheetId;
    if (s.columnGroups && s.columnGroups.length)
      maxDepths.col[sId] = s.columnGroups.reduce(dgMaxDepth_, 0);
    if (s.rowGroups && s.rowGroups.length)
      maxDepths.row[sId] = s.rowGroups.reduce(dgMaxDepth_, 0);
  });

  // Add all delete requests to an array
  const rqs = [];
  for (var rqType in maxDepths) {
    for (var sheetId in maxDepths[rqType]) {
      addDeleteDGRequests_(rqs, rqType, sheetId, maxDepths[rqType][sheetId]);
    }
  }

  // Send all requests.
  if (rqs.length) {
    const replies = Sheets.Spreadsheets.batchUpdate({ requests: rqs }, ssId);
    console.log({ message: "Batch response", response: replies });
  }
}

function removeAllGroupsExcept(ssId, sheetsToKeepGroups) {
  const initial = Sheets.Spreadsheets.get(ssId, {
    fields: "sheets(columnGroups,properties(sheetId,title),rowGroups)",
  });

  // Determine the maximum depth of row & column groups on each sheet in the workbook.
  const maxDepths = { row: {}, col: {} };
  initial.sheets.forEach(function (s) {
    if (!sheetsToKeepGroups.includes(s.properties.title)) {
      var sId = s.properties.sheetId;
      if (s.columnGroups && s.columnGroups.length)
        maxDepths.col[sId] = s.columnGroups.reduce(dgMaxDepth_, 0);
      if (s.rowGroups && s.rowGroups.length)
        maxDepths.row[sId] = s.rowGroups.reduce(dgMaxDepth_, 0);
    }
  });

  // Add all delete requests to an array
  const rqs = [];
  for (var rqType in maxDepths) {
    for (var sheetId in maxDepths[rqType]) {
      addDeleteDGRequests_(rqs, rqType, sheetId, maxDepths[rqType][sheetId]);
    }
  }

  // console.log(JSON.stringify(rqs[0], null, 2));

  // Send all requests.
  if (rqs.length) {
    const replies = Sheets.Spreadsheets.batchUpdate({ requests: rqs }, ssId);
    console.log({ message: "Batch response", response: replies });
  }
}

// Callback for Array#reduce
function dgMaxDepth_(val, dg) {
  return Math.max(val, dg.depth);
}

function addDeleteDGRequests_(requests, rqType, sheetId, num) {
  const dim = rqType === "col" ? "COLUMNS" : "ROWS";
  while (num > 0) {
    var rq = {
      deleteDimensionGroup: {
        range: { sheetId: sheetId, dimension: dim },
      },
    };
    requests.push(rq);
    --num;
  }
}

