/**
 * Convert a cell reference from A1Notation to 0-based indices (for arrays)
 * or 1-based indices (for Spreadsheet Service methods).
 * @param {string}    cellA1   Cell reference to be converted.
 * @param {number}    index    (optional, default 0) Indicate 0 or 1 indexing
 * @return {object}            {row,col}, both 0-based array indices.
 * @throws                     Error if invalid parameter
 */
function cellA1ToIndex(cellA1, index) {
  // Ensure index is (default) 0 or 1, no other values accepted.
  index = index || 0;
  index = index == 0 ? 0 : 1;

  // Use regex match to find column & row references.
  // Must start with letters, end with numbers.
  // This regex still allows induhviduals to provide illegal strings like "AB.#%123"
  let match = cellA1.match(/(^[A-Z]+)|([0-9]+$)/gm);
  if (match.length != 2) throw new Error("Invalid cell reference");
  let colA1 = match[0];
  let rowA1 = match[1];
  return [rowA1ToIndex(rowA1, index), colA1ToIndex(colA1, index)];
}

/**
 * Return a 0-based array index corresponding to a spreadsheet row
 * number, as in A1 notation. Almost pointless, really, but maintains
 * symmetry with colA1ToIndex().
 * @param {number}    rowA1    Row number to be converted.
 * @param {number}    index    (optional, default 0) Indicate 0 or 1 indexing
 * @return {number}            0-based array index.
 */
function rowA1ToIndex(rowA1, index) {
  // Ensure index is (default) 0 or 1, no other values accepted.
  index = index || 0;
  index = index == 0 ? 0 : 1;
  return rowA1 - 1 + index;
}

/**
 * Return a 0-based array index corresponding to a spreadsheet column
 * label, as in A1 notation.
 * @param {string}    colA1    Column label to be converted.
 * @param {number}    index    (optional, default 0) Indicate 0 or 1 indexing
 * @return {number}            0-based array index.
 * @throws                     Error if invalid parameter
 */
function colA1ToIndex(colA1, index) {
  if (typeof colA1 !== "string" || colA1.length > 2)
    throw new Error("Expected column label.");

  // Ensure index is (default) 0 or 1, no other values accepted.
  index = index || 0;
  index = index == 0 ? 0 : 1;
  let A = 65; // "A".charCodeAt(0);
  let number = colA1.charCodeAt(colA1.length - 1) - A;
  if (colA1.length == 2) {
    number += 26 * (colA1.charCodeAt(0) - A + 1);
  }
  return number + index;
}

/**
 * Имя столбца по его номеру
 * @param {number} col номер столбца
 * @returns {string} имя столбца
 */
function col2A1(col) {
  let result = "";
  while (col > 0) {
    col--; // Excel использует 0-based индексацию
    result = String.fromCharCode(65 + (col % 26)) + result;
    col = Math.floor(col / 26);
  }
  return result;
}

/**
 * Полный адрес ячейки по номеру столбца и строки
 * @param {number} col номер столбца
 * @param {number} row номер строки
 * @returns {string} адрес ячейки (например, "A1", "B5", "AA10")
 */
function cell2A1(col, row) {
  return col2A1(col) + row.toString();
}

/**
 * Диапазон ячеек
 * @param {number} startCol начальный столбец
 * @param {number} startRow начальная строка
 * @param {number} endCol конечный столбец
 * @param {number} endRow конечная строка
 * @returns {string} диапазон (например, "A1:B5")
 */
function range2A1(startCol, startRow, endCol, endRow) {
  return `${col2A1(startCol)}${startRow}:${col2A1(endCol)}${endRow}`;
}

/**
 * Преобразовать float дату в дату
 * @param {number} date float дата
 * @returns {Date} дата
 */
function floatDateValueToDate(
  date,
  timeZoneOffset = 0
) {
  // Excel/Google Sheets использует 30 декабря 1899 как базовую дату
  // Создаем базовую дату в UTC, чтобы избежать проблем с часовыми поясами
  const baseDate = new Date(Date.UTC(1899, 11, 30)); // 30 декабря 1899 UTC
  const millisecondsPerDay = 24 * 60 * 60 * 1000;

  const days = Math.floor(date);
  const fractionalPart = date - days;

  // Добавляем дни к базовой дате
  const dateInMillis = days * millisecondsPerDay;

  // Преобразуем дробную часть в миллисекунды
  const timeInMillis = fractionalPart * millisecondsPerDay;

  const resultDate = new Date(baseDate.getTime() + dateInMillis + timeInMillis);

  const currentOffset = resultDate.getTimezoneOffset(); // Текущий часовой пояс в минутах
  console.log(currentOffset);
  const offsetDiff = timeZoneOffset * 60 + currentOffset; // Разница в минутах
  console.log(offsetDiff);

  resultDate.setMinutes(resultDate.getMinutes() - offsetDiff);

  return resultDate;
}

