/**
 * Удалить старые значения или получить строку, rrdid и дату для обновления.
 * @param {SpreadsheetApp.ActiveSpreadsheet.Sheet} sh лист книги.
 * @param {number} lastRow последняя строка на листе.
 * @param {number} minusDays True печать URL и OPTIONS запроса при выполнении, по умочанию false.
 * @param {number} lastDateColumn номер столбца "lastChangeDate".
 * @param {number} rrdidColumn номер столбца с rrdid, для getReportDetailByPeriod.
 * @param {boolean} sortedAz сортировка данных перед поиском даты, по умочанию false.
 * @param {boolean} clear удалить данные с найденной строки, по умочанию false.
 * @returns {object.<string, number>} dateFrom: dateFrom, numberRow: numberRow, rrdid: rrdid
 */
function getUpdateDateRowOrDeleteOld(
  sh,
  lastRow,
  minusDays,
  lastDateColumn,
  rrdidColumn,
  sortedAz = true,
) {
  const timeZone = CONFIG.settings.time.timeZone;
  const formatDate = CONFIG.formats.dateyyyy_MM_dd;

  if (sortedAz) {
    if (!sh.getFilter()) {
      sh.getRange(1, 1, sh.getMaxRows(), sh.getMaxColumns()).createFilter();
    }
    // сортировка данные от A-Z
    if (rrdidColumn) {
      sh.getFilter().sort(rrdidColumn, true).sort(lastDateColumn, true);
    } else {
      sh.getFilter().sort(lastDateColumn, true);
    }
    sh.getFilter().remove();
  }

  const checkDate = getCheckDate(minusDays);

  // let numberRow = serchDateRowLastIndex(sh, lastDateColumn, lastRow, checkDate);
  let numberRow = serchDateRowLastIndexOptimized(
    sh,
    lastDateColumn,
    lastRow,
    checkDate,
  );

  let dateFrom;
  if (!rrdidColumn && numberRow === 0) {
    // дата для обновления (первая в строке)
    dateFrom = Utilities.formatDate(
      new Date(sh.getRange(2, lastDateColumn).getValue()),
      timeZone,
      formatDate,
    );
  } else if (sortedAz && !rrdidColumn && numberRow !== 0) {
    // дата для обновления (найденная строка + 1 строка)
    dateFrom = Utilities.formatDate(
      new Date(sh.getRange(numberRow + 1, lastDateColumn).getValue()),
      timeZone,
      formatDate,
    );
  } else if (!sortedAz && !rrdidColumn && numberRow !== 0) {
    // дата для обновления (последняя в строке) с сортировкой массива
    let dates = sh
      .getRange(2, lastDateColumn, sh.getLastRow() - 1, 1)
      .getValues()
      .flat();
    let sorted = dates.slice().sort((a, b) => new Date(a) - new Date(b));
    dateFrom = Utilities.formatDate(
      new Date(sorted.pop().setDate(sorted.pop().getDate())),
      timeZone,
      formatDate,
    );
  }

  let rrdid;
  if (rrdidColumn) {
    if (numberRow === 0) {
      [[dateFrom, rrdid]] = sh.getRange(2, rrdidColumn - 1, 1, 2).getValues();
    } else {
      numberRow = lastRow;
      [[dateFrom, rrdid]] = sh
        .getRange(numberRow, rrdidColumn - 1, 1, 2)
        .getValues();

      dateFrom = Utilities.formatDate(new Date(dateFrom), timeZone, formatDate);

      if (!dateFrom || dateFrom === "1970-01-01")
        throw new Error(
          `Invalid date: ${dateFrom}.\nОчистите лист перед запуском скрипта.\n`,
        );

      console.log(
        `Дата запроса: ${dateFrom}\nRRDID: ${rrdid}\nНомер найденной строки: ${numberRow}`,
      );
    }
  }

  if (!rrdidColumn) {
    let lastDate;
    if (numberRow === 0)
      lastDate = new Date(sh.getRange(2, lastDateColumn).getValue());
    else lastDate = new Date(sh.getRange(numberRow, lastDateColumn).getValue());

    if (!dateFrom || dateFrom === "1970-01-01")
      throw new Error(
        `Invalid date: ${dateFrom}.\nОчистите лист перед запуском скрипта.\n`,
      );

    console.log(
      `Дата с которой удаляем данные: ${checkDate}, -${minusDays} ${getNoun(
        minusDays,
        "день",
        "дня",
        "дней",
      )} от текущей\n${
        numberRow > 0
          ? `После даты: ${lastDate}\n`
          : "⚠️ Дата не найдена, делаем перезапись.\n"
      }С строки: ${
        numberRow === 0 ? 2 : numberRow + 1
      }\nДата запроса: ${dateFrom}`,
    );
  }

  return { dateFrom, numberRow, rrdid };
}

/**
 * Полчуить дату для сверки.
 * @param {number} minusDays кол-во дней для перезаписи.
 * @returns {Date} дата для сверки.
 */
function getCheckDate(minusDays) {
  // дата minusDays дней от текущей
  let minusDay = new Date(Date.now() - minusDays * 24 * 60 * 60 * 1000); // минус сколько то дней
  const yy = minusDay.getFullYear();
  const mm = String(minusDay.getMonth() + 1).padStart(2, "0");
  const dd = String(minusDay.getDate()).padStart(2, "0");
  return new Date(`${yy}-${mm}-${dd}T00:00:00`);
}

/**
 * Найти номер строки с датой.
 * @param {SpreadsheetApp.ActiveSpreadsheet.Sheet} sh лист книги.
 * @param {number} lastDateColumn номер столбца "lastChangeDate".
 * @param {number} lastRow последняя строка на листе.
 * @param {Date} checkDate дата для сверки.
 * @returns {number} номер строки с датой
 */
const serchDateRowLastIndex = (sh, lastDateColumn, lastRow, checkDate) => {
  const values = sh.getRange(2, lastDateColumn, lastRow - 1, 1).getValues();
  const targetTimestamp = new Date(checkDate).getTime(); // Date.parse(checkDate); //
  const index = values.findLastIndex(
    (array) => new Date(array[0]).getTime() <= targetTimestamp,
  );
  if (index !== -1) return index + 2;
  else return 0;
};

/**
 * Найти номер строки с датой (оптимизированная версия).
 * @param {SpreadsheetApp.ActiveSpreadsheet.Sheet} sh лист книги.
 * @param {number} lastDateColumn номер столбца "lastChangeDate".
 * @param {number} lastRow последняя строка на листе.
 * @param {Date} checkDate дата для сверки.
 * @returns {number} номер строки с датой
 */
const serchDateRowLastIndexOptimized = (
  sh,
  lastDateColumn,
  lastRow,
  checkDate,
) => {
  // Валидация входных параметров
  if (!sh || !lastDateColumn || !lastRow || !checkDate) {
    console.warn("serchDateRowLastIndexOptimized: некорректные параметры");
    return 0;
  }

  // Проверяем, что есть данные для поиска
  if (lastRow <= 2) return 0;

  const targetTimestamp = new Date(checkDate).getTime();

  // Проверяем валидность даты
  if (isNaN(targetTimestamp)) {
    console.warn("serchDateRowLastIndexOptimized: некорректная дата");
    return 0;
  }

  try {
    // Получаем данные из диапазона
    const values = sh.getRange(2, lastDateColumn, lastRow - 1, 1).getValues();

    // Бинарный поиск для больших объемов данных (более эффективен)
    if (values.length > 100) {
      return binarySearchDateRow(values, targetTimestamp);
    }

    // Линейный поиск для небольших объемов
    const index = values.findLastIndex((array) => {
      const cellValue = array[0];
      if (!cellValue) return false; // Пропускаем пустые ячейки
      const cellTimestamp = new Date(cellValue).getTime();
      return !isNaN(cellTimestamp) && cellTimestamp <= targetTimestamp;
    });

    return index !== -1 ? index + 2 : 0;
  } catch (error) {
    console.error(
      "serchDateRowLastIndexOptimized: ошибка при работе с листом",
      error,
    );
    return 0;
  }
};

/**
 * Бинарный поиск строки с датой (для больших объемов данных).
 * @param {Array} values массив значений дат
 * @param {number} targetTimestamp целевая временная метка
 * @returns {number} номер строки
 */
const binarySearchDateRow = (values, targetTimestamp) => {
  let left = 0;
  let right = values.length - 1;
  let result = -1;

  while (left <= right) {
    const mid = Math.floor((left + right) / 2);
    const cellValue = values[mid][0];

    if (!cellValue) {
      // Если ячейка пустая, идем влево
      right = mid - 1;
      continue;
    }

    const cellTimestamp = new Date(cellValue).getTime();

    if (isNaN(cellTimestamp)) {
      // Если дата некорректная, идем влево
      right = mid - 1;
      continue;
    }

    if (cellTimestamp <= targetTimestamp) {
      result = mid;
      left = mid + 1; // Ищем последнее вхождение
    } else {
      right = mid - 1;
    }
  }

  return result !== -1 ? result + 2 : 0;
};

/**
 * Найти номер строки с датой.
 * @param {SpreadsheetApp.ActiveSpreadsheet.Sheet} sh лист книги.
 * @param {number} lastDateColumn номер столбца "lastChangeDate".
 * @param {number} lastRow последняя строка на листе.
 * @param {Date} checkDate дата для сверки.
 * @returns {number} номер строки с датой
 */
function serchDateRowFilter(sh, lastDateColumn, lastRow, checkDate) {
  const values = sh.getRange(2, lastDateColumn, lastRow - 1, 1).getValues();
  const targetTimestamp = new Date(checkDate).getTime(); //Date.parse(checkDate); //
  const index = values.filter(
    (array) => new Date(array[0]).getTime() <= targetTimestamp,
  ).length;
  if (index) return index + 1;
  else return 0;
}

function getUpdateDate({
  sheet,
  lastRow,
  startDate,
  daysMinus = 7,
  searchColumn = 4,
}) {
  let numberRow = lastRow;
  if (lastRow > 1) {
    const result = getUpdateDateRowOrDeleteOld(
      sheet,
      lastRow,
      daysMinus,
      searchColumn,
    );
    startDate = result?.dateFrom || startDate;
    numberRow = result?.numberRow || null;
  }

  return {
    numberRow,
    startDate,
  };
}

