      "Mozilla/5.0 (Macintosh; Intel Mac OS X 12_6) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/15.6 Safari/605.1.15",
    ],
    edge: [
      "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/107.0.0.0 Safari/537.36 Edg/107.0.1418.62",
    ],
    opera: [
      "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/107.0.0.0 Safari/537.36 OPR/93.0.4585.64",
    ],
  };

  // Получить массив агентов по браузеру
  if (browser) {
    var agents = userAgents[String(browser).toLowerCase()];
    if (agents && agents.length) {
      return agents[Math.floor(Math.random() * agents.length)];
    }
    // Если не найден — вернуть chrome по умолчанию
    var chromeAgents = userAgents.chrome;
    return chromeAgents[Math.floor(Math.random() * chromeAgents.length)];
  }

  // Если не указан браузер — случайный из всех
  var allAgents = [];
  Object.keys(userAgents).forEach(function (key) {
    allAgents = allAgents.concat(userAgents[key]);
  });
  return allAgents[Math.floor(Math.random() * allAgents.length)];
}

