/**
 * Получение диапазонов для извлечения ссылки на basket
 * @return {Array<Object>}
 */
function getBasketData() {
  // URL и заголовки
  const url = "https://cdn.wbbasket.ru/api/v3/upstreams";
  const headers = {
    "Content-Type": "application/json;charset=utf-8",
    Accept: "*/*",
    "User-Agent": getRandomUserAgent(), // реализуйте эту функцию отдельно
  };

  // Выполняем запрос
  const response = UrlFetchApp.fetch(url, {
    headers: headers,
    muteHttpExceptions: true,
  });

  if (!response.getResponseCode() === 200) {
    console.error("Error fetching getBasketData:", response.getContentText());
    return;
  }

  // Парсим ответ
  const json = JSON.parse(response.getContentText());
  const result = [];

  // Безопасно обрабатываем вложенные объекты
  const origin = json && json.origin;
  const routeMap = origin && origin.mediabasket_route_map;

  if (Array.isArray(routeMap)) {
    routeMap.forEach(function (media_baskets) {
      if (media_baskets.hosts && Array.isArray(media_baskets.hosts)) {
        media_baskets.hosts.forEach(function (hosts) {
          result.push({
            domain: "//" + (hosts.host || ""),
            min: hosts.vol_range_from,
            max: hosts.vol_range_to,
            num: String(
              (hosts.host.match(/basket-(\d+)\.wbbasket\.ru/) || [])[1],
            ),
          });
        });
      }
    });
  }

  return result;
}

function getUrlGenerator() {
  let basketData;
  try {
    basketData = getBasketData();
  } catch (error) {
    console.warn("Error getBasketData");
  }
  return basketData && basketData?.length
    ? new GenerateUrl({ basketData })
    : new GenerateUrl();
}

class GenerateUrl {
  constructor({ nmId = 0, photoSize, photoNumber, format, basketData } = {}) {
    if (!GenerateUrl.isValidNmId(nmId)) {
      throw new Error("Invalid nmId value");
    }

    this.nmId = parseInt(nmId, 10);
    this.size =
      {
        big: "big",
        c246x328: "c246x328",
        c516x688: "c516x688",
        hq: "hq",
        square: "square",
        tm: "tm",
      }[photoSize] || "c246x328";
    this.number = photoNumber || 1;
    this.format = format || "webp";
    this.basketData = basketData || null;
  }

  static isValidNmId(nmId) {
    return typeof nmId === "number" && nmId >= 0;
  }

  static getVol(nmId) {
    // const vol = ~~(this.nmId / 1e5);
    return Math.floor(nmId / 1e5);
  }

  static getPart(nmId) {
    // const part = ~~(this.nmId / 1e3);
    return Math.floor(nmId / 1e3);
  }

  getBasket(vol) {
    if (this.basketData && this.basketData?.length) {
      for (var i = 0; i < this.basketData.length; i++) {
        var item = this.basketData[i];
        if (item.min <= vol && vol <= item.max) {
          return item.domain;
        }
      }
      throw new Error(`Invalid vol: ${vol} value`);
    }

    // стандартная логика
    const ranges = [
      143, 287, 431, 719, 1007, 1061, 1115, 1169, 1313, 1601, 1655, 1919, 2045,
      2189, 2405, 2621, 2837, 3053, 3269, 3485, 3701, 3917, 4133, 4349, 4565,
      4877, 5189, 5501, 5813, 6125, 6437, 6749, 7061, 7373, 7685, 7997, 8309,
      8741, 9173, 9605, 10373, 11141, 11909, 12677, 13445, 14213,
    ];

    for (let i = 0; i < ranges.length; i++) {
      if (vol <= ranges[i])
        return `//basket-${(i + 1).toString().padStart(2, "0")}.wbbasket.ru`;
    }
    return "//basket-41.wbbasket.ru";
  }

  _host() {
    try {
      const response = UrlFetchApp.fetch(
        "https://cdn.wbbasket.ru/api/v3/upstreams",
        {
          muteHttpExceptions: true,
          headers: {
            "Content-Type": "application/json",
            "User-Agent":
              "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/89.0.142.86 Safari/537.36",
          },
        },
      );

      if (response.getResponseCode() !== 200) {
        console.error("Error fetching data:", response.getContentText());
        return [];
      }

      const responseJson = JSON.parse(response.getContentText());

      // console.log(JSON.stringify(responseJson, null, 2));

      const mediabasketRouteMap = responseJson?.origin?.mediabasket_route_map;
      if (!mediabasketRouteMap) return [];
      const nmidData = mediabasketRouteMap.flatMap((mediabaskets) =>
        mediabaskets.hosts.map((hosts) => ({
          domain: hosts.host,
          maxVol: hosts.vol_range_to,
        })),
      );

      let condition = `{`;
      let lastItem = 1;
      nmidData.forEach(({ maxVol }, i) => {
        condition += `if (id <= ${maxVol}) return "${(i + 1)
          .toString()
          .padStart(2, "0")}";`;
        lastItem++;
      });

      condition += `return "${lastItem.toString().padStart(2, "0")}";}`;

      return { condition, nmidData };
    } catch (error) {
      console.error("Error fetching data:", error.stack);
      return [];
    }
  }

  getBaseUrl(nmId) {
    if (nmId && GenerateUrl.isValidNmId(nmId)) this.nmId = parseInt(nmId, 10);
    const vol = GenerateUrl.getVol(this.nmId);
    const part = GenerateUrl.getPart(this.nmId);
    return `https:${this.getBasket(vol)}/vol${vol}/part${part}/${this.nmId}`;
  }

  image() {
    // ссылка на изображение
    return `${this.getBaseUrl()}/images/${this.size}/${this.number}.${
      this.format
    }`;
  }

  cardLink() {
    // ссылка на карточку
    return `https://www.wildberries.ru/catalog/${this.nmId}/detail.aspx`;
  }

  hyperlink(nmId) {
    // формула перехода на карточку по фото
    if (nmId && GenerateUrl.isValidNmId(nmId)) this.nmId = parseInt(nmId, 10);
    else throw new Error(`Некорректный nmId"${nmId} для генерации ссылки`);
    return `=HYPERLINK("${this.cardLink()}";IMAGE("${this.image()}"))`;
  }

  card() {
    // карточка - поля описания товара
    return `${this.getBaseUrl()}/info/ru/card.json`;
  }

  sellerByNmId(nmId) {
    // данные селлера по артикулу
    if (nmId && GenerateUrl.isValidNmId(nmId)) this.nmId = parseInt(nmId, 10);
    else throw new Error(`Некорректный nmId"${nmId} для генерации ссылки`);
    return `${this.getBaseUrl()}/info/sellers.json`;
  }

  seller(sellerId) {
    // данные селлера по sellerId
    return `https://static-basket-01.wbbasket.ru/vol0/data/supplier-by-id/${sellerId}.json`;
  }

  priceHistory(nmId) {
    // история изменения цен 12 дней
    if (nmId && GenerateUrl.isValidNmId(nmId)) this.nmId = parseInt(nmId, 10);
    else throw new Error(`Некорректный nmId"${nmId} для генерации ссылки`);
    return `${this.getBaseUrl(this.nmId)}/info/price-history.json`;
  }
}

/**
 * Создание ссылки и вставка изображений
 * @param {SpreadsheetApp.Sheet} sheet лист книги
 * @param {number} wbIdColumn столбец с nmId Wildberries
 * @param {number} pastColumn столбец для вставки ссылок на изображения
 */
function img(sheet, wbIdColumn, pastColumn, debug = false) {
  const data = sheet.getDataRange().getValues();
  const wbIdColumnIndex = wbIdColumn - 1;

  const urlGenerator = getUrlGenerator();
  if (debug) console.log(JSON.stringify(urlGenerator, null, 2));
  // const urlGenerator = new GenerateUrl({ basket_dat: basketData });

  const result = [["Фото"]];
  data.map((r, i) => {
    if (i > 0) {
      if (
        r[wbIdColumnIndex] &&
        typeof r[wbIdColumnIndex] === "number" &&
        r[wbIdColumnIndex] > 0
      ) {
        result.push([urlGenerator.hyperlink(r[wbIdColumnIndex])]);
      } else {
        result.push([""]);
      }
    }
  });

  if (debug) console.log(result);

  sheet.getRange(1, pastColumn, result.length, 1).setValues(result);
}

function settingsStat(report = false) {
  const main = CONFIG.settings.settings.stat;
  const sheet = setSheet(main.sheet);

  if (report) {
    const valueDateFrom = sheet.getRange(main.reportDateFrom).getValue();
    const valueDateTo = sheet.getRange(main.reportDateTo).getValue();

    if (valueDateFrom || valueDateTo) {
      return {
        dateFrom: valueDateFrom ? dateStrToFormatDate(valueDateFrom) : null,
        dateTo: valueDateTo ? dateStrToFormatDate(valueDateTo) : null,
      };
    }
  } else {
    const date = sheet.getRange(main.dateFrom).getValue();
    if (date) return dateStrToFormatDate(date);
  }

  return;
}

/**
 * Retrieves the settings range from the specified function in the configuration.
 *
 * @param {string} func - The function name to retrieve the range from.
 * @param {boolean} [str=true] - Whether to convert the date values to str format.
 * @return {Object} An object containing the dateFrom, dateTo, and settings values from the range.
 */
function settingsMain({
  funcName,
  range,
  row,
  str = true,
  custom = false,
  sheetName,
}) {
  const main = CONFIG.settings.settings.main;
  const sheet = setSheetNew(sheetName || main.sheet);

  if (!(funcName in main.range)) {
    return;
  }

  range = row
    ? main.range[funcName].replace(/\d+/g, row)
    : range || main.range[funcName];

  if (context?.debug) console.log(`settingsMain range:`, range);

  if (custom) {
    const settings = range.includes(":")
      ? sheet
          .getRange(range)
          .getValues()
          .map((item) => {
            return item.map((e) => {
              return e instanceof Date && str ? dateStrToFormatDate(e) : e;
            });
          })
      : sheet.getRange(range).getValue();

    // Отладочная информация
    if (context?.debug)
      console.log(`settingsMain для ${funcName} custom:`, {
        range,
        settings,
      });

    return {
      settings,
    };
  }

  const [[dateFrom, dateTo, settings]] = sheet.getRange(range).getValues();

  // Отладочная информация
  if (context?.debug)
    console.log(`settingsMain для ${funcName}:`, {
      range,
      dateFrom,
      dateTo,
      settings,
    });

  return {
    dateFrom: dateFrom && str ? dateStrToFormatDate(dateFrom) : dateFrom,
    dateTo: dateTo && str ? dateStrToFormatDate(dateTo) : dateTo,
    settings,
  };
}

