/**
 * Calculate delay based on requests per second, requests per minute, and request in seconds.
 *
 * @param {Object} param - Destructured object with optional parameters:
 * @param {number} [param.requestsPerSecond] - The number of requests per second (default is 1)
 * @param {number} [param.requestsPerMinute] - The number of requests per minute (default is 1)
 * @param {number} [param.requestInSeconds] - The request in seconds (default is 1)
 * @return {Object} Object containing calculated delay values: inSeconds, perSecond, perMinutes
 */
function calculateDelay({
  requestsPerSecond = 1,
  requestInSeconds = 1,
  requestsPerMinute = 1,
} = {}) {
  const delayPerSecond = 1000 / Number(requestsPerSecond); // * 1000;
  const delaInXSeconds = 1000 * Number(requestInSeconds);
  const delayPerMinutes = (60 * 1000) / Number(requestsPerMinute); // * 60 * 1000;
  return {
    delayPerSecond,
    delaInXSeconds,
    delayPerMinutes,
  };
}

/**
 * Converts a string date value to a Date object and then formats it according to the specified format.
 *
 * @param {string} dateValue - The string date value to be converted.
 * @param {string} [timeZone="Europe/Moscow"] - The timezone to use for conversion.
 * @param {string} [format="yyyy-MM-dd"] - The date format to use for conversion.
 * @return {string} The formatted date value.
 */
function dateStrToFormatDate(
  dateValue,
  format = "yyyy-MM-dd",
  timeZone = "Europe/Moscow",
) {
  if (!dateValue) return null;

  // Если это не объект даты, то преобразуем в объект
  if (!(dateValue instanceof Date)) {
    if (typeof dateValue === "number" || typeof dateValue === "string") {
      dateValue = new Date(dateValue);
    } else {
      return null; // Если не можем преобразовать, возвращаем null
    }
  }

  return Utilities.formatDate(dateValue, timeZone, format);
}

/**
 * @param { string|Date } date
 * @param { Object } options
 * @param { number } [options.years=0]
 * @param { number } [options.months=0]
 * @param { number } [options.days=0]
 * @param { number } [options.hours=0]
 * @param { number } [options.minutes=0]
 * @example Utilities.formatDate(offsetDate(new Date(), { days: -14 }), "Europe/Moscow", "yyyy-MM-dd")
 * @returns { Date }
 */
function offsetDate(
  date,
  { years = 0, months = 0, days = 0, hours = 0, minutes = 0 },
) {
  const newDate = new Date(date);
  if (years !== 0) newDate.setFullYear(newDate.getFullYear() + years);
  if (months !== 0) newDate.setMonth(newDate.getMonth() + months);
  if (days !== 0) newDate.setDate(newDate.getDate() + days);
  if (hours !== 0) newDate.setHours(newDate.getHours() + hours);
  if (minutes !== 0) newDate.setMinutes(newDate.getMinutes() + minutes);
  return newDate;
}

