/**
 * Decodes a JWT token and returns the decoded payload as a JavaScript object.
 *
 * @param {string} token - The JWT token to decode.
 * @return {Object} - The decoded payload of the JWT token.
 */
function decodedWildberriesJwtTokenFetch(token) {
  // Функция для парсинга text/x-component формата
  function parseTextComponent(responseText) {
    try {
      // Убираем лишние пробелы и переносы строк
      const cleanText = responseText.trim();

      // Пытаемся найти структуру массива
      if (cleanText.startsWith("[") && cleanText.endsWith("]")) {
        // Это массив, пробуем парсить как JSON
        return JSON.parse(cleanText);
      }

      // Если это не JSON, парсим построчно
      const lines = cleanText.split("\n").filter((line) => line.trim());
      const result = [];

      for (let line of lines) {
        line = line.trim();
        if (line.includes(":")) {
          const [index, ...dataParts] = line.split(":");
          const data = dataParts.join(":").trim();

          try {
            // Пытаемся парсить как JSON
            const parsedData = JSON.parse(data);
            result[parseInt(index)] = parsedData;
          } catch (e) {
            // Если не JSON, сохраняем как строку
            result[parseInt(index)] = data;
          }
        }
      }

      return result;
    } catch (error) {
      console.error("Ошибка парсинга text/x-component:", error);
      return responseText; // Возвращаем исходный текст если не удалось распарсить
    }
  }

  const response = UrlFetchApp.fetch("https://dev.wildberries.ru/jwt", {
    method: "post",
    headers: {
      "content-type": "text/plain;charset=UTF-8",
      "next-action": "7d1384707d939c7b33467afa23360f7fc50d41ce",
      "user-agent":
        "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/139.0.0.0 Safari/537.36",
    },
    payload: JSON.stringify([token]),
    muteHttpExceptions: true,
  });

  return parseTextComponent(response.getContentText())[1];
}

