      en: "Read and write access",
    },
    tokenDeleted: {
      ru: "Токен удален",
      en: "Token deleted",
    },
    tokenExpired: {
      ru: "Срок действия токена истек",
      en: "Token expired",
    },
    // Типы токенов по полю acc
    tokenTypes: {
      1: {
        ru: "Базовый",
        en: "Basic",
      },
      2: {
        ru: "Тестовый",
        en: "Test",
      },
      3: {
        ru: "Персональный",
        en: "Personal",
      },
      4: {
        ru: "Сервисный",
        en: "Service",
      },
    },
  };

  /**
   * Decodes a JWT token and returns the decoded payload as a JavaScript object.
   *
   * @param {string} token - The JWT token to decode.
   * @return {Object} - The decoded payload of the JWT token.
   */
  const jwtDecode = (token) => {
    return JSON.parse(
      Utilities.newBlob(
        Utilities.base64Decode(token.split(".")[1]),
      ).getDataAsString(),
    );
  };

  /**
   * Calculates the lifetime of a token based on a given Unix timestamp.
   *
   * @param {number|null} myUnixTimestamp - The Unix timestamp to calculate the token's lifetime from. If null, an empty string is returned.
   * @return {string} The string representation of the token's lifetime.
   */
  const tokenLifeTime = (myUnixTimestamp) => {
    if (myUnixTimestamp == null) return "";
    const te = new Date(myUnixTimestamp * 1000); // действует до
    return te.toString();
  };

  /**
   * Determines the token type based on the acc field.
   *
   * @param {number} acc - The acc field from the token.
   * @param {string} lng - The language code.
   * @return {string} The token type in the specified language.
   */
  const getTokenType = (acc, lng) => {
    const tokenType = languageDictionary.tokenTypes[acc];
    if (!tokenType) {
      return lng === "ru" ? "Базовый" : "Basic";
    }
    return tokenType[lng];
  };

  /**
   * Calculates the scopes based on the given scope number and language.
   * Improved version with better maintainability and performance.
   *
   * @param {number} s - The scope number.
   * @param {string} lng - The language code.
   * @return {Array<string>} An array of scopes based on the scope number and language.
   */
  const checkScope = (s, lng) => {
    // Маппинг битовых позиций на ключи словаря согласно официальной документации
    const scopeMapping = [
      { bit: 0, key: "testContour" }, // Специальный случай для бита 0 (не в документации, но используется в коде)
      { bit: 1, key: "content" }, // Доступ к категории Контент
      { bit: 2, key: "contentanalytics" }, // Доступ к категории Аналитика
      { bit: 3, key: "discountsandprices" }, // Доступ к категории Цены и скидки
      { bit: 4, key: "marketplace" }, // Доступ к категории Маркетплейс
      { bit: 5, key: "statistics" }, // Доступ к категории Статистика
      { bit: 6, key: "advert" }, // Доступ к категории Продвижение
      { bit: 7, key: "questionsandfeedback" }, // Доступ к категории Вопросы и отзывы
      // Бит 8 - не используется согласно документации
      { bit: 9, key: "buyerchat" }, // Доступ к категории Чат с покупателями
      { bit: 10, key: "supplies" }, // Доступ к категории Поставки
      { bit: 11, key: "returns" }, // Доступ к категории Возвраты покупателями
      { bit: 12, key: "documents" }, // Доступ к категории Документы
      { bit: 13, key: "finance" }, // Доступ к категории Финансы
    ];

    const scopes = [];

    // Проверяем каждый бит и добавляем соответствующий scope
    scopeMapping.forEach(({ bit, key }) => {
      if (bit === 0) {
        // Специальная обработка для бита 0
        if (s === 0) {
          scopes.push(languageDictionary[key][lng]);
        }
      } else {
        // Проверяем бит сдвигом
        if ((s >> bit) % 2 !== 0) {
          scopes.push(languageDictionary[key][lng]);
        }
      }
    });

    // Если нет scopes, возвращаем пустой массив
    if (scopes.length === 0) {
      return scopes;
    }

    // Добавляем информацию о правах доступа (бит 30)
    const accessRights =
      (s >> 30) % 2 !== 0
        ? languageDictionary.tokenReadOnly[lng]
        : languageDictionary.tokenReadWrite[lng];

    scopes.push(accessRights);

    return scopes;
  };

  let decodedToken = "";

  // декодируем токен, получаем полузную нагрузку токена
  try {
    decodedToken = jwtDecode(token);
  } catch (error) {
    throw new Error("Invalid token: impossible to decode the token");
  }

  //получаем время жизни токена
  let timeEnd;
  try {
    let times = tokenLifeTime(decodedToken.exp);
    timeEnd = times;
    if (timeEnd == "")
      throw new Error(
        "Invalid token: impossible to determine the lifetime of the token",
      );
  } catch (error) {
    throw new Error(
      "Invalid token: impossible to determine the lifetime of the token",
    );
  }

  if (get_expiration)
    return {
      is_expired: new Date(timeEnd) < new Date(),
      to: new Date(timeEnd).toLocaleString(
        language === "ru" ? "ru-RU" : "en-EN",
      ),
    };

  // получаем к каким категориям апи есть доступ по токену
  let scopes, rw;
  try {
    scopes = checkScope(decodedToken["s"], language);
    if (scopes.length == 0)
      throw new Error(
        "Invalid token: impossible to determine the scope of the token",
      );

    rw = scopes.pop();
  } catch (error) {
    throw new Error(
      "Invalid token: impossible to determine the scope of the token",
    );
  }

  // Определяем тип токена по полю acc
  const tokenType = getTokenType(decodedToken.acc, language);

  return {
    "ID токена:": decodedToken.id,
    "ID продавца:": decodedToken.sid,
    "Тип токена:": tokenType,
    "Действует до:": new Date(timeEnd).toLocaleString(
      language === "ru" ? "ru-RU" : "en-EN",
    ),
    "Чтение / Запись:": rw,
    "Тестовый (песочница):": decodedToken.t,
    "Доступные категории:\n": scopes
      .map((el, index) => (index > 0 ? `* ${el}` : `* ${el}`))
      .join("\n"),
  };
}

