function checkApiKey({ service, apiKey, lang = "ru" } = {}) {
  const storage =
    context?.storage ||
    (service && setStorage({ service, serviceType: context?.serviceType })) ||
    null;

  if (!apiKey && !storage) {
    throw new Error(
      "В функции не указан service || const WB.context = { service: PropertiesService }",
    );
  }

  apiKey = apiKey || storage.getProperty("MultipleAccess");

  // console.log(
  //   "checkApiKey apiKey:",
