/**
 * Функция для отладочного логирования различных типов данных
 *
 * @param {string} [message] - сообщение перед выводом данных (например, 'Ответ API:', 'Обработанные данные:')
 * @param {*} data - данные для логирования (массив массивов, массив объектов, объект, null, undefined, пустой объект/массив)
 * @param {string} [key] - ключ для доступа к вложенным данным (например, 'response.items')
* @param {number} [maxItems=2] - максимальное количество элементов для вывода
 * @param {string} [label] - метка для лога

 */
function debugLog(
  message = "Ответ:\n",
  data,
  maxItems = 1,
  key = null,
  label = "DEBUG",
) {
  if (!context?.debug) return;

  try {
    console.log(`\n=== ${label} ===`);

    // Если указан ключ, извлекаем данные по ключу
    let targetData = data;
    if (key) {
      const keys = key.split(".");
      for (const k of keys) {
        if (targetData && typeof targetData === "object" && k in targetData) {
          targetData = targetData[k];
        } else {
          console.log(`Ключ '${key}' не найден в данных`);
          console.log("Доступные ключи:", Object.keys(data || {}));
          return;
        }
      }
    }

    // Проверяем на null/undefined
    if (targetData === null) {
      console.log("null");
      return;
    }

    if (targetData === undefined) {
      console.log("undefined");
      return;
    }

    // Проверяем тип данных
    if (!Array.isArray(targetData) && typeof targetData !== "object") {
      console.log("Примитивное значение:", targetData);
      return;
    }

    // Пустой массив или объект
    if (Array.isArray(targetData) && targetData.length === 0) {
      console.log("Пустой массив: []");
      return;
    }

    if (!Array.isArray(targetData) && Object.keys(targetData).length === 0) {
      console.log("Пустой объект: {}");
      return;
    }

    // Массив массивов
    if (
      Array.isArray(targetData) &&
      targetData.length > 0 &&
      Array.isArray(targetData[0])
    ) {
      console.log(
        `${message} массив массивов (${
          targetData.length
        } элементов, показываем первые ${Math.min(
          maxItems,
          targetData.length,
        )}):`,
      );
      const itemsToShow = targetData.slice(0, maxItems);
      itemsToShow.forEach((item, index) => {
        console.log(`[${index}]:`, item);
      });
      return;
    }

    // Массив объектов
    if (
      Array.isArray(targetData) &&
      targetData.length > 0 &&
      typeof targetData[0] === "object" &&
      !Array.isArray(targetData[0])
    ) {
      const itemsToShow = targetData.slice(0, maxItems);
      console.log(
        `${message} массив объектов (${targetData.length} элементов, показываем первые ${itemsToShow.length}):`,
      );
      console.log(JSON.stringify(itemsToShow, null, 2));
      return;
    }

    // Обычный массив
    if (Array.isArray(targetData)) {
      console.log(
        `${message} массив (${
          targetData.length
        } элементов, показываем первые ${Math.min(
          maxItems,
          targetData.length,
        )}):`,
      );
      const itemsToShow = targetData.slice(0, maxItems);
      itemsToShow.forEach((item, index) => {
        console.log(`[${index}]:`, item);
      });
      return;
    }

    // Объект
    if (typeof targetData === "object") {
      console.log(`${message} объект:`);
      console.log(JSON.stringify(targetData, null, 2));
      return;
    }

    // Fallback
    console.log("Неизвестный тип данных:", targetData);
  } catch (error) {
    console.error("Ошибка в debugLog:", error.message);
    console.log("Исходные данные:", data);
    if (key) {
      console.log("Ключ:", key);
    }
  }
}

/**
 * Создает файл в Google Drive пользователя для отладки
 * @param {string} name - Имя файла (без расширения)
 * @param {*} data - Данные для сохранения
 * @param {string} type - Тип файла (json или txt)
 * @param {boolean} [raw=false] - Если true, сохраняет данные в сыром виде (только для json)
 * @param {string} folderId - ID папки (опционально, по умолчанию корневая папка)
 */
function debugSaveFileToDrive(name, data, type = "json", raw, folderId = null) {
  if (!context?.requestLog) return;
  try {
    if (type === "json") {
      saveAsJSON(name, data, raw, folderId);
    } else if (type === "txt") {
      saveAsTxt(name, data, folderId);
    } else {
      throw new Error(`Неизвестный тип файла: ${type}`);
    }
  } catch (error) {
    console.error("Ошибка создания файла:", error);
    throw new Error(
      `Не удалось создать файл ${name}.${type}: ${error.message}`,
    );
  }
}

