function newOrdersBot(options) {
  const { service, botToken, sendTo, apiKey, requestLog } = options;

  const ordersList = Properties.init(service, "ordersNewList");
  const ordersCall = Properties.init(service, "ordersCall");
  // const botToken = Properties.init(service, "bot").get()?.["token"];
  // const admins = Properties.init(service, "bot").get()?.["admins"];

  const Bot = TGbot.bot({ botToken });

  const dateFromNow = getTodaysDate_();

  const call = ordersCall.get();

  if (!call || call.dateFrom !== dateFromNow) {
    ordersList.delete();
    ordersCall.put({ dateFrom: dateFromNow });
  }

  const dateFrom = ordersCall.get().dateFrom;

  const orders = new Statistics({ apiKey, requestLog }).orders({
    flag: 1,
    dateFrom,
    json: true,
  });

  console.log(`Всего заказов за ${dateFrom} >>>`, orders.length);

  const ordersListTmp = {};
  if (orders.length > 0) {
    orders.forEach((order) => {
      const { srid, gNumber } = order;

      if (!ordersList.has(srid)) {
        console.log("New >>>", srid);
        const ordersListData = processOrderData_(order);
        ordersListTmp[gNumber] = ordersListTmp[gNumber]
          ? [...ordersListTmp[gNumber], ordersListData]
          : [ordersListData];
        ordersList.add({ [srid]: true });
      }
    });

    const ordersGroup = Object.values(ordersListTmp);

    if (ordersGroup.length > 0) {
      ordersGroup.forEach((order) => {
        let text = generateOrderText(order);
        // console.log(text);
        sendTo.forEach((chat_id) => {
          Bot.sendMessage({ chat_id, text });
        });
      });
    }
  }
}

function processOrderData_(order) {
  const {
    date,
    warehouseName,
    supplierArticle,
    nmId,
    barcode,
    subject,
    brand,
    techSize,
    isCancel,
    cancelDate,
    orderType,
    gNumber,
    finishedPrice,
  } = order;
  const dateTime = Utilities.formatDate(
    new Date(date),
    Session.getScriptTimeZone(),
    "yyyy-MM-dd HH:mm"
  );
  return {
    gNumber,
    dateTime,
    warehouseName,
    supplierArticle,
    nmId,
    barcode,
    subject,
    brand,
    techSize,
    isCancel,
    cancelDate,
    orderType,
    finishedPrice,
  };
}

