      techSize,
      brand,
      isCancel,
      cancelDate,
      finishedPrice,
    }) => {
      // if (!isCancel && cancelDate === "0001-01-01T00:00:00") {
      total += finishedPrice;
      const revenue = new Intl.NumberFormat("ru-RU", {
        style: "currency",
