/**
 * Оптимизированная версия функций для работы с Google Sheets
 * Основные улучшения:
 * - Параллельное выполнение batchUpdate запросов
 * - Улучшенная обработка ошибок
 * - Более эффективное использование памяти
 */

/**
 * Оптимизированная функция добавления данных в лист
 * @param {Object} options - параметры функции
 * @param {number} options.fromRow - начальная строка
 * @param {number} options.lastRow - последняя строка
 * @param {Object} options.sheet - объект листа
 * @param {Array} options.result - данные для вставки
 * @param {boolean} options.api - использовать API
 * @param {boolean} options.raw - сырые данные
 * @param {boolean} options.setHead - установить заголовки
 * @param {string} options.script - скрипт
 * @param {number} options.start - начальная позиция
 * @param {boolean} options.debug - отладка
 * @returns {Promise|Object} результат выполнения
 */
function addDataToSheetOptimized(options) {
  const {
    fromRow,
    lastRow,
    sheet,
    result,
    api,
    raw,
    setHead = true,
    script,
    start,
    debug = context?.debug,
  } = options;

  // Валидация входных данных
  if (!result || !Array.isArray(result) || result.length === 0) {
    throw new Error("result должен быть непустым массивом");
  }

  if (!sheet) {
    throw new Error("sheet обязателен");
  }

  if (setHead && fromRow <= 1) {
    if (debug) console.log(`setSheetHead: true`);
    setSheetHead(sheet);
  }

  // Простой случай без API
  if (!api) {
    return sheet
      .getRange(lastRow + 1, 1, result.length, result[0].length)
      .setValues(result);
  }

  const chunkSize = getChunkSize(result);

  if (debug) {
    console.log(`Данные: ${result.length} строк, chunkSize: ${chunkSize}`);
  }

  const spreadsheetId = sheet.getParent().getId();
  // const sheetId = sheet.getSheetId();
  const sheetName = sheet.getName();
  const startRow = fromRow === -1 ? 1 : fromRow === 0 ? 2 : fromRow + 1;

  // Для больших объемов данных используем параллельную обработку
  if (result.length > chunkSize * 2) {
    return batchUpdateParallel({
      result,
      chunkSize,
      spreadsheetId,
      // sheetId,
      sheetName,
      startRow,
      lastRow,
      sheet,
      raw,
      // setHead,
      debug,
    });
  } else {
    const rangeA1Notation = getRangeA1NotationApiV4(sheet, result, startRow);
    return updateExtra({
      result,
      spreadsheetId,
      // sheetId,
      sheetName,
      startRow,
      lastRow,
      sheet,
      raw,
      // setHead,
      rangeA1Notation,
      script,
      start,
      debug,
    });
  }
}

/**
 * Параллельная обработка batchUpdate запросов
 * @param {Object} params - параметры
 * @returns {Promise} результат выполнения
 */
function batchUpdateParallel(params) {
  const {
    result,
    chunkSize,
    spreadsheetId,
    // sheetId,
    sheetName,
    startRow,
    lastRow,
    sheet,
    raw,
    // setHead,
    debug,
  } = params;

  // const spreadsheetId = sheet.getParent().getId();
  // // const sheetId = sheet.getSheetId();
  // const sheetName = sheet.getName();
  // const startRow = fromRow === -1 ? 1 : fromRow === 0 ? 2 : fromRow + 1;

  // if (setHead && fromRow <= 1) setSheetHead(sheet);

  // updateSheetRange(
  //   { spreadsheetId, sheetId, sheetName },
  //   {
  //     rowCount: sheet.getMaxRows() + result.length,
  //     columnCount: sheet.getMaxColumns(),
  //     frozenRowCount: 1,
  //   }
  // );

  safeBatchUpdate(sheet, result, startRow, lastRow, debug);

  // Создаем массив промисов для параллельного выполнения
  const promises = [];
  let currentRow = startRow;

  // Разбиваем данные на чанки и создаем промисы
  for (let i = 0; i < result.length; i += chunkSize) {
    const chunk = result.slice(i, i + chunkSize);
    const chunkLength = chunk.length;
    const endCol = chunk[0].length;
    const endRow = currentRow + chunkLength - 1;
    const range = `'${sheetName}'!${range2A1(1, currentRow, endCol, endRow)}`;

    if (debug) {
      console.log(
        `Создание запроса для диапазона: ${range}, строк: ${chunkLength}`
      );
    }

    // Создаем промис для каждого чанка
    const promise = new Promise((resolve, reject) => {
      try {
        const response = Sheets.Spreadsheets.Values.batchUpdate(
          {
            valueInputOption: raw ? "RAW" : "USER_ENTERED",
            data: [
              {
                range: range,
                values: chunk,
                majorDimension: "ROWS",
              },
            ],
          },
          spreadsheetId
        );
        resolve({
          range: range,
          rows: chunk.length,
          response: response,
        });
      } catch (error) {
        reject({
          range: range,
          error: error,
          rows: chunk.length,
        });
      }
    });

    promises.push(promise);
    currentRow += chunk.length;
  }

  // Выполняем все запросы параллельно
  return Promise.allSettled(promises)
    .then((results) => {
      const successful = results.filter((r) => r.status === "fulfilled").length;
      const failed = results.filter((r) => r.status === "rejected").length;

      if (debug) {
        console.log(
          `Запросы завершены: успешно ${successful}, с ошибками ${failed}`
        );
      }

      // Если есть ошибки, логируем их
      if (failed > 0) {
        const errors = results
          .filter((r) => r.status === "rejected")
          .map((r) => r.reason);

        console.error("Ошибки при выполнении batchUpdate:", errors);

        // Можно выбрать стратегию: выбросить ошибку или продолжить
        if (failed > successful) {
          throw new Error(
            `Критическое количество ошибок: ${failed} из ${results.length}`
          );
        }
      }

      return {
        totalChunks: results.length,
        successful: successful,
        failed: failed,
        totalRows: result.length,
      };
    })
    .catch((error) => {
      console.error("Критическая ошибка в batchUpdateParallel:", error);
      throw error;
    });
}

function safeBatchUpdate(sheet, result, startRow, lastRow, debug = false) {
  const maxRows = sheet.getMaxRows();
  const endRow = startRow + result.length - 1;

  const rowsToInsert = Math.max(0, endRow - maxRows);

  if (debug)
    console.log({
      startRow,
      lastRow,
      maxRows,
      endRow,
      rowsToInsert,
    });

  // Если данных больше чем строк на листе - добавляем строки
  if (endRow > maxRows) {
    const rowsToInsert = endRow - maxRows;
    if (debug) console.log(`Добавление строк: ${rowsToInsert}`);
    sheet.insertRowsAfter(maxRows, rowsToInsert);
  }
  // else {
  //   if (debug)
  //     console.log(
  //       `Удаление строк: ${endRow} - ${maxRows} = ${maxRows - endRow}`
  //     );
  //   sheet.deleteRows(endRow, maxRows - endRow);
  // }

  // if (rowsToInsert > 0) {
  //   if (debug) console.log(`Добавление строк: ${rowsToInsert}`);
  //   sheet.insertRowsAfter(maxRows, rowsToInsert);
  // }

  // Теперь безопасно делаем batchUpdate
  return true;
}

