/**
 * Альтернативная версия с ограничением параллельных запросов
 * @param {Object} params - параметры
 * @param {number} maxConcurrent - максимальное количество параллельных запросов
 * @returns {Promise} результат выполнения
 */
function batchUpdateParallelLimited(params, maxConcurrent = 5) {
  const { result, chunkSize, fromRow, lastRow, sheet, raw, setHead, debug } =
    params;

  const spreadsheetId = sheet.getParent().getId();
  const sheetName = sheet.getName();
  const startRow = fromRow === -1 ? 1 : fromRow === 0 ? 2 : fromRow + 1;

  if (setHead && fromRow <= 1) setSheetHead(sheet);

  // Создаем массив задач
  const tasks = [];
  let currentRow = startRow;

  for (let i = 0; i < result.length; i += chunkSize) {
    const chunk = result.slice(i, i + chunkSize);
    const range = `'${sheetName}'!A${currentRow}`;

    tasks.push({
      range: range,
      chunk: chunk,
      startIndex: i,
      endIndex: Math.min(i + chunkSize, result.length),
    });

    currentRow += chunk.length;
  }

  // Выполняем задачи с ограничением параллельности
  return executeTasksWithLimit(
    tasks,
    maxConcurrent,
    (task) => {
      return new Promise((resolve, reject) => {
        try {
          const response = Sheets.Spreadsheets.Values.batchUpdate(
            {
              valueInputOption: raw ? "RAW" : "USER_ENTERED",
              data: [
                {
                  range: task.range,
                  values: task.chunk,
                },
              ],
            },
            spreadsheetId
          );
          resolve({
            task: task,
            response: response,
          });
        } catch (error) {
          reject({
            task: task,
            error: error,
          });
        }
      });
    },
    debug
  );
}

/**
 * Выполнение задач с ограничением параллельности
 * @param {Array} tasks - массив задач
 * @param {number} limit - лимит параллельных задач
 * @param {Function} taskExecutor - функция выполнения задачи
 * @param {boolean} debug - отладка
 * @returns {Promise} результат выполнения
 */
function executeTasksWithLimit(tasks, limit, taskExecutor, debug = false) {
  return new Promise((resolve, reject) => {
    const results = [];
    const errors = [];
    let running = 0;
    let index = 0;

    function runNext() {
      if (index >= tasks.length && running === 0) {
        // Все задачи завершены
        resolve({
          results: results,
          errors: errors,
          total: tasks.length,
          successful: results.length,
          failed: errors.length,
        });
        return;
      }

      while (running < limit && index < tasks.length) {
        const task = tasks[index++];
        running++;

        if (debug) {
          console.log(`Запуск задачи ${index}/${tasks.length}: ${task.range}`);
        }

        taskExecutor(task)
          .then((result) => {
            results.push(result);
            if (debug) {
              console.log(`Задача завершена успешно: ${task.range}`);
            }
          })
          .catch((error) => {
            errors.push(error);
            if (debug) {
              console.error(`Ошибка в задаче ${task.range}:`, error);
            }
          })
          .finally(() => {
            running--;
            runNext();
          });
      }
    }

    runNext();
  });
}

/**
 * Получение размера чанка на основе размера данных
 * @param {Array} data - данные
 * @returns {number} размер чанка
 */
function getChunkSize(data) {
  if (!data || data.length === 0) return 1000;

  let round = (a, b) => a - (a % b);
  return 10000 + round((data[0].length * 10000) / 26, 1000);
}

/**
 * Валидация данных перед вставкой
 * @param {Array} data - данные для валидации
 * @returns {boolean} результат валидации
 */
function _validateData(data) {
  if (!Array.isArray(data)) {
    throw new Error("Данные должны быть массивом");
  }

  if (data.length === 0) {
    throw new Error("Данные не могут быть пустыми");
  }

  // Проверяем, что все строки имеют одинаковую длину
  const firstRowLength = data[0].length;
  for (let i = 1; i < data.length; i++) {
    if (data[i].length !== firstRowLength) {
      throw new Error(
        `Строка ${i} имеет неправильную длину: ${data[i].length}, ожидается: ${firstRowLength}`
      );
    }
  }

  return true;
}

