      if (debug) console.log(`2 ${script} updateData:\n${logSheet}`);
      sheet.insertRowsAfter(maxRows, 1);
      updateData(dataOptions);
    } else {
      if (debug) console.log(`3 ${script} appendData:\n${logSheet}`);
      sheet.insertRowsAfter(maxRows, 1);
      appendData(dataOptions);
    }

    return rangeLastRow;
  } catch (error) {
    CONFIG.func.endScript({
      script,
      start,
      error,
    });
  }
}

function insertRowsForApi({
  sheet,
  fromRow,
  lastRow,
  result,
  insert = false,
  debug,
}) {
  fromRow = fromRow === -1 ? 0 : fromRow === 0 ? 2 : fromRow + 1;
  const startRow = fromRow;

  const range = sheet.getRange(fromRow, 1, result.length, result[0].length);

  const spreadsheetId = sheet.getParent().getId();
  const sheetName = sheet.getName();
  const rangeA1Notation = range.getA1Notation();
  const rangeLastRow = range.getLastRow();
  const maxRows = sheet.getMaxRows();
  const len = rangeLastRow - maxRows;

  const insertRowsCount =
    (Math.max(len, result.length, lastRow - fromRow + 1) + maxRows - lastRow,
    len);

  if (insert) {
    if (debug) console.log(`Добавление строк: ${insertRowsCount}`);
    if (insertRowsCount > 0) sheet.insertRowsAfter(maxRows, insertRowsCount);
  }

  return {
    spreadsheetId,
    sheetName,
    rangeA1Notation,
    startRow,
    _fromRow: fromRow,
    fromRow,
    rangeLastRow,
    maxRows,
    len,
    insertRowsCount,
  };
}

