/**
 * Decorator function that retries a function call if it throws an error with a specific message.
 *
 * @param {function} func - The function to be wrapped and retried.
 * @return {function} - The wrapped function that retries the original function call if it throws an error.
 */
function retryOnError(func) {
  /**
   * Executes the wrapped function and retries if an error occurs.
   * @param {...*} args - The arguments to be passed to the wrapped function.
   * @returns {*} - The result of the wrapped function.
   */
  return function (...args) {
    try {
      return func.apply(this, args);
    } catch (err) {
      console.log("Error", err.stack);
      const message = err.message;
      const stopPattern =
        /500|Too many simultaneous invocations: Spreadsheets|The service is currently unavailable|Service timed out: Spreadsheets|Service Spreadsheets timed out while accessing document with id/i;

      if (stopPattern.test(message)) {
        console.log("Retry...");
        Utilities.sleep(5000); // Wait for 5 seconds before retrying
        return func.apply(this, args);
      } else {
        throw err;
      }
    }
  };
}

/**
 * Создает лист, если он отсутствует в книге и возвращет его
 * @param {string} sheetName название листа
