 * @param {SpreadsheetApp.Sheet} sheet ссылка на лист
 * @param {boolean} clear очистить данные на листе
 * @param {number} fontSize размер шрифта
 */
function setSheetHead(sheet, clear = false, clearRange = false, fontSize = 7) {
  if (!clear && sheet && sheet.getFilter()) sheet.getFilter().remove();

  if (clear) {
    rangeClear({
      sheet,
      clearRange,
    });
  }

  sheet
    .getRange("1:1")
    .setVerticalAlignment("middle")
    .setHorizontalAlignment("center")
    .setBackground("#434343")
    .setFontSize(fontSize)
    .setFontColor("BACKGROUND")
    .setFontWeight("bold")
    .setBorder(
      true,
      true,
      true,
      true,
      true,
      true,
      "#ffffff",
      SpreadsheetApp.BorderStyle.SOLID
    )
    .setWrapStrategy(SpreadsheetApp.WrapStrategy.WRAP);
