}

/**
 * Clears the specified sheet based on the provided options.
 *
 * @param {Object} options - The options for clearing the sheet.
 * @param {GoogleAppsScript.Spreadsheet.Sheet} options.sheet - The sheet to clear.
 * @param {boolean} [options.contents=false] - Whether to clear the contents of the sheet.
 * @param {boolean} [options.formats=false] - Whether to clear the formats of the sheet.
 * @param {boolean} [options.formatRules=false] - Whether to clear the conditional format rules of the sheet.
 * @param {boolean} [options.notes=false] - Whether to clear the notes of the sheet.
 * @return {void}
 */
function sheetClear({
  sheet,
  contents = false,
  formats = false,
  formatRules = false,
  notes = false,
}) {
  if (sheet && sheet.getFilter()) sheet.getFilter().remove();

  if (contents) sheet.clearContents();
  else if (formats) sheet.clearFormats();
  else if (formatRules) sheet.clearConditionalFormatRules();
  else if (notes) sheet.clearNotes();
  else sheet.clear();
}

/**
 * Clears the specified range in the given sheet.
 *
 * @param {Object} options - The options for clearing the range.
 * @param {GoogleAppsScript.Spreadsheet.Sheet} options.sheet - The sheet containing the range to clear.
 * @param {boolean} [options.content=false] - If true, clears the content of the range.
 * @param {boolean} [options.format=false] - If true, clears the formatting of the range.
 * @param {boolean} [options.dataValidations=false] - If true, clears the data validations of the range.
 * @param {boolean} [options.note=false] - If true, clears the notes of the range.
 */
function rangeClear({
  sheet,
  clearRange,
  content = false,
  format = false,
  dataValidations = false,
  note = false,
}) {
  if (sheet && sheet.getFilter()) sheet.getFilter().remove();

  const range = Array.isArray(clearRange)
    ? sheet.getRangeList(clearRange)
    : typeof clearRange === "string"
    ? sheet.getRange(clearRange)
    : sheet.getDataRange();

  if (content) range.clearContent();
  else if (format) range.clearFormat();
  else if (dataValidations) range.clearDataValidations();
  else if (note) range.clearNote();
  else range.clear();
}

function sortSheetsInBook() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();

  const config = CONFIG.settings;
  const sheet = setSheetNew(config.sheetSheetsOrder, "BLACK", ss);

  const array = sheet
    .getDataRange()
    .getValues()
    .slice(1)
    .filter((e) => e[0] && e[1]);

  if (!array.length) {
    return ss.toast(`[INFO] Нет листов для сортировки`, "⚠️ ATTENTION", 7);
  }

  const sheetNameArray = array
    .sort((a, b) => a[0] - b[0])
    .map((r) => r[1].toString());

  const sheets = ss.getSheets();
  for (var j = 0; j < sheetNameArray.length; j++) {
    if (sheets[j].getName() !== sheetNameArray[j]) {
      ss.setActiveSheet(ss.getSheetByName(sheetNameArray[j]));
      ss.moveActiveSheet(j + 1);
    }
  }

  getSheetsInBook();
  ss.toast(`[INFO] Отсортировали листы`, "✅ SUCCESS", 7);
}

