    sheet = SpreadsheetApp.getActiveSheet();
  } catch (error) {
    console.error("Error get sheet", error.stack);
    sheet = ss.getActiveSheet();
  }

  const sheetName = sheet.getName();

  const ui = SpreadsheetApp.getUi();
  const copyInSheetId = ui
    .prompt("Введите URL или ID книги в которую копируем лист", ui.ButtonSet.OK)
    .getResponseText()
    .trim();

  if (copyInSheetId) {
    const destinationSpreadsheet = SpreadsheetApp.openById(
      copyInSheetId.match(/[-\w]{25,}/)[0]
    );
    let copiedSheet;
    try {
      copiedSheet = sheet.copyTo(destinationSpreadsheet);
      copiedSheet.setName(sheetName);
    } catch (error) {
      console.error("Error copyTo", error.stack);
    }

    copiedSheet.activate();
    destinationSpreadsheet.moveActiveSheet(1);
  } else ui.alert(`URL или ID не введён!!!`);
}

