 */
function sortDataBySheet(sheet, columnName) {
  const filter = sheet.getFilter();
  if (filter) {
    filter.sort(columnName, true);
  } else {
    const range = sheet.getRange(
      1,
      1,
      sheet.getMaxRows(),
      sheet.getMaxColumns()
    );
    const filter = range.createFilter();
    filter.sort(columnName, true);
  }
}

