  const allSheets = ss.getSheets();
  allSheets.forEach((sheet) => {
    const sheetName = sheet.getName();
    if (!sheetsToKeep.includes(sheetName)) {
      // Раскрываем все группы строк
      var maxRows = sheet.getMaxRows();
      for (var i = 1; i <= maxRows; i++) {
        var rowGroupDepth = sheet.getRowGroupDepth(i);
        if (rowGroupDepth > 0) {
          sheet.expandRowGroups(i);
        }
      }

      // Раскрываем все группы столбцов
      var maxColumns = sheet.getMaxColumns();
      for (var j = 1; j <= maxColumns; j++) {
        var colGroupDepth = sheet.getColumnGroupDepth(j);
        if (colGroupDepth > 0) sheet.expandColumnGroups(j);
      }
    }
  });
}

/**
 * Проверяет и исправляет формулы в столбце
 * Преобразует текстовые формулы в рабочие формулы
 * @param {string} sheetName - имя листа (по умолчанию текущий)
 * @param {string} column - столбец для обработки (например, "A", "B", "C")
 * @param {number} startRow - начальная строка (по умолчанию 1)
 * @param {number} endRow - конечная строка (по умолчанию последняя заполненная)
 */
function fixFormulasInColumn(sheetName, column, startRow = 1, endRow = null) {
  const sheet = sheetName
    ? SpreadsheetApp.getActiveSpreadsheet().getSheetByName(sheetName)
    : SpreadsheetApp.getActiveSheet();

  if (!sheet) {
    console.error(`Лист "${sheetName}" не найден`);
    return;
  }

  // Определяем конечную строку если не указана
  if (!endRow) {
    endRow = sheet.getLastRow();
  }

  console.log(
    `Быстро исправляем формулы в столбце ${column} с ${startRow} по ${endRow} строку`
  );

  // Получаем все значения и формулы сразу
  const range = sheet.getRange(`${column}${startRow}:${column}${endRow}`);
  const values = range.getValues();
  const formulas = range.getFormulas();

  let fixedCount = 0;
  const formulasToSet = [];

  // Обрабатываем массив значений
  for (let i = 0; i < values.length; i++) {
    const cellValue = values[i][0];
    const cellFormula = formulas[i][0];
    const currentRow = startRow + i;

    // Проверяем, является ли значение строкой, начинающейся с =
    if (typeof cellValue === "string" && cellValue.startsWith("=")) {
      // Если формула пустая, но значение содержит формулу - добавляем в массив для установки
      if (!cellFormula && cellValue.startsWith("=")) {
        formulasToSet.push([cellValue]);
        fixedCount++;
      }
      // Если формула отличается от значения - обновляем формулу
      else if (cellFormula !== cellValue) {
        formulasToSet.push([cellValue]);
        fixedCount++;
      } else {
        // Формула уже правильная
        formulasToSet.push([cellFormula]);
      }
    } else {
      // Не формула - оставляем как есть
      formulasToSet.push([cellValue]);
    }
  }

  // Устанавливаем все формулы одним вызовом
  if (fixedCount > 0) {
    range.setFormulas(formulasToSet);
    console.log(`Быстро исправлено ${fixedCount} формул в столбце ${column}`);
  } else {
    console.log(`Формулы в столбце ${column} уже корректны`);
  }

  return fixedCount;
}

