/**
 * Splits the given date range into smaller date ranges of the specified chunk size.
 *
 * @param {Date} startDate - the start date of the range
 * @param {Date} endDate - the end date of the range
 * @param {number} [chunk=14] - the size of each chunk in days
 * @return {Array} an array of date range pairs
 */
function splitDateRange(startDate, endDate, chunk = 14) {
  const dateArray = [];
  let currentDate = new Date(startDate);
  const stopDate = new Date(endDate);

  while (currentDate <= stopDate) {
    const periodStart = new Date(currentDate);
    let periodEnd = new Date(currentDate);
    periodEnd.setDate(periodEnd.getDate() + chunk); // Add 14 days to get the end of the 15-day period
    if (periodEnd > stopDate) {
      periodEnd = new Date(stopDate); // Adjust the end date to the stop date if it exceeds it
    }
    dateArray.push([periodStart, periodEnd]);
    currentDate.setDate(currentDate.getDate() + chunk + 1); // Move to the next 15-day period
  }
  return dateArray;
}

