}

/**
 * Calculates the week number of a given date.
 *
 * @param {Date} date - The date for which to calculate the week number.
 * @return {number} The week number of the given date.
 */
function getWeekNumber(date) {
  const sunday = new Date(date);
  sunday.setDate(sunday.getDate() + ((0 - sunday.getDay() + 6) % 7));
  const yearStart = new Date(sunday.getFullYear(), 0, 1);
  const weekNumber = Math.ceil(((sunday - yearStart) / 86400000 + 1) / 7);
  return weekNumber;
}

/**
 * Получить номер текущей недели ISO 8601
 * @return {number} номер текущей недели
 */
function getISOWeekNumber(date) {
  Date.prototype.getWeek = function () {
    // Create a copy of this date object.
    let target = new Date(this.valueOf());

    // ISO week date weeks start on monday, so correct the day number.
    let dayNr = (this.getDay() + 6) % 7;

    // ISO 8601 states that week 1 is the week with the first thursday of that year.
    // Set the target date to the thursday in the target week.
    target.setDate(target.getDate() - dayNr + 3);

    // Store the millisecond value of the target date.
    let firstThursday = target.valueOf();

    // Set the target to the first thursday of the year.
    // First set the target to january first.
    target.setMonth(0, 1);
    // Not a thursday? Correct the date to the next thursday.
    if (target.getDay() != 4)
      target.setMonth(0, 1 + ((4 - target.getDay() + 7) % 7));

    // The weeknumber is the number of weeks between the first thursday of the year and the thursday in the target week.
    return 1 + Math.ceil((firstThursday - target) / 604800000);
  };

  return date ? new Date(date).getWeek() : new Date().getWeek();
}

