 */
function getMondays(d = new Date(), time = false) {
  let month = d.getMonth(),
    mondays = [];

  d.setDate(1);

  // Get the first Monday in the month
  while (d.getDay() !== 1) {
    d.setDate(d.getDate() + 1);
  }

  // Get all the other Mondays in the month
  while (d.getMonth() === month) {
    time ? mondays.push(d.getTime()) : mondays.push(new Date(d.getTime()));
    d.setDate(d.getDate() + 7);
  }

  return mondays;
}

/**
 * Generates an array of date ranges between a start date and an end date.
 *
 * @param {Date} startDate - The start date of the range.
 * @param {Date} endDate - The end date of the range.
 * @param {number} [step=8] - The number of days between each date in the range. Default is 8.
 * @return {Array<Array<string>>} - An array of date ranges between the start and end dates.
 */
function getDatesBetween(startDate, endDate, step = 8) {
  const dates = [];
  let currentStart = new Date(startDate);
  const end = new Date(endDate);

  while (currentStart <= end) {
    const endOfInterval = new Date(
      currentStart.getTime() + (step - 1) * 24 * 60 * 60 * 1000
    );
    const intervalEnd =
      endOfInterval.getTime() > end.getTime() ? end : endOfInterval;

    dates.push([
      currentStart.toISOString().slice(0, 10),
      intervalEnd.toISOString().slice(0, 10),
    ]);

    if (intervalEnd.getTime() === end.getTime()) {
      break;
    }

    // Устанавливаем следующую начальную дату на день после окончания текущего интервала
    currentStart = new Date(intervalEnd);
    currentStart.setDate(currentStart.getDate() + 1);
  }

  return dates;
}

/**
 * Calculate the previous Monday based on the input date string, adjusting for Moscow time.
 *
 * @param {string} dateString - The input date string.
 * @return {string} The previous Monday formatted as "YYYY-MM-DD".
 */
function getPreviousMonday(dateString) {
  const date = new Date(dateString);
  const dayOfWeek = date.getDay();
  const diff = (dayOfWeek - 1 + 7) % 7; // Calculate the difference in days to Monday (1 is Monday, 0 is Sunday)
  const previousMonday = new Date(date.getTime() - diff * 24 * 60 * 60 * 1000); // Subtract the difference in milliseconds
  const moscowTimeOffset = 3 * 60 * 60 * 1000; // Moscow time is 3 hours ahead of UTC
  previousMonday.setTime(previousMonday.getTime() + moscowTimeOffset);
  // Format the previous Monday as "YYYY-MM-DD"
  return previousMonday.toISOString().split("T")[0];
}

/**
 * Calculate the next Monday based on the input date string.
 *
 * @param {string} dateString - The input date string in the format "YYYY-MM-DD".
 * @return {string} The next Monday formatted as "YYYY-MM-DD".
 */
function getNextMonday(dateString) {
  const date = new Date(dateString);
  const dayOfWeek = date.getDay();
  const daysUntilMonday = (8 - dayOfWeek) % 7; // Calculate the number of days until the next Monday
  const nextMonday = new Date(
    date.getTime() + (daysUntilMonday === 0 ? 7 : daysUntilMonday) * 86400000 // Monday to the timestamp of the current date
  );
  // Convert the next Monday date to an ISO string and extract the substring
  // representing the date (e.g., "2022-03-21")
  return nextMonday.toISOString().substring(0, 10);
}

