  }
  if (addDay) {
    dateValue = dateValue.setDate(dateValue.getDate() + addDay);
    return Utilities.formatDate(new Date(dateValue), timeZone, format);
  }
  return Utilities.formatDate(dateValue, timeZone, format);
}

/**
 * Converts milliseconds to HH:MM:SS format.
 *
 * @param {number} milliseconds - The number of milliseconds to convert.
 * @return {string} The converted time in HH:MM:SS format.
 */
function millisecondsToHHMMSS(milliseconds) {
  var seconds = Math.floor(milliseconds / 1000);
  var hours = Math.floor(seconds / 3600);
  seconds -= hours * 3600;
  var minutes = Math.floor(seconds / 60);
  seconds -= minutes * 60;

  if (hours < 10) hours = "0" + hours;
  if (minutes < 10) minutes = "0" + minutes;
  if (seconds < 10) seconds = "0" + seconds;

  return hours + ":" + minutes + ":" + seconds;
}

