/**
 * Generates date ranges for Moscow time zone based on the input start and end dates.
 *
 * @param {Date} dateFrom - The starting date for the date range.
 * @param {Date} dateTo - The ending date for the date range.
 * @return {Array} An array of date ranges in Moscow time zone.
 */
function generateDateRangesMoscow(dateFrom, dateTo) {
  const dateRanges = [];
  let currentMonth = new Date(dateFrom);
  const endMonth = new Date(dateTo);

  while (currentMonth <= endMonth) {
    const startOfMonth = new Date(
      Date.UTC(currentMonth.getFullYear(), currentMonth.getMonth(), 1)
    );
    const endOfMonth = new Date(
      Date.UTC(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 0)
    );

    // Convert to Moscow time zone
    startOfMonth.setHours(startOfMonth.getHours() + 3); // UTC+3 for Moscow
    endOfMonth.setHours(endOfMonth.getHours() + 3); // UTC+3 for Moscow

    let endOfMonthString = endOfMonth.toISOString().slice(0, 10);
    if (currentMonth.getMonth() === endMonth.getMonth()) {
      endOfMonthString = dateTo;
    }

    let startOfMonthString = startOfMonth.toISOString().slice(0, 10);
    if (currentMonth.getMonth() === new Date(dateFrom).getMonth()) {
      startOfMonthString = dateFrom;
    }

    dateRanges.push([startOfMonthString, endOfMonthString]);

    currentMonth.setMonth(currentMonth.getMonth() + 1);
  }

  return dateRanges;
}

