/**
 * Generates an array of start dates for each month between the input start date and the current date.
 *
 * @param {string} startDateStr - The starting date in string format.
 * @return {Array<string>} - An array of start dates in ISO string format.
 */
function getStartDatesOfMonths(startDateStr, setDateStartFirst) {
  const startDates = [];
  const currentDate = new Date();

  let startDate;
  if (setDateStartFirst) {
    startDate = new Date(startDateStr).setDate(1);
  } else {
    startDate = new Date(startDateStr);
  }

  let dateCursor = new Date(startDate);
  while (dateCursor <= currentDate) {
    startDates.push(new Date(dateCursor).toISOString());
    dateCursor.setMonth(dateCursor.getMonth() + 1, 1);
  }

  if (startDates.length === 0) {
    startDates.push(new Date(startDate).toISOString());
  }

  return startDates;
}

