function dataFromZippedCsv(response, unshift = true, delimiter = ",") {
  let result = [];
  const files = unzipData(response);

  try {
    console.log(`Total files: ${files.length}`); // Лог количества файлов

    for (let i = 0; i < files.length; i++) {
      let report = files[i];

      // Проверяем, что report.content не пустой
      if (!report || !report.content) {
        console.warn(`Skipped empty or invalid content at index ${i}`);
        continue;
      }

      let data = parseCsv(report.content, delimiter);

      // Проверяем, что CSV данные успешно обработаны
      if (!data || !Array.isArray(data) || data.length === 0) {
        console.warn(`Skipped invalid CSV data at index ${i}`);
        continue;
      }

      // console.log(data);

      // Удаляем заголовки данных
      if (unshift) data.shift();

      // Трансформируем данные
      const transformedData = data.map((row) =>
        row.map((cell) => (isNumeric(cell) ? Number(cell) : cell))
      );

      // Проверяем данные перед добавлением
      if (Array.isArray(transformedData) && transformedData.length > 0) {
        result = result.concat(transformedData); // Объединяем массивы
      } else {
        console.warn(`Transformed data is invalid at index ${i}`);
      }
    }
  } catch (error) {
    console.error("Error in dataFromZippedCsv", error.message, error.stack);
    throw error;
  }

  console.log("Result length", result.length);

  return result;
}

