/**
 * Преобразует 2D array (двумерный массив) в коллекцию
 * @param {Array.<Array.<any>>} e
 * @returns {Array.<object>}
 */
function arrayToCollection(e) {
  // Deep copy
  const array = e.map((r) => [...r]);
  // Headings become keys
  array[0].forEach((_, i) => (array[0][i] = array[0][i].toLocaleLowerCase()));
  return array
    .slice(1)
    .map(
      (r, c) => e[0].reduce((r, n, o) => ((r[n] = array[c + 1][o]), r), {}),
      []
    );
}

/**
 * Парсит csv
 * @param {string} csvString csv в строковом формате
 * @param {string} delimiter разделитель
 * @return {Array.<string,number>} массив данных
 */
function parseCsv(csvString, delimiter = ",") {
  let sanitizedString = csvString.replace(
    /(["'])(?:(?=(\\?))\2[\s\S])*?\1/g,
    function (e) {
      return e.replace(/\r?\n|\r/g, " ");
    }
  );
  return Utilities.parseCsv(sanitizedString, delimiter);
}

