}

/**
 * Divides an array into smaller arrays of a specified size.
 * @param {Array} arr - The array to be divided.
 * @param {number} size - The size of each smaller array.
 * @return {Array[]} An array containing smaller arrays of the specified size.
 */
function chunkArray(arr, size) {
  if (!Array.isArray(arr) || size <= 0) return [];
  const out = [];
  for (let i = 0; i < arr.length; i += size) out.push(arr.slice(i, i + size));
  return out;
}

