function lastRow(sh, col) {
  const values = sh.getRange(col + ":" + col).getValues();
  let lastRow;
  for (let i = values.length - 1; i >= 0; i--) {
    if (values[i][0]) {
      lastRow = i + 1;
      break;
    }
  }
  return lastRow;
}

