/**
 * Returns the column names of a Google Sheets table based on the length of the passed array.
 *
 * @param {number} length - The length of the array.
 * @return {string} - The column names corresponding to the given array length.
 */
function getColumnNamesByArrayLength(length) {
  var result = "";
  var quotient = Math.floor((length - 1) / 26);
  var remainder = (length - 1) % 26;
  var startCharCode = "A".charCodeAt(0);
  var firstLetter = String.fromCharCode(startCharCode + quotient - 1);
  var secondLetter = String.fromCharCode(startCharCode + remainder);
  if (quotient > 0) {
    result += firstLetter;
  }
  result += secondLetter;
  return `A:${result}`;
}

