 * @returns {string|null}
 */
function truncateString(str, maxLength = 50000) {
  if (typeof str !== 'string' || str.trim() === '') return null;
  return str.length > maxLength ? str.substring(0, maxLength) : str;
}


function secondsToHMS(seconds, longFormat = true) {
  const hours = Math.floor(seconds / 3600);
  const minutes = Math.floor((seconds % 3600) / 60);
  const remainingSeconds = seconds % 60;
  if (longFormat)
    return `${hours.toString().padStart(2, "0")}:${minutes
      .toString()
      .padStart(2, "0")}:${remainingSeconds.toString().padStart(2, "0")}`;
  return `${hours.toString().padStart(2, "0")}:${minutes
    .toString()
    .padStart(2, "0")}`;
}

/**
 * Универсальное форматирование суммы с разделителями тысяч
 * @param {number} amount - Сумма для форматирования
 * @param {string} separator - Разделитель тысяч (по умолчанию пробел)
 * @param {string} decimalSeparator - Разделитель десятичных (по умолчанию точка)
 * @param {number} decimals - Количество знаков после запятой (по умолчанию 2)
 * @returns {string} Отформатированная сумма
 */
function formatNumber(
  amount,
  separator = " ",
  decimalSeparator = ".",
  decimals = 2
) {
  if (typeof amount !== "number" || isNaN(amount)) {
    return "0";
  }

  // Преобразуем в строку с нужным количеством знаков после запятой
  const numStr = amount.toFixed(decimals);

  // Разделяем на целую и дробную части
  const parts = numStr.split(".");
  const integerPart = parts[0];
  const decimalPart = parts[1] || "";

  // Добавляем разделители тысяч к целой части
  let formattedInteger = "";
  for (let i = 0; i < integerPart.length; i++) {
