 * @param {Object} data - Объект с данными
 * @param {string} separator - Разделитель тысяч (по умолчанию пробел)
 * @param {string} decimalSeparator - Разделитель десятичных (по умолчанию точка)
 * @param {number} decimals - Количество знаков после запятой (по умолчанию 2)
 * @returns {Object} Объект с отформатированными числами
 */
function formatNumbers(
  data,
  separator = " ",
  decimalSeparator = ".",
  decimals = 2
) {
  const formatted = {};

  for (const [key, value] of Object.entries(data)) {
    if (typeof value === "number" && !isNaN(value)) {
      formatted[key] = formatNumber(
        value,
        separator,
        decimalSeparator,
        decimals
      );
    } else {
      formatted[key] = value;
    }
  }

  return formatted;
}

function setVerticalAlignmentWrapStrategy(sheet, rangeList) {
  if (!sheet) return;

  let range;

  if (rangeList) {
    range = sheet.getRangeList(rangeList);
  } else {
    range = sheet.getDataRange();
  }

  range
    // .activate()
    .setVerticalAlignment("middle")
    .setWrapStrategy(SpreadsheetApp.WrapStrategy.WRAP);
}

/**
 * Очистить лист
 */
function clear() {
  const sheet = SpreadsheetApp.getActiveSheet();
  const filter = sheet.getFilter();
  if (filter) {
    filter.remove();
  }
  sheet.clear();
}

/**
 * Очистить листы в списке
 * @param {string[]} sheets массив очищаемых листов
 * @param {SpreadsheetApp.ActiveSpreadsheet} [spreadsheet] книга, если используется не текущая
 */
function clearSheets(sheets, spreadsheet) {
  let ss = SpreadsheetApp.getActiveSpreadsheet();
  if (spreadsheet) ss = spreadsheet;
  sheets.forEach((item) => {
    const sheet = ss.getSheetByName(item);
    sheet.getFilter() ? sheet.getFilter().remove() : null;
    sheet.clear();
  });
  ss.toast(`Очистили листы ${sheets.join("\n")}`, "✅ SUCCESS", 10);
}

/**
 * Вставка проверки данных
 */
function setDataValidation(sheet, range, shp, rangeValidation, comment) {
  sheet
    .getRange(range)
    .setDataValidation(
      SpreadsheetApp.newDataValidation()
        .setAllowInvalid(false)
        .setHelpText(`${comment}`)
        .requireValueInRange(shp.getRange(rangeValidation), true)
        .build()
    );
  sheet.getRange(range).setFontSize(10).setHorizontalAlignment("center");
}

/**
 * Вставка проверки данных формула
 */
function setDataValidationFormula(sheet, range, formula, comment) {
  sheet
    .getRange(range)
    .setDataValidation(
      SpreadsheetApp.newDataValidation()
        .setAllowInvalid(false)
        .setHelpText(`${comment}`)
        .requireFormulaSatisfied(formula)
        .build()
    );
}

/**
 * Добавление условного форматирования формула
 */
function setConditionalFormulaRules(sh, range, formula, color) {
  let rangeToHighlight = sh.getRange(range);
  const rule = SpreadsheetApp.newConditionalFormatRule()
    .whenFormulaSatisfied(formula)
    .setBackground(color)
    .setRanges([rangeToHighlight])
    .build();
  let rules = sh.getConditionalFormatRules();
  rules.push(rule);
  sh.setConditionalFormatRules(rules);
}

/**
