 * @param {Array<Object>} data - массив объектов для группировки
 * @param {Array<string>} groupKeys - массив ключей для группировки
 * @param {Array<string>} sumKeys - массив ключей для суммирования
 * @param {string} separator - разделитель для составного ключа (по умолчанию "|")
 * @returns {Array<Object>} сгруппированные данные
 */
function universalGroupAndSum(data, groupKeys, sumKeys, separator = "|") {
  if (!Array.isArray(data) || data.length === 0) {
    return [];
