  if (!Array.isArray(groupKeys) || groupKeys.length === 0) {
    throw new Error("groupKeys должен быть непустым массивом");
  }

  if (!Array.isArray(sumKeys) || sumKeys.length === 0) {
    throw new Error("sumKeys должен быть непустым массивом");
