    const groupKey = groupKeyParts.join(separator);

    // Создаем объект для хранения сумм
    const sumValues = {};
    sumKeys.forEach((key) => {
      const value = item[key];
      const numValue = Number(value);
      sumValues[key] = isNaN(numValue) ? 0 : numValue;
    });

    if (result.has(groupKey)) {
      // Если группа уже существует, суммируем значения
      const existing = result.get(groupKey);
      sumKeys.forEach((key) => {
        existing[key] += sumValues[key];
