    }

    // Создаем составной ключ для группировки
    const groupKeyParts = groupIndices.map((index) => {
      const value = row[index];
      // Обрабатываем пустые значения: null, undefined, "" заменяем на специальный маркер
      if (value === null || value === undefined || value === "") {
