        // Сохраняем оригинальные значения, включая пустые
        newGroup[index] = row[index];
      });
      sumIndices.forEach((index) => {
        newGroup[index] = sumValues[index];
      });
      result.set(groupKey, newGroup);
    }
  });

  // Преобразуем результат обратно в массив массивов
