/**
 * Создает текстовый файл в Google Drive пользователя
 * @param {string} name - Имя файла (без расширения)
 * @param {string} data - Данные для сохранения
 * @param {string} folderId - ID папки (опционально, по умолчанию корневая папка)
 * @returns {Object} Информация о созданном файле
 */
function saveAsTxt(name, data, folderId) {
  try {
    const fileSets = {
      title: `${name}.txt`,
      mimeType: "text/plain",
      parents: [{ id: folderId || DriveApp.getRootFolder().getId() }],
    };

    const blob = Utilities.newBlob(data, "text/plain");
    const file = Drive.Files.insert(fileSets, blob);

    console.log(
      "ID: %s, File size (bytes): %s, title: %s",
      file.id,
      file.fileSize,
      file.title
    );

    return file;
  } catch (error) {
    console.error("Ошибка создания текстового файла:", error);
    throw new Error(`Не удалось создать файл ${name}.txt: ${error.message}`);
  }
}

/**
 * Создает JSON файл в Google Drive пользователя
 * @param {string} name - Имя файла (без расширения)
 * @param {*} data - Данные для сохранения
 * @param {boolean} [raw=true] - без отступов (компактный JSON); false — с отступами
 * @param {string} folderId - ID папки (опционально, по умолчанию корневая папка)
 * @returns {Object} Информация о созданном файле
 */
function saveAsJSON(name, data, raw = true, folderId) {
  try {
    const fileSets = {
      title: `${name}.json`,
      mimeType: "application/json",
      parents: [{ id: folderId || DriveApp.getRootFolder().getId() }],
    };

    const MAX_RECORDS = 3000;
    const payload = Array.isArray(data) && data.length > MAX_RECORDS
      ? { __truncated: true, total: data.length, sample: data.slice(0, MAX_RECORDS) }
      : data;
    const blob = Utilities.newBlob(
      raw ? JSON.stringify(payload) : JSON.stringify(payload, null, 2),
      "application/json",
    );
    const file = Drive.Files.insert(fileSets, blob);

    console.log(
      "ID: %s, File size (bytes): %s, title: %s",
      file.id,
      file.fileSize,
      file.title,
    );

    return file;
  } catch (error) {
    console.error("Ошибка создания JSON файла:", error);
    throw new Error(`Не удалось создать файл ${name}.json: ${error.message}`);
  }
}

