/**
 * Установить триггер с частой запуска
 * @see https://developers.google.com/apps-script/reference/script/clock-trigger-builder
 * @param {name} название триггера
 * @param {number} minutes время в минутах (1, 5, 10, 15, 30)
 * @param {number} hours каждый n час (1, 2, 4, 6, 8, 12)
 * @param {number} hour в n час (совместно с days и monthDay)
 * @param {number} days каждый n день (1-7, совместно с hour)
 * @param {number} monthDay каждый день месяца (1-31, совместно с hour)
 * @param {ScriptApp.WeekDay} weekDay в день недели (ScriptApp.WeekDay.MONDAY):
 * - SUNDAY - Воскресенье;
 * - MONDAY - Понедельник;
 * - TUESDAY - Вторник;
 * - WEDNESDAY - Среда;
 * - THURSDAY - Четверг;
 * - FRIDAY - Пятница;
 * - SATURDAY - Суббота.
 * @return {boolean} true или false
 */
function setTriggerBy(options) {
  const {
    minutes,
    hour,
    hours,
    days,
    weeks,
    weekDay,
    monthDay,
    name,
    exclude,
  } = options;

  const ss = SpreadsheetApp.getActiveSpreadsheet();
  if (!name) {
    ss.toast("Не указано название функции для триггера", "⛔️ ATTENTION", 5);
    return;
  }

  const owner = context?.owner || ss.getOwner()?.getEmail();
  const user = Session.getActiveUser().getEmail();

  // console.log("owner", owner, user);

  const config = CONFIG.settings;

  if (![owner, config.mail].includes(user)) {
    ss.toast(
      "Только владелец таблицы может установить триггер",
      "⛔️ ATTENTION",
      5
    );
    return;
  }

  const triggers = ScriptApp.getProjectTriggers();

  if (triggers.length === 20) {
    ss.toast(
      "В этом файле слишком много триггеров. Чтобы добавить новые, сначала удалите существующие",
      "⛔️ ATTENTION",
      15
    );
    return;
  }

  for (var i in triggers) {
    const trigger = triggers[i].getHandlerFunction();
    if (!exclude && trigger === name) {
      ss.toast(`Триггер ${name} установлен`, "⚠️ ATTENTION", 5);
      return false;
    }
  }

  const triggerBuilder = ScriptApp.newTrigger(name).timeBased();

  if (minutes) {
    // Set the trigger to run every n minutes, must be 1, 5, 10, 15, or 30.
    triggerBuilder.everyMinutes(minutes);
  }

  if (hours) {
    // Set the trigger to run every n hours.
    triggerBuilder.everyHours(hours);
  }

  if (days && hour) {
    if (hour === 0) {
      // Set the trigger to run every n days at n hour.
      triggerBuilder.everyDays(days);
    } else {
      triggerBuilder.everyDays(days).atHour(hour);
    }
  }

  if (weeks) {
    // Set the trigger to run every n weeks.
    triggerBuilder.everyWeeks(weeks);
  }

  if (weekDay && hour) {
    if (hour === 0) {
      // Set the trigger to run on the specified day of the week.
      triggerBuilder.onWeekDay(weekDay);
    } else {
      triggerBuilder.onWeekDay(weekDay).atHour(hour);
    }
  }

  if (monthDay && hour) {
    // Set the trigger to run on the specified date of the month at n hour.
    triggerBuilder.onMonthDay(monthDay).atHour(hour);
  }

  triggerBuilder.create();

  const triggerRange = context?.triggerRange || config.triggerRange;

  // console.log("Lib", JSON.stringify(triggerRange, null, 2));

  const range = triggerRange[name] || 0;

  if (range)
    ss.getSheetByName(config.sheetSettings)
      .getRange(`F${range}`)
      .setValue("✅");

  console.log(`Триггер ${name} установлен`);
  ss.toast(`Триггер ${name} установлен`, "✅ SUCCESS", 5);
}

/**
 * Удалить триггер по имени
 * @param {name} название триггера
 * @return {boolean} true или false
 */
function deleteTrigger(name) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  if (!name) {
    ss.toast("Не указано название функции для триггера", "⛔️ ATTENTION", 5);
    return;
  }

  const triggers = ScriptApp.getUserTriggers(ss);

  const triggerToDelete = triggers.find(
    (trigger) => trigger.getHandlerFunction() === name
  );

  if (triggerToDelete) {
    ScriptApp.deleteTrigger(triggerToDelete);
    ss.toast("Триггер удалён", "✅ SUCCESS", 5);
    return true;
  }

  ss.toast("Триггера для удаления не найдено", "⚠️ ATTENTION", 5);
  return false;
}

/**
 * Удалить все триггеры
 * @return {boolean} true или false
 */
function deleteTriggers() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();

  const owner = context?.owner || ss.getOwner()?.getEmail();
  const user = Session.getActiveUser().getEmail();
  const config = CONFIG.settings;

  if (![owner, config.mail].includes(user)) {
    ss.toast(
      "Только владелец таблицы может удалить триггеры",
      "⛔️ ATTENTION",
      5
    );
    return false;
  }

  const sheet = ss.getSheetByName(config.sheetSettings);

  const triggerRange = context?.triggerRange || config.triggerRange;

  // console.log("Lib", JSON.stringify(triggerRange, null, 2));

  ScriptApp.getProjectTriggers().forEach((trigger) => {
    ScriptApp.deleteTrigger(trigger);
    const range = triggerRange[trigger.getHandlerFunction()];
    if (range) {
      sheet.getRange(`F${range}`).setValue("❌");
    }
  });

  ScriptApp.getUserTriggers(ss).forEach((trigger) => {
    ScriptApp.deleteTrigger(trigger);
    const range = triggerRange[trigger.getHandlerFunction()];
    if (range) {
      sheet.getRange(`F${range}`).setValue("❌");
    }
  });

  ss.toast("Триггеры удалёны", "✅ SUCCESS", 5);
  return true;
}

/**
 * Creates a time-based trigger that runs after a specified number of seconds.
 *
 * @param {string} name - The name of the function to trigger.
 * @param {number} [seconds=1] - The delay in seconds before the trigger runs. Defaults to 1 minute.
 */
function createTriggerRun(triggerName, seconds = 1) {
  const createTime = seconds * 1000 * 60;
  ScriptApp.newTrigger(triggerName)
    .timeBased()
    .after(createTime) // 1 минута
    // .everyMinutes(seconds)
    .create();
}

function deleteTriggersWithName(triggerName) {
  var triggers = ScriptApp.getProjectTriggers();
  for (var i = 0; i < triggers.length; i++) {
    if (triggers[i].getHandlerFunction() === triggerName) {
      ScriptApp.deleteTrigger(triggers[i]);
    }
  }
}
